-- 1b. VIEWS (CREATE OR REPLACE)
-- ============================================
-- View: panihati_yatra_combined_stats
DROP VIEW IF EXISTS `panihati_yatra_combined_stats`;
CREATE ALGORITHM=UNDEFINED SQL SECURITY DEFINER VIEW `panihati_yatra_combined_stats` AS select 'individual' AS `entry_type`,`panihati_yatra_registrations`.`id` AS `source_id`,`panihati_yatra_registrations`.`name` AS `name`,`panihati_yatra_registrations`.`phone` AS `phone`,`panihati_yatra_registrations`.`email` AS `email`,`panihati_yatra_registrations`.`travel_mode` AS `travel_mode`,`panihati_yatra_registrations`.`adults_count` AS `adults_count`,`panihati_yatra_registrations`.`kids_count` AS `kids_count`,`panihati_yatra_registrations`.`bhakti_sadan` AS `bhakti_sadan`,coalesce(`panihati_yatra_registrations`.`pickup_location`,'') AS `pickup_location`,`panihati_yatra_registrations`.`amount` AS `amount`,`panihati_yatra_registrations`.`payment_status` AS `payment_status`,`panihati_yatra_registrations`.`is_offline` AS `is_offline`,year(`panihati_yatra_registrations`.`created_at`) AS `report_year`,`panihati_yatra_registrations`.`created_at` AS `report_date` from `panihati_yatra_registrations` where (`panihati_yatra_registrations`.`payment_status` in ('paid','offline')) union all select 'aggregate' AS `entry_type`,`panihati_yatra_offline_aggregates`.`id` AS `source_id`,'' AS `name`,'' AS `phone`,'' AS `email`,`panihati_yatra_offline_aggregates`.`travel_mode` AS `travel_mode`,`panihati_yatra_offline_aggregates`.`adults_count` AS `adults_count`,`panihati_yatra_offline_aggregates`.`kids_count` AS `kids_count`,`panihati_yatra_offline_aggregates`.`bhakti_sadan` AS `bhakti_sadan`,coalesce(`panihati_yatra_offline_aggregates`.`pickup_location`,'') AS `pickup_location`,`panihati_yatra_offline_aggregates`.`amount` AS `amount`,'offline' AS `payment_status`,1 AS `is_offline`,`panihati_yatra_offline_aggregates`.`reported_year` AS `reported_year`,str_to_date(concat(`panihati_yatra_offline_aggregates`.`reported_year`,'-01-01'),'%Y-%m-%d') AS `report_date` from `panihati_yatra_offline_aggregates`;

