-- donation_causes (74 rows)
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (1, 'festival-seva-fund', 'Festival Seva Fund', 'Festival Fund', 'Support all major festival celebrations throughout the year.', 'Throughout the year, ISKCON Sri Jagannath Mandir celebrates numerous festivals that bring the community together in devotion. From grand chariot processions to intimate temple ceremonies, each festival requires extensive planning, materials, and resources.', 'Festivals are the lifeblood of temple culture. They bring the timeless pastimes of the Lord to life, allowing devotees to immerse themselves in divine consciousness and celebrate the glories of the Supreme Lord.', 'By contributing to the Festival Seva Fund, you earn the collective blessings of all festivals celebrated throughout the year. Your support ensures that these sacred traditions continue to inspire and uplift countless souls.', 'festival', NULL, NULL, NULL, 0, NULL, NULL, 1, 1, 'monthly', 100.00, 'tiers', 1, 0, 1, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 06:00:02', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (2, 'ekadashi-seva-fund', 'Ekadashi Seva Fund', 'Ekadashi Fund', 'Support Ekadashi observances and special offerings.', 'Ekadashi, the eleventh day of the lunar fortnight, is a day especially dear to Lord Vishnu. Observed since time immemorial, this sacred day involves fasting and heightened devotional practices as described in the Padma Purana.', 'Lord Krishna Himself states in the Bhagavad-gita, \"Among days I am Ekadashi.\" Observing Ekadashi purifies the mind and senses, helping devotees advance in spiritual life.', 'Supporting Ekadashi observances helps maintain the tradition of fasting, special deity offerings, and prasadam distribution. Donors receive the spiritual benefits of these sacred observances throughout the year.', 'ekadashi', NULL, NULL, NULL, 0, NULL, NULL, 1, 1, 'monthly', 100.00, 'tiers', 2, 0, 1, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 06:00:02', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (3, 'appearance-seva-fund', 'Appearance Seva Fund', 'Appearance Fund', 'Support appearance day celebrations of our exalted acharyas.', 'The appearance days of our beloved acharyas mark the advent of great souls who dedicated their lives to spreading Krishna consciousness. Srila Prabhupada, Bhaktivinoda Thakura, Bhaktisiddhanta Sarasvati Thakura, and Advaita Acharya all appeared in this world to fulfill specific missions.', 'These mahatmas appear out of their causeless mercy to deliver the fallen souls. Their appearance days are transcendental occasions, more significant than ordinary birthdays, as they commemorate the descent of pure representatives of the Lord.', 'Celebrating their appearance days invokes their special blessings. Supporting these celebrations helps continue their mission of spreading the holy name and Vedic wisdom worldwide.', 'appearance', NULL, NULL, NULL, 0, NULL, NULL, 1, 1, 'monthly', 100.00, 'tiers', 3, 0, 1, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 06:00:02', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (4, 'disappearance-seva-fund', 'Disappearance Seva Fund', 'Disappearance Fund', 'Support disappearance day observances.', 'The disappearance days of our exalted acharyas are observed with reverence and gratitude. These great souls left behind a legacy of love for Krishna, having dedicated every moment of their lives to the mission of Sri Chaitanya Mahaprabhu.', 'Their departure is not an end but a transition to their eternal pastimes. Observing these days reminds us of their teachings, sacrifices, and the urgency of making progress in spiritual life.', 'Honoring the disappearance of great devotees brings their mercy and blessings. Supporting these observances preserves their legacy and teachings for future generations.', 'disappearance', NULL, NULL, NULL, 0, NULL, NULL, 1, 1, 'monthly', 100.00, 'tiers', 4, 0, 1, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 06:00:02', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (5, 'events-seva-fund', 'Events Seva Fund', 'Events Fund', 'Support special temple events and programs.', 'Throughout the year, the temple organizes various special events including Caturmasya observances, Shiksha ceremonies, and programs that enrich the spiritual lives of devotees.', 'These events provide structured opportunities for devotees to deepen their spiritual practices, learn from scriptures, and participate in community-building activities.', 'Supporting temple events allows more devotees to benefit from these spiritual programs. Your contribution helps cover costs of materials, food, and facilities needed for successful events.', 'event', NULL, NULL, NULL, 0, NULL, NULL, 1, 1, 'monthly', 100.00, 'tiers', 5, 0, 1, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 06:00:02', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (6, 'daily-seva', 'Daily Seva', 'Daily Seva', 'Sponsor the daily worship, offerings, and maintenance of the deities at the temple. Your contribution supports the sacred daily rituals.', 'The daily worship of the Deities in the temple follows the ancient Pancaratra system, a tradition meticulously preserved in ISKCON temples worldwide. Srila Prabhupada established rigorous standards for deity worship, emphasizing that the Lord accepts our offerings through the pure medium of devotional service.', 'Daily Seva is the foundation of temple worship. Each day, the deities are bathed, dressed, offered food, and worshipped with arati five times. Participating in this daily service connects you directly to the Lord pastimes.', 'Sponsoring daily seva brings immense spiritual merit. You become a partner in the daily worship of the Lord, receiving blessings that purify your consciousness and bring peace to your home and family.', 'service', 'deity_worship', 'assets/images/banners/tulasi-maharani.jpg', NULL, 0, NULL, NULL, 1, 1, 'one_time', 100.00, 'cart', 10, 1, 1, 'service', 'daily-seva', '2026-06-29 21:56:55', '2026-06-30 14:25:08', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (7, 'nitya-seva', 'Nitya Seva', 'Nitya Seva', 'Become a regular sponsor of the daily seva of the deities. Choose from various levels of eternal service.', 'The concept of Nitya (eternal) Seva has been practiced in Indian temples for millennia. Regular devotees take up the responsibility of sponsoring specific aspects of temple worship on an ongoing basis, ensuring the continuity of sacred rituals.', 'Nitya Seva represents an unbroken chain of devotion. By committing to regular sponsorship, you establish an eternal connection with the temple and the deities.', 'Regular seva brings sustained spiritual benefits. It creates a continuous flow of blessings, purifies your daily life, and ensures your family spiritual well-being.', 'service', 'deity_worship', 'assets/images/banners/shaligram.jpg', NULL, 0, NULL, NULL, 1, 1, 'monthly', 100.00, 'cart', 11, 1, 1, 'service', 'nitya-seva', '2026-06-29 21:56:55', '2026-06-30 14:25:08', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (8, 'food-for-life', 'Food for Life (Annadana)', 'Food for Life', 'Sponsor sanctified meals for devotees, visitors, and the needy through our Food for Life program.', 'Food for Life is ISKCON international relief initiative, inspired by Srila Prabhupada directive that No one within ten miles of a temple should go hungry. Since 1974, ISKCON has served billions of plant-based meals worldwide.', 'Annadana (donation of food) is considered the highest form of charity in Vedic culture. When the food is first offered to Lord Krishna, it becomes sanctified prasadam that purifies the heart and elevates consciousness.', 'By sponsoring meals, you feed the hungry and give them the opportunity to receive Krishna prasadam. The Bhagavad-gita states that offering food to the Lord and sharing it with others brings immense spiritual merit.', 'service', 'food', 'assets/images/banners/food-for-life-service.jpeg', NULL, 0, NULL, NULL, 1, 1, 'one_time', 100.00, 'cart', 12, 1, 1, 'service', 'food-for-life', '2026-06-29 21:56:55', '2026-06-30 14:25:08', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (9, 'shastra-daan', 'Shastra Daan (Book Donation)', 'Shastra Daan', 'Sponsor the distribution of Srila Prabhupada\'s Bhagavad-gita As It Is to spread Krishna consciousness.', 'Srila Prabhupada Bhagavad-gita As It Is, translated and commented upon to present the timeless wisdom in its pure form. He emphasized book distribution as the most effective method of preaching.', 'The Bhagavad-gita is the essence of all Vedic knowledge. Distributing this sacred text gives others the opportunity to understand the purpose of life, the nature of the soul, and the path to eternal happiness.', 'Sponsoring Gita distribution makes you part of Srila Prabhupada mission to spread Krishna consciousness worldwide. Every book distributed has the potential to transform someone life forever.', 'service', 'education', 'assets/images/banners/bhagavad-gita-as-it-is-banner.jpg', NULL, 0, NULL, NULL, 1, 1, 'one_time', 100.00, 'quantity', 13, 1, 1, 'service', 'shastra-daan', '2026-06-29 21:56:55', '2026-06-30 05:35:59', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (10, 'tula-daan-utsav', 'Tula Daan Utsav', 'Tula Daan', 'Donate items by weight — rice, wheat flour, edible oil, or dry fruits — in this sacred ritual of proportionate giving.', 'Tula Daan (donation by weight) is an ancient Vedic practice where devotees donate items equal to their body weight. This temple offers a simplified version where you can donate essential food items by weight for distribution as prasadam.', 'This practice symbolizes offering one\'s entire being to the Lord. By donating in proportion, you acknowledge that everything belongs to the Supreme and that we are merely caretakers of His resources.', 'Tula Daan helps provide nutritious meals for thousands. The act of giving by weight symbolizes complete surrender and brings proportionally greater spiritual blessings.', 'service', 'donation', 'assets/images/banners/govindas-prasadam.jpg', NULL, 0, NULL, NULL, 1, 1, 'one_time', 100.00, 'multi_item', 14, 1, 1, 'service', 'tula-daan', '2026-06-29 21:56:55', '2026-06-30 06:00:02', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (11, 'donate-a-brick', 'Donate a Brick (Temple Construction)', 'Donate a Brick', 'Contribute to temple construction and development. Each brick helps build the divine abode.', 'Temple construction has been a cornerstone of Vedic culture for thousands of years. Kings, sages, and common people alike have contributed to building magnificent temples that stand as spiritual beacons through the ages.', 'Building a temple creates a permanent center for spiritual activities. It provides a place where the Lord can reside and bless countless visitors for generations to come.', 'The Srimad-Bhagavatam glorifies those who build temples for the Lord. Every brick contributed becomes part of the Lord\'s divine abode, bringing lasting spiritual merit to the donor and their family.', 'construction', NULL, 'assets/images/banners/golden-temple.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 15, 1, 1, 'service', 'donate-a-brick', '2026-06-29 21:56:55', '2026-06-30 14:25:08', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (12, 'general-donation', 'General Donation', 'General', 'Support the overall mission of the temple. Your donation helps us direct funds where they are most needed.', 'The temple functions as a spiritual oasis, offering daily worship, educational programs, community services, and outreach activities. General donations provide the flexibility to allocate resources where they create the most impact.', 'Your general donation becomes a lifeline for the temple operations, supporting everything from electricity bills to spiritual programs, ensuring the temple remains a vibrant center of Krishna consciousness.', 'General donors become essential partners in the temple mission. Your support enables us to respond to urgent needs, seize opportunities for service, and maintain the highest standards of worship and hospitality.', 'general', NULL, 'assets/images/banners/founder-acharya.jpg', NULL, 0, NULL, NULL, 1, 1, 'one_time', 100.00, 'cart', 20, 1, 1, 'service', 'general', '2026-06-29 21:56:55', '2026-06-30 10:07:31', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (13, 'janmashtami', 'Sri Krishna Janmashtami', 'Janmashtami', 'The appearance day of Lord Sri Krishna — celebrate with grand abhishekam, flower decorations, and midnight arati.', 'Janmashtami commemorates the birth of Lord Krishna, the Supreme Personality of Godhead, who appeared in the prison of Mathura at midnight on Bhadrapada Krishna Ashtami. Born to Devaki and Vasudeva, Krishna advent was prophesied to end the tyrannical rule of King Kansa.', 'Lord Krishna appearance marks the descent of the Absolute Truth into this material world. As He states in the Bhagavad-gita (4.7-8), Whenever and wherever there is a decline in religious practice, I descend Myself.', 'Sponsoring Janmashtami celebrations brings immense spiritual blessings. Fasting and worshipping on this day removes all sins and bestows liberation. Donors receive the Lord special blessings and protection.', 'festival', '', 'assets/images/banners/janmashtami.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 30, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-07-03 16:07:16', '<p>
        Janmashtami is one of the most prominent festivals, celebrated with great grandeur and enthusiasm to commemorate the birth of Lord Krishna. Devotees express their love for the Lord through fasts, night sankirtans, dramatic presentations, and temple offerings.
      </p>
      
      <p>
        The advent of Lord Krishna is highly significant. The reason for the Supreme Lord\'s descent is to end the cruel rule of demon Kansa and give pleasure to His surrendered devotees. Lord Krishna appeared in the prison of Mathura at midnight on the eighth day of Krishna paksha to Mother Devaki and Vasudeva.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Prophecy and the Trials of Devaki</h3>
      <p>
        According to the Puranas, King Kansa made grand arrangements for the marriage of his sister Devaki. But during the wedding procession, a voice from the sky foretold that Devaki\'s eighth son would destroy Kansa and end his dictatorial rule. In a rage, Kansa grabbed Devaki\'s hair to kill her. 
      </p>
      
      <p>
        Vasudeva stepped in with patience and wisdom to save his wife, promising Kansa that they would hand over every child born to them. Kansa spared Devaki\'s life but imprisoned the couple under heavy guard. Encouraged by Narada Muni, who warned that the Lord could appear in any form at any time, Kansa brutally killed the first seven children born to them.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Divine Descent</h3>
      <p>
        At midnight, the eighth child appeared. Lord Krishna descended not as an ordinary human child, but in His four-armed (chaturbhuj) form, adorned with jewels, holding a disc, conch, club, and lotus. He then adopted the form of a small baby. 
      </p>
      
      <p>
        As soon as the Lord appeared, the shackles unlocked, the iron gates of the prison cell opened by themselves, and all the guards fell under a deep magic spell. Vasudeva placed the child in a basket, crossed the raging Yamuna River (which parted for them), and exchanged Him with the baby girl born to Maharaja Nanda and Mother Yashoda in Gokula. Vasudeva then returned to the prison.
      </p>
      
      <p>
        When Kansa was informed of the birth, he rushed to the cell to kill the child. As he grabbed the baby girl, she slipped from his hands, flew into the sky, and manifested as the eight-armed goddess Durga, proclaiming: 
        <em>\"O Kansa, the one who will kill you has already been born elsewhere!\"</em>
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"yadā yadā hi dharmasya glānir bhavati bhārata<br>
        abhyutthānam adharmasya tadātmānaṁ sṛijāmyaham\"<br><br>
        \"Whenever and wherever there is a decline in religious practice, O descendant of Bharata, and a predominant rise of irreligion—at that time I descend Myself.\" &mdash; Bhagavad Gita 4.7
      </blockquote>

      <p>
        Lord Krishna\'s birth is purely spiritual. Srila Prabhupada explained it through the analogy of the sun: the sun rises and sets, but this does not mean the sun dies or is born anew; it merely goes out of our sight. Similarly, the Supreme Lord is beyond birth and death, appearing to perform His pastimes before moving to another universe.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">How Janmashtami is Celebrated</h3>
      <p>
        In ISKCON temples, festivities begin before dawn and extend past midnight:
      </p>
      
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Fasting:</strong> Devotees fast the entire day until midnight to focus their thoughts on Krishna.</li>
        <li><strong>Abhisheka:</strong> The deities are bathed in auspicious liquids (milk, honey, yogurt, fruit juices) in a grand, two-hour ceremony.</li>
        <li><strong>Offerings:</strong> Priests offer a massive feast of over a hundred different preparations.</li>
        <li><strong>Bhajans & Kirtans:</strong> Congregational singing of the Hare Krishna Mahamantra echoes throughout the day.</li>
        <li><strong>Altar Opening:</strong> At midnight, the curtains pull back to reveal the freshly dressed deities on a beautifully festooned altar, followed by a rousing, ecstatic arati.</li>
      </ul>', 'Calendar: Celebrated on Bhadrapada Krishna Ashtami (8th day of waning moon) (August/September)|Significance: The appearance day of the Supreme Personality of Godhead, Lord Sri Krishna, to end evil and protect His devotees.|Key Highlights: Day-long fasting until midnight, grand abhishekam (bathing deities with auspicious liquids), elaborate flower decorations, 108 dishes offered, and ecstatic midnight arati.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', '', '');
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (14, 'gaura-purnima', 'Gaura Purnima', 'Gaura Purnima', 'The appearance day of Sri Chaitanya Mahaprabhu — celebrate with sankirtan, abhishekam, and feast.', 'Gaura Purnima celebrates the appearance of Sri Chaitanya Mahaprabhu, who is Lord Krishna Himself appearing in the golden complexion of Srimati Radharani. He took birth in Sridham Mayapur in 1486 AD as the son of Jagannath Mishra and Sachi Devi. His mission was to establish the sankirtana movement — congregational chanting of the Hare Krishna maha-mantra — as the yuga-dharma for the age of Kali.', 'Lord Chaitanya is the most merciful incarnation, freely distributing the highest spiritual nectar of Krishna-prema (love of God) to all without distinction. He is known as Vishwambhara, \"one who maintains the universe,\" and appeared for the liberation of all fallen souls.', 'Participating in Gaura Purnima celebrations brings the special mercy of Lord Chaitanya. Sponsoring the abhishekam, deities\' outfits, or the grand feast invokes His blessings and helps you advance rapidly in Krishna consciousness.', 'festival', NULL, 'assets/images/banners/gaura-purnima.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 31, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Gaura Purnima is the auspicious appearance day of Sri Chaitanya Mahaprabhu (who is also known as Gauranga due to His golden complexion). The Supreme Lord Sri Krishna appeared as Sri Chaitanya Mahaprabhu to establish Sankirtana (the collective chanting of the Holy Names) &mdash; the Yuga Dharma for this age of Kali.
      </p>
      
      <p>
        He appeared on Phalguni Purnima, the full moon day in the month of Phalguna (Feb-March), in the year 1486 AD (1407 Shakabda) at Sridham Mayapura, as the son of Sri Jagannath Mishra and Srimati Sachidevi. His parents named Him Nimai since He was born under a nimba (neem) tree in the courtyard of His paternal house.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Supernatural Birth</h3>
      <p>
        Lord Chaitanya appeared first in the heart of Jagannath Mishra and was then transferred to the heart of Mother Sachi. He stayed for 13 months in the womb of Mother Sachi. When Nilambara Chakravarty, Sachi\'s father and a renowned astrologer, was asked about the delay, he predicted that the delivery would take place at the perfect astrological moment.
      </p>
      
      <p>
        When Sri Chaitanya Mahaprabhu appeared, He was a golden-colored baby, and Jagannath Mishra was overjoyed. Heavenly demigoddesses came from the celestial planets disguised as brahmanis to take darshan of Gauranga and offer prayers to this Kali-yuga avatar.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Hare Krishna Hare Krishna Krishna Krishna Hare Hare<br>
        Hare Rama Hare Rama Rama Rama Hare Hare\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Purpose of His Descent</h3>
      <p>
        The primary reason for Lord Gauranga\'s descent was the prayer of Advaita Acharya, who worshipped his Shaligram Sila with Tulasi manjaris and cried out loudly for Krishna to descend and deliver the fallen souls of Kali-yuga through Prema Bhakti.
      </p>
      
      <p>
        Lord Chaitanya Mahaprabhu came to distribute the highest spiritual nectar &mdash; Krishna Prema &mdash; freely to all without distinction. He did not appear just for a specific group or country; His name is *Vishwambhara* (one who maintains the universe), and He appeared for the liberation of the entire universe. Chanting the names of Lord Hari is the source of unlimited bliss (*anander sima nai*).
      </p>', 'Calendar: Celebrated on Phalguni Purnima (the full moon day of Phalguna month) (February/March)|Significance: The appearance day of Sri Chaitanya Mahaprabhu, who is Lord Krishna Himself dressed in the golden complexion of Radharani to distribute Krishna Prema.|Key Highlights: Fasting until moonrise, grand abhishekam of Gaura-Nitai deities, ecstatic Hari-nam sankirtan, and a grand feast the next day.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (15, 'ratha-yatra', 'Ratha Yatra', 'Ratha Yatra', 'The Festival of Chariots — Lord Jagannath\'s annual procession.', 'Ratha-yatra has been celebrated for thousands of years in Jagannatha Puri, Odisha. The festival commemorates Lord Jagannath\'s (Krishna\'s ecstatic form) annual ride to the Gundicha temple. The British coined the term \"juggernaut\" from the massive chariots used. Srila Prabhupada was especially fond of this festival, organizing the first Ratha-yatra in San Francisco in 1967 and later in London, Paris, and other major cities worldwide.', 'Ratha-yatra represents Lord Jagannatha\'s intense longing to reunite with His devotees in Vrindavan. The deities ride on grand chariots, allowing everyone — regardless of caste or creed — to see Them and receive Their blessings. Simply seeing the Lord on His chariot brings immense spiritual benefit.', 'Pulling the chariot ropes is considered highly auspicious and removes all sins. Sponsoring the chariot, decorations, or prasadam distribution during Ratha-yatra brings the Lord\'s special blessings and ensures your name is remembered in His service.', 'festival', NULL, 'assets/images/banners/ratha-yatra.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 32, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Ratha-yatra, or the Festival of Chariots, is a joyous event celebrated for thousands of years in the Indian holy city of Jagannatha Puri, and more recently by Hare Krishna devotees in major cities around the world. Lord Jagannatha, meaning \"the Lord of the Universe,\" refers to the ecstatic form of Lord Krishna with large round eyes and rugged features who rides on a gigantic chariot during this festival.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of the Deities\' Ecstatic Forms</h3>
      <p>
        As the story goes, Lord Krishna once overheard His Vrindavan associates discussing how His dearest devotees, the Gopis, were constantly crying in His absence. When Krishna heard these accounts of overwhelming love in separation, His hair stood on end, His eyes opened wide, and His limbs contracted into His body in a state of supreme spiritual ecstasy. 
      </p>
      
      <p>
        Seeing Lord Krishna in this condition, His elder brother Balarama also began to feel ecstatic symptoms, showing similar features. When Their sister Subhadra arrived at the scene, she too became consumed with ecstatic joy. The sublime deity forms of Jagannatha, Subhadra, and Baladeva represent this sweet Vrindavan pastime.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Chariot Ride to Vrindavana</h3>
      <p>
        The festival of Ratha-yatra represents Lord Jagannatha\'s longing to reunite with His dear devotees in Vrindavana, foremost Srimati Radharani. According to tradition, the Lord gets lovesick once a year just prior to the festival. To cheer Him up, His servants arrange a lavish chariot procession to carry Him to meet His devotees. Lord Jagannatha rides on a grand, three-story-high wooden chariot, pulled by thousands of devotees and accompanied by marching bands, drummers, singers, and dancers.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"India\'s colonial British rulers coined the term \'juggernaut\' from the massive, heavy chariot used to celebrate this festival in the city of Jagannatha Puri.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Chaitanya Mahaprabhu & Srila Prabhupada\'s Legacy</h3>
      <p>
        Five hundred years ago, Lord Chaitanya Mahaprabhu (the combined incarnation of Radha-Krishna) encouraged all His followers to celebrate Ratha-yatra with great enthusiasm. His biographies recount how He got down on His hands and knees to scrub the Gundicha temple (where Lord Jagannatha stays at the end of the parade) to prepare it for the Lord.
      </p>
      
      <p>
        Srila Prabhupada, the founder-acharya of ISKCON, was extremely fond of Ratha-yatra. As a child of five, he built a small homemade cart and pulled it around his neighborhood in Calcutta. Later in life, from 1967 onward, Srila Prabhupada joined thousands of disciples in celebrating Ratha-yatra in the streets of London, Paris, Sydney, Tokyo, San Francisco, Los Angeles, and on New York\'s Fifth Avenue.
      </p>
      
      <p>
        Ratha-yatra signifies the Lord\'s love for His devotees. He personally leaves His temple to visit the public who welcome Him in the streets, making it a beautiful reunion of love and devotion.
      </p>', 'Calendar: Celebrated in Ashadha month (June/July)|Significance: Represents Lord Jagannatha\'s intense longing to return to Vrindavan to meet His dear devotees, especially Srimati Radharani.|Key Highlights: Pulling of majestic wooden chariots, ecstatic dancing and chanting, Gundicha temple cleaning, and free feast distribution.|Deities: Lord Jagannatha, Baladeva, and Subhadra Maharani.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (16, 'diwali', 'Diwali - Festival of Lights', 'Diwali', 'The festival of lights celebrating light over darkness.', 'Diwali (Deepawali) has multiple historical significances: the return of Lord Rama to Ayodhya after 14 years of exile, Lord Krishna killing the demon Narakasura, the Damodara-lila of Mother Yashoda binding Krishna, the appearance of Goddess Lakshmi during the churning of the ocean, and Lord Vamana\'s rescue of Lakshmi from King Bali.', 'The festival represents the victory of light over darkness, knowledge over ignorance, and good over evil. It coincides with the auspicious Damodara month (Kartika), which is especially dear to Lord Krishna.', 'Lighting diyas in the temple and sponsoring special offerings during Diwali brings prosperity and spiritual advancement. Supporting the grand arati and prasadam distribution invokes the blessings of Lord Rama, Goddess Lakshmi, and Lord Krishna.', 'festival', NULL, 'assets/images/banners/diwali.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 33, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Diwali or Deepawali is the festival of lights. This festival is celebrated throughout the world with extreme splendor, representing the ultimate victory of good over evil, knowledge over ignorance, and light over darkness.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Why Do We Celebrate Diwali?</h3>
      <p>
        Scriptures record several historical occurrences on this day:
      </p>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Return of Lord Rama:</strong> Lord Ramachandra returned to Ayodhya after 14 years of exile and defeating the demon king Ravana. The citizens illuminated the entire kingdom with rows of clay lamps (*diya*).</li>
        <li><strong>Krishna Kills Narakasura:</strong> In Dvapara Yuga, Lord Krishna killed the demon Narakasura and liberated 16,000 captive princesses. This is celebrated as Narakachaturdashi.</li>
        <li><strong>Damodara Lila:</strong> Mother Yashoda tied little Krishna to a grinding mortar on this day. Krishna crawled and dragged the mortar, liberating the two sons of Kuvera (Nalakuvara and Manigriva) who had been cursed to stand as Yamalarjuna trees.</li>
        <li><strong>Birth of Goddess Lakshmi:</strong> Goddess Lakshmi appeared during the churning of the cosmic ocean of milk (*Samudra Manthan*) and married Lord Vishnu on this day.</li>
        <li><strong>Vishnu Saves Lakshmi from King Bali:</strong> Lord Vishnu, in His fifth incarnation as Vamanadeva, rescued Goddess Lakshmi from the prison of King Bali and sent Bali to rule the sub-terranean world.</li>
        <li><strong>Return of the Pandavas:</strong> The five Pandava brothers returned to Hastinapur on Kartik Amavasya after 12 years of exile.</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Tale of Ramayana</h3>
      <p>
        Lord Rama was the eldest son of King Dasharatha and the seventh incarnation of Lord Vishnu, born with the specific purpose of defeating Ravana. After winning His wife Sita in an archery competition, they returned to Ayodhya. However, His stepmother Kaikeyi forced King Dasharatha to exile Rama to the forest for 14 years. His wife Sita and brother Lakshmana accompanied Him.
      </p>
      
      <p>
        During their forest exile, the demon king Ravana kidnapped Sita and carried her to his palace in Lanka. With the help of the monkey king Sugriva and His devoted general Hanuman, Lord Rama built a bridge to Lanka, defeated Ravana, and rescued Sita. The return of Sita and Rama to Ayodhya marked the beginning of *Ram Rajya* &mdash; the glorious reign of righteous order.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Why Do We Do Lakshmi-Ganesha Puja?</h3>
      <p>
        While Diwali marks the return of Lord Rama, Goddess Lakshmi and Lord Ganesha are traditionally worshipped in the evening. In Kali Yuga, which is heavily influenced by *rajoguna* (the mode of passion), people seek wealth above all else. Devotees worship Goddess Lakshmi for prosperity.
      </p>
      
      <p>
        Lord Ganesha, the elephant-headed god of wisdom, is worshipped alongside Lakshmi. Ganesha was adopted by Lakshmi out of love, and she declared that those who do not worship Ganesha with her will never see prosperity. What is wealth without wisdom to use it properly? Wisdom (Ganesha) and wealth (Lakshmi) must remain balanced to bring true prosperity.
      </p>
      
      <p>
        As we decorate our houses with lights and rangolis, let us also cleanse our hearts by bringing in spiritual knowledge, making our hearts pure temples to serve Radha-Krishna and progress in Bhakti.
      </p>', 'Calendar: Celebrated on Kartik Amavasya (new moon day of the month of Kartika) (October/November)|Alternative Names: Deepawali, Festival of Lights|Deities Worshipped: Lord Ramachandra, Goddess Lakshmi, Lord Ganesha, and Lord Damodara|Significance: Represents the return of Lord Rama to Ayodhya, the killing of demon Narakasura by Krishna, the birth of Goddess Lakshmi, and the Damodara-lila.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (17, 'govardhan-puja', 'Govardhan Puja', 'Govardhan Puja', 'Commemorating Lord Krishna lifting Govardhan Hill.', 'Govardhan Puja commemorates the pastime when seven-year-old Lord Krishna lifted the Govardhana Hill with His little finger to protect the residents of Vrindavana from the devastating rains sent by King Indra. This pastime, described in the Srimad-Bhagavatam (10th Canto), established that a devotee of Krishna need not worship demigods for material benefits.', 'This festival teaches the importance of surrendering to Krishna and the futility of worshipping demigods. The Annakut (hill of food) prepared on this day represents the Vrajavasis\' love for Krishna and their gratitude for His protection.', 'Sponsoring Govardhan Puja, especially the Annakut offering and cow worship, brings Krishna\'s special protection and blessings. Donors who support this festival receive the same mercy that Krishna showed to the residents of Vrindavana.', 'festival', NULL, 'assets/images/banners/govardhan-puja-banner.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 34, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        Govardhana Puja is celebrated in the auspicious month of Kartika (October – November) to commemorate the pastime of Lord Sri Krishna lifting the Govardhan Hill to protect the residents of Vrindavan from the wrath of King Indra.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Pastime of Govardhana Lila</h3>
      <p>
        When the Supreme Lord Sri Krishna saw the residents of Vrindavana preparing for Indra-yajna (a traditional ceremony to please Indra, who supplies rain), He suggested they forgo the worship of Indra and instead worship the Govardhana Hill, which directly sustains the cows and cowherd men. 
      </p>
      
      <p>
        Upon coming to know of this, Indra became angry and ordered Samvartaka (the clouds of devastation) to inundate Vrindavana. Severe rains fell like piercing sharp arrows, accompanied by thunder, lightning, and strong winds. The residents took shelter of Krishna, who immediately picked up the Govardhana Hill with His little finger and held it aloft like an umbrella. For one week, the Vrajavasis lived safely under the hill without hunger or discomfort. Indra, astonished to see the seven-year-old child hold the hill, called back his clouds and begged for forgiveness. Thus the Supreme Lord established that a surrendered devotee engaged in devotional service is free from all obligations and need not worship demigods for material favors.
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/govardhan-puja.jpg\" alt=\"Govardhan Puja Celebrations\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Deity of Giri Govardhan receiving abhishekam</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Annakut Festival & Cow Worship</h3>
      <p>
        Following in the footsteps of the residents of Vrindavana, this festival is celebrated with great joy. Devotees prepare varieties of foodstuffs with grain, ghee, and milk, stacking them like a hill (Annakut) to offer to the Lord. After the offering, the food hill is distributed to everyone as prasadam.
      </p>
      
      <p>
        Devotees also worship cows on this day, as Krishna is Gopala, the protector of cows. The cows are decorated, bathed, and fed well. Devotees perform circumambulation (parikrama) of the cows and Govardhana Hill.
      </p>

      <!-- Sub-image block 2 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/govardhan-hill.jpg\" alt=\"Devotees carrying Govardhana\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Lord Krishna lifting Govardhan Hill with His little finger</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Govardhanastakam</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        By Srila Visvanatha Cakravarti Thakura (from Stavamrta Lahari)
      </p>
      
      <div style=\"display:flex; flex-direction:column; gap:var(--space-md); margin-top:var(--space-sm); font-size:var(--font-size-sm); line-height:1.6;\">
        <p>
          <strong>(1)</strong> <em>krsna-prasadena samasta-saila-samrajyam apnoti ca vairino pi / sakrasya yah prapa balim sa saksad govardhano me disatam abhistam</em><br>
          May Govardhana Hill, which by Krsna\'s mercy became the king of all mountains and received the respectful tribute of its arch-enemy Indra, fulfill my desire.
        </p>
        <p>
          <strong>(2)</strong> <em>sva-prestha-hastambuja-saukumarya-sukhanubhuter ati-bhumi-vrtteh / mahendra-vajrahatim apy ajanan govardhano me disatam abhistam</em><br>
          As it was held above the earth, it became so filled with happiness by experiencing the softness of its beloved Krsna\'s lotus hand, it did not even know it was being struck by Indra\'s thunderbolt. May Govardhana Hill fulfill my desire.
        </p>
        <p>
          <strong>(3)</strong> <em>yatraiva krsno vrsabhanu-putrya danam grhitum kalaham vitene / sruteh sprha yatra mahaty atah sri-govardhano me disatam abhistam</em><br>
          Trying to collect a toll, Krsna quarreled there with King Vrsabhanu\'s daughter. The personified Vedas yearn to listen to that quarrel. May Govardhana Hill fulfill my desire.
        </p>
        <p>
          <strong>(8)</strong> <em>vina bhavet kim hari-dasa-varya-padasrayambhaktir atah srayami / yam eva saprema nijesayoh sri-govardhano me disatam abhistam</em><br>
          Without taking shelter of the feet of the hill that is the best of Lord Hari\'s servants and full of love for the divine king and queen, how is it possible to attain pure devotional service? May Govardhana Hill fulfill my desire.
        </p>
      </div>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (18, 'narasimha-chaturdashi', 'Narasimha Chaturdashi', 'Narasimha', 'The appearance day of Lord Nrsimhadeva.', 'Lord Narasimhadeva appeared from a palace pillar to save His five-year-old devotee Prahlada Maharaja from his demoniac father, Hiranyakashipu. The Lord\'s form as half-man, half-lion was uniquely designed to fulfill Hiranyakashipu\'s benedictions while still ending his reign of terror. This pastime illustrates the Lord\'s unlimited creative power to protect His devotees.', 'Lord Narasimha is known as the great protector of devotees and remover of obstacles. He appeared at twilight (neither day nor night), on a threshold (neither inside nor outside), using His fingernails (no weapons), as neither man nor animal.', 'Worshipping Lord Narasimha removes all obstacles on the spiritual path. Sponsoring the abhishekam, special lamps, and offerings on this day invokes His fierce protection and destroys all negativity and obstacles in one\'s life.', 'festival', NULL, 'assets/images/banners/narasimha-chaturdashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 35, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Narasimha Chaturdashi is the divine appearance day of Lord Narasimhadeva, Lord Krishna\'s incarnation as half-man, half-lion, who removes all obstacles on the path of devotional service out of His great compassion.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"tava kara-kamala-vare nakham adbhuta-srngam<br>
        dalita-hiranyakasipu-tanu-bhrngam<br>
        keshava dhrta-narahari-rupa jaya jagadisa hare\"<br><br>
        \"O Keshava! O Lord of the universe! O Lord Hari, who have assumed the form of half-man, half-lion! All glories to You! Just as one can easily crush a wasp between one\'s fingernails, so in the same way the body of the wasp-like demon Hiranyakashipu has been ripped apart by the wonderful pointed nails on Your beautiful lotus hands.\" &mdash; Sri Dasavatara-stotra
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Pastime of Prahlada and Hiranyakashipu</h3>
      <p>
        Lord Nrisimhadeva appeared to save Prahlada Maharaja, a five-year-old boy who was being severely tortured by his atheistic father, Hiranyakasipu. Prahlada\'s only \"fault\" was that he was Krishna conscious and chanted the holy names. 
      </p>
      
      <p>
        Hiranyakasipu had performed intense austerities and obtained a benediction from Lord Brahma that he could not be killed by any man or animal, in the sky, on water or land, during day or night, by any weapon, or inside or outside any residence. Confident that this made him immortal, he declared himself God and tortured his own son for worshipping Vishnu.
      </p>
      
      <p>
        The Supreme Lord, out of His infinite intelligence, kept all of Brahma\'s benedictions intact while still finishing the demon:
      </p>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Neither Man nor Animal:</strong> The Lord appeared as Narasimhadeva (half-man, half-lion).</li>
        <li><strong>Neither Inside nor Outside:</strong> He killed the demon on the threshold (doorway) of the assembly hall.</li>
        <li><strong>Neither in the Sky, Water, nor Land:</strong> He placed the demon on His lap.</li>
        <li><strong>Neither Day nor Night:</strong> He killed him at dusk (the twilight junction of day and night).</li>
        <li><strong>No Weapons:</strong> The Lord ripped him apart using His sharp fingernails.</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Nine Processes of Devotional Service</h3>
      <p>
        When Hiranyakasipu asked Prahlada what the best thing he had learned from his teachers was, Prahlada Maharaja replied:
      </p>
      <div style=\"background:var(--cream); padding:var(--space-md); border-radius:var(--radius-md); font-family:var(--font-subheading); color:var(--dark); margin-bottom:var(--space-sm);\">
        <em>\"sravanam kirtanam vishnoh smaranam pada-sevanam arcanam vandanam dasyam sakhyam atma-nivedanam\"</em> (SB 7.5.23)
      </div>
      <p>
        Prahlada explained that the best education is to cultivate these nine processes of devotional service directed toward Lord Vishnu:
      </p>
      <ol style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Sravanam:</strong> Hearing about the Lord (like chanting kirtan and reading scripture).</li>
        <li><strong>Kirtanam:</strong> Chanting the glories of the Lord.</li>
        <li><strong>Smaranam:</strong> Remembering the Lord constantly.</li>
        <li><strong>Pada-sevanam:</strong> Serving the lotus feet of the Lord.</li>
        <li><strong>Arcanam:</strong> Offering worship to the deity in the temple.</li>
        <li><strong>Vandanam:</strong> Offering prayers to the Lord.</li>
        <li><strong>Dasyam:</strong> Serving the Lord as His humble servant.</li>
        <li><strong>Sakhyam:</strong> Developing an intimate friendship with the Lord.</li>
        <li><strong>Atma-nivedanam:</strong> Fully surrendering one\'s mind, body, and soul.</li>
      </ol>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glory of Nrsimha Shalagram Sila</h3>
      <p>
        Srila Rupa Goswami mentions in his *Padyavali* the benefits of worshipping a Nrsimha Shalagram Sila:
      </p>
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"A tulasi leaf offered to the lotus feet of the Nrsimha Shalagram Sila destroys the sin of murder. Water that has washed His feet destroys the sin of theft. Foodstuff offered to Him destroys the sin of drinking liquor. Sincere surrender to Him destroys the sin of adultery with the wife of the spiritual master. Association with His devotees destroys the sin of offenses to devotees.\"
      </blockquote>', 'Calendar: Celebrated on Vaisakha Shukla Chaturdashi (14th day of the bright moon of Vaisakha month) (May)|Significance: The appearance day of Lord Narasimhadeva (the half-man, half-lion incarnation) who appeared from a palace pillar to save His dear devotee Prahlada.|Key Highlights: Fasting until dusk (sunset), grand abhishekam with honey, milk, and fruit juices, and singing of Narasimha prayers.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (19, 'rama-navami', 'Sri Rama Navami', 'Rama Navami', 'The appearance day of Lord Sri Ramachandra.', 'Sri Rama Navami celebrates the birth of Lord Ramachandra, the seventh incarnation of Lord Vishnu, born to King Dasharatha and Queen Kaushalya of Ayodhya. Lord Rama\'s life story is told in the epic Ramayana by Sage Valmiki. He is known as Maryada-purushottama — the perfect embodiment of righteousness, duty, and virtue.', 'Lord Rama\'s life exemplifies how to live as an ideal son, husband, king, and devotee. His victory over the demon Ravana represents the triumph of dharma over adharma. His reign (Ram Rajya) is remembered as a golden age of peace and prosperity.', 'Observing Rama Navami and sponsoring the celebrations invokes Lord Rama\'s blessings for a life of righteousness and integrity. Donors receive the protection of Lord Rama, Mother Sita, Lakshmana, and Hanuman.', 'festival', NULL, 'assets/images/banners/rama-navami.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 36, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Sri Rama Navami is the appearance day of Lord Sri Ramachandra. He is widely known as *Maryada-purushottama* &mdash; the protector of religious principles &mdash; for He always set an excellent example of how to act as a king, a husband, a son, and an individual.
      </p>
      
      <p>
        This day of Rama Navami brings great spiritual assets and devotion when we selflessly serve Lord Rama and His devotees.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Lord Rama is considered the seventh incarnation of Lord Vishnu. The deities of Sri Rama, Mother Sita, Lakshmana, and Hanuman represent the pastimes of Ramayana and teach the values of truth, duty, and surrender.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">How Rama Navami is Celebrated</h3>
      <p>
        During Rama Navami, devotees engage in various spiritual activities:
      </p>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Kirtan and Bhajans:</strong> Devotees gather to sing sweet kirtans and bhajans that glorify Lord Rama\'s qualities and pastimes. The chanting of Lord Rama\'s holy names is a central aspect of the day.</li>
        <li><strong>Lectures and Discourses:</strong> Spiritual discourses are conducted to narrate stories from the Ramayana, emphasizing the teachings, values, and virtues of Lord Rama, guiding devotees in their lives.</li>
        <li><strong>Arati and Puja:</strong> Special arati and puja ceremonies are performed to honor Lord Rama. Devotees offer fresh flowers, incense, fruits, and food items to the deity.</li>
        <li><strong>Feasting:</strong> A significant part of the celebration is the distribution of sanctified prasadam to all visitors, promoting a sense of unity and spiritual harmony.</li>
      </ul>
      
      <p>
        Ram Navami celebrations provide a wonderful opportunity for devotees to connect with the spiritual essence of Lord Rama\'s teachings and to deepen their devotion. While ISKCON\'s main focus is on Radha-Krishna worship, celebrating Ram Navami showcases the organization\'s respect for all avatars of the divine and commitment to promoting spiritual growth.
      </p>', 'Calendar: Celebrated on Chaitra Shukla Navami (9th day of the bright fortnight of Chaitra month) (March/April)|Significance: The appearance day of Lord Sri Ramachandra, the ideal king and seventh avatar of Lord Vishnu.|Key Highlights: Ramayana discourses, special arati and puja, chanting of Ram-nam, and grand distribution of panakam and prasadam.|Deity Worshipped: Lord Ramachandra, Mother Sita, Lakshmana, and Hanuman.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (20, 'radhashtami', 'Sri Radhashtami', 'Radhashtami', 'The appearance day of Srimati Radharani.', 'Radhashtami celebrates the appearance of Srimati Radharani, Krishna\'s eternal consort and the feminine aspect of the Absolute Truth. She is the Hladini-shakti (pleasure potency) of Lord Krishna, appearing in Vrindavan as the daughter of King Vrishabhanu and Queen Kirtida. Her name comes before Krishna\'s in the Hare Krishna maha-mantra.', 'Without Radharani\'s mercy, one cannot approach Krishna. She is the most compassionate and merciful aspect of the Divine, recommending sincere souls to Krishna. Her love for Krishna is the ultimate expression of devotion.', 'Sponsoring Radhashtami celebrations, especially the floral decorations and abhishekam, invokes Radharani\'s special mercy. Donors receive Her compassionate blessings, which help them develop love for Krishna and progress in devotional life.', 'festival', NULL, 'assets/images/banners/radhashtami-banner.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 37, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        Radha Astami is the appearance anniversary of Srimati Radharani. She is Krishna\'s greatest devotee, the feminine aspect of the Absolute Truth, and Krishna\'s spiritual energy personified.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Male and Female Aspects of the Divine</h3>
      <p>
        The highest truth has both male and female aspects. Like the sun and the sunshine, each gives meaning to the other. The male and female aspects of the Supreme Being appear together as Vishnu and Laksmi, Rama and Sita, and Krishna and Radharani. Srimati Radharani represents Lord Krishna\'s *Hladini-shakti*, His internal pleasure-giving potency.
      </p>
      
      <p>
        During Krishna\'s childhood pastimes in Vrindavan, Radharani is His feminine counterpart. The Srimad-Bhagavatam and the books of the Six Goswamis of Vrindavan tell how They eternally enjoy each other\'s company and are always making plans to meet.
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/radharani.jpg\" alt=\"Srimati Radharani\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Srimati Radharani, the Queen of Vrindavan</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Transcendental Nature of Radha-Krishna Pastimes</h3>
      <p>
        Srila Prabhupada, in his commentary on Srimad-Bhagavatam, cautions that although Krishna and Radharani\'s relationship may appear like romantic dealings between young boys and girls, it is purely transcendental. There are spiritual prerequisites for properly understanding it. 
      </p>
      
      <p>
        In his summary study of the Tenth Canto &mdash; <em>Krsna, the Supreme Personality of Godhead</em> &mdash; Srila Prabhupada recommends that an aspiring devotee of Krishna thoroughly study the Bhagavatam\'s first nine cantos &mdash; which stress the greatness of God and His divine energy &mdash; before delving into the more intimate, confidential pastimes found in the Tenth Canto.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Radharani also appears in the Hare Krishna mantra as \'Hare\', the vocative form of \'Hara\'. Hara is the feminine form of Hari, another name of Krishna. Her name appears before Krishna\'s in the mantra because She is known for Her compassionate nature; devotees of Krishna approach Her first to seek recommendation to Krishna.\"
      </blockquote>

      <p>
        On Radhashtami day, the temple is decorated with colorful flowers, and a grand abhishekam is performed. Devotees sing sweet prayers, listen to discourses on Srimati Radharani\'s transcendental qualities, and join in a grand feast offered in Her honor.
      </p>', 'Calendar: 8th day of the bright fortnight (Shukla Ashtami) of Bhadrapada month (August/September)|Significance: The appearance anniversary of Srimati Radharani, the feminine counterpart of the Absolute Truth.|Deity Worshipped: Srimati Radharani (the internal pleasure potency, Hladini-shakti, of Lord Krishna)|Key Highlights: Special flower decorations, grand abhishekam with milk and honey, devotional songs, and lectures.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (21, 'gopastami', 'Gopastami', 'Gopastami', 'Marks the day Krishna and Balarama began herding cows.', 'Gopastami commemorates the day when five-year-old Krishna and Balarama were allowed by Their father Nanda Maharaja to go to the forest to herd cows for the first time. This marked Their transition from infancy to cowherd boys and is described in the Srimad-Bhagavatam\'s 10th Canto.', 'Lord Krishna is known as Gopala (protector of cows) and Govinda (one who gives pleasure to the cows). This festival highlights the importance of cow protection (go-raksha) in Vedic culture and Krishna\'s intimate relationship with the cows of Vrindavan.', 'Participating in Gopastami celebrations and cow worship brings the special blessings of Lord Krishna and Lord Balarama. Sponsoring gau-seva (cow service) on this day is considered extremely meritorious and purifies one\'s existence.', 'festival', NULL, 'assets/images/banners/gopastami.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 38, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        On Gopashtami day, Nanda Maharaja performed a ceremony for the cows and Krishna (and His friends) in Vrindavan as He reached the *pauganda* age. This was the day Nanda Maharaja sent his children Krishna and Balarama to herd the cows for the first time.
      </p>
      
      <p>
        Initially, this was a celebration meant only for men and boys. However, Srimati Radharani and Her friends also wanted to enjoy the fun. Because of Her resemblance to Subala-sakha (Krishna\'s close friend), Srimati Radharani put on his dhoti and garments and joined Krishna. The other gopis joined in too, disguised as cowherd boys.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"suklastami karttike tu smrta gopastami budhaih<br>
        tad-dinad vasudevo bhud gopah purvam tu vatsapah\"<br><br>
        \"The eighth lunar day of the bright fortnight of the month of Kartik is known by authorities as Gopastami. From that day, Lord Vasudeva served as a cowherd, whereas previously He had tended the calves.\" &mdash; Srimad Bhagavatam 10.15.1
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">How Gopastami is Celebrated</h3>
      <p>
        On this highly auspicious day, people worship the cows. Early in the morning, devotees bathe the cows, offer them fresh flowers and sweet scents, and decorate them with beautiful clothes. They feed them sweet fodder, perform parikrama (circumambulation) around them, and follow them for some distance as they go out to graze.
      </p>
      
      <p>
        In the evening, when the cows return at the time of dusk (known as *godhuli muhurat*), they are greeted and worshipped once again. Devotees touch the cows\' lotus feet and pray for a healthy, prosperous future. Charitable donations are offered to Gaushalas (cow sanctuaries) on this day.
      </p>
      
      <p>
        In the Srimad Bhagavatam, it is stated that Lord Sri Krishna walked barefooted at the age of six, keeping the cows ahead of Him. At that time, His footsteps were not even fully developed. Krishna was delighted when the dust raised by the cows\' hooves (*gauraj*) fell upon Him. Krishna walked barefooted in the dust of Vrindavan, leaving the footprints of His lotus feet everywhere. This is the primary reason for the dazzling beauty and spiritual potency of Vrindavan.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Krishna\'s Intimate Affection for Cows</h3>
      <p>
        It is said that Nanda Maharaja had 9 lakh (900,000) cows, and Lord Sri Krishna was intimately aware of each of their names. All the cows were identified by their specific names. If any cow got separated from the group, Krishna would call her back by playing His flute and calling her name. Due to this immense affection, Krishna is known as Gopal (\"protector of cows\") and Govinda (\"one who gives pleasure to the cows\").
      </p>
      
      <p>
        Krishna showed His affection for *gau seva* (cow service) through both His words and His pastimes, establishing Krishna and Balarama as the eternal symbols of cow protection.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Sacred Importance of the Cow</h3>
      <p>
        In Vedic culture, cows are not considered ordinary animals; they are revered as mothers. Shastras state that inside the cow exist thirty-three million demigods and goddesses. Consuming the milk of the indigenous cow (*desi cow*) active-izes the brain tissues, helping devotees understand the subtleties of the shastras. The cow is the ultimate symbol of prosperity and spirituality.
      </p>
      
      <p>
        The objective of Gopastami is to protect cows and provide loving services for their welfare. Places where cow seva is performed are blessed with the infinite grace of Lord Hari. Whether we live in cities or villages, supporting local cow protection and consuming pure dairy products from protected cows contributes to cow seva.
      </p>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (22, 'jhulan-yatra', 'Jhulan Yatra', 'Jhulan Yatra', 'The swing festival of Sri Sri Radha-Krishna.', 'Jhulan Yatra is celebrated during the month of Sravana (July-August) when devotees place the deities of Radha and Krishna on a beautifully decorated swing (jhulan). This festival is especially associated with the pastimes of Radha-Krishna in Vrindavan during the monsoon season.', 'The swinging pastimes of Radha and Krishna represent the intimate, loving exchanges between the Supreme Lord and His consort. Participating in this festival helps devotees develop a personal relationship with the divine couple.', 'Sponsoring the decoration of the swing, offerings of cool drinks, and special prasadam during Jhulan Yatra brings the loving blessings of Radha and Krishna. It is an opportunity to participate in their intimate pastimes.', 'festival', NULL, 'assets/images/banners/jhulan-yatra.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 39, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Jhulan Yatra is among the most auspicious festivals celebrated in Vrindavana. Also known as the Swing Festival, this beautiful pastime lasts for thirteen days in the sacred town of Vrindavana, celebrating Radha-Krishna\'s pastimes of swinging on a golden swing every day until Balarama-purnima.
      </p>
      
      <p>
        In accordance with Srila Prabhupada\'s instructions, ISKCON temples worldwide observe this festival for 5 days, starting on the Pavitropana Ekadashi in the waxing phase of the moon and continuing until Sawan Purnima (the Full Moon day).
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Swing Festival Celebrations</h3>
      <p>
        During these five days, the small deities of Radha and Krishna are placed on a beautifully decorated swing in the temple hall. After receiving traditional arati worship, the deities are gently pushed on their swing. The swing is decorated with all types of colorful flowers, creepers, and leaves, giving the feel as if the swing has appeared directly from the groves of Vrindavana. Devotees work hard and put their heart and soul into making this festival a blissful sight for visitors.
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"In the evening, members of the congregation come to the temple to participate. Each person offers personal prayers and then pushes the swing several times while ecstatic kirtan is going on simultaneously. The atmosphere is exciting and jubilant, offering an intimate, practical service to Radha and Krishna.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Cooling the Lordships in the Monsoon Heat</h3>
      <p>
        Like every festival, Jhulan Yatra is a meaningful way to offer practical service to the Lord. In Vrindavan, the monsoon season is very sticky and the temperature remains hot despite the cooling rains. Heavy humidity makes finding a cool breeze a true luxury. Devotees, therefore, place Radha and Krishna on a swing (Jhulan) to create a pleasant breeze from its own motion, providing satisfaction and comfort to Their Lordships.
      </p>
      
      <p>
        The final day of Jhulan Yatra falls on the full moon, which also marks Balarama Purnima, the appearance day of Lord Balarama. Be a part of this Jhulan Yatra with us this year and offer your loving spiritual services to Lord Krishna and Srimati Radharani.
      </p>', 'Calendar: Celebrated for five days in the waxing phase of Shravana month (July/August), starting on Pavitropana Ekadashi and ending on Balarama Purnima.|Significance: Celebrates the sweet pastime of Srimati Radharani and Lord Krishna swinging on a flower-bedecked swing.|Observance: Deities are placed on a beautifully decorated swing. Devotees offer prayers and pull the swing during ecstatic kirtan.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (23, 'nandotsava', 'Nandotsava', 'Nandotsava', 'The grand celebration by Nanda Maharaja after Krishna\'s birth.', 'After Vasudeva brought baby Krishna to Gokula, Nanda Maharaja celebrated the birth of his son with great joy, not knowing the child was the Supreme Lord Himself. He distributed gifts, fed the brahmanas, and performed grand celebrations. This festival is celebrated the day after Janmashtami.', 'Nandotsava demonstrates the pure love of the Vrajavasis for Krishna. Although Nanda Maharaja thought Krishna was his son, his love was actually transcendental. The festival reminds us of the joyful mood of Krishna\'s appearance.', 'Sponsoring Nandotsava celebrations brings the blessings of Nanda Maharaja and Mother Yashoda. It is particularly beneficial for those seeking to develop parental affection for Krishna.', 'festival', NULL, 'assets/images/banners/nandotsava.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 40, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Nandotsava is a festival celebrated the day after Janmashtami, commemorating the joy and celebrations of foster-father Nanda Maharaja. Overwhelmed with jubilation over the birth of his son, Nanda Maharaja hosted a grand ceremony, welcoming all the villagers of Braj (Vrindavan) to congratulate him and Mata Yashoda and take darshan of little Krishna.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Scriptural Description of the Celebrations</h3>
      <p>
        The tenth canto of Srimad Bhagavatam gives a vivid and beautiful description of how Vrajapura celebrated Lord Krishna\'s birth:
      </p>
      
      <p>
        <strong>1. Sweeping & Decorating:</strong> Vrajapura, the residence of Nanda Maharaja, was fully decorated with festoons, flags, and gates made of mango leaves and flower garlands. The courtyards, roads, and inner rooms were swept clean and washed with water.
      </p>
      
      <p>
        <strong>2. Decorating the Animals:</strong> The cows, bulls, and calves were thoroughly smeared with turmeric, oil, and mineral powders. Their heads were bedecked with peacock feathers, and they were covered with cloth and golden ornaments.
      </p>
      
      <p>
        <strong>3. Dress of the Cowherd Men:</strong> The cowherd men dressed opulently with valuable garments, coats, and turbans. Carrying presentations in their hands, they approached the house of Nanda Maharaja.
      </p>
      
      <p>
        <strong>4. The Joy of the Gopis:</strong> The gopi wives of the cowherd men decorated themselves with saffron and kunkuma, jeweled earrings, metal lockets, and bangles. As they hurried along, flowers fell from their hair onto the streets. They sprinkled a mixture of turmeric powder, oil, and water upon the birthless Supreme Lord and offered blessings.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"In gladness, the cowherd men enjoyed the great festival by splashing one another\'s bodies with a mixture of curd, condensed milk, butter, and water. They threw butter on one another and smeared it on one another\'s bodies.\"
      </blockquote>

      <p>
        <strong>5. Nanda Maharaja\'s Charity:</strong> To please Lord Vishnu and ensure the welfare of his son, Nanda Maharaja gave away clothing, ornaments, and two million decorated cows in charity to the brahmanas, along with seven hills of grain covered with jewels and gold-embroidered cloth.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Key Aspects of Nandotsava</h3>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Swings and Cradles:</strong> Images or idols of baby Krishna (Ladu Gopal) are placed in beautifully decorated swings and cradles. Devotees take turns gently swinging the cradle, experiencing the mood of parenting the Supreme Lord.</li>
        <li><strong>Devotional Singing and Dancing:</strong> The festival is filled with constant kirtans and sweet baby-pastime bhajans.</li>
        <li><strong>Scriptural Readings:</strong> Devotees hold readings and lectures from Srila Prabhupada\'s <em>Srimad Bhagavatam</em> and <em>Krsna Book</em>.</li>
      </ul>', 'Calendar: Celebrated on the day following Janmashtami (Bhadrapada Krishna Navami) (August/September)|Significance: Celebrates foster-father Nanda Maharaja\'s grand birth ceremony for baby Krishna and welcoming the Braj inhabitants.|Key Highlights: Swinging baby Krishna in a decorated cradle, ecstatic kirtans and dances, splashing milk/yoghurt/butter, and lectures.|Deity: Baby Krishna (Ladu Gopal)|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (24, 'balarama-purnima', 'Sri Balarama Purnima', 'Balarama', 'The appearance day of Lord Balarama.', 'Sri Balarama appeared as the seventh son of Devaki and was transferred to the womb of Rohini to protect Him from Kansa. He is the first expansion of Lord Krishna (Sankarshana) and the reservoir of spiritual strength. His appearance day is celebrated on the full moon day of Sravana month.', 'Lord Balarama represents the original spiritual master and the source of all spiritual power. He is the embodiment of service to Krishna, always protecting and serving His younger brother.', 'Sponsoring Balarama Purnima celebrations invokes spiritual strength and purification. Balarama\'s blessings help devotees overcome material attachments and develop firm faith in Krishna consciousness.', 'festival', NULL, 'assets/images/banners/balarama-purnima.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 41, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Lord Balarama is the first physical expansion of Lord Krishna. These two are identical, sharing the same identity and essence, differing only in complexion: Balarama is fair as a spring cloud, while Krishna has the complexion of a fresh monsoon cloud. Lord Balarama represents the attitude of service, executing all the creation work of Krishna.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Services and Forms of Balaram Ji</h3>
      <p>
        Lord Balarama assumes four different forms (Chatur-vyuha) to serve Krishna: Vasudeva, Pradyumna, Sankarshana, and Aniruddha. He also serves directly as Lord Ananta Shesha &mdash; manifesting as the Lord\'s bed, umbrella, shoes, and resting place. He is the original spiritual master, and it is impossible to approach Lord Krishna without first obtaining the mercy of Lord Balarama.
      </p>
      
      <p>
        Around 5,000 years ago, when Lord Krishna descended onto this material planet, He was preceded by Lord Balarama, who appeared as the son of Rohini.
      </p>
      
      <p>
        Lord Balarama is depicted as a 16-year-old boy full of strength and youthful vigor. He wears deep blue clothes, a forest flower garland, and has His hair tied in a topknot. He wears beautiful earrings that brush His cheeks, matching His bracelets, armlets, and anklets. Physically, He possesses a broad chest, a deep voice, and immense physical strength.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Notable Pastimes of Lord Balarama</h3>
      <p>
        Lord Balarama performed many heroic pastimes in the forests of Vrindavan:
      </p>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Dhenukasura and Pralambasura:</strong> He killed the ass-demon Dhenukasura in the Talavana forest and defeated the demon Pralambasura.</li>
        <li><strong>Chastising the Yamuna:</strong> When Yamuna Devi refused to shift her course to allow Him to bathe, Lord Balarama dragged her with His plow, forcing her to submit.</li>
        <li><strong>Chastising the Kauravas:</strong> He dragged the city of Hastinapur with His plow to rescue His nephew Samba.</li>
        <li><strong>Marriage to Revati:</strong> He married Princess Revati from a previous yuga cycle, who was brought down to size by His plow.</li>
        <li><strong>Romaharshana:</strong> He killed Romaharshana Suta for failing to show respect to Vyasadeva\'s seat.</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Mercy of Lord Balarama</h3>
      <p>
        Lord Balarama is the source of spiritual strength (*bala*). He appeared as Lakshmana with Lord Sri Rama and later as Lord Nityananda with Sri Caitanya Mahaprabhu. Devotees worship Lord Balarama to obtain the strength needed to advance in spiritual life. 
      </p>
      
      <p>
        Balarama Purnima marks the official end of the five-day Jhulan Yatra and the completion of the first month of Chaturmasya.
      </p>', 'Calendar: Celebrated on Shravana Purnima (the full moon day of Shravana month) (August)|Significance: The appearance day of Lord Balarama, the first physical expansion of Lord Krishna and the original spiritual master.|Deity Worshipped: Lord Balarama / Baladeva|Key Highlights: End of Jhulan Yatra, beginning of the first month of Chaturmasya, and grand abhishekam for Lord Balarama.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (25, 'snana-yatra', 'Snana Yatra', 'Snana Yatra', 'The sacred bathing festival of Lord Jagannath.', 'Snana Yatra, also known as Devasnan Purnima, is an ancient festival originating from the Skanda Purana. King Indradyumna established this grand bathing ceremony for Lord Jagannath. The deities are bathed with 108 pots of sanctified water from the Golden Well (Suna Kua) amidst Vedic mantras.', 'Witnessing the deities during Snana Yatra is believed to absolve all sins. The festival marks the appearance of Lord Jagannath and precedes the 15-day Anasara period when the deities recuperate before Ratha Yatra.', 'Sponsoring the Jalabhisheka ingredients (water, sandalwood, turmeric, perfumes), the Hati Vesha (elephant attire), or the medical offerings during Anasara brings immense spiritual merit. Donors receive the Lord\'s special blessings for purification.', 'festival', NULL, 'assets/images/banners/snana-yatra.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 42, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        The Snana Yatra festival, also known as Devasnan Purnima, is a significant and sacred festival dedicated to Lord Jagannath. It is celebrated on the full moon day (Purnima) in the month of Jyestha. This unique festival marks the bathing ceremony of Lord Jagannath, Lord Balabhadra, and Goddess Subhadra. It attracts thousands of devotees worldwide who believe that a glimpse of the deities on this auspicious day washes away all sins. The festival\'s grandeur, rituals, and historical significance make it a unique and spiritual experience for everyone.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Historical Significance of Snana Yatra</h3>
      <p>
        The origins of the Snana Yatra are deeply rooted in the Skanda Purana, which narrates the story of King Indradyumna, who installed the wooden deities and initiated this sacred bathing festival. This festival commemorates the appearance of Lord Jagannath – the Lord of the Universe. It is said that when King Indradyumna arranged the bathing ceremony for the deities, he set a precedent for the celebration of Snana Yatra, making it an integral part of the Jagannath worship tradition.
      </p>
      
      <p>
        Its association with various legends further enriches the festival\'s historical significance. One such story involves a profound scholar and staunch devotee of Lord Ganesh who visited Puri during Snana Yatra. Initially reluctant to worship any deity other than his Ishtadevata Ganesh, the scholar was astonished when Lord Jagannath appeared in a huge form resembling Lord Ganesh. This miraculous event led to the tradition of dressing the deities in Hati Vesha (elephant attire) during the Snana Yatra, thus blending Snana Yatra history and divine intervention into a captivating narrative.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Why Snana Yatra is Celebrated</h3>
      <p>
        Snana Yatra is celebrated to honor Lord Jagannath\'s appearance and perform the sacred ritual of bathing the deities. The festival serves multiple purposes:
      </p>
      
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Spiritual Cleansing:</strong> Devotees believe that witnessing the deities during Snana Yatra absolves them of all sins, making the sight of the Lord being bathed highly auspicious and purifying.</li>
        <li><strong>Preserving Ancient Rituals:</strong> It commemorates the ancient ritual established by King Indradyumna, preserving and continuing the tradition of worshipping Lord Jagannath with grandeur and devotion.</li>
        <li><strong>Renewal:</strong> The sacred bathing festival symbolizes the purification and renewal of the deities, reflecting the cyclical nature of life.</li>
        <li><strong>Cultural Heritage:</strong> Beyond its religious significance, Snana Yatra is a cultural spectacle featuring vibrant processions, traditional music, and elaborate decorations that showcase the rich cultural heritage of Odisha and its devotion to Lord Jagannath.</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Rituals and Ceremonies</h3>
      <p>
        The rituals and ceremonies of Snana Yatra are elaborate and meticulously planned, reflecting deep-rooted traditions and spiritual significance:
      </p>

      <p>
        <strong>1. Pahandi Vijay</strong><br>
        On the eve of the Lord Jagannath Snana Yatra, the deities are ceremonially brought out from the temple\'s inner sanctum in a grand procession called Pahandi Vijay. This procession is a spectacular sight accompanied by music, chanting, and drum beating. The deities, Lord Jagannath, Lord Balabhadra, Goddess Subhadra, and Sudarshana, are taken to the Snana Mandapa (bathing platform). The Snana Mandapa is strategically located northeast of Ananda Bazar and beside the temple\'s outer wall, known locally as Meghanada Pacheri. It is elevated to a height that allows devotees outside the temple to have a clear view.
      </p>

      <p>
        <strong>2. Fetching of the Holy Water</strong><br>
        The ritual of fetching holy water is an integral part of Snana Yatra. On the morning of the festival, a ceremonial procession is undertaken to draw 108 water pots from the Golden Well (Suna Kua). The well is specially opened only once a year for this purpose. To ensure the sanctity of the water, those involved in drawing it cover their mouths with cloth to avoid contamination even from their breath. The water-filled pots are then preserved in the Bhoga Mandap, where they undergo purification with turmeric (Haladi), whole rice (Java), sandalwood (Chandan), flowers, and perfumes.
      </p>

      <p>
        <strong>3. Jalabhisheka</strong><br>
        The main bathing ritual, known as Jalabhisheka, occurs in the morning. The deities, adorned in silk cloth and smeared with red powder, are bathed with the water from the 108 golden vessels. This sacred bath is performed amidst the chanting of Vedic mantras, ecstatic kirtan, and the blowing of conch shells.
      </p>

      <p>
        <strong>4. Hati Vesha (Elephant Attire)</strong><br>
        In the evening, after the bathing ritual, the deities assume the Hati Vesha, where Lord Jagannath and Lord Balabhadra are dressed as elephants, and Goddess Subhadra is adorned with a lotus flower attire. This unique tradition stems from the legend of the scholar devotee of Lord Ganesh and adds a fascinating dimension to the festival.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"<strong>5. Anasara (Period of Recuperation)</strong><br>
        Following the Snana Yatra, the deities are believed to fall ill and are kept away from public view for 15 days, known as Anasara. During this time, the Raj Vaidya (the king\'s physician) treats the deities with specific medicines and offers them only fruits and water mixed with cheese. This period is a time of rest and recovery for the deities after their grand bath.\"
      </blockquote>

      <p>
        <strong>6. Netrotsava (Festival for the Eyes)</strong><br>
        On the 16th day, after the deities have recovered, they are reintroduced to the public in a festival called Netrotsava, or the Festival for the Eyes. This marks the first appearance of the deities after Snana Yatra, and it is a moment of great joy. The deities, freshly painted and decorated, bless the devotees with their divine presence.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Divine Deities of Snana Yatra</h3>
      <p>
        The Snana Yatra primarily centers around the divine trio—Lord Jagannath, Lord Balabhadra, and Goddess Subhadra. Each deity holds a unique significance:
      </p>
      
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Lord Jagannath:</strong> The Lord of the Universe, character-filled wooden idol with large round eyes and broad smile. He is a manifestation of Lord Krishna, whose glance during Snana Yatra washes away sins.</li>
        <li><strong>Lord Balabhadra:</strong> Elder brother of Lord Jagannath, fair-complexioned and associated with strength. He is bathed and adorned in the Hati Vesha during the festival.</li>
        <li><strong>Goddess Subhadra:</strong> The benevolent sister of Lord Jagannath and Lord Balabhadra, completing the divine trio. She is dressed in a lotus flower attire, representing purity and grace.</li>
        <li><strong>Sudarshana:</strong> The symbolic representation of Lord Vishnu\'s divine discus, acting as a protector to dispel evil and bring righteousness.</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Conclusion</h3>
      <p>
        The Snana Yatra is a profound and deeply spiritual festival that celebrates the divine bathing ceremony of Lord Jagannath and his siblings. Steeped in history, mythology, and vibrant rituals, it offers a unique opportunity for devotees to connect with the divine. By participating in the Snana Yatra, devotees experience a journey of spiritual renewal and divine connection, reinforcing the timeless worship traditions of Lord Jagannath.
      </p>', 'Calendar: Full moon day (Purnima) in the Vedic month of Jyestha (May/June)|Alternative Names: Devasnan Purnima, Snana Yatra|Deities Worshipped: Lord Jagannath, Lord Balabhadra, Goddess Subhadra, and Sudarshana|Key Highlights: Jalabhisheka with 108 pots of purified water, Hati Vesha (elephant attire), 15 days Anasara (recuperation), and Netrotsava.|Significance: Commemorates the appearance day of Lord Jagannath. Looking upon the bathed deities washes away all sins.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (26, 'akshaya-tritiya', 'Akshaya Tritiya', 'Akshaya', 'A day of infinite auspiciousness — start of Chandana Yatra.', 'Akshaya Tritiya is considered the most auspicious day in the Vedic calendar, requiring no astrological muhurta. On this day, the Treta Yuga began, the Ganges descended to earth, and Parasurama appeared. It also marks the beginning of Chandana Yatra (sandalwood paste festival) for the deities.', '\"Akshaya\" means \"imperishable\" — any charity or spiritual activity performed on this day yields eternal, never-diminishing results. The day falls on the third day of the bright fortnight of Vaishakha.', 'Donations made on Akshaya Tritiya multiply exponentially and never diminish. Sponsoring the Chandana Yatra offerings and prasadam distribution on this day ensures eternal spiritual merit and material prosperity.', 'festival', NULL, 'assets/images/banners/akshaya-tritiya.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 43, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Akshaya Tritiya is a highly auspicious day in the Vedic calendar. The word *Akshaya* means \"that which never decays or diminishes.\" There is no inauspiciousness to be found on this day, so even checking for favorable *muhurthas* is considered unnecessary. Whatever spiritual service one performs for Lord Krishna or His devotees on this day yields eternal, inexhaustible benefits.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Key Historical Events on This Day</h3>
      
      <p>
        Several significant pastimes and scriptural events occurred on this tithi:
      </p>
      
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:var(--space-lg);\">
        <li>
          <strong>Beginning of Chandana Yatra:</strong> 
          To protect Their Lordships from the blistering summer heat, the 21-day Chandana Yatra begins. The deities are completely smeared with cooling, fragrant sandalwood paste (*chandana*) mixed with camphor.
        </li>
        <li>
          <strong>The Gift of the Akshaya Patra:</strong> 
          Draupadi received the famous *akshaya-patra* (the inexhaustible pot) from Lord Krishna. Given by the Sun-god, this pot would produce unlimited amounts of food for the Pandavas and their guests until Draupadi herself finished eating and turned the pot upside down for the day.
        </li>
        <li>
          <strong>Vyasadeva Writes the Mahabharata:</strong> 
          The great sage Srila Vyasadeva began writing the epic *Mahabharata* on this day, dictating it to Lord Ganesha for the spiritual welfare of all humanity.
        </li>
        <li>
          <strong>Sudama\'s Offering of Chipped Rice:</strong> 
          Sudama, Lord Krishna\'s poor Brahmin classmate, visited Dwarka to meet the Lord. Hesitant to ask for help, he offered Krishna a tiny handful of chipped rice. In return, Lord Krishna secretly rewarded him with unimaginable opulence, turning his humble hut into a golden palace.
        </li>
        <li>
          <strong>Twice Protection of Draupadi:</strong> 
          Lord Krishna protected Draupadi twice on this day: first, by providing her with an unlimited sari during the assembly hall dice game, and second, when Durvasa Muni and his thousands of disciples visited the forest demanding food. Lord Krishna took a single grain of leftover rice from Draupadi\'s pot, ate it, and instantly satisfied the hunger of all the sages.
        </li>
      </ul>', 'Calendar: Celebrated on Vaisakha Shukla Tritiya (3rd day of the bright moon of Vaisakha) (April/May)|Significance: A day of supreme auspiciousness where checking Muhurthas is considered unnecessary. Any charitable or devotional deed performed on this day yields inexhaustible (*akshaya*) benefits.|Key Highlights: Start of the 21-day Chandana Yatra festival where the deities are smeared with sandalwood paste.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (27, 'gita-jayanti', 'Gita Jayanti', 'Gita Jayanti', 'The advent day of Srimad Bhagavad-gita.', 'Gita Jayanti marks the day when Lord Krishna spoke the Bhagavad-gita to Arjuna on the battlefield of Kurukshetra over 5,000 years ago. This sacred dialogue, recorded in the Bhishma Parva of the Mahabharata, contains the essence of all Vedic wisdom. Srila Prabhupada translated and commented on the Gita as \"Bhagavad-Gita As It Is,\" which has been distributed in millions worldwide.', 'The Bhagavad-gita is the only book that contains the actual words of the Supreme Personality of Godhead. It provides complete knowledge of the self, the universe, and the ultimate goal of life — surrender to Krishna.', 'Sponsoring Gita distribution on this day multiplies the benefit millions of times. Supporting the recitation of all 18 chapters, the fire yajna, and book distribution invokes Lord Krishna\'s special blessings for knowledge and enlightenment.', 'festival', NULL, 'assets/images/banners/gita-jayanti.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 44, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        Gita Jayanti is the auspicious day of the advent of Srimad Bhagavad-gita. This is the day on which Lord Krishna imparted the essence of Vedic knowledge to Arjuna over 5,000 years ago and enlightened him about the ultimate goal of life. This day is also called Mokshada Ekadashi, and it generally occurs in the month of December.
      </p>
      
      <p>
        As stated in the Gita-mahatmya, if one properly follows the instructions of Bhagavad-gita, one can be freed from all miseries and anxieties in this life, and one\'s next life will be spiritual.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"imam vivasvate yogam proktavan aham avyayam<br>
        vivasvan manave praha manur iksvakave bravit\"<br><br>
        \"The Blessed Lord said: I instructed this imperishable science of yoga to the sun-god, Vivasvan, and Vivasvan instructed it to Manu, the father of mankind, and Manu in turn instructed it to Ikshvaku.\" &mdash; Bhagavad-gita 4.1
      </blockquote>

      <p>
        Gita Jayanti is not simply a historical birthday; it is the day the Bhagavad-gita was spoken for the first time on this planet during this particular yuga cycle. As Lord Krishna explains, this supreme science was received through the chain of disciplic succession, but in course of time the succession was broken, and therefore the science appeared to be lost (BG 4.2). This shows that the message of the Bhagavad-gita is eternally present, and Lord Krishna delivers it in its original form as and when it needs to be revived.
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/gita-jayanti-advent.jpg\" alt=\"Lord Krishna speaking Bhagavad-gita to Arjuna\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Krishna\'s discourse to Arjuna at Kurukshetra</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Key Teachings from the Bhagavad Gita</h3>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Sensitivity to Reality:</strong> Teaches awareness of both the material and spiritual realities.</li>
        <li><strong>A Willing Dialogue:</strong> The conversation between an eager disciple and a caring teacher.</li>
        <li><strong>Stability in Action:</strong> Impels us to understand our field of activity (Kshetra) and function with stability.</li>
        <li><strong>Harmonizing Opposites:</strong> War on the outside, peace on the inside; fierce action without attachment to outcomes.</li>
        <li><strong>Selfless Service:</strong> Balances self-growth with dedicated, selfless service to the Supreme.</li>
        <li><strong>Respect for Time:</strong> Reminds us to respect eternal time and make every moment thoughtful.</li>
        <li><strong>Divine Vision:</strong> Inspires us to see divinity everywhere and see everything within the divine.</li>
        <li><strong>Unforced Wisdom:</strong> Krishna explains everything but allows Arjuna the freedom to decide (BG 18.63).</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Preaching & Book Distribution</h3>
      <p>
        Following the revolutionary preaching of Srila Prabhupada, the founder-acharya of ISKCON, Gita Jayanti has become one of the most widely celebrated festivals. <em>Bhagavad-Gita As It Is</em> has been translated into practically every major language, and millions of copies have been distributed. 
      </p>
      
      <p>
        On Gita Jayanti, devotees gather to read all 18 chapters of the Gita, offer oblations in fire sacrifices (yajnas), and distribute Gita copies.
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Anyway, print books, distribute profusely, and that will be the best preaching work. What will your three minutes preaching do? But if they buy one book, it may turn their life. So, make this your important task, to print our books and distribute widely, and that will please my Guru Maharaja.\"<br>
        &mdash; Srila Prabhupada, Letter to Bhagavan das, 5 November, 1972
      </blockquote>', 'Calendar: Celebrated on Mokshada Ekadashi, in the bright fortnight of Margashirsha month (November/December)|Significance: The anniversary of Lord Krishna speaking the Bhagavad-gita to Arjuna at Kurukshetra over 5,000 years ago.|Observances: Recitation of all 18 chapters of Bhagavad-gita, fire yajna, and massive book distribution.|Core Message: The eternal science of bhakti-yoga and surrender to the Supreme Lord (BG 18.66).|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (28, 'nityananda-trayodashi', 'Nityananda Trayodashi', 'Nityananda', 'The appearance day of Lord Nityananda Prabhu.', 'Nityananda Trayodashi celebrates the appearance of Lord Nityananda, the elder brother of Lord Chaitanya and the combined incarnation of Lord Balarama. Born in Ekachakra, Nityananda Prabhu traveled extensively as a young sannyasi before meeting Chaitanya Mahaprabhu and joining His sankirtana movement.', 'Lord Nityananda is known as the most merciful incarnation, who delivers even the most fallen souls. His mercy is so powerful that whoever receives it is immediately purified and becomes eligible for Krishna-prema.', 'Sponsoring Nityananda Trayodashi celebrations invokes His unlimited mercy. Supporting the festival helps deliver fallen souls and brings the associate-like blessings of Lord Nityananda.', 'festival', NULL, 'assets/images/banners/nityananda-trayodashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 45, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Lord Nityananda is the eternal associate of Chaitanya Mahaprabhu, the Supreme Personality of Godhead. Rarely is the name Nimai (Chaitanya Mahaprabhu) taken without that of Nitai (Lord Nityananda). Lord Chaitanya Mahaprabhu cannot be approached or understood without the mercy of Nityananda Prabhu, who is the cardinal guru of all the universes and serves as an intermediary between Mahaprabhu and His devotees. 
      </p>
      
      <p>
        He is the Lord\'s active principle in both creation and lila, the second body of the Lord, manifesting as Balarama to Sri Krishna, Lakshman to Sri Ram, and Nityananda Prabhu to Caitanya Mahaprabhu.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"preme matta nityananda krpa-avatara / uttama, adhama, kichu na kare vicara<br>
        ye age padaye, tare karaye nistara / ataeva nistarila mo-hena duracara\"<br><br>
        \"Because He is intoxicated by ecstatic love and is an incarnation of mercy, He does not distinguish between the good and the bad. He delivers all those who fall down before Him. Therefore He has delivered such a sinful and fallen person as me.\" &mdash; Caitanya Caritamrta Adi Lila 5.208-209
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Childhood in Ekachakra</h3>
      <p>
        Nityananda Prabhu was born in Ekachakra, a small village in present-day West Bengal, around the year 1474 to Hadai Ojha and Padmavati. He was born on the thirteenth day of the bright fortnight of the month of Magha. As a child, Nitai loved to enact the pastimes of Sri Krishna or Lord Rama. He did this so authoritatively and with such rapture that the entire village would be immersed in the love of Godhead.
      </p>
      
      <p>
        Nitai\'s favorite role was that of Lakshman, and He enacted it with so many apparently authentic scenes not described in the Ramayana that people wondered if He was actually relishing His own pastimes. In His 13th year, a travelling sannyasi, said to be Lakshmipati Tirtha, requested Nitai from his parents as a travelling companion. Reluctantly, they parted with Nitai. Devastated by the separation, Hadai Pandit soon gave up his life.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Travels and Meeting with Mahaprabhu</h3>
      <p>
        Nitai traveled with Lakshmipati Tirtha for about 20 years, visiting all the holy places in India. He was later initiated by Lakshmipati Tirtha and associated closely with Madhavendra Puri.
      </p>
      
      <p>
        Nityananda Prabhu met Caitanya Mahaprabhu in 1506, when He was 32 years old and the Lord was 20. When He reached Nadia, He hid in the house of Nandan Acharya. Chaitanya Mahaprabhu, aware of the arrival of His eternal associate, dispatched Haridas Thakur and Srivas Pandit to search for Nitai, but they could not find Him. Finally, Chaitanya Mahaprabhu went directly to Nandan Acharya\'s house, and the ecstasy of their meeting was a sublime experience for all who witnessed it.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Preaching and Unconditional Mercy</h3>
      <p>
        Lord Nityananda was instrumental in spreading the Yuga Dharma of Sankirtana all over Bengal and Orissa. His mercy knew no bounds. It was by His mercy that Raghunatha dasa Gosvami started the Danda Mahotsava of Panihati, which enabled him to serve Caitanya Mahaprabhu. He extended His mercy to even the most fallen, protecting and delivering Jagai and Madhai from their sinful lives.
      </p>
      
      <p>
        At the request of Lord Chaitanya, Nityananda Prabhu abandoned His avadhuta status and married Jahnavadevi and Vasudha, the daughters of Suryadasa Sarakhel. Jahnavadevi later initiated Virchandra (Nityananda\'s son) and became a prominent instructing guru in the Gaudiya tradition. Lord Nityananda wound up His earthly pastimes by merging into the deity of Bankim Ray near Ekachakra.
      </p>', 'Calendar: Celebrated on Magha Shukla Trayodashi (13th day of the bright moon of Magha month) (January/February)|Significance: The appearance day of Lord Nityananda Prabhu, the incarnation of Lord Balarama who distributes Krishna Prema without restriction.|Key Highlights: Grand abhishekam of Gaura-Nitai deities, singing of Nitai glories, and prasadam feast.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (29, 'bahulastami', 'Bahulastami', 'Bahulastami', 'The appearance of Radha-kunda and Syama-kunda.', 'Bahulastami celebrates the appearance of Radha-kunda and Syama-kunda in Vrindavan. These sacred ponds were created by Lord Krishna and Srimati Radharani during their pastimes. A bath in these kundas on this day is considered equal to performing all austerities and pilgrimages.', 'These ponds are non-different from Radha and Krishna themselves. Devotees consider taking bath in these sacred waters as the most purifying act, cleansing all sins and bestowing love of God.', 'Sponsoring the special arati and offerings at the temple\'s sacred water source on Bahulastami invokes the purifying blessings of Radha-kunda and Syama-kunda.', 'festival', NULL, 'assets/images/banners/bahulastami.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 46, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        On the eighth day of the waning phase of the Damodara month, the appearance day of Radha-kunda and Syama-kunda is celebrated by the residents and pilgrims of Vraja. Bathing in Radha-kunda is especially beneficial on this day. By this bath, one gains the favor of Radharani, by which one easily gains the favor of Krishna.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"The holy place known as Mathura is spiritually superior to Vaikuntha, the transcendental world, because the Lord appeared there. Superior to Mathura-puri is the transcendental forest of Vrindavana because of Krishna\'s rasa-lila pastimes. And superior to the forest of Vrindavana is Govardhana Hill... And, above all, the superexcellent Sri Radha-kunda stands supreme, for it is overflooded with the ambrosial nectarean prema of the Lord of Gokula, Sri Krishna.\" &mdash; Srila Rupa Goswami, Nectar of Instruction (Upadeshamrita)
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Origin of Radha-kund</h3>
      <p>
        The pastime begins after Lord Krishna killed the bull-demon Aristasura. When Krishna approached Srimati Radharani to engage in loving pastimes, She rebuked Him, stating that He was impure because He had committed the sin of killing a bull &mdash; the symbol of religion. She suggested that to counteract this sin, He must bathe in all the sacred rivers of the universe.
      </p>
      
      <p>
        Krishna, eager to please Srimati Radharani, shoved His lotus foot into the ground, creating a large cavity, and called all the sacred rivers in person to enter into it. They appeared before Him, offering prayers, and entered the cavity to form Syama-kunda (the bathing place of Syama).
      </p>
      
      <p>
        After bathing, Krishna teased Radharani, stating that He had become pure, but the gopis had become impure by siding with a demon (even though he appeared as a bull). Radharani and Her gopi friends then broke their bangles and dug a hole in the ground with the broken pieces. Since there was no water in it, Krishna laughed. The gopis then formed a line to the Manasi Ganga, passing water from one to another to fill the hole. At that time, all the personified sacred rivers emerged from Syama-kunda, paid obeisances to Radharani, and requested Her permission to enter Her kunda. Upon receiving Radharani\'s blessing, they entered, forming Radha-kunda.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Midnight Bathing Ritual</h3>
      <p>
        Radha-kunda appeared at midnight, and thus the grand bathing ritual takes place at midnight on Bahulastami. Thousands of devotees gather at the banks, offering garlands, prasadam, and pumpkins (gourds) into the water before taking a holy dip in Radha-kunda, followed by Syama-kunda. 
      </p>
      
      <p>
        Many devotees prefer to bathe at the ghat where Lord Nityananda\'s consort, Jahnava Mata, used to bathe. The atmosphere is deeply spiritual, filled with ecstatic kirtan and chants glorifying Srimati Radharani.
      </p>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (30, 'odana-sasthi', 'Odana Sasthi', 'Odana Sasthi', 'Lord Jagannath is offered winter garments.', 'Odana Sasthi marks the day when Lord Jagannath and His siblings are dressed in thick, warm winter garments. This festival signals the arrival of the winter season and the deities\' preparation for the cold months ahead. The ritual has been observed in Jagannatha Puri for centuries.', 'This festival highlights the intimate relationship between the Lord and His devotees, who lovingly care for His comfort. It demonstrates that the Lord accepts our loving service in whatever form we offer it.', 'Sponsoring Odana Sasthi offerings brings the Lord\'s blessings for protection and warmth. Donors who offer winter garments to the deities receive spiritual warmth and the Lord\'s special care.', 'festival', NULL, 'assets/images/banners/odana-sasthi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 47, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        As autumn surrenders to the cool breeze of the winter, we are reminded of the approaching winter season and the divine festival of Odana Sasthi. This auspicious occasion reminds us of the Lord\'s loving reciprocation with His devotees by accepting a starched cloth for winter.
      </p>
      
      <p>
        Odana-sasti is the date on which Lord Jagannatha is given a winter shawl. One year when Lord Caitanya and His associates celebrated this festival in Puri, Pundarika Vidyanidhi, who is Vrsabhanu Maharaja (Srimati Radharani\'s father in krsna-lila), received some special mercy. His experience is instructive for us all.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"gadādhara-paṇḍite teṅho punaḥ mantra dila<br>
        oḍana-ṣaṣṭhīra dine yātrā ye dekhila\"<br><br>
        \"Puṇḍarīka Vidyānidhi initiated Gadādhara Paṇḍita for the second time, and on the day of Oḍana-ṣaṣṭhī Puṇḍarīka Vidyānidhi saw the festival.\" &mdash; Sri Caitanya Caritamrta Madhya Lila 16.78
      </blockquote>

      <p>
        Srila Prabhupada explains: 
        <em>\"At the beginning of winter, there is a ceremony known as the Odana-sasthi. This ceremony indicates that from that day forward, a winter covering should be given to Lord Jagannatha. That covering is directly purchased from a weaver. According to the arcana-marga, a cloth should first be washed to remove all the starch, and then it can be used to cover the Lord. Pundarika Vidyanidhi saw that the priest neglected to wash the cloth before covering Lord Jagannatha. Since he wanted to find some fault in the devotees, he became indignant.\"</em> (Cc Madhya 16.78 purport)
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Pastime of Pundarika Vidyanidhi</h3>
      <p>
        The Lord\'s mercy comes in many forms and the story behind Odana Sasthi is one amongst many to tell. Once, Sri Caitanya Mahaprabhu, accompanied by all His devotees, came to see Lord Jagannatha on Odana Sasthi and was gripped in waves of ecstasy. Musical bands with numerous instruments, mridangas, kartals, conch shells, and bells echoed all around, and the entire town wore a festive look. 
      </p>
      
      <p>
        Srila Pundarika Vidyanidhi and Srila Svarūpa Dāmodara Gosvāmī had a friendly, intimate relationship. They attended the festival of Odana-sasthi in Sri Kshetra Puri Dham. Srila Pundarika Vidyanidhi saw that the Lord was offered new cloth directly purchased from a weaver, which was not washed before being offered. According to proper injunctions to be followed when worshipping the deities, the purchased cloth should first be washed to remove all the starch, which is considered impure.
      </p>
      
      <p>
        Seeing the Lord wearing starched clothes, Pundarika Vidyanidhi became very angry; thus his mind became polluted. He spoke to Srila Svarupa Damodara and criticized the behavior of Lord Jagannatha\'s servants, asking why they would offer starched cloth to the Lord. Svarūpa Dāmodara Gosvāmī tried to pacify Pundarika Vidyanidhi with gentle words, saying that it was simply how it was done, and surely if the Lord was not pleased, He would have stopped it. Svarupa Damodara remarked that the characteristics of the Supreme Lord are beyond the jurisdiction of worldly etiquette, but Pundarika Vidyanidhi was still not satisfied.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Chastisement and Mercy in a Dream</h3>
      <p>
        That night, Lord Jagannatha and Lord Baladeva came to Pundarika Vidyanidhi in his dream and began to slap him, chastising him for criticizing Their servants and the way they worshipped the Lord. This chastisement went on for a length of forty-eight minutes (one ghati). After Pundarika Vidyanidhi begged for Their forgiveness, the Lords mercifully glanced at Pundarika and went back to Their temple. 
      </p>
      
      <p>
        Upon waking up, Pundarika felt that his face was swollen and bore the imprints of the Lords\' hand marks. He understood this to be the pure, intimate mercy of the Lord, and thus upon seeing his swollen face, he laughed with great joy.
      </p>
      
      <p>
        Learning from this incident, we understand that the Lord does not tolerate offenses against His servants, even from an advanced devotee, and that He chastises a devotee who commits such an offense even within the mind. We can also learn that a pure devotee accepts such chastisement from the Lord with great happiness, as a manifestation of the Lord\'s mercy, His love, and His care. Pundarika Vidyanidhi thanked the Lord for rectifying him and preventing him from committing further offenses, feeling great jubilation within his heart.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"sabe na janena sarva-dasera prabhava<br>
        sarva-se janena yanra yata anuraga<br>
        bhramo karayena krsna apana-dasere<br>
        bhramac-chedo kare pache sadaya-antare\"<br><br>
        \"No one can understand the glories of the Lord\'s servants. Only Krishna knows their attachment for Him. Krishna sometimes bewilders His devotee, and then, feeling compassion for him, He destroys his illusion.\" &mdash; Sri Caitanya Bhagavata, Antya-khanda texts 120-121
      </blockquote>

      <p>
        The Odana-sasthi festival is most definitely a favorite winter festival in Sri Jagannatha Mandir, bringing devotees together to blissfully celebrate the pastime activities of Lord Jagannatha.
      </p>', 'Calendar: Observed on the sixth day of the bright fortnight (Shukla Sasthi) of Margashirsha month (November/December)|Significance: Marks the beginning of winter, when Lord Jagannatha is dressed in a winter shawl and new starched cloth.|Key Pastime: Pundarika Vidyanidhi (Srimati Radharani\'s father Vrishabhanu Maharaja in krsna-lila) receives dream chastisement and mercy from Lord Jagannatha.|Deities: Lord Jagannath, Lord Balabhadra, Goddess Subhadra|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (31, 'tulasi-shaligram-vivaha', 'Tulasi-Shaligram Vivaha', 'Tulasi Vivaha', 'The sacred wedding of Tulasi Devi and Lord Shaligram.', 'Tulasi Vivaha marks the ceremonial marriage of the Tulasi plant (an expansion of Srimati Radharani) to the Shaligram shila (a form of Lord Vishnu). This festival begins the wedding season in India and is considered highly auspicious. Tulasi Devi is supremely dear to Lord Krishna.', 'Tulasi is the most sacred plant in Vedic tradition. She is worshipped daily in Vaishnava homes and temples. Her marriage to Lord Vishnu/Shaligram represents the eternal union of the devotee with the Lord.', 'Participating in Tulasi-Shaligram Vivaha brings enormous spiritual merit. It is considered equal to performing a Vedic wedding ceremony. Donors who sponsor this festival receive Tulasi Devi\'s blessings and are freed from all sins.', 'festival', NULL, 'assets/images/banners/tulasi-shaligram-vivaha.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 48, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        The Full Moon day (Purnima) marks the end of the month of Kartika. This day is celebrated with great devotional sentiment as Kartika Purnima, representing the Sri Krishna Rasa-yatra, the last day of Chaturmasya, and most notably, the Tulasi-Shaligrama Vivaha &mdash; the sacred marriage ceremony of Srimati Tulasi Devi and Lord Sri Krishna.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Scriptural Origins & Marriage Guidelines</h3>
      <p>
        The marriage of Srimati Tulasi Devi is described by Sri Vasishthaji in ancient times as heard from Lord Brahma, and is detailed in the Narada-pancharatra:
      </p>
      
      <p>
        First, one should plant Tulasi either in the house or the forest, and after three years one may perform her marriage. The auspicious times when one may perform the marriage of Shalagrama and Tulasi are in the month of Kartika, from the Ekadashi (Devutthana) to the Full Moon day.
      </p>
      
      <p>
        A sacrificial arena (yajna-kunda) is established under a canopy (mandapa). After performing shanti-vidhana and installing the sixteen goddesses, one installs an attractive Shalagrama-shila (representing Lakshmi-Narayana). When it is dusk, a golden Deity of Narayana and a silver murti of Tulasi are installed according to one\'s means. With Vedic mantras, two cloths are tied together, marriage bracelets (kangana) are tied, and the marriage is consecrated. The host performs parikrama of Tulasi four times with the Shalagrama-shila.
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/tulasi-shaligram-marriage.jpg\" alt=\"Tulasi Shaligram Marriage Altars\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Deities adorned for Tulasi-Shaligram Vivaha</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Legend of Vrinda and Jalandhar</h3>
      <p>
        According to the Padma Purana, Tulasi in her former birth was Vrinda, the daughter of a giant named Nemi and the faithful wife of the demon Jalandhar. Being born in water, Jalandhar claimed sovereignty over the ocean and demanded the fourteen treasures churned out during the Samudra Manthan. He declared war on the demigods and became a cause of great danger. He had a boon that he would be free from death as long as his wife Vrinda remained chaste.
      </p>
      
      <p>
        To defeat the demon, Lord Vishnu assumed the form of Jalandhar and approached Vrinda. In her wrath upon discovering the deceit, Vrinda cursed Lord Vishnu to turn into a black stone (Shalagrama). Lord Vishnu accepted her curse, but in admiration of her unimpeachable chastity, He transformed her into the sacred Tulsi plant and promised to marry her annually. The origin of the ammonite black stones found in the Gandaki River bed is attributed to this legend.
      </p>
      
      <p>
        Devout Vaishnavas perform a mock marriage between Srimati Tulasi Devi and Shalagrama-shila on this day. The belief is that one who performs the ceremony of giving away Tulasi Devi obtains the spiritual credit of Kanyadan (giving away a daughter in marriage), which is regarded as an extremely meritorious act.
      </p>

      <!-- Sub-image block 2 -->
      <div style=\"margin:var(--space-xl) 0; display:flex; gap:var(--space-md); flex-wrap:wrap; justify-content:center;\">
        <div style=\"flex:1; min-width:260px; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
          <img src=\"{{BASE_URL}}assets/images/banners/shaligram.jpg\" alt=\"Sacred Shaligram Shila\" style=\"width:100%; height:200px; object-fit:cover; display:block;\">
          <span style=\"display:block; background:var(--light); padding:8px; font-size:11px; color:var(--text-light); border-top:1px solid var(--border);\">Sacred Shalagrama Shila</span>
        </div>
        <div style=\"flex:1; min-width:260px; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
          <img src=\"{{BASE_URL}}assets/images/banners/tulasi-maharani.jpg\" alt=\"Worshipping Srimati Tulasi Devi\" style=\"width:100%; height:200px; object-fit:cover; display:block;\">
          <span style=\"display:block; background:var(--light); padding:8px; font-size:11px; color:var(--text-light); border-top:1px solid var(--border);\">Srimati Tulasi Devi (Lakshmi)</span>
        </div>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Simple Vivaha Prayog (Home worship guidelines)</h3>
      <p>
        Devotees can easily perform a simplified marriage ceremony at home:
      </p>
      
      <ol style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Adorning Srimati Tulasi:</strong> Dress her pot in a nice red skirt. Adorn her branches with red bangles, kumkum, and bindhis. Use a fresh or dried turmeric root as a mangala-sutra.</li>
        <li><strong>Kanya Sampradanam (Giving of Bride):</strong> Recite the lineage of the bride and the groom. Tie a red thread (kankabandanam) to the Shaligram\'s right side and Tulsi\'s left pot-side.</li>
        <li><strong>Mala Dharanam (Exchange of Garlands):</strong> Place a garland on the Tulsi plant and the Shaligram. Exchange the garlands three times. Tulasi garlands Him first.</li>
        <li><strong>Sindhur Danam:</strong> Mark her leaves and upper trunk with sindhur three times on Lord Shaligram\'s behalf.</li>
        <li><strong>Vastra Bandhanam (Tying their cloth):</strong> Tie a corner of Shaligram\'s angavastra to Tulsi\'s red cloth. Keep them bound for seven nights.</li>
        <li><strong>Saptapadi (Seven Steps):</strong> Take seven symbolic steps around the altar chanting: 
          <em>\"OM EKAM ISE VISNUH TVA NAYATU\"</em> (First step for strength), 
          <em>\"DVE URJE\"</em> (Power), 
          <em>\"TRINI VRATAYA\"</em> (Vows), 
          <em>\"CATVARI MAYOBHAVAYA\"</em> (Happiness), 
          <em>\"PANCA PASUBHYO\"</em> (Cows), 
          <em>\"SAD RAYAS POSAYA\"</em> (Wealth), and 
          <em>\"SAPTA SAPRABHYO HOTRABHYO\"</em> (Maintaining sacrifices).
        </li>
      </ol>
      
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); text-align:center; font-style:italic;\">
        Whoever plants Tulasi, collects her leaves, or installs her along with Lord Vishnu will achieve liberation, the spiritual abode, and eternal association with Shri Hari.
      </p>', 'Calendar: Celebrated on Kartika Purnima (the Full Moon day ending the month of Kartika)|Significance: The marriage ceremony of Srimati Tulasi Devi (the sacred basil plant) and Lord Sri Krishna (in His form as the black ammonite stone, Shalagrama-shila).|Scriptural Reference: Padma Purana & Narada Pancharatra|Key Highlights: Canopy mandapa yajna, simple flower/dress decoration of Tulasi pot, kankabandanam thread, Sindhur Danam, Saptapadi, and Kanya Sampradanam.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (32, 'panihati', 'Panihati Chida-Dahi Utsav', 'Panihati', 'Commemorating Lord Nityananda\'s pastime with Raghunatha dasa Gosvami.', 'The Panihati Chida-Dahi Utsav commemorates the famous pastime where Lord Nityananda Prabhu, along with His associates, sat under a tree in Panihati (near Kolkata) and distributed chida (flattened rice) and dahi (yogurt) to everyone. Ragunatha dasa Gosvami, who was then a young boy from a wealthy family, was initiated into devotional service on this day.', 'This festival demonstrates Nityananda Prabhu\'s unlimited mercy and His ability to attract anyone to devotional service, regardless of their background. It teaches the importance of humble association with pure devotees.', 'Sponsoring the distribution of chida-dahi prasadam on this day brings the special mercy of Lord Nityananda and Raghunatha dasa Gosvami. It is an opportunity to participate in a pastime that has been celebrated for over 500 years.', 'festival', NULL, 'assets/images/banners/panihati.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 49, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        Panihati is the name of a village located on the banks of the River Ganges (10 miles north of Kolkata) in West Bengal. It was one of the leading trade centers in earlier days. Once a center of Buddhist Tantrics and Kapalikas, it became a major Gaudiya Vaishnava center in the 16th century through the pastimes of Sri Chaitanya Mahaprabhu and Lord Nityananda.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Why is it known as the Festival of Punishment?</h3>
      <p>
        Srila Raghunatha dasa Gosvami, a personal associate of Sri Chaitanya Mahaprabhu, displayed a spirit of complete renunciation and detachment from the material world at a very early age. He wanted to leave home to join Sri Chaitanya Mahaprabhu\'s mission. However, Mahaprabhu instructed him to remain at home and assured him that Krishna would deliver him soon.
      </p>
      
      <p>
        Two years later, when Lord Nityananda came to Panihati, Raghunatha dasa took permission from his father and went to meet Him. He saw Nityananda Prabhu sitting on a rock under a banyan tree on the banks of the Ganges, surrounded by many devotees. Raghunatha dasa was hesitant to approach and paid his obeisances from a distance. 
      </p>
      
      <p>
        Upon noticing him, Lord Nityananda called out: 
        <em>\"Raghunatha dasa! You are hiding like a thief. Now I have caught hold of you. Come here. I shall punish you today!\"</em> 
        Lord Nityananda forcibly caught him, placed His lotus feet on Raghunatha dasa\'s head, and ordered him to celebrate a big festival, serving yogurt and chipped rice (chida-dahi) to all the devotees.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"dadhi, ciḍā bhakṣaṇa karāha mora gaṇe<br>
        śuni ānandita haila raghunātha mane\"<br><br>
        \"Make a festival and feed all My associates yogurt and chipped rice. Hearing this, Raghunātha dāsa was greatly pleased.\" &mdash; Sri Caitanya Caritamrta Madhya Lila 16.78
      </blockquote>

      <p>
        Raghunatha dasa immediately purchased chipped rice, milk, yogurt, sweetmeats, bananas, sugar, and other eatables. The chipped rice was soaked in milk. Half was mixed with yogurt, sugar, and bananas, and the remaining half was mixed with condensed milk, clarified butter, and camphor. All the devotees received two earthen pots, one of each preparation.
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/nityananda-darshan.jpg\" alt=\"Lord Nityananda Prabhu Darshana\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Lord Nityananda Prabhu blessing His devotees</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Meditation Pastime with Mahaprabhu</h3>
      <p>
        When everyone was served, Lord Nityananda brought Sri Chaitanya Mahaprabhu there in meditation. Together, the two brothers walked through all the groups of eaters. Nityananda Prabhu would take a morsel of chipped rice from a devotee\'s pot and jokingly feed it to Chaitanya Mahaprabhu, who would in turn feed Nityananda and laugh. 
      </p>
      
      <p>
        While most could not perceive what was happening, some very fortunate devotees saw that Lord Sri Chaitanya Mahaprabhu was present in person. Then, Nityananda Prabhu ordered everyone to eat, chanting the holy name of Hari. The sound of \"Hari, Hari\" resounded, filling the entire universe. Devotees remembered how Krishna and Balarama ate with Their cowherd companions on the banks of the Yamuna.
      </p>
      
      <p>
        The mercy of Lord Nityananda is unfathomable. It was Raghunatha dasa\'s great fortune that Lord Nityananda accepted these dealings, which eventually freed him from material bondage and allowed him to join Sri Chaitanya Mahaprabhu in Puri.
      </p>', 'Calendar: Celebrated on the 13th day of the bright moon (Shukla Trayodashi) in the month of Jyeshta (May/June)|Alternative Names: Chida-dahi Mahotsava, Danda Mahotsava (the Festival of Punishment)|Deities: Lord Nityananda Prabhu and Sri Chaitanya Mahaprabhu|Significance: Commemorates the pastime where Lord Nityananda lovingly \"punished\" Raghunatha dasa Gosvami by ordering him to feed yogurt and chipped rice (chida-dahi) to all the Vaishnavas.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (33, 'varaha-dwadashi', 'Varaha Dwadashi', 'Varaha', 'The appearance day of Lord Varahadeva.', 'Varaha Dwadashi celebrates Lord Varahadeva, the third incarnation of Lord Vishnu, who appeared as a gigantic boar to rescue the Earth (personified as Bhumi Devi) from the demon Hiranyaksha. Lord Varaha lifted the Earth on His tusks from the depths of the Garbhodaka Ocean and killed the demon.', 'This incarnation demonstrates the Lord\'s willingness to assume any form to protect His devotees and the cosmic order. Lord Varaha is also intimately connected with the creation and preservation of the universe.', 'Sponsoring Varaha Dwadashi celebrations invokes the Lord\'s protective blessings. Donors receive protection from all dangers and the assurance that the Lord will always come to their rescue.', 'festival', NULL, 'assets/images/banners/varaha-dwadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 50, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<p>
        Today is the incarnation day of Lord Krishna appearing as the Boar, Lord Varahadeva. He lifted the world when it was submerged within the waters of the Garbhodaka Ocean. 
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"vasati dasana-sikhare dharani tava lagna<br>
        sasini kalanka-kaleva nimagna<br>
        kesava dhrta-sukara-rupa jaya jagadisa hare<br>
        jaya jagadisa hare, jaya jagadisa hare\"<br><br>
        \"O Kesava! O Lord of the universe! O Lord Hari, who have assumed the form of a boar! All glories to You! The earth, which had become immersed in the Garbhodaka Ocean at the bottom of the universe, sits fixed upon the tip of Your tusk like a spot upon the moon.\" &mdash; Sri Dasavatara-stotra, Verse 3
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of the Boar Incarnation</h3>
      <p>
        In Vedic cosmology, planets are conscious persons. The planet Earth once fell into the universal Garbhodaka water when demonic persons disturbed her orbit by drilling for oil and upsetting her balance. The celestial devas, who manage the universe in service to Krishna, prayed for Earth to be rescued.
      </p>
      
      <p>
        Responding to their prayers, the Lord assumed the form of a splendid, gigantic boar (Varaha). He dove to the bottom of the universal ocean, picked up Earth, and gently carried her on His tusk to the water\'s surface. 
      </p>
      
      <p>
        As He did so, the great demon Hiranyaksha challenged Him. Lord Varaha carefully placed the fearful Earth on the water, giving her the ability to float, and fought the demon in the universal ocean. After defeating Hiranyaksha, Lord Varaha returned to the spiritual sky.
      </p>
      
      <p>
        We can just imagine the size of Lord Varahadeva: the entire world sat on His tusk, appearing just like a moon disc with marks on it. Devotees pray to Lord Varahadeva for protection, strength, and purification.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">A Prayer for Purification</h3>
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Just as You protect the Earth by going to a dirty place within the universe, kindly uncover our pure devotion to Your lotus feet that lies deep underneath the dirt within our hearts, and purify us.\"
      </blockquote>', 'Calendar: Celebrated on Phalguni Krishna Dwadashi (12th day of the dark moon of Phalguna month) (February/March)|Significance: The appearance day of Lord Varahadeva, Lord Krishna\'s incarnation as a giant Boar who lifted the Earth from the depths of the Garbhodaka Ocean.|Key Highlights: Special prayers, kirtan chanting, and bathing ceremony.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (34, 'pushya-abhisheka', 'Pushya Abhisheka', 'Pushya', 'Lord Krishna is decorated with flower outfits and bathed in petals.', 'Pushya Abhisheka is a special festival where the deity of Lord Krishna is decorated with flower garments and bathed with flower petals. This unique abhishekam takes place when the moon is in the Pushya nakshatra, an especially auspicious constellation.', 'The flower decorations and petal bath represent the beauty and sweetness of the Lord\'s pastimes. This festival celebrates the intimate mood of loving service to Krishna in Vrindavan.', 'Sponsoring the Pushya Abhisheka, especially the flower garments and petal offerings, brings the most beautiful and sweet blessings of Lord Krishna. Donors receive the Lord\'s special affection and grace.', 'festival', NULL, 'assets/images/banners/pushya-abhisheka.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 51, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        In the Skanda Purana 2.2.42, Sri Krishna Pusya abhiseka is described as one of the festivals observed for Lord Jagannath in Puri. The chapter gives an elaborate description of the rituals for observing the festival. In Skanda Purana 2.27.99, the pusya naksatra is also mentioned, wherein it is stated that on a Thursday, Astami tithi, during Sukla-paksa of the month of Vaishakha, in conjunction with the Pusya-naksatra, Lord Jagannath was installed in the original temple in Puri.
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"patram puspam phalam toyam yo me bhakta prayacchati\"<br>
        \"If one offers Me with love and devotion a leaf, a flower, fruit or water, I will accept it.\" &mdash; Bhagavad-gita 9.26
      </blockquote>

      <p>
        Flowers are a special part of our tradition. It is the way we honor special guests, the spiritual master, and the Vaishnavas. Offering flowers is a simple service for Krishna but it\'s a deep meditation. Whether it is stringing flowers together or pulling them apart, with every flower, our meditation should be an offering out of love and devotion to Krishna.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Preparation for the Abhisheka</h3>
      <p>
        In preparation for the festival, the devotees sit around, plucking out tender petals from different kinds of flowers. There are around five types of chandramallika (chrysanthemum) flowers, three types of marigolds, dopati (impatiens balsamina) and dahlia flowers, and thousands of roses. All the flowers are brought from different parts of India. The plucking proceeds till dusk, as basket after basket gets filled to the brim with fragrant petals. Whoever it may be, young or old, there is that consciousness of humility, generosity, and devotion in them with each flower petal they pluck &mdash; with every single one of them as an offering, and a cry for help to attain the highest perfection of life.
      </p>
      
      <p>
        Srila Prabhupada once explained the festival this way: 
        <em>\"Krishna was just a toy in the hands of the Gopis, so one day the Gopis decided that we shall decorate Him. Pusya abhisheka means a ceremony to decorate the deity profusely with flowers, ornaments, cloths. After, there should be lavish feasting and a procession through the streets, so that all the citizens should see how beautiful Krishna appears.\"</em>
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/pushya-abhisheka-deities.jpg\" alt=\"Sri Sri Radha Madhava Decorated Profusely\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Deity Darshana during Pushya Abhisheka</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Grandeur of Flower Outfits</h3>
      <p>
        In the spiritual world, the Gopis decorate Krishna and Balaram with feathers, fruits, leaves, and flowers. Amongst their many gardens in Pushpavan near Kusum Sarovar, every day, just before noon, Srimati Radharani collects flowers to make beautiful garlands to offer to Krishna when He meets her at Radha Kund.
      </p>
      
      <p>
        His Grace Jananivasa Prabhu was instructed by Srila Prabhupada to celebrate festivals related to the pastimes of Sri Sri Radha Krishna in a grand way in Sri Dham Mayapur.
      </p>
      
      <p>
        Therefore, now for the abhisheka alone, the devotees make petals from over thirty thousand Chrysanthemums in different colours, fifty kilos of dopati flowers in colours ranging from white and light pinks and oranges to dark pinks, purples, and red, more than two hundred and forty marigold garlands in yellow and orange, and over forty thousand roses. That is the definition of grand!
      </p>
      
      <p>
        Devotees and pilgrims turn up in huge numbers. When the altar opens, the sight of the deities takes your breath away. Devotees stand astounded, taking darshan and singing to Their Lordships. The deities stand decorated in their all-new floral outfits, ornaments, flower garlands, Tulsi garlands, and anklets. For the skirts alone, the devotees use over five thousand flowers per skirt. Sri Madhava also graces a uniquely special flower outfit tailor-made perfectly for His Tribhanga (three-folding) form, as well as flower jewellery and flower mukut (crown) pieces for His turban.
      </p>

      <!-- Sub-image block 2 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/pushya-abhisheka-rangoli.jpg\" alt=\"Vibrant Flower Petal Rangoli\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Beautiful floral rangoli prepared for the festival</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Shower of Mercy</h3>
      <p>
        The festival reaches its climax after the Sandhya arati, when it is finally time for the abhisheka. The small Radha Madhava deities (Utsav Murtis) come forward to everyone\'s delight. Sri Sri Radha Madhava are then showered in flower petals as mantras and chanting of the Holy names go on simultaneously. A beautiful pastime unveils in front of everyone\'s eyes: the deities get fully covered in a mountain of flower petals showered from all directions. The devotees chant even louder and the kirtan goes even faster. When it finally comes to an end, Their Lordships return to the altar to be dressed in fresh clothes, and everyone goes home with the sweet remembrance of the festival.
      </p>
      
      <p>
        The day of the Sri Krishna Pushya Abhisheka is not to be missed! All the collective efforts and services of the devotees are recorded by the compassionate eyes of the deities, always ready to reciprocate with Their unconditioned mercy.
      </p>
      
      <p style=\"font-weight:600; color:var(--maroon); text-align:center; font-size:var(--font-size-lg); margin-top:var(--space-md);\">
        Sri Krishna Pushya Abhisheka Ki Jay!
      </p>', 'Scriptural Origin: Skanda Purana (2.2.42 & 2.27.99)|Significance: Celebrates the decoration of the Deity with flowers and bathing them in thousands of petals.|Key Highlights: Petal-plucking by devotees, grand flower ornaments and outfits (over 5,000 flowers per skirt), and a majestic flower petal abhisheka during ecstatic kirtan.|Deities: Sri Sri Radha Krishna (Sri Sri Radha Madhava)|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (35, 'bhishma-panchaka', 'Bhishma Panchaka', 'Bhishma', 'Five days of austerities commemorating Grandfather Bhishma.', 'Bhishma Panchaka refers to the five days during the Kartika month dedicated to special spiritual practices. Grandfather Bhishma, one of the greatest maharathis in the Mahabharata, observed these five days with great austerity. It is said that Bhishma chose to leave his body on this auspicious period.', 'These five days are considered the most sacred part of the already-auspicious Kartika month. Observing special vows during this period destroys all sins and bestows the highest spiritual benefits.', 'Sponsoring the special offerings, lamps, and prasadam during Bhishma Panchaka brings the combined blessings of the entire Kartika month. Donors receive the grace of Grandfather Bhishma and Lord Krishna.', 'festival', NULL, 'assets/images/banners/bhishma-panchaka.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 52, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:27:09', '<p>
        The last five days of the month of Kartika (Damodara month) are traditionally known as the Bhishma Panchaka or the Vishnu Panchaka. Grandfather Bhishma fasted for these five days, preparing to give up his life while lying on a bed of arrows, meditating on the universal form of Lord Sri Krishna. 
      </p>
      
      <p>
        In the Hari Bhakti-Vilasa, it is stated that if one is capable, one should observe fasting from certain foodstuffs on the Bhishma-panchaka for the pleasure of the Lord. The Padma Purana states that one pleases the Lord and makes rapid spiritual advancement by such optional austerities. Lord Krishna, highly pleased by Grandfather Bhishma\'s devotion, agreed to grant His pure love to those fortunate souls who chant, sing, hear, read, worship, and fast during these five days.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"If anyone fasts and observes the Kartika-vrata according to the rules and regulations, the Yamadutas, the messengers of Yamaraja, run away from him, just as an elephant runs away by seeing a lion.\" &mdash; Padma Purana
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Levels of Fasting (Bhishma Panchaka Vrata)</h3>
      <p>
        Depending on physical capacity, devotees can choose between three progressive types of fasting from Ekadashi to Purnima (broken at moonrise on Purnima):
      </p>
      
      <p>
        <strong>Type 1 (Strict Pancha-gavya Vrata):</strong><br>
        The devotee takes only the five products of the cow, one on each of the five days:
      </p>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Day 1 (Ekadashi):</strong> Cow dung (Gomaya)</li>
        <li><strong>Day 2 (Dvadashi):</strong> Cow urine (Go-mutra)</li>
        <li><strong>Day 3 (Trayodashi):</strong> Cow milk (Kshiira)</li>
        <li><strong>Day 4 (Chaturdashi):</strong> Cow yogurt (Dahi)</li>
        <li><strong>Day 5 (Purnima):</strong> All five cow products mixed together (Pancha-gavya)</li>
      </ul>

      <p>
        <strong>Type 2 (Ekadashi-style Fruits & Roots Vrata):</strong><br>
        If one cannot follow the first type, one can eat only fruits and roots. Fruits with many seeds (like guava, pomegranate, cucumber) should be avoided. Plain cashew nuts, raisins, and dates are allowed. Potatoes, sweet potatoes, and raw bananas can be boiled and taken with sea salt. No dairy or milk products are taken.
      </p>

      <p>
        <strong>Type 3 (Havishya Khichari Vrata):</strong><br>
        One can eat only \"Havishya\" (a sacred, unboiled form of rice and specific ingredients cooked without oil). 
        <em>Allowed ingredients:</em> Aatap rice, pure cow ghee, sea salt (Saindhava), cow milk, ripe bananas, wheat, mango, jackfruit, roots, pippali, haritakii, and sugarcane derivatives (other than gur). Mung dal, sesame oil, radishes, tamarind, and jeera must be avoided.
      </p>

      <!-- Sub-image block 1 -->
      <div style=\"margin:var(--space-xl) 0; text-align:center; overflow:hidden; border-radius:var(--radius-md); border:1px solid var(--border); box-shadow:var(--shadow-sm);\">
        <img src=\"{{BASE_URL}}assets/images/banners/bhishma-panchaka-offerings.jpg\" alt=\"Bhishma Panchaka flower offerings chart\" style=\"width:100%; height:auto; display:block;\">
        <span style=\"display:block; background:var(--light); padding:8px 12px; font-size:12px; color:var(--text-light); border-top:1px solid var(--border);\">Special flower offerings to the Lord\'s body parts</span>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Daily Flower Offerings (Garuda Purana)</h3>
      <p>
        During the five days, devotees offer specific leaves, scents, and flowers to different parts of the Lord\'s deity form:
      </p>
      <ul style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Day 1 (Feet):</strong> Offer Padma (lotus) flowers to the lotus feet of the Lord.</li>
        <li><strong>Day 2 (Thighs):</strong> Offer Bilva (wood-apple) leaves to the thighs of the Lord.</li>
        <li><strong>Day 3 (Navel):</strong> Offer Gandha (scents/sandalwood paste) to the navel of the Lord.</li>
        <li><strong>Day 4 (Shoulders):</strong> Offer Java (hibiscus) flowers to the shoulders of the Lord.</li>
        <li><strong>Day 5 (Head):</strong> Offer Malati (jasmine) flowers to the head of the Lord.</li>
      </ul>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Daily Bhishma Tarpana & Prayers</h3>
      <p>
        It is highly recommended to take a bath in the Ganges (or other holy rivers) early in the morning and offer water tarpana three times for Grandfather Bhishma with the following mantras:
      </p>
      
      <p>
        <strong>1. Tarpana (Water offering):</strong><br>
        <span style=\"font-family:monospace; display:block; background:var(--light); padding:var(--space-sm); border-radius:var(--radius-sm);\">
          om vaiyaghra padya gotraya samkrti pravaraya ca<br>
          aputraya dadamyetat salilam bhismavarmane
        </span>
      </p>
      
      <p>
        <strong>2. Arghya (Auspicious offering):</strong><br>
        <span style=\"font-family:monospace; display:block; background:var(--light); padding:var(--space-sm); border-radius:var(--radius-sm);\">
          vasunamavataraya santanoratmajaya ca<br>
          arghyam dadami bhismaya ajanma brahmacarine
        </span>
      </p>
      
      <p>
        <strong>3. Pranam (Obeisances):</strong><br>
        <span style=\"font-family:monospace; display:block; background:var(--light); padding:var(--space-sm); border-radius:var(--radius-sm);\">
          om bhismah santanavo birah satyavadi jitendriyah<br>
          abhiradbhiravapnatu putrapautrocitam kriyam
        </span>
      </p>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (36, 'sri-sri-radha-ramana', 'Sri Sri Radha-Ramana Appearance', 'Radha-Ramana', 'The self-manifestation of Sri Radha-Ramana deity.', 'Sri Sri Radha-Ramana is one of the seven main deities of Vrindavan, self-manifested through the devotional service of Srila Gopala Bhatta Goswami. The deity appeared from a Shalagram shila and has been worshipped in Vrindavan for over 500 years. This festival celebrates the appearance of this famous deity.', 'The Radha-Ramana temple is one of the most significant Gaudiya Vaishnava temples in Vrindavan. The deity\'s self-manifestation demonstrates the Lord\'s reciprocation with the sincere service of His devotees.', 'Sponsoring this festival connects you with the rich heritage of Vrindavan\'s worship. Donors receive the blessings of the Radha-Ramana deity and Srila Gopala Bhatta Goswami.', 'festival', NULL, 'assets/images/banners/sri-sri-radha-ramana-appearance-banner.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 53, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-06-30 18:21:19', '<h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl);\">Srila Gopal Bhatta Goswami & Lord Caitanya</h3>
      <p>
        The all-merciful Lord Sri Gaura Hari, as He traveled from village to village throughout the south of India, continued to distribute love of Godhead wherever He went. In 1511 A.D., Sri Gaurasundar came to the ancient holy place of Sri Rangam on an island in the middle of the Kaveri river.
      </p>
      <p>
        Sri Vyenkata Bhatta, a priest of the temple, invited Mahaprabhu to stay at his house during the four months of the rainy season (Chaturmasya). Vyenkata Bhatta had a son named Gopal, who was then just a child. When the boy came to offer his obeisances, Mahaprabhu picked him up and affectionately seated him in His lap. He would call Gopal after He had finished His meals and offer His remnants to the boy, preparing him for the position of Acarya.
      </p>
      <p>
        Being pleased with Gopala Bhatta Gosvamis sincere service, Sri Caitanya Mahaprabhu initiated him and ordered him to move to Vrindavana after the disappearance of his parents, to perform bhajan, and write.
      </p>

      <blockquote style=\"border-left:4px solid var(--primary); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Sri Sri Radha-ramanaji is the only one of the original Deities of Vrindavana who never left Vrindavana to go to Jaipur.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Arrival in Vrindavan and Shaligrama Shilas</h3>
      <p>
        At the age of thirty, Gopala Bhatta Gosvami arrived in Vrindavana. Rupa and Sanatana Gosvamis treated him with the same care and affection they would their own brother, immediately becoming life-long companions. 
      </p>
      <p>
        Sri Caitanya Mahaprabhu, hearing of Gopal Bhatta\'s arrival, sent him His personal wooden sitting plank (piri) along with His undergarments and an upper cloth (chaddar). Gopal Bhatta sat on this wooden plank during worship, and it is still worshiped today at the Radha-Ramana Mandir.
      </p>
      <p>
        After Mahaprabhu\'s disappearance, Gopala Bhatta Gosvami felt intense separation. The Lord instructed him in a dream: <em>\"If you want my darshan, make a trip to Nepal.\"</em> In Nepal, he bathed in the Kali-Gandaki River, where twelve Shaligrama Shilas entered his water pot. Gopal Bhatta brought these shilas back to Vrindavana and worshiped them daily.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Self-Manifestation of Radha-Ramana Devji</h3>
      <p>
        One day, a wealthy merchant came to Vrindavana and offered Gopala Bhatta valuable clothing and ornaments for his Shaligrams. Because Shaligrams are round, Gopal Bhatta could not use these decorations. He placed the ornaments before the shilas and prayed in transcendental lamentation:
      </p>
      <p style=\"font-style:italic; background:var(--light); padding:var(--space-md); border-radius:var(--radius-sm); color:var(--text-dark); border-left:3px solid var(--maroon);\">
        \"Oh my Lord, you are very merciful and always fulfill the desires of your devotees. I wish to serve you in your form, having arms and legs and a blissful smiling face, with lotus eyes. If I had a Deity then I would be able to decorate Him so nicely with these clothes and ornaments.\"
      </p>
      <p>
        The next morning, after bathing in the Yamuna, Gopala Bhatta returned to render worship. When he uncovered the shilas under the wicker basket, he was astounded. Amongst the shilas was a Deity of Krishna playing the flute. The Damodara shila had manifested as the beautiful three-fold bending form of <strong>tri-bhangananda-krishna</strong>. 
      </p>
      <p>
        Gazing on the Lord\'s form, Rupa, Sanatana, and other devotees were filled with ecstasy. They named the Deity <strong>Sri Radha-raman Deva</strong>. This miracle happened on the day after Narasimha Caturdasi, on the full moon day of Vaisakha in 1542 A.D.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Deity Features and Standard of Worship</h3>
      <p>
        Sri Sri Radha-raman-ji is still being worshiped in Vrindavana near Nidhiban kunj in the temple compound. The Deity has extremely intricate features, including fingernails and teeth. On the back of His body, parts of the original Shalagram shila from which He manifested can still be seen.
      </p>
      <p>
        The Deity is called Radha-raman (\"one who brings pleasure to Srimati Radharani\") although physically there is no Deity of Radha on the altar. To Ramanji\'s left is a gold place setting representing Srimati Radhika. In this way, the pujaris worship Sri Radha and Ramanji together.
      </p>
      <p>
        The descendants of Gopala Bhatta\'s brother, Damodara dasa (the Radha-Raman Gosais), maintain and serve the Deity to this day with the highest standard of Deity worship in Vraja.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Gopala Bhatta\'s Legacy & Literature</h3>
      <p>
        Gopala Bhatta was the initiating guru of Srinivasa Acarya Prabhu. He was very learned, trained in Pancharatra, and wrote many books including <em>Sat-sandarbha karika</em>, <em>Sri Krsna-vallabha</em>, and <em>Sat kriya sara dipika</em> (Vaishnava samskara viddhi). From his initial compile, Srila Sanatana Gosvami published the famous Vaishnava smriti titled <em>Hari Bhakti Vilas</em>.
      </p>
      <p>
        Out of great humility, Gopala Bhatta Gosvami requested Srila Krsnadasa Kaviraja not to mention his name in the classic work <em>Sri Caitanya Charitamrita</em>. In nitya-vraja lila, he serves as Guna Manjari.
      </p>', 'Manifestation Date: Full Moon Day of Vaisakha in the year 1542 A.D. (Vrindavan)|Worshiper: Srila Gopala Bhatta Gosvami (Guna Manjari in nitya-vraja lila)|Deity Identity: Self-manifested from a Damodara Shaligrama Shila (Nepal)|Standard of Worship: Renowned for the highest standard of Deity worship in Vraja-mandala.|Observance: Celebrated on the day after Narasimha Caturdasi. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (37, 'srila-prabhupada-appearance', 'Srila Prabhupada Appearance Day', 'Srila Prabhupada', 'The appearance day of His Divine Grace A.C. Bhaktivedanta Swami Prabhupada, founder-acharya of ISKCON.', 'Srila Prabhupada appeared in Calcutta on September 1, 1896. He met his spiritual master, Srila Bhaktisiddhanta Sarasvati Thakura, in 1922 and received the order to spread Krishna consciousness in the English-speaking world. At the age of 69, he sailed to America with only seven dollars and a trunk of books, establishing the International Society for Krishna Consciousness in 1966.', 'Srila Prabhupada is the foremost exponent of Krishna consciousness in the modern age. He translated and commented on over 70 volumes of Vedic literature and established 108 temples worldwide. His appearance day is celebrated as a major festival across all ISKCON centers.', 'Celebrating Srila Prabhupada\'s appearance day invokes his special blessings for advancing in Krishna consciousness. Sponsoring the celebration helps continue his mission of spreading the holy name worldwide.', 'appearance', NULL, 'assets/images/banners/srila-prabhupada-appearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 60, 1, 0, 'appearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        As per the Hindu lunar calendar, His Divine Grace, A.C. Bhaktivedanta Swami Prabhupada (1896-1977) was born on the day of Nandotsava (the next day of Krishna Janmashtami). He was born Abhay Charan De on September 1st, 1896 in Calcutta, India. His father was Gour Mohan De, a cloth merchant, and his mother was Rajani.
      </p>
      
      <p>
        His parents, in accordance with Bengali tradition, employed an astrologer to calculate the child\'s horoscope, and they were made jubilant by the auspicious reading. The astrologer made a specific prediction:
      </p>

      <blockquote style=\"border-left:4px solid var(--accent); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"When this child reaches the age of seventy, he would cross the ocean, become a great exponent of religion, and open 108 temples.\"
      </blockquote>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/srila-prabhupada-appearance-childhood.jpg\" alt=\"Abhay Charan De (Childhood Portrait)\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border); max-height:400px; object-fit:contain;\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">Young Abhay Charan De (Srila Prabhupada) in Calcutta</p>
      </div>

      <p>
        Srila Prabhupada Appearance Day, also known as <strong>Vyasa-Puja</strong>, is a significant observance in ISKCON Seshadripuram and among followers of the Bhakti tradition. It marks the anniversary of the birth of A.C. Bhaktivedanta Swami Prabhupada, the founder-acharya of ISKCON, and a prominent spiritual leader and teacher in the Bhakti lineage.
      </p>
      
      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Observances on Srila Prabhupada Appearance Day</h3>
      <p>
        On this auspicious day, devotees and followers dedicate themselves to gratitude and remembrance:
      </p>
      
      <ul style=\"display:flex; flex-direction:column; gap:12px; padding-left:var(--space-lg);\">
        <li>
          <strong>Devotees Gather:</strong> Devotees and followers of Srila Prabhupada gather in ISKCON Seshadripuram to commemorate his birth anniversary and read their written Vyasa-Puja offerings expressing deep gratitude.
        </li>
        <li>
          <strong>Special Services & Abhishek:</strong> ISKCON Seshadripuram holds a grand abhishek ceremony of Srila Prabhupada\'s deity form, accompanied by ecstatic kirtans and discourses dedicated to his glorious life and teachings.
        </li>
        <li>
          <strong>Offering Homage:</strong> Devotees offer arati, incense, and floral decorations (pushpanjali) to Srila Prabhupada. 
        </li>
        <li>
          <strong>Lectures and Readings:</strong> Readings from Srila Prabhupada\'s books (such as <em>Bhagavad-gita As It Is</em> and <em>Srimad-Bhagavatam</em>) and biographies are read to reflect on his foundational guidelines.
        </li>
        <li>
          <strong>Grand Feast (Prasadam):</strong> Devotees prepare and share a sumptuous vegetarian feast (prasadam) offered to Lord Krishna, fostering community, warmth, and spiritual association.
        </li>
        <li>
          <strong>Service and Reflection:</strong> Devotees reflect on their spiritual journeys and renew their dedication to the principles of Bhakti yoga and spreading the message of Lord Chaitanya.
        </li>
      </ul>

      <p style=\"margin-top:var(--space-md);\">
        Srila Prabhupada Appearance Day serves as an opportunity for devotees to express their gratitude and reverence for the profound impact Srila Prabhupada had on their lives and on the propagation of Bhakti philosophy worldwide. It is a day of celebration, reflection, and recommitment to the principles of devotion to Lord Krishna as taught by Srila Prabhupada.
      </p>', 'Birth Date: September 1, 1896 (Calcutta, India)|Birth Name: Abhay Charan De|Parents: Gour Mohan De & Rajani Devi|Observance Date: Nandotsava (the day after Sri Krishna Janmashtami)|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (38, 'srila-bhaktivinoda-thakura-appearance', 'Srila Bhaktivinoda Thakura Appearance', 'Bhaktivinoda Thakura', 'The appearance day of Srila Bhaktivinoda Thakura, the pioneer of the Gaudiya Vaishnava revival in the 19th century.', 'Srila Bhaktivinoda Thakura (1838-1914) was a great scholar, magistrate, and the pioneer of the Gaudiya Vaishnava revival in the 19th century. He rediscovered the birthplace of Sri Chaitanya Mahaprabhu in Mayapur, wrote extensively on Vaishnava philosophy, and predicted the coming of a \"broad-minded preacher\" who would spread Krishna consciousness worldwide — Srila Prabhupada.', 'Bhaktivinoda Thakura revived the teachings of Lord Chaitanya and the Six Goswamis at a time when they were almost lost. His books and compositions continue to inspire millions.', 'Sponsoring his appearance day celebrations invokes the blessings of a great acharya who dedicated his life to spreading the glories of the holy name.', 'appearance', NULL, 'assets/images/banners/srila-bhaktivinoda-thakura-appearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 61, 1, 0, 'appearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        Sri Sacidananda Bhaktivinoda Thakura appeared in 1838 in a wealthy family in the Nadia district, West Bengal. He revealed that he is an eternal associate of Sri Caitanya Mahaprabhu by his extraordinary preaching activities and prolific writing. Living as a <em>mahabhagavata</em> Vaisnava, he stayed in the <em>grhastha</em> (householder) ashram until the last few years of his life. Then he renounced everything, accepted babaji, and entered samadhi, totally absorbed in the loving service of Gaura-Gadadhara and Radha-Madhava.
      </p>
      
      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Superhuman Daily Schedule</h3>
      <p>
        His Divine Grace A.C. Bhaktivedanta Swami Prabhupada praised his diligence and schedule:
      </p>
      <blockquote style=\"border-left:4px solid var(--primary); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"He had a responsible government position as the District Magistrate (high court judge), maintained a Krishna conscious family, and wrote almost one hundred books on Krishna consciousness. At the same time, he served the Supreme Lord in so many ways. That is the beauty of his life. After a full day of government service he would sleep four hours, get up at midnight and write until morning. That was his daily program.\"
      </blockquote>

      <!-- Schedule Table -->
      <div style=\"margin:var(--space-md) 0; overflow-x:auto;\">
        <table style=\"width:100%; border-collapse:collapse; background:var(--light); border-radius:var(--radius-md); overflow:hidden;\">
          <thead>
            <tr style=\"background:var(--primary); color:var(--white); text-align:left;\">
              <th style=\"padding:var(--space-md); font-family:var(--font-heading);\">Activity</th>
              <th style=\"padding:var(--space-md); font-family:var(--font-heading);\">Duration</th>
            </tr>
          </thead>
          <tbody>
            <tr style=\"border-bottom:1px solid var(--border);\">
              <td style=\"padding:var(--space-md); font-weight:600;\">Sleep</td>
              <td style=\"padding:var(--space-md);\">3 hours</td>
            </tr>
            <tr style=\"border-bottom:1px solid var(--border);\">
              <td style=\"padding:var(--space-md); font-weight:600;\">Writing Devotional Works</td>
              <td style=\"padding:var(--space-md);\">8.5 hours</td>
            </tr>
            <tr style=\"border-bottom:1px solid var(--border);\">
              <td style=\"padding:var(--space-md); font-weight:600;\">Japa and Study</td>
              <td style=\"padding:var(--space-md);\">4.5 hours</td>
            </tr>
            <tr>
              <td style=\"padding:var(--space-md); font-weight:600;\">Government Service (Magistrate)</td>
              <td style=\"padding:var(--space-md);\">6 hours</td>
            </tr>
          </tbody>
        </table>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Humility & Saranagati Teachings</h3>
      <p>
        Thakura Bhaktivinoda took Vaisnava diksa from Sri Vipinvihari Goswami in the line of Sri Jahnava Mata. Afterwards, he received spiritual inspiration and direction from Srila Jagannatha Dasa Babaji.
      </p>
      <p>
        Holding an exalted government post, vast erudition, and spiritual accomplishment never disturbed Bhaktivinoda Thakura. He remained prideless, always humble, friendly to all. Charity seekers at his home always left happy and satisfied. A well-wisher to everyone, he never kept grudges, even with opponents to his preaching. In fact, he never spoke a word that would hurt another\'s feelings.
      </p>
      <p>
        In the following entry from his book <em>Saranagati</em>, Srila Bhaktivinoda, who possessed all pure divine qualities, takes the role of a conditioned soul to teach us how to advance in Krishna consciousness:
      </p>
      
      <p style=\"font-style:italic; background:var(--light); padding:var(--space-md); border-radius:var(--radius-sm); color:var(--text-dark); border-left:3px solid var(--maroon);\">
        \"You should always absorb your mind in attentively chanting Krishna\'s glories. By performing Krishna kirtana you\'ll gain mastery over the mind. Give up all false pride. Always think yourself to be worthless, destitute, lower and more humble than straw in the street. Practice forgiveness like the tree. Giving up all violence toward other living beings, you should maintain them. Throughout your life you should never give anxiety to others. But do good to them, make them happy, and forget about your own happiness.
        <br><br>
        \"Thus when you become a pious good soul by possessing all good qualities, you should give up desires for fame and honor. And just make your heart humble. Knowing that Lord Sri Krishna lives within all living beings, you should respect and honor everyone at all times. You will attain virtue by being humble, merciful, respecting others, and renouncing desires for fame and honor. In such a state, you should sing the glories of the Supreme Lord.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The \"Seventh Gosvami\" & Devotion to Sri Radhika</h3>
      <p>
        Srinivasa Acarya praises the six Gosvamis of Vrindavana: <em>nana-sastra-vicaranaika-nipunau sad-dharma samsthakapau, lokanam hita karinau</em> (\"The six Gosvamis deeply studied all the sastras in order to establish eternal religious principles for the benefit of everyone\"). Similarly, Thakura Bhaktivinoda made unlimited preaching contributions to help humanity, and for this, he is recognized as the \"Seventh Gosvami.\"
      </p>
      
      <p>
        Besides books in Bengali, Oriya, and English reviving and explaining Mahaprabhu\'s message, he wrote hundreds of poems and songs full of spiritual sentiments and sastric siddhanta. The following quote comes from Thakura Bhaktivinoda\'s <em>Gitavali</em>, highlighting the absolute necessity of taking shelter of Srimati Radharani:
      </p>

      <div style=\"background:var(--light); padding:var(--space-xl); border-radius:var(--radius-md); border-top:3px solid var(--accent); border-bottom:3px solid var(--accent); text-align:center; margin:var(--space-xl) 0;\">
        <p style=\"font-family:var(--font-subheading); font-size:var(--font-size-base); color:var(--dark); line-height:1.6; font-style:italic;\">
          \"He who has failed to carefully worship the lotus feet of Sri Radhika, which are the abodes of all auspiciousness. He who has not taken shelter in the transcendental abode of Vrindavana, which is decorated with the lotus flower named Radha. He who in this life has not associated with the devotees of Radhika, who are full of wisdom and love for Radhika. How will such a person ever feel the bliss of bathing in the ocean of Lord Syamasundara\'s sublime mellows?<br><br>
          Without taking shelter of Radha\'s lotus feet one can never meet Krishna. The Vedic scriptures declare that Krishna is the property of the maidservants of Sri Radha. Give up wife, sons, friends, wealth, followers, speculative knowledge, all materialistic actions. Just become absorbed in the sweetness of serving the lotus feet of Srimati Radharani.\"
        </p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Discovery of Yogapitha & Three Predictions</h3>
      <p>
        During the last five-hundred years, the original appearance place of Lord Caitanya had vanished under the shifting course of the Ganges River. In 1888, Srila Bhaktivinoda Thakura revealed Sri Caitanya Mahaprabhu\'s janmasthana at the Yogapitha in Sridhama Mayapur. This discovery was joyfully confirmed by Srila Jagannatha Dasa Babaji Maharaja. He established the worship of Lord Gauranga and Srimati Vishnupriya at Yogapitha.
      </p>
      
      <p>
        In the mood of innovation, in 1896 he sent to universities around the world a book of slokas, <em>Sri Gauranga-lila smarana</em>, which had a forty-seven page English introduction: \"Sri Caitanya Mahaprabhu: His Life and Precepts,\" rising from a keen desire to spread Lord Caitanya\'s teachings in the Western countries.
      </p>
      
      <p>
        Bhaktivinoda Thakura made three famous predictions:
      </p>
      <ol style=\"display:flex; flex-direction:column; gap:10px; padding-left:var(--space-lg); font-weight:500;\">
        <li>\"A personality will soon appear and he will travel all over the world to spread the teachings of Lord Caitanya.\"</li>
        <li>\"Very soon the chanting of Harinama sankirtana will be spread all over the world. Oh, when will that day come when people from America, England, France, Germany, Russia will take up karatals and mrdangas and chant Hare Krishna in their towns?\"</li>
        <li>\"When will that day come when the fair-skinned foreigners will come to Sri Mayapur-dhama and join with the Bengali Vaisnavas to chant, Jaya Sacinandana, Jaya Sacinandana. When will that day be?\"</li>
      </ol>
      
      <p style=\"margin-top:var(--space-md);\">
        Srila Prabhupada said it is spiritually significant that he himself appeared in 1896, the same year Bhaktivinoda Thakura sent his book overseas. The will of Lord Caitanya, the desire of Thakura Bhaktivinoda, and the mercy of Srila Sarasvati Thakura empowered Srila A.C. Bhaktivedanta Swami Prabhupada to spread Sri Caitanya\'s teachings and the chanting of Hare Krishna all over the world, fulfilling all three of the Thakura\'s predictions.
      </p>', 'Birth Date: September 2, 1838 (Bir Nagar, Nadia district, West Bengal)|Spiritual Identity: Kamala-manjari (in nitya-vraja lila)|Diksa Guru: Sri Vipinvihari Goswami (in the line of Sri Jahnava Mata)|Spiritual Inspiration: Srila Jagannatha dasa Babaji Maharaja|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (39, 'srila-bhaktisiddhanta-sarasvati-appearance', 'Srila Bhaktisiddhanta Sarasvati Appearance', 'Sarasvati Thakura', 'The appearance day of Srila Bhaktisiddhanta Sarasvati Thakura, the spiritual master of Srila Prabhupada.', 'Srila Bhaktisiddhanta Sarasvati Thakura (1874-1937) was the son of Srila Bhaktivinoda Thakura and the spiritual master of Srila Prabhupada. He established 64 Gaudiya Mathas worldwide and vigorously preached against sahajiyaism and impersonalism. His powerful preaching and establishment of the Gaudiya Matha set the stage for ISKCON.', 'He was a powerful preacher who fearlessly established the supremacy of Krishna consciousness. His emphasis on combining book distribution with preaching became the model for ISKCON\'s missionary work.', 'Celebrating his appearance day brings the blessings of a pure Vaishnava who dedicated his life to establishing the true teachings of Lord Chaitanya.', 'appearance', NULL, 'assets/images/banners/srila-bhaktisiddhanta-sarasvati-thakura-appearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 62, 1, 0, 'appearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        His Divine Grace Bhaktisiddhanta Sarasvati Thakur Goswami Prabhupada (reverently known as the <strong>Lion Guru</strong>) appeared in Sri Ksetra Dhama (Jagannatha Puri) on 6 February 1874 as the son of Srila Sacidananda Bhaktivinoda Thakura. In his childhood, he quickly mastered the Vedas, memorized the Bhagavad-gita, and relished his father\'s philosophical works. He became known as \"The Living Encyclopedia\" for his vast, peerless knowledge. He was born as Bimala Prasad, which means the mercy of the internal potency (Bimala Devi) of Lord Jagannatha.
      </p>
      
      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">A Dynamic Preacher and Erudite Scholar</h3>
      <p>
        Bhaktisiddhanta Sarasvati Thakur was a very dynamic, uncompromising preacher who adjusted his outreach according to the audience. When he had to mix with kings, landlords, and British dignitaries, he wore a long coat and rode in carriages, and when he had to mix with the Babajis in Radha-kunda, he went barefoot and wore the simple clothing of a sannyasi.
      </p>
      <p>
        His English was pristine and highly structured, displaying his immense scholarship. He established 64 branches of the Gaudiya Math throughout India, introducing modern printing presses (which he referred to as the <em>brhad-mrdanga</em>, or \"greater drum\") to mass-distribute transcendental literatures.
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"What kind of Bhakta is this who simply wants to chant and does not want to deliver the fallen souls?\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Instructions to Srila Prabhupada and Global Prophecies</h3>
      <p>
        At their very first meeting in 1922, Srila Bhaktisiddhanta Sarasvati Thakura instructed A.C. Bhaktivedanta Swami Prabhupada (who was then a young householder) to preach the message of Lord Chaitanya in the Western world in the English language. He declared that it would bring immense spiritual benefit to him and to all who assisted him.
      </p>
      <p>
        A few years before his departure, Bhaktisiddhanta Sarasvati Thakur made a prophetic announcement: 
      </p>
      <p style=\"font-style:italic; background:var(--light); padding:var(--space-md); border-radius:var(--radius-sm); color:var(--text-dark); border-left:3px solid var(--accent);\">
        \"One of my disciples will go to the Western world and preach. People from the Western world will come and participate in the Navadvipa Parikrama. There will be chanting together of \'Jaya Sachinandana, Jaya Sachinandana\', and they will embrace their Indian brothers, with no prejudice regarding caste, color, or creed.\"
      </p>
      <p>
        This prediction was fulfilled in letter and spirit by His Divine Grace A.C. Bhaktivedanta Swami Prabhupada through the establishment of ISKCON, bringing thousands of Western devotees to Navadvipa Dhama.
      </p>', 'Appearance Date: February 6, 1874 (Sri Ksetra Dhama / Jagannatha Puri)|Birth Name: Bimala Prasad (meaning \"Jagannath Prasad\")|Parents: Srila Saccidananda Bhaktivinoda Thakura & Sriyukta Bhagavati Devi|Key Contribution: Founded 64 Gaudiya Math branches, pioneered printing and outreach, and instructed Srila Prabhupada to preach in the English language.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (40, 'sri-advaita-acharya-appearance', 'Sri Advaita Acharya Appearance', 'Advaita Acharya', 'The appearance day of Sri Advaita Acharya, the incarnation of Mahavishnu who brought about Lord Chaitanya\'s descent.', 'Sri Advaita Acharya was a great devotee and incarnation of Mahavishnu who lived in Shantipur, West Bengal. He was instrumental in bringing about the descent of Sri Chaitanya Mahaprabhu. When he saw the suffering condition of the fallen souls of Kali-yuga, he fervently worshipped Lord Krishna with Tulasi leaves and water, crying out for His appearance.', 'Advaita Acharya\'s intense prayers were the immediate cause of Lord Chaitanya\'s descent. He is considered the combined incarnation of Mahavishnu and Lord Brahma, and his role in the Gaudiya Vaishnava tradition is unparalleled.', 'Sponsoring Advaita Acharya\'s appearance day invokes the blessings of the great devotee whose prayers brought Lord Chaitanya to this world. Donors receive his mercy for developing intense devotion.', 'appearance', NULL, 'assets/images/banners/sri-advaita-acharya-appearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 63, 1, 0, 'appearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        Lord Advaita Ācārya is the incarnation of Mahā-Viṣṇu, whose main function is to create the cosmic world through the actions of <em>māyā</em>. He appeared in the village of Navagrama near the city of Sylhet as the son of the Varendra Brahmin Kubera Pandit and his wife Nabha Devi, on the seventh day of the waxing moon in the month of Magh (January–February). 
      </p>
      
      <p>
        Advaita Acharya also maintained a home in Nabadwip. His full name was Sri Kamalaksha (or Kamala Kanta Vedapanchanana). His birth took place in 1434 A.D., and he disappeared in the year 1559, at the exalted age of 125 years.
      </p>

      <!-- Pranama Verse Box -->
      <div style=\"background:var(--light); padding:var(--space-xl); border-radius:var(--radius-sm); border-left:4px solid var(--primary); text-align:center; margin:var(--space-md) 0;\">
        <p style=\"font-family:var(--font-subheading); font-size:var(--font-size-base); font-weight:600; color:var(--primary-dark); line-height:1.6; margin-bottom:12px;\">
          maha-vishnur jagat-karta mayaya yah srijaty adah<br>
          tasyavatara evayam advaitacarya ishvarah<br><br>
          advaitam harinadvaitad acaryam bhakti-shasanat<br>
          bhaktavataram isham tam advaitacaryam ashraye
        </p>
        <p style=\"font-size:var(--font-size-sm); color:var(--text-dark); line-height:1.5; font-style:italic; margin:0;\">
          \"Because He is nondifferent from Hari, the Supreme Lord, He is called Advaita, and because He propagates the cult of devotion, He is called Acarya. He is the Lord and the incarnation of the Lord\'s devotee. Therefore I take shelter of Him.\"<br>
          <span style=\"font-size:11px; color:var(--text-light); font-weight:600; font-style:normal; display:block; margin-top:6px;\">— Śrī Caitanya-caritāmṛta Ādi-līlā 1.12-13</span>
        </p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Calling Down the Supreme Lord</h3>
      <p>
        It is written that Lord Caitanya Mahaprabhu is the main trunk of the wish-fulfilling tree of devotion. Sri Advaita Acharya and Sri Nityananda Prabhu were the two secondary trunks into which the main trunk divided.
      </p>
      <p>
        When Advaita Acharya appeared along with the other elderly members of Lord Chaitanya\'s retinue, he observed that the sinfulness of the age of Kali had reached a disturbing limit. The world was entirely devoid of devotion to Krishna, with people absorbed in materialistic rituals. He realized that a partial incarnation of the Lord would not be sufficient to bring about the welfare of the earth in such a fallen state. 
      </p>
      <p>
        He determined that only the Supreme Personality of Godhead Himself could deliver the fallen souls. Therefore, he began to worship Krishna\'s lotus feet with Ganges water and Tulasi leaves, shouting and pleading to the Lord to manifest. With roars of love (<em>prema-hunkara</em>), Advaita Acharya showed his intense desire for the Lord of Goloka to descend to the earth.
      </p>

      <blockquote style=\"border-left:4px solid var(--accent); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"He constantly offered water from the Ganges and tulasi manjaris while meditating on Krishna\'s lotus feet, calling to Him with loud roars. This is how he caused Lord Caitanya to descend.\"
      </blockquote>
      
      <p>
        This worship and loud calling was the chief cause for the descent of Sri Krishna Chaitanya Mahaprabhu. Out of affection for His devotee, the Supreme Lord descended to inaugurate the Sankirtana movement and deliver all living entities.
      </p>', 'Appearance Date: Seventh day of the waxing moon in the month of Magh (1434 A.D.)|Appearance Location: Navagrama (near Sylhet, Bangladesh)|Disappearance: 1559 A.D. (Age 125 years)|Parents: Kubera Pandit & Nabha Devi|Divine Identity: Incarnation of Maha-Vishnu and Sadashiva|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (41, 'srila-prabhupada-disappearance', 'Srila Prabhupada Disappearance Day', 'Srila Prabhupada', 'The disappearance day of His Divine Grace A.C. Bhaktivedanta Swami Prabhupada, who left this world in Vrindavan.', 'Srila Prabhupada left this world on November 14, 1977, in Vrindavan, surrounded by his loving disciples. He had established ISKCON in just 11 years, spreading Krishna consciousness to every continent. His passing was a transcendental event, with devotees around the world remembering his extraordinary contributions.', 'The disappearance of a great Vaishnava is not a cause for mourning but for reflection on his teachings and legacy. Srila Prabhupada continues to guide millions through his books, which are his eternal presence.', 'Observing Srila Prabhupada\'s disappearance day reminds us to follow his instructions. Sponsoring the celebrations helps preserve his legacy and brings his blessings for advancing in devotional service.', 'disappearance', NULL, 'assets/images/banners/srila-prabhupada-disappearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 70, 1, 0, 'disappearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        His Divine Grace <strong>A.C. Bhaktivedanta Swami Prabhupada</strong> departed from this world on <strong>November 14, 1977</strong>, in Vrindavan, India, in his rooms at the Krishna-Balarama temple, surrounded by hundreds of his disciples chanting Hare Krishna. Up until moments before his passing, he was dictating commentaries on the tenth canto of the Srimad-Bhagavatam.
      </p>
      
      <p>
        Today the entire world is inundated by the chanting of the holy names of the Lord, being sung by people from all walks of life who have transformed into Vaishnavas by taking to the process of Krishna consciousness. The prophecy of Sri Caitanya Mahaprabhu has indeed come true, as today in every town and village the Mahamantra can be heard purifying all living entities.
      </p>
      
      <p>
        This massive transformation of a great portion of society from a majorly materialistic and atheistic mentality to one in which the practitioner of the spiritual path is encouraged to realize their eternal relation with God in loving service, was brought about in this age by His Divine Grace A.C. Bhaktivedanta Swami Prabhupada. It is nothing less than a true miracle that Srila Prabhupada performed by transforming numerous materialists into faithful followers of the Gaudiya Vaishnava sampradaya and imbibing them with a desire to attain the ultimate goal of life, to go back home, back to Godhead.
      </p>

      <!-- Video Embed Section -->
      <div style=\"margin:var(--space-lg) 0; border-radius:var(--radius-lg); overflow:hidden; box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <div style=\"position:relative; padding-bottom:56.25%; height:0; overflow:hidden; max-width:100%;\">
          <iframe style=\"position:absolute; top:0; left:0; width:100%; height:100%; border:none;\" src=\"https://www.youtube.com/embed/mg27W68tII0\" title=\"Srila Prabhupada Tribute Video\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>
        </div>
        <p style=\"font-size:12px; color:var(--text-light); text-align:center; padding:10px; margin:0; background:var(--light); font-style:italic;\">
          Watch: Tribute to His Divine Grace A.C. Bhaktivedanta Swami Prabhupada
        </p>
      </div>

      <p>
        The departure of such a great personality, the savior of the entire world, Srila Prabhupada, from amidst the fallen conditioned souls is greatly mourned. As it is mentioned in the bhajans written by our previous acharyas, the mere darshan (audience) of a great Vaishnava purifies one of all sins.
      </p>

      <!-- Bengali verse with translation -->
      <div style=\"background:var(--light); padding:var(--space-md); border-radius:var(--radius-sm); border-left:3px solid var(--maroon); margin:var(--space-sm) 0;\">
        <p style=\"font-weight:600; color:var(--maroon); margin-bottom:4px; font-size:var(--font-size-base);\">
          gańgāra paraśa hoile paścate pāvan<br>
          darśane pavitra koro-ei tomāra guṇ
        </p>
        <p style=\"margin:0; font-size:var(--font-size-sm); color:var(--text); font-style:italic;\">
          \"After bathing in the waters of the sacred Ganges many times, one becomes purified, but just by the sight of you, the fallen souls are purified. This is your great power.\"
        </p>
      </div>

      <p>
        Hearing transcendental spiritual discourses from the lotus mouth of such exalted Nitya-siddha associates of Sri Krishna sows within the hearts of one and all the seed of Bhakti. Although the instructions (vani) of the guru are given higher importance than the physical presence (vapu), yet the impact of the constant association of the guru is of unquestionable importance, for the presence of the pure devotee makes the jivas feel the presence of Krishna Himself, as the guru is the representative of Krishna.
      </p>

      <div style=\"background:var(--light); padding:var(--space-md); border-radius:var(--radius-sm); border-left:3px solid var(--accent); margin:var(--space-sm) 0;\">
        <p style=\"font-weight:600; color:var(--primary-dark); margin-bottom:4px; font-size:var(--font-size-base);\">
          hariḥ sadā vaset tatra<br>
          yatra bhāgavatā janāḥ<br>
          gāyanti bhakti-bhāvena<br>
          harer nāmaiva kevalam
        </p>
        <p style=\"margin:0; font-size:var(--font-size-sm); color:var(--text); font-style:italic;\">
          \"Lord Hari eternally dwells in that place where truly exalted, spiritually advanced souls sing in the mood of pure devotion. The holy name of Sri Hari alone is everything.\"
        </p>
      </div>

      <p>
        It was on this day in the month of Kartik that all the devotees were plunged in an ocean of distress when Srila Prabhupada departed from this world and entered nitya lila at 7:20 in the evening. This day of Srila Prabhupada\'s disappearance is celebrated in ISKCON Vrindavan surcharged with prayers in separation, as it is in Sridham Vrindavan that Srila Prabhupada left this world in his quarters amidst kirtan and surrounded by his disciples.
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/srila-prabhupada-disappearance-content.jpg\" alt=\"A. C. Bhaktivedanta Swami Prabhupada\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">His Divine Grace A. C. Bhaktivedanta Swami Prabhupada</p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Observance of the Disappearance Day</h3>
      <p>
        As every year, this year also Srila Prabhupada\'s disappearance day is observed with constant glorification and remembrance of the divine pastimes and extraordinarily amazing feat of his spreading Krishna consciousness throughout the world.
      </p>
      <p>
        After the daily morning program, the deity of Prabhupada is taken to the temple hall where a grand guru puja is performed with the assembled devotees experiencing simultaneously both inexpressible joy at being blessed with the good fortune of having come in touch with him and intense separation of not having his physical presence amongst us anymore.
      </p>
      <p>
        Thereafter, a drop of the unlimited glories of Srila Prabhupada are described by the fortunate Prabhupada disciples who had personal association of Srila Prabhupada. Following the glorification, Srila Prabhupada is bathed (Abhishek) by his loving disciples and grand disciples, while the sweet holy names of the Lord are sung with accompaniment by mridangas and kartals, creating a beautiful atmosphere. The pushpanjali and arati are offered after Abhishek in Prabhupada\'s Samadhi, in which all the devotees offer their hearts and souls to Srila Prabhupada, for his lotus feet are the boat that can deliver all souls from the ocean of nescience.
      </p>
      <p>
        After the bhoga offering prepared by the devotees for the pleasure of Srila Prabhupada comprising of various delicacies—including Prabhupada\'s favorite kachodis, shukta, and other items—is offered, all the devotees honor the grand feast. The glorifications continue in the afternoon after which all the devotees assemble in Prabhupada\'s house for the arati at 7:20 PM, where all assembled Vaishnavas sing the Guruvastakam with tearful voices and hearts filled with intense separation while they pray to Srila Prabhupada for a particle of his mercy.
      </p>
      <p>
        No matter how much one may endeavor, without the mercy of the Vaishnavas, we cannot make progress in our spiritual life. Therefore, we pray to Srila Prabhupada to please always keep us under the shade of his most merciful lotus feet and engage us in the service of Sri Sri Guru, Gauranga, and Krishna.
      </p>', 'Disappearance Date: November 14, 1977 A.D. (at 7:20 PM in Sri Vrindavan Dhama)|Deity Location: Krishna-Balarama Mandir, Vrindavan, India|Last Activities: Dictated commentary on the 10th Canto of Srimad-Bhagavatam until his final moments.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (42, 'srila-bhaktivinoda-thakura-disappearance', 'Bhaktivinoda Thakura Disappearance', 'Bhaktivinoda Thakura', 'The disappearance day of Srila Bhaktivinoda Thakura, the great scholar and pioneer of Vaishnava revival.', 'Srila Bhaktivinoda Thakura left this world on June 23, 1914, in Calcutta. He spent his final years in complete dedication to writing and publishing Vaishnava literature. Even his government service as a magistrate was used as an opportunity to spread Krishna consciousness.', 'His departure marked the end of an era of Vaishnava revival. His legacy continues through his numerous books, songs, and the institution he established.', 'Honoring his disappearance brings the blessings of a great acharya who revived Lord Chaitanya\'s movement in the modern age.', 'disappearance', NULL, 'assets/images/banners/srila-bhaktivinoda-thakura-disappearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 71, 1, 0, 'disappearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        His Divine Grace <strong>Śrīla Saccidānanda Bhakti Vinod Ṭhākur</strong> was born on September 2nd, 1838, in Bir Nagar near Navadwip, in the state of West Bengal in India. He was given the name Kedarnath Dutta by his parents, Bir Chandra Dutta and Jagan Mohini Devi Dasi.
      </p>
      
      <p>
        His appearance took place at a critical and historical juncture for the Gaudiya Vaishnavas, when the pure teachings of Sri Caitanya Mahaprabhu and the Goswamis were almost lost due to corruption and pseudo-sects. The original devotional scriptures were so scarce that it took Bhaktivinoda Thakura eight years to locate a single copy of the <em>Caitanya Caritamrta</em>. He single-handedly re-established the teachings of Lord Caitanya, re-discovered the birth site of the Lord (Yogapitha) in Mayapur, and brought pure Vaishnavism back to the forefront of society.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Pioneer and Grandfather of the Movement</h3>
      <p>
        Srila Bhaktivinoda Thakura is revered as the pioneer and the grandfather of the modern Hare Krishna Movement. In 1896, he initiated worldwide preaching by sending his English book, <em>The Life and Precepts of Sri Caitanya</em>, to learned institutions and libraries across the globe.
      </p>
      <p>
        He prayed to the Lord for a \"ray of Vishnu\" to assist him in spreading the teachings of Sri Caitanya Mahaprabhu. In response to his prayers, his illustrious son, Srila Bhaktisiddhanta Sarasvati Thakura (the spiritual master of ISKCON\'s Founder-Acharya, His Divine Grace A.C. Bhaktivedanta Swami Prabhupada), was born. Srila Bhaktivinoda Thakura also famously predicted: 
      </p>

      <blockquote style=\"border-left:4px solid var(--accent); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Soon there will appear a personality who will preach the holy name of Hari all over the world.\"
      </blockquote>

      <p>
        Today, it is clearly understood that His Divine Grace A.C. Bhaktivedanta Swami Prabhupada is indeed that predicted personality who delivered the holy name to every corner of the earth.
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/srila-bhaktivinoda-thakura-disappearance-content.jpg\" alt=\"His Divine Grace Śrīla Saccidānanda Bhakti Vinod Ṭhākur\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">His Divine Grace Śrīla Saccidānanda Bhakti Vinod Ṭhākur</p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">An Exemplary Magistrate and Prolific Writer</h3>
      <p>
        Bhaktivinoda Thakura served as an excellent magistrate under the British regime and solved many critical and complex legal cases. It took only five minutes for him to solve a case that would take his contemporaries two hours. Even the British Government was astounded by his efficiency and superhuman capabilities.
      </p>
      <p>
        Despite his heavy governmental responsibilities and householder duties, he wrote over a hundred books, poems, and songs glorifying Lord Krishna and His devotees. He gave the world immortal works such as <em>Sri Harinama Chintamani</em>, <em>Bhajana-rahasya</em>, <em>Jaiva Dharma</em>, <em>Kalyana Kalpataru</em>, <em>Navadwipa Dhama Mahatmiya</em>, and <em>Saranagati</em>.
      </p>

      <!-- The Samadhi Quote -->
      <div style=\"background:var(--light); padding:var(--space-xl); border-radius:var(--radius-md); border-top:3px solid var(--primary); border-bottom:3px solid var(--primary); text-align:center; margin:var(--space-xl) 0; box-shadow:var(--shadow-sm);\">
        <p style=\"font-family:var(--font-subheading); font-size:var(--font-size-lg); font-weight:600; color:var(--maroon); line-height:1.6; font-style:italic; margin:0;\">
          \"He reasons ill who tells that Vaishnavas die,<br>
          When thou art living still in sound!<br>
          The Vaishnavas die to live, and living try<br>
          To spread the holy name around!\"
        </p>
        <p style=\"font-size:11px; text-transform:uppercase; letter-spacing:1px; color:var(--text-light); margin-top:12px; font-weight:700;\">
          — Written by Srila Bhaktivinoda Thakura on the Samadhi of Haridasa Thakura
        </p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Final Years & Secluded Bhajan</h3>
      <p>
        In his final years, Srila Bhaktivinoda Thakura performed intense <em>nirjana bhajan</em> (secluded worship) at Surabhi Kunj in Navadwip, Bhakti Kuti in Puri, and at Bhakti Bhavan in Calcutta. In 1914, at the age of 76, he disappeared from this material world to enter the eternal pastimes of the Lord.
      </p>
      
      <p style=\"margin-top:var(--space-lg); border-top:1px dashed var(--border); padding-top:var(--space-lg); font-weight:500; text-align:center; color:var(--primary-dark);\">
        We honor this great acharya, whose teachings, books, and prayers laid the path for our spiritual journey and brought Krishna Consciousness to the global stage.
      </p>', 'Birth Date: September 2, 1838 (Bir Nagar near Navadwip, West Bengal)|Parents: Bir Chandra Dutta & Jagan Mohini Devi Dasi|Given Name: Kedarnath Dutta|Disappearance Year: 1914 A.D. (aged 76, in Calcutta)|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (43, 'srila-bhaktisiddhanta-disappearance', 'Bhaktisiddhanta Sarasvati Disappearance', 'Sarasvati Thakura', 'The disappearance day of Srila Bhaktisiddhanta Sarasvati Thakura, who established 64 Gaudiya Mathas worldwide.', 'Srila Bhaktisiddhanta Sarasvati Thakura departed from this world on January 1, 1937, in Calcutta. Despite facing many obstacles, he established 64 mathas and tirelessly preached the philosophy of acintya-bhedabheda-tattva (inconceivable oneness and difference).', 'His powerful preaching left an indelible mark on the spiritual landscape of India. His disciple, Srila Prabhupada, would go on to fulfill his vision of spreading Krishna consciousness worldwide.', 'Honoring his disappearance invokes the blessings of a powerful spiritual warrior who fearlessly established the truth of devotional service.', 'disappearance', NULL, 'assets/images/banners/srila-bhaktisiddhanta-sarasvati-thakura-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 72, 1, 0, 'disappearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        On the fifth day of the dark lunar fortnight of the month of Govinda [corresponding to February 6th, 1874 A.D. by the western calendar], at 3:30 in the afternoon, Bimala Prasad Datta, later to be known as <strong>Srila Bhaktisiddhanta Sarasvati Thakura</strong>, made his appearance in Purusottama Ksetra [Jagannatha Puri] in the state of Orissa, not far from the temple of Lord Jagannatha. He was the fourth son of Srila Bhaktivinoda Thakura and Sriyukta Bhagavati Devi.
      </p>
      
      <p>
        At the time of his birth, all thirty-two bodily symptoms of a <em>maha-purusa</em>, a great personality, were pointed out by an experienced astrologer. Furthermore, the boy was born with his umbilical cord wrapped around his neck like a Brahmin\'s thread. The astrologer commented, <em>\"I have done many horoscopes in my life, but I have never before seen such a horoscope filled with all the signs of a great personality. This child will become world famous as a brilliant teacher of life\'s ultimate goal.\"</em>
      </p>

      <blockquote style=\"border-left:4px solid var(--primary); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"This child will become world famous as a brilliant teacher of life\'s ultimate goal.\"
      </blockquote>

      <p>
        When the child was six months old, Lord Jagannatha\'s Rathayatra Festival was in procession, and the cart stopped in front of Srila Bhaktivinoda Thakura\'s house for three days. Following the instructions of Srila Bhaktivinoda Thakura, Bhagavati Devi brought the child before the cart and an offered garland fell from the neck of the Lord, encircling the boy. This was taken as a sign of special favor by all present. The grain ceremony was observed on the cart at this time and was done with Jagannatha prasada. When the boy\'s vocational inclination was tested, he immediately embraced the Srimad-Bhagavatam, indicating his future as a preacher. Therefore, from the very beginning of his appearance, Srila Bhaktisiddhanta Sarasvati Thakura exhibited all the signs of an exalted, eternal associate of the Lord, who had descended in answer to Srila Bhaktivinoda\'s prayer for a \"ray of Visnu\" to help him spread the Krsna Consciousness Movement.
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/srila-bhaktisiddhanta-sarasvati-thakura-portrait.jpg\" alt=\"Srila Bhaktisiddhanta Sarasvati Thakura\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">Srila Bhaktisiddhanta Sarasvati Thakura Prabhupada</p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Ancestral Lineage</h3>
      <p>
        Although family lineage may be ultimately irrelevant when considering the appearance of an eternally liberated associate of the Lord, still it is interesting to see what sort of family is blessed with such a transcendental personality. As history shows us, Lord Brahma himself appeared in the family of Muslims as Srila Haridasa Thakura, and there are other instances of exalted persons taking birth in humble families. Still, as a point of interest, we may hear something of the lineage of Srila Bhaktisiddhanta Sarasvati Thakura.
      </p>
      <p>
        His family line traces back to Lord Brahma from the descendants of Chitragupta, and they are known as the Brahma kayasthas. Bharata is in the 87th generation from Chitragupta, Bharadvaja is the 88th. After him came Angira, and after him appeared Brhaspati. In the 149th generation of descendants, Purusottama, son of Sivadatta, went to Bengal upon the summons of the King of Bengal, Adisura. Purusottama\'s youngest son took sannyasa and became famous as Kanaka Dandi.
      </p>
      <p>
        In the 7th and 8th generations of Purusottama\'s family, Binayaka and his son Narayana Datta both did ministerial work for the king of Bengal. In the 15th generation from Purusottama, Raja Krsnananda, the king of Kheturi (in Bengal), and the father of Srila Narottama dasa Thakura, the great Vaisnava acarya, appeared. Raja Krsnananda was also a great devotee and was personally favored by Lord Nityananda Prabhu.
      </p>
      <p>
        The 7th generation from Raja Krsnananda saw the appearance of Madanamohana Datta, who was very famous in Bengal and Calcutta for his spiritual qualities. His great-grandson was Anandachandra Datta, and his son was Srila Bhaktivinoda Thakura, whose 4th son was Bimala Prasad. The name Bimala or Shri Bimala Devi refers to the para sakti (internal potency) of Lord Jagannatha, so his name literally means the mercy of the internal potency of the Lord.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Transcendental Childhood & The Mango Vow</h3>
      <p>
        Bimala Prasad stayed in Jagannatha Puri for ten months after his appearance and then journeyed to Bengal by palanquin on his mother\'s lap. He grew up in his early years in Ranaghata in the District of Nadia, hearing about Krsna from his mother.
      </p>
      <p>
        When he was a small boy, perhaps two or three years old, Srila Bhaktivinoda Thakura brought some ripe mangoes from the market. Bimala Prasad took one to eat, saying, \"This is mine.\" Srila Bhaktivinoda Thakura got up and said in a grave voice, <em>\"What is this? New fruit has come into the house. It has not been offered to Giridhari and you have taken it first? Remember, new fruit is to be given first to the Lord. Without giving the first share to the Lord, nothing is to be taken.\"</em>
      </p>
      <p>
        The child was very repentant and exclaimed, <em>\"Oh, what evil thoughts I have had! Throughout my whole life I shall not eat these again. This is the right punishment for one ruled by greed.\"</em> He made the promise and observed it throughout his whole life. His Divine Grace A.C. Bhaktivedanta Swami Prabhupada comments on this incident:
      </p>
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Whenever we offered him mango he said, \'No, I am an offender. I cannot take mango.\' He was thinking that \'I have offended [Krsna] in my childhood by taking the mango of the Deity.\' So this is the characteristic of the acarya. They teach by their life\'s action—one should be so much determined. A child took the mango, there is no offense, but he took that vow.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Astounding Education and Astronomy Title</h3>
      <p>
        When Bimala Prasad was seven years old, Srila Bhaktivinoda Thakura was constructing the Bhakti Bhavan in Calcutta at Ramabagana. During that construction, a Deity of Lord Kurma was unearthed. Srila Bhaktivinoda Thakura ordered his son to begin regulated worship of that Deity. By the age of seven he had committed the entire Bhagavad-gita to memory and could wonderfully explain the verses as well.
      </p>
      <p>
        He possessed an eidetic memory; whatever he would read once he could recall with perfect clarity. He was trained in mathematics and astrology at the Sri Ramapura School, and he achieved such astounding scholarship that he was eventually awarded the title <strong>Siddhanta Sarasvati</strong> by his tutors, Pandit Mahesh Chandra Chauramani and Pandit Sundar Lal.
      </p>
      <p>
        In 1892, at the age of eighteen, he entered Calcutta\'s Sanskrit College. He paid scant attention to the prescribed books, but read all of the philosophical books in the library. In 1895 he left the college to avoid family life pressure. He stated in his autobiography:
      </p>
      <blockquote style=\"border-left:4px solid var(--accent); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0; font-size:var(--font-size-sm);\">
        \"If I remain studying with careful attention at the College, then extreme pressure will be brought upon me to enter family life, but if I am considered to be foolish and inefficient, then no one will put such an inducement upon me for becoming so engaged... I left the Sanskrit College, and, in order to maintain my life for the service of Hari, I was desirous of getting an honest occupation...\"
      </blockquote>
      <p>
        In 1897 he established a small academy called <em>Saraswati Chatuspati</em> where many learned persons from Calcutta attended his lectures and discourses on astronomy. He also published magazines like <em>Jyotirvid</em> and <em>Brihaspati</em> and edited the <em>Bhakti Panjika</em> almanac.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Transcendental Initiation</h3>
      <p>
        In 1898, Srila Gaura Kisora dasa Babaji Maharaja arrived in Navadvipa Dhama. He was extremely renounced and was widely known as a liberated paramahamsa of the highest caliber. Siddhanta Sarasvati was very attracted to his lotus feet at first sight.
      </p>
      <p>
        At Srila Bhaktivinoda Thakura\'s urging, the young man approached Srila Gaura Kisora dasa Babaji for initiation in 1900. Babaji Maharaja expressed reluctance to accept him, knowing Siddhanta Sarasvati to be a great scholar. He repeatedly postponed the initiation, saying he needed to ask Mahaprabhu\'s permission.
      </p>
      <p>
        On the third attempt, when Babaji Maharaja said he had not received the command of Mahaprabhu, Siddhanta Sarasvati stood up with a breaking heart and said, <em>\"If there is no mercy, weeping and weeping, I can sustain my life no more. If I do not receive your mercy I do not see any need in holding onto life.\"</em> Seeing his absolute determination, Babaji Maharaja\'s heart melted. He told him to take a bath in the sacred Sarasvati River and initiated him, giving him the name <strong>Sri Varsabhanavi-devi-dayita dasa</strong>.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Nama-Bhajana Vow of 1 Billion Holy Names</h3>
      <p>
        In 1905, at the age of 31, he began his great vow, following the example of Namacarya Haridasa Thakura, of chanting three lakhs of names (192 rounds) per day. At this rate, it took him about 9 years to complete one billion names.
      </p>
      <p>
        He resided in a grass hut at the Yogapitha for four years. When the roof of his hut became broken, rather than take time away from his chanting, he would simply use an umbrella when it rained and go on chanting. He strictly followed his vow and observed Caturmasya, cooking rice dried in the sun in ghee and eating it directly from the floor in the manner of a cow.
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/lion-acharyas.jpg\" alt=\"The Lion Acharya and Disciples\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">Srila Bhaktisiddhanta Sarasvati Thakura (The Lion Guru) with his disciples</p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Preaching the Absolute Truth Without Compromise</h3>
      <p>
        Siddhanta Sarasvati was a fierce preacher who never compromised the absolute truth. In 1911, when a controversy challenged that the name \"Gaura\" in the Gayatri mantra was not found in the original Vedas, he cited proof from the Atharva Veda (Caitanyopanisad) and Svetasvatara Upanisad, completely defeating the opposing scholars.
      </p>
      <p>
        He also vehemently opposed the caste gosvamis and smartas who believed guru qualifications were hereditary. He established that anyone who knows the science of Krsna, regardless of caste or social status, is a qualified guru. His Divine Grace A.C. Bhaktivedanta Swami Prabhupada commented:
      </p>
      <blockquote style=\"border-left:4px solid var(--primary-dark); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"My Guru Maharaja\'s contribution is that he defeated the caste gosvamis. He defeated this brahmanism. He did it the same way as Caitanya Mahaprabhu did... So-called saints, avataras, yogis—everyone who was false was an enemy to my Guru Maharaja. He never compromised.\"
      </blockquote>
      <p>
        Because of his bold preaching, some opposing groups even conspired to take his life, but he was protected by his spiritual potency and even warned by a righteous police officer who refused to accept bribes from the conspirators.
      </p>
      
      <p style=\"margin-top:var(--space-lg); border-top:1px dashed var(--border); padding-top:var(--space-lg); font-weight:500; text-align:center; color:var(--primary-dark);\">
        We celebrate the glorious disappearance anniversary of this transcendental personality to remind ourselves of his absolute surrender, dedication, and uncompromising preaching of Krishna Consciousness.
      </p>', 'Appearance Date: Feb 6, 1874 A.D. (Purusottama Ksetra, Jagannatha Puri)|Initiation Name: Sri Varsabhanavi-devi-dayita dasa (initiated by Srila Gaura Kisora dasa Babaji Maharaja)|Vow of Nama-Bhajana: Completed chanting one billion Holy Names (300,000 daily for 9 years)|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (44, 'srila-jagannatha-dasa-babaji-disappearance', 'Srila Jagannatha dasa Babaji Disappearance', 'Jagannatha dasa Babaji', 'The disappearance day of Srila Jagannatha dasa Babaji, the great paramahamsa of Vrindavan.', 'Srila Jagannatha dasa Babaji was one of the most exalted Vaishnava paramahamsas of the 19th century. He lived in Vrindavan for many years and was intimately connected with Srila Bhaktivinoda Thakura. He personally identified the actual birthplace of Sri Chaitanya Mahaprabhu in Mayapur.', 'His pure love for Krishna and humble disposition made him one of the most respected Vaishnavas of his time. His confirmation of Chaitanya Mahaprabhu\'s birthplace was crucial for the Gaudiya Vaishnava revival.', 'Honoring his disappearance brings the blessings of a pure devotee who had the highest realization of Krishna consciousness.', 'disappearance', NULL, 'assets/images/banners/srila-jagannatha-dasa-babaji-disappearance-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 73, 1, 0, 'disappearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        <strong>Jagannatha dasa Babaji Maharaja</strong> (1776-1894), revered as the <em>Vaishnava Sarvabhauma</em> (emperor of the Vaishnavas), was the spiritual master of Srila Bhaktivinoda Thakura. He is celebrated for confirming Srila Bhaktivinoda Thakura\'s discovery of the birthplace of Lord Caitanya. 
      </p>
      
      <p>
        Upon arriving at the birthplace, Jagannatha dasa Babaji Maharaja—who was at that time blind, crippled, and carried in a basket by his servant—suddenly leaped high into the air in transcendental ecstasy. He began chanting the holy names of Krishna and dancing, confirming beyond all doubt that this was indeed the sacred site of Lord Caitanya\'s descent.
      </p>

      <blockquote style=\"border-left:4px solid var(--primary); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Blind and crippled, he leaped high into the air in transcendental ecstasy, confirming the sacred birthplace of Lord Caitanya.\"
      </blockquote>

      <p>
        Until Bhaktivinoda Thakura\'s time, the precise location of Caitanya Mahaprabhu\'s appearance was unknown—a fact that indicates how moribund His teachings had become in India. Srila Bhaktivinoda combed old government records and consulted antiquarian maps and authentic books written during the time of Lord Caitanya. Then he took support from the inspired testimony of his spiritual master, Srila Jagannatha dasa Babaji. In Sridhama Mayapur, on the eastern bank of the Ganges, the holy site was finally ascertained. 
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/srila-jagannatha-dasa-babaji-disappearance-content.jpg\" alt=\"Srila Jagannatha dasa Babaji Maharaja\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">Srila Jagannatha dasa Babaji Maharaja</p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Pranama Mantra</h3>
      <p>
        For his divine vision and role in preserving Lord Caitanya\'s legacy, Jagannatha dasa Babaji is memorialized by all Vaishnavas with the following pranama mantra:
      </p>

      <!-- Pranama Mantra Box -->
      <div style=\"background:var(--light); padding:var(--space-xl); border-radius:var(--radius-sm); border-left:4px solid var(--maroon); text-align:center; margin:var(--space-md) 0;\">
        <p style=\"font-family:var(--font-subheading); font-size:var(--font-size-lg); font-weight:600; color:var(--maroon); line-height:1.6; margin-bottom:8px;\">
          gauravirbhava-bhumes tvam nirdeshta saj-jana-priyah<br>
          vaishnava–sarvabhaumah shri–jagannathaya te namaha
        </p>
        <p style=\"font-size:var(--font-size-sm); color:var(--text-dark); line-height:1.5; font-style:italic; margin:0;\">
          \"I offer my respectful obeisances to Jagannatha dasa Babaji, who is respectful to the entire community of devotees and who discovered the place where Lord Chaitanya appeared.\"
        </p>
      </div>

      <p>
        In this way, Jagannatha dasa Babaji and Bhaktivinoda Thakura followed the example of the six exalted Gosvamis of Vrindavana, who were sent to Vrindavana by Lord Caitanya to uncover the lost sites of Krishna\'s pastimes. Their joint work resurrected the Navadvipa Dhama and opened the path for the global sankirtana movement.
      </p>', 'Life Span: 1776 – 1894 A.D. (118 years)|Spiritual Role: Spiritual Master of Srila Bhaktivinoda Thakura|Title: Vaishnava Sarvabhauma (The Emperor of the Vaishnavas)|Key Contribution: Confirmed the exact birthplace of Lord Sri Caitanya Mahaprabhu (Yogapitha, Mayapur)|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (45, 'gaura-kisora-dasa-babaji-disappearance', 'Gaura Kisora dasa Babaji Disappearance', 'Gaura Kisora dasa Babaji', 'The disappearance day of Srila Gaura Kisora dasa Babaji, the spiritual master of Srila Bhaktisiddhanta Sarasvati.', 'Srila Gaura Kisora dasa Babaji was a paramahamsa Vaishnava who lived as a wandering mendicant, always absorbed in chanting the holy names. Despite being illiterate, he was the spiritual master of the great scholar Srila Bhaktisiddhanta Sarasvati Thakura, demonstrating that pure devotion transcends all material qualifications.', 'His life exemplified that love for Krishna can be attained through simple, sincere chanting, without any material qualifications. His position as the spiritual master of a great scholar shows Krishna\'s special mercy on the humble.', 'Honoring his disappearance brings the blessings of a pure paramahamsa who demonstrates that sincere devotion is more important than any material accomplishment.', 'disappearance', NULL, 'assets/images/banners/gaura-kisora-dasa-babaji-banner.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 74, 1, 0, 'disappearance', NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<p>
        The next in the parampara, after and as a close associate of Bhaktivinoda Thakura, is a great paramahamsa babaji by the name of <strong>Gaura Kisora dasa Babaji Maharaja</strong>. In 1897, Gaura Kisora dasa Babaji Maharaja arrived in Mayapur Navadwipa Dhama from Sri Vrndavana Dhama, where he was accredited the exalted title <strong>\"Bhajananandi\"</strong>.
      </p>
      
      <p>
        Srila Bhaktivinoda Thakura, seeing the transcendental behavior of Babaji Maharaja, would use him as an example of <em>nirapeksa</em> (complete indifference and detachment), as his level of renunciation was beyond belief. He was the spiritual master of Srila Bhaktisiddhanta Sarasvati Gosvami, the founder of the Caitanya Mathas and Gaudiya Mathas.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Example of Utter Humility and Vairagya</h3>
      <p>
        This Vaishnava saint\'s life was an example of utter humility and poverty, the true attributes of a pure Vaisnava. Gaura Kisora never accepted any material object from anyone. For his clothing, he used the discarded loincloths from corpses left on the bank of the Ganges. For food, he would collect rice by begging (<em>madhukari</em>), soak it in river water, and garnish it with salt and chili. He never asked favors from anyone and lived a fully detached life, devoid of all possessions.
      </p>
      
      <p>
        He spent about thirty years at Vraja mandala serving the deities there, sleeping beneath trees, and offering his prostrate, humble obeisances to the residents of Vraja, considering them as embodiments of Lord Krsna. He even offered his obeisances to the flowers, trees, and land around him. Afterwards, by the direction of the Supreme Lord, he left for Navadvipa.
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/gaura-kisora-dasa-babaji-meditating.jpg\" alt=\"Shrila Gaura Kishora Dasa Babaji Maharaj Meditating\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">Shrila Gaura Kishora Dasa Babaji Maharaj absorbed in deep meditation</p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Spiritual Moods & Association with Bhaktivinoda</h3>
      <p>
        During his stay at Navadvipa, Gaura Kisora underwent various transformations of spiritual moods. Sometimes he danced on the bank of the Ganges chanting, <em>\"Gaura, Gaura\"</em>, while at other times he would lie on the ground in an unconscious state of ecstasy. He joyfully moved throughout the groves located on the bank of the Ganges, considering them sites of the divine sports of Sri Sri Radha Govinda.
      </p>
      <p>
        Babaji Maharaja would often visit Bhaktivinoda Thakura. During his last days in retirement, absorbed in Krsna katha, he would hear Srimad-Bhagavatam at Bhaktivinoda\'s house and they would discuss together. Though Babaji Maharaja could neither read nor write, he was regarded as vastly learned and self-realized. His only possessions were the Tulasi beads around his neck and the japa mala he kept in his hand. Sometimes he wore no Tulasi mala on his neck and would chant on knotted cloth as beads—such was his renunciation.
      </p>
      <p>
        Sometimes he would live under an old broken overturned boat, and other times he would scatter fish bones around a place he occasionally used as his bhajan kutir to make materialists think he was a fish-eater, and thus they would not disturb him. But by his pure bhajan, he purified the three worlds.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Initiation of Siddhanta Saraswati</h3>
      <p>
        In 1898, Bhaktivinoda\'s son, Siddhanta Saraswati (later Srila Bhaktisiddhanta Sarasvati Thakura), came in contact with the person who was to be his spiritual master. At that first meeting, the crest jewel of avadhutas was wearing a tigerskin hat and carrying a basket with puja paraphernalia inside. Bhaktivinoda later told his son, <em>\"You must take initiation from Babaji Maharaja, and don\'t return to this house if you don\'t.\"</em>
      </p>
      <p>
        Gaura Kisora dasa Babaji used to walk across a bridge at the same time daily, so on one occasion, Siddhanta Saraswati blocked his path and in all humility said, <em>\"If you don\'t give me initiation then I will finish my life by throwing this useless body off this bridge.\"</em>
      </p>
      <p>
        Gaura Kisora dasa Babaji Maharaja didn\'t want any disciples—he himself had taken siksa from Bhaktivinoda, and this was Bhaktivinoda\'s dear son! However, seeing Siddhanta Saraswati\'s absolute determination, Babaji Maharaja gave him initiation in 1900 under the name <strong>Varsabhanavi-devi-dayita dasa</strong>.
      </p>

      <blockquote style=\"border-left:4px solid var(--accent); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"I will never accept this service. Better I throw myself in the Saraswati (Jalanghi) and drown.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Refusal of Material Association</h3>
      <p>
        In 1908, Gaura Kisora dasa Babaji Maharaja lost his external eyesight. He then stopped traveling and sat in his bhajan kutir, internally absorbed in Krsna\'s pastimes. He could be heard in a very deep voice calling the names of the gopis of Vrndavana.
      </p>
      <p>
        Once, Siddhanta Saraswati offered to take Babaji Maharaja to Calcutta to see an eye specialist, but he refused saying, <em>\"Never! I will never go to the material world.\"</em> His disciple protested, <em>\"But in Calcutta I could serve you nicely. You wouldn\'t have to undergo any inconvenience.\"</em> But Babaji Maharaja was adamant declaring, <em>\"I will never accept this service. Better I throw myself in the Saraswati and drown.\"</em>
      </p>
      <p>
        One day Srila Gaura Kisora dasa Babaji Maharaja wrapped his body and two feet with a cloth. Sitting covered like this he said:
      </p>
      <p style=\"font-style:italic; background:var(--light); padding:var(--space-md); border-radius:var(--radius-sm); color:var(--text-dark);\">
        \"Many persons, after being informed by others, come here to collect the dust from my feet. I tell them I am not a Vaisnava. If you go to the vicinity where there are Vaisnavas with their feet pretentiously decorated and extended to touch, you can have unlimited dust. How can I bless you? I don\'t have barfi or sandesh or rasagulla, or even sweet words. How can I bless you? Nowadays people are interested in spiritual masters who can give these things—wealth, good wife, sweet words—these cheating things are now taken as anukula (favorable).\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Bhajan Anywhere: The Toilet Room Story</h3>
      <p>
        Giribabu and his wife once ardently requested Gaurakisora to stay in their house at Navadvipa. Gaurakisora was moved by their sincere devotion and finally agreed to oblige them on the condition that he would live only in their toilet room where he would perform Hari bhajan.
      </p>
      <p>
        Giribabu tried to persuade him to change his mind but Gaurakisora remained firm. Giribabu reluctantly arranged to have the toilet thoroughly cleaned, and Gaurakisora used it for Haribhajan. A realized soul can practice Haribhajan anywhere in an unconcerned manner, and wherever he resides, that place becomes Vaikuntha.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Departure</h3>
      <p>
        On June 22, 1914, Bhaktivinoda Thakura passed from this world. Shortly after, on November 17, 1915, on the auspicious day of Utthana Ekadasi, Srila Gaura Kisora dasa Babaji Maharaja also left this world, entering into his eternal samadhi.
      </p>

      <div style=\"margin:var(--space-lg) 0; text-align:center;\">
        <img src=\"{{BASE_URL}}assets/images/banners/gaura-kisora-dasa-babaji-samadhi.jpg\" alt=\"Samadhi Temple of Gaurakisora Das Babaji\" style=\"max-width:100%; border-radius:var(--radius-md); box-shadow:var(--shadow-md); border:1px solid var(--border);\">
        <p style=\"font-size:12px; color:var(--text-light); margin-top:8px; font-style:italic;\">The Samadhi Temple of Srila Gaura Kisora dasa Babaji Maharaja in Navadvipa Dhama</p>
      </div>', 'Disappearance Date: November 17, 1915 A.D. (Utthana Ekadasi)|Title: Bhajananandi / Paramahamsa Babaji|Spiritual Master: Bhagavata dasa Babaji Maharaja|Primary Disciple: Srila Bhaktisiddhanta Sarasvati Thakura|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (46, 'ekadashi-general', 'Ekadashi Seva', 'Ekadashi', NULL, 'Ekadashi, the eleventh day of both the waxing and waning moon, has been observed as a day of fasting and increased devotion since time immemorial. The Padma Purana and other scriptures glorify this day as \"Hari-vasara\" — the day of Lord Hari. Lord Krishna declares in the Bhagavad-gita, \"Among days I am Ekadashi.\"', 'Observing Ekadashi helps control the senses and mind, making it easier to focus on Krishna. Fasting on this day is said to destroy all sins and bring one closer to the Lord. Even broken observance gives great benefit.', 'Sponsoring Ekadashi offerings and prasadam helps others observe this sacred day. Donors receive the combined spiritual benefits of all Ekadashi observances throughout the year.', 'ekadashi', NULL, 'assets/images/banners/bhaimi-ekadashi.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 80, 0, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-07-03 19:32:18', NULL, NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (47, 'caturmasya', 'Caturmasya Seva', 'Caturmasya', 'Sponsor the four-month Chaturmasya observance — a period of heightened spiritual discipline and austerities.', 'Caturmasya is the four-month period (July to October) during the rainy season when Lord Vishnu is said to sleep (Yoga-nidra). Devotees observe various vows during this period — such as avoiding certain foods — as an austerity to please the Lord. This tradition is followed by all Vaishnavas.', 'Observing Caturmasya vows helps control the senses and deepen one\'s spiritual practice. Each month has specific observances that purify different aspects of one\'s life and bring one closer to Krishna.', 'Sponsoring Caturmasya observances supports devotees in their vows. Donors receive the spiritual benefits of the austerities performed and the Lord\'s special blessings during this sacred period.', 'event', NULL, 'assets/images/banners/caturmasya.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 90, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<!-- Banner Image in Content Area -->
    <div class=\"reveal\" style=\"margin-bottom: var(--space-xl); border-radius: var(--radius-lg); overflow: hidden; box-shadow: var(--shadow-md);\">
      <img src=\"{{BASE_URL}}assets/images/banners/caturmasya.jpg\" alt=\"Caturmasya Vrata\" style=\"width: 100%; height: auto; display: block;\">
    </div>
    
    <!-- Intro description -->
    <div class=\"reveal\" style=\"text-align: center; margin-bottom: var(--space-3xl);\">
      <div class=\"section-divider\"><span class=\"divider-icon\">🌙</span></div>
      <h2 style=\"margin-bottom: var(--space-md);\">What is Caturmasya Vrata?</h2>
      <p style=\"color: var(--text-light); max-width: 800px; margin: 0 auto; line-height: 1.8; font-size: var(--font-size-base);\">
        <strong>Catur</strong> means four, <strong>Masya</strong> means months, and <strong>vrata</strong> means austerity. The Caturmasya Vrata is observed for a period of four holy lunar months, starting from the day after Deva Sayana Ekadashi in the Ashada month (June – July) and concluding on Utthana Ekadashi in the Kartika month (October – November). Some Vaishnavas also observe it from the Full Moon day of Ashada until the Full Moon day of Kartika.
      </p>
    </div>

    <!-- Divine Sleep and Awakening -->
    <div class=\"reveal\" style=\"background: var(--cream); border-radius: var(--radius-lg); padding: var(--space-xl); margin-bottom: var(--space-3xl); border: 1px solid var(--border); display: flex; gap: var(--space-lg); align-items: center; flex-wrap: wrap;\">
      <div style=\"font-size: 48px; color: var(--primary); flex-shrink: 0;\"><i class=\"fas fa-bed\"></i></div>
      <div style=\"flex: 1; min-width: 280px;\">
        <h3 style=\"margin-top: 0; margin-bottom: 6px; color: var(--text-dark);\">Sayana & Utthana</h3>
        <p style=\"color: var(--text-light); font-size: var(--font-size-sm); line-height: 1.6; margin: 0;\">
          It is understood that Lord Vishnu falls asleep in the <strong>Ksheer Sagar</strong> (the Ocean of Milk) resting upon <strong>Shesha Naga</strong> (Ananta Shesha) on Sayana Ekadashi. He awakens from this yoga-nidra after four holy months on Utthana Ekadashi in the month of Kartika.
        </p>
      </div>
    </div>

    <!-- Monthly Fasting Table -->
    <div class=\"reveal\" style=\"margin-bottom: var(--space-3xl);\">
      <h3 style=\"text-align: center; margin-bottom: var(--space-xl); color: var(--text-dark); display: flex; align-items: center; justify-content: center; gap: 8px;\">
        <i class=\"fas fa-utensils\" style=\"color: var(--primary);\"></i> Four Months of Dietary Restraints
      </h3>
      
      <div style=\"overflow-x: auto; background: var(--white); border-radius: var(--radius-lg); box-shadow: var(--shadow-sm); border: 1px solid var(--border);\">
        <table style=\"width: 100%; border-collapse: collapse; text-align: left;\">
          <thead>
            <tr style=\"background: var(--gradient-primary); color: var(--white);\">
              <th style=\"padding: var(--space-md) var(--space-lg); font-weight: 600;\">Caturmasya Period</th>
              <th style=\"padding: var(--space-md) var(--space-lg); font-weight: 600;\">Traditional Lunar Months</th>
              <th style=\"padding: var(--space-md) var(--space-lg); font-weight: 600;\">Fasting Restrictions</th>
            </tr>
          </thead>
          <tbody>
            <tr style=\"border-bottom: 1px solid var(--border-light);\">
              <td style=\"padding: var(--space-md) var(--space-lg); font-weight: 600; color: var(--text-dark);\">First Month</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--text-light); font-size: var(--font-size-sm);\">Sravana (Jul – Aug)</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--primary); font-weight: 600;\">Fasting from Shak (green leafy vegetables)</td>
            </tr>
            <tr style=\"border-bottom: 1px solid var(--border-light);\">
              <td style=\"padding: var(--space-md) var(--space-lg); font-weight: 600; color: var(--text-dark);\">Second Month</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--text-light); font-size: var(--font-size-sm);\">Bhadra (Aug – Sep)</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--primary); font-weight: 600;\">Fasting from Yogurt (curd)</td>
            </tr>
            <tr style=\"border-bottom: 1px solid var(--border-light);\">
              <td style=\"padding: var(--space-md) var(--space-lg); font-weight: 600; color: var(--text-dark);\">Third Month</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--text-light); font-size: var(--font-size-sm);\">Asvina (Sep – Oct)</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--primary); font-weight: 600;\">Fasting from Milk</td>
            </tr>
            <tr style=\"border-bottom: none;\">
              <td style=\"padding: var(--space-md) var(--space-lg); font-weight: 600; color: var(--text-dark);\">Fourth Month</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--text-light); font-size: var(--font-size-sm);\">Kartika (Oct – Nov)</td>
              <td style=\"padding: var(--space-md) var(--space-lg); color: var(--primary); font-weight: 600;\">Fasting from Urad Dal (pulses/beans)</td>
            </tr>
          </tbody>
        </table>
      </div>
    </div>

    <!-- Ultimate Purpose of Bhaktas -->
    <div class=\"reveal\" style=\"background: var(--cream-light); border-left: 5px solid var(--primary); padding: var(--space-xl); border-radius: var(--radius-md); margin-bottom: var(--space-3xl); box-shadow: var(--shadow-sm); line-height: 1.7;\">
      <h3 style=\"margin-top: 0; margin-bottom: var(--space-sm); color: var(--text-dark);\">The Goal of Austerity</h3>
      <p style=\"color: var(--text-light); font-size: var(--font-size-sm); margin: 0; line-height: 1.6;\">
        The Caturmasya Vrata is observed by all classes of seekers (Karmis, Gyanis, Yogis, and Bhaktas) for the attainment of their respective ends. For devotees of Lord Krishna, the ultimate goal of observing these vows is to attain <strong>Krishna-prema</strong> (pure love for the Supreme Personality of Godhead).
      </p>
      <p style=\"color: var(--text-light); font-size: var(--font-size-sm); margin: 12px 0 0 0; line-height: 1.6;\">
        Sri Caitanya Mahaprabhu Himself and our predecessor Acharyas strictly observed Caturmasya to set an example. Sri Caitanya Mahaprabhu spent this period at Jagannath Puri (Purushottam Dham) absorbed constantly in **Krishna-katha**, kirtan, and hearing.
      </p>
    </div>

    <!-- Srila Prabhupada & Scriptural Purports -->
    <div class=\"reveal\" style=\"margin-bottom: var(--space-3xl);\">
      <h3 style=\"margin-bottom: var(--space-lg); color: var(--text-dark);\"><i class=\"fas fa-book-open\" style=\"color: var(--primary); margin-right: 8px;\"></i> Srila Prabhupada\'s Instructions</h3>
      
      <div style=\"background: var(--white); border: 1px solid var(--border); border-radius: var(--radius-lg); padding: var(--space-xl); box-shadow: var(--shadow-sm); display: flex; flex-direction: column; gap: var(--space-md);\">
        
        <div>
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-base);\">Chaitanya Caritamrita Madhya-lila 4.169 (Purport):</h4>
          <blockquote style=\"margin: 0; padding-left: var(--space-md); border-left: 3px solid var(--primary); color: var(--text-light); font-size: var(--font-size-sm); line-height: 1.7; font-style: italic;\">
            \"Caturmasya should be observed by all sections of the population. It does not matter whether one is a grhastha or a sannyasi. The observance is obligatory for all asramas. The real purpose behind the vow taken during these four months is to minimize the quantity of sense gratification. This is not very difficult... On the whole, during the four-month period of Caturmasya one should practice giving up all food intended for sense enjoyment.\"
          </blockquote>
        </div>

        <div style=\"border-top: 1px dashed var(--border); padding-top: var(--space-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-base);\">Vishnu Rahasya (Lord Brahma to Narada Muni):</h4>
          <blockquote style=\"margin: 0; padding-left: var(--space-md); border-left: 3px solid var(--primary); color: var(--text-light); font-size: var(--font-size-sm); line-height: 1.7; font-style: italic;\">
            \"If one accepts all these Vaisnava austerities and observances with devotion, one attains the supreme destination, O Narada. One who desires within himself to execute all these Vaisnava austerities and vows, his sins obtained within one hundred births are destroyed. If one is exclusively devoted, peaceful, takes a daily bath, is fixed in vow, and worships the Lord during these four months, he goes to the abode of the Lord.\"
          </blockquote>
        </div>

      </div>
    </div>

    <!-- Internal Cleaning and Mental Restraints -->
    <div class=\"reveal\" style=\"background: var(--white); border: 1px solid var(--border); border-radius: var(--radius-lg); padding: var(--space-xl); box-shadow: var(--shadow-sm); margin-bottom: var(--space-3xl);\">
      <h3 style=\"margin-top: 0; margin-bottom: var(--space-md); color: var(--text-dark); display: flex; align-items: center; gap: 8px;\">
        <i class=\"fas fa-heart\" style=\"color: var(--accent);\"></i> Internal Purification
      </h3>
      <p style=\"color: var(--text-light); font-size: var(--font-size-sm); line-height: 1.7; margin-bottom: var(--space-md);\">
        Beyond physical dietary changes, Caturmasya is a time to cleanse our mind and attachments. One should carefully give up attachments for material assets (house, ornaments, wealth, etc.) and habits that obstruct spiritual progress.
      </p>
      
      <div style=\"background: var(--cream); border-radius: var(--radius-md); padding: var(--space-md); font-family: monospace; font-size: var(--font-size-xs); color: var(--text-dark); border-left: 4px solid var(--accent); margin-bottom: var(--space-sm);\">
        sokamarsadibhir bhavair akrantam yasya manasam<br>
        katham tasya mukundasya sphurttih sambhavana bhavet
      </div>
      <p style=\"color: var(--text-light); font-size: var(--font-size-xs); line-height: 1.6; margin: 0; font-style: italic;\">
        <strong>Padma Purana:</strong> Within the heart of one who is full of anger, pride, or lamentation on the state of his wife or sons, there is no possibility of Krsna and Gauranga being manifest.
      </p>
    </div>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (48, 'shiksha-ceremony', 'Shiksha Ceremony', 'Shiksha', 'Sponsor the Shiksha Ceremony — a sacred educational program for devotees and seekers of spiritual knowledge.', 'The Shiksha ceremony (sacred thread initiation) is a Vedic samskara that marks the beginning of a child\'s formal education in Vedic knowledge. This ceremony has been performed for thousands of years and is an important tradition for preserving Vedic culture.', 'This ceremony marks a child\'s second birth (dvija) into spiritual life. It is a crucial step in preserving Vedic culture and ensuring the next generation grows up with spiritual values.', 'Sponsoring a Shiksha ceremony helps a child begin their spiritual education. Donors receive the blessings of the child\'s family and the satisfaction of helping preserve Vedic traditions for future generations.', 'event', NULL, 'assets/images/banners/shiksha-ceremony.jpg', NULL, 0, NULL, NULL, 1, 0, 'one_time', 100.00, 'cart', 91, 1, 0, NULL, NULL, '2026-06-29 21:56:55', '2026-07-03 23:31:03', '<!-- Banner Image in Content Area -->
    <div class=\"reveal\" style=\"margin-bottom: var(--space-xl); border-radius: var(--radius-lg); overflow: hidden; box-shadow: var(--shadow-md);\">
      <img src=\"{{BASE_URL}}assets/images/banners/shiksha-ceremony.jpg\" alt=\"Shiksha Ceremony\" style=\"width: 100%; height: auto; display: block;\">
    </div>
    
    <!-- Intro -->
    <div class=\"reveal\" style=\"text-align: center; margin-bottom: var(--space-3xl);\">
      <div class=\"section-divider\"><span class=\"divider-icon\">🪷</span></div>
      <h2 style=\"margin-bottom: var(--space-md);\">Formal Spiritual Commitment</h2>
      <p style=\"color: var(--text-light); max-width: 800px; margin: 0 auto; line-height: 1.8; font-size: var(--font-size-base);\">
        In the context of the International Society for Krishna Consciousness (ISKCON), the Shiksha Ceremony holds a unique significance. Founded by His Divine Grace A.C. Bhaktivedanta Swami Prabhupada in 1966, ISKCON focuses on the teachings of the Bhagavad Gita and the practice of devotional service to Lord Krishna.
      </p>
    </div>

    <!-- Overview Details -->
    <div class=\"reveal\" style=\"background: var(--white); border-radius: var(--radius-lg); padding: var(--space-xl); box-shadow: var(--shadow-sm); margin-bottom: var(--space-3xl); border: 1px solid var(--border);\">
      <h3 style=\"margin-bottom: var(--space-lg); color: var(--text-dark); display: flex; align-items: center; gap: 8px;\">
        <i class=\"fas fa-info-circle\" style=\"color: var(--primary);\"></i> Overview of the Ceremony
      </h3>
      <p style=\"color: var(--text-light); line-height: 1.7; margin-bottom: var(--space-md);\">
        The Shiksha Ceremony is a formal initiation ceremony through which individuals commit themselves to the spiritual path outlined by the organization\'s teachings. It marks a significant step for those who wish to align themselves with ISKCON\'s teachings and engage in a life dedicated to devotional service and spiritual growth.
      </p>
      
      <!-- Steps / Elements list -->
      <div style=\"display: grid; grid-template-columns: 1fr 1fr; gap: var(--space-md); margin-top: var(--space-lg);\">
        <div style=\"background: var(--cream); padding: var(--space-md); border-radius: var(--radius-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-sm);\"><i class=\"fas fa-user-clock\" style=\"color: var(--primary); margin-right: 6px;\"></i> Aspiring Devotees</h4>
          <p style=\"color: var(--text-light); font-size: var(--font-size-xs); margin: 0; line-height: 1.5;\">Serious practitioners ready to adopt Krishna conscious principles are considered aspiring devotees.</p>
        </div>
        <div style=\"background: var(--cream); padding: var(--space-md); border-radius: var(--radius-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-sm);\"><i class=\"fas fa-book-reader\" style=\"color: var(--primary); margin-right: 6px;\"></i> Preparation & Study</h4>
          <p style=\"color: var(--text-light); font-size: var(--font-size-xs); margin: 0; line-height: 1.5;\">Devotees undergo training, read books, attend classes and practice under senior guides and mentors.</p>
        </div>
        <div style=\"background: var(--cream); padding: var(--space-md); border-radius: var(--radius-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-sm);\"><i class=\"fas fa-file-contract\" style=\"color: var(--primary); margin-right: 6px;\"></i> Formal Acceptance</h4>
          <p style=\"color: var(--text-light); font-size: var(--font-size-xs); margin: 0; line-height: 1.5;\">Devotees publicly express their dedication to the spiritual path by taking vows to follow principles.</p>
        </div>
        <div style=\"background: var(--cream); padding: var(--space-md); border-radius: var(--radius-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-sm);\"><i class=\"fas fa-tag\" style=\"color: var(--primary); margin-right: 6px;\"></i> Spiritual Names</h4>
          <p style=\"color: var(--text-light); font-size: var(--font-size-xs); margin: 0; line-height: 1.5;\">Devotees receive spiritual names reflecting their commitment to devotional service.</p>
        </div>
        <div style=\"background: var(--cream); padding: var(--space-md); border-radius: var(--radius-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-sm);\"><i class=\"fas fa-pray\" style=\"color: var(--primary); margin-right: 6px;\"></i> Senior Blessings</h4>
          <p style=\"color: var(--text-light); font-size: var(--font-size-xs); margin: 0; line-height: 1.5;\">Temple leaders and mentors offer blessings, guidelines, and encouragement for spiritual growth.</p>
        </div>
        <div style=\"background: var(--cream); padding: var(--space-md); border-radius: var(--radius-md);\">
          <h4 style=\"margin: 0 0 6px 0; color: var(--text-dark); font-size: var(--font-size-sm);\"><i class=\"fas fa-tshirt\" style=\"color: var(--primary); margin-right: 6px;\"></i> Sacred Cloth</h4>
          <p style=\"color: var(--text-light); font-size: var(--font-size-xs); margin: 0; line-height: 1.5;\">Based on commitment levels, devotees receive white or saffron cloth as a dedication symbol.</p>
        </div>
      </div>

      <div style=\"margin-top: var(--space-lg); padding-top: var(--space-md); border-top: 1px dashed var(--border); font-size: var(--font-size-sm); color: var(--text-light); line-height: 1.6;\">
        <strong>Note on Diksha:</strong> The Shiksha Ceremony in ISKCON is distinct from formal initiation known as \"Diksha.\" Diksha involves a deeper level of commitment and a connection with an authorized diksha-guru, including additional vows.
      </div>
    </div>

    <!-- Five Levels of Shiksha -->
    <div class=\"reveal\" style=\"margin-bottom: var(--space-3xl);\">
      <h3 style=\"text-align: center; margin-bottom: var(--space-xl); color: var(--text-dark); display: flex; align-items: center; justify-content: center; gap: 8px;\">
        <i class=\"fas fa-graduation-cap\" style=\"color: var(--primary);\"></i> The 5 Levels of Shiksha
      </h3>

      <div style=\"display: flex; flex-direction: column; gap: var(--space-lg);\">
        
        <!-- Level 1 -->
        <div style=\"background: var(--white); border-radius: var(--radius-lg); box-shadow: var(--shadow-sm); border-left: 5px solid #a3e635; padding: var(--space-lg);\">
          <div style=\"display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--space-md);\">
            <h4 style=\"margin: 0; color: var(--text-dark); font-size: var(--font-size-md);\">LEVEL 1: Śraddhāvān</h4>
            <span style=\"background: #f4fbf0; color: #4d7c0f; padding: 2px 8px; border-radius: var(--radius-sm); font-size: 10px; font-weight: 600; border: 1px solid #d9f99d;\">LEVEL 1</span>
          </div>
          <ul style=\"padding-left: var(--space-md); margin: 0; color: var(--text-light); font-size: var(--font-size-sm); display: flex; flex-direction: column; gap: 6px;\">
            <li>To be an active devotee and attend programs regularly, participating and associating with Krishna Conscious devotees.</li>
            <li>To chant at least one round of the Hare Krishna Maha-mantra everyday.</li>
            <li>To read the teachings of Lord Krishna as given in the books of Srila Prabhupada.</li>
          </ul>
        </div>

        <!-- Level 2 -->
        <div style=\"background: var(--white); border-radius: var(--radius-lg); box-shadow: var(--shadow-sm); border-left: 5px solid #84cc16; padding: var(--space-lg);\">
          <div style=\"display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--space-md);\">
            <h4 style=\"margin: 0; color: var(--text-dark); font-size: var(--font-size-md);\">LEVEL 2: Krishna Sevak</h4>
            <span style=\"background: #ecfdf5; color: #047857; padding: 2px 8px; border-radius: var(--radius-sm); font-size: 10px; font-weight: 600; border: 1px solid #a7f3d0;\">LEVEL 2</span>
          </div>
          <ul style=\"padding-left: var(--space-md); margin: 0; color: var(--text-light); font-size: var(--font-size-sm); display: flex; flex-direction: column; gap: 6px;\">
            <li>To be dedicated to taking the divine shelter of Srila Prabhupada by following the principles of Krishna Consciousness.</li>
            <li>To accept that Lord Krishna is the Supreme Personality of Godhead.</li>
            <li>To engage in practical devotional service to Lord Krishna during festivals such as Sri Krishna Janmastami, Gaura Purnima, etc.</li>
            <li>To chant a minimum of four rounds of the Hare Krishna Maha-mantra everyday.</li>
            <li>To refrain from eating non-vegetarian food (meat, fish, and eggs) and try to lead a moral life.</li>
          </ul>
        </div>

        <!-- Level 3 -->
        <div style=\"background: var(--white); border-radius: var(--radius-lg); box-shadow: var(--shadow-sm); border-left: 5px solid var(--accent); padding: var(--space-lg);\">
          <div style=\"display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--space-md);\">
            <h4 style=\"margin: 0; color: var(--text-dark); font-size: var(--font-size-md);\">LEVEL 3: Krishna Sādhaka</h4>
            <span style=\"background: #fff7ed; color: #c2410c; padding: 2px 8px; border-radius: var(--radius-sm); font-size: 10px; font-weight: 600; border: 1px solid #ffedd5;\">LEVEL 3</span>
          </div>
          <ul style=\"padding-left: var(--space-md); margin: 0; color: var(--text-light); font-size: var(--font-size-sm); display: flex; flex-direction: column; gap: 6px;\">
            <li>To be dedicated to leading a devotional way of life, by gradually learning and practicing Bhakti-Yoga, according to the teachings of Srila Prabhupada under the guidance of his representatives.</li>
            <li>To study the books of Srila Prabhupada and attend classes as often as possible (at least the weekend Bhagavad-Gita class every week).</li>
            <li>To worship Lord Krishna, as far as practical in the home, by setting up an altar, offering arati and foodstuffs, worshiping the sacred Tulasi plant, and following basic sadhana like rising early in the morning.</li>
            <li>To chant eight to sixteen rounds of the Hare Krishna Maha-mantra everyday.</li>
            <li>To lead a pure, holy life by avoiding intoxication (alcoholic drinks and smoking), meat-eating, gambling, and extra-marital sex.</li>
            <li>To observe fasting on Ekadasi and festival days as indicated in the Vaishnava Calendar.</li>
          </ul>
        </div>

        <!-- Level 4 -->
        <div style=\"background: var(--white); border-radius: var(--radius-lg); box-shadow: var(--shadow-sm); border-left: 5px solid var(--primary); padding: var(--space-lg);\">
          <div style=\"display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--space-md);\">
            <h4 style=\"margin: 0; color: var(--text-dark); font-size: var(--font-size-md);\">LEVEL 4: Srila Prabhupada Āśraya</h4>
            <span style=\"background: #fff7ed; color: var(--primary); padding: 2px 8px; border-radius: var(--radius-sm); font-size: 10px; font-weight: 600; border: 1px solid #ffedd5;\">LEVEL 4</span>
          </div>
          <ul style=\"padding-left: var(--space-md); margin: 0; color: var(--text-light); font-size: var(--font-size-sm); display: flex; flex-direction: column; gap: 6px;\">
            <li>To be dedicated to taking divine shelter of Srila Prabhupada by following the principles of Krishna Consciousness with strong conviction.</li>
            <li>To chant a minimum of sixteen rounds of the Hare Krishna Maha-mantra everyday.</li>
            <li>To strictly avoid intoxication including coffee and tea, meat-eating including onion and garlic, gambling, mundane cinema, sports, and illicit sex.</li>
            <li>To be well-versed in the basics of Krishna conscious philosophy by reading the books of Srila Prabhupada systematically and actively engaging in preaching (according to capacity) to others.</li>
            <li>To do some responsible service (however simple it may be) on a regular basis.</li>
            <li>To follow a strict sadhana program at home by rising early and following a program similar to the temple as far as possible.</li>
            <li>To attend at least one Srimad Bhagavatam/Bhagavad-Gita class every week.</li>
          </ul>
        </div>

        <!-- Level 5 -->
        <div style=\"background: var(--white); border-radius: var(--radius-lg); box-shadow: var(--shadow-sm); border-left: 5px solid #7c3aed; padding: var(--space-lg);\">
          <div style=\"display: flex; justify-content: space-between; align-items: center; margin-bottom: var(--space-md);\">
            <h4 style=\"margin: 0; color: var(--text-dark); font-size: var(--font-size-md);\">LEVEL 5: Śrī Guru Caraṇa Āśraya</h4>
            <span style=\"background: #faf5ff; color: #6d28d9; padding: 2px 8px; border-radius: var(--radius-sm); font-size: 10px; font-weight: 600; border: 1px solid #e9d5ff;\">LEVEL 5</span>
          </div>
          <p style=\"color: var(--text-light); font-size: var(--font-size-sm); margin: 0 0 var(--space-sm) 0; line-height: 1.6;\">
            After a minimum of six months of following Srila Prabhupada Ashraya standards, one may select an ISKCON-authorized diksha guru from amongst one\'s established siksha gurus. Note that six months is the minimum period, and one may take as much time as required to make this selection.
          </p>
          <h5 style=\"margin: var(--space-sm) 0 var(--space-xs) 0; color: var(--text-dark); font-size: var(--font-size-sm);\">Candidates\' Responsibility & Process:</h5>
          <ul style=\"padding-left: var(--space-md); margin: 0; color: var(--text-light); font-size: var(--font-size-sm); display: flex; flex-direction: column; gap: 4px;\">
            <li>Select guru by the exercise of their own intelligence.</li>
            <li>Notify the local Temple President or relevant authority.</li>
            <li>Take written examination issued by ISKCON authority.</li>
            <li>Receive formal letter of recommendation from ISKCON authority.</li>
            <li>Receive permission from the selected guru.</li>
          </ul>
        </div>

      </div>
    </div>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (49, 'lord-vamanadeva', 'Sri Vamana Dwadashi', 'Lord Vamanadeva', 'Appearance day of Lord Vamanadeva, the dwarf incarnation of Lord Vishnu who appeared to reclaim the universe from King Bali Maharaja.', 'Lord Vamanadeva is the fifth incarnation of Lord Vishnu, appearing as a dwarf Brahmin during the reign of the great demon king Bali Maharaja. Bali had conquered the three worlds through his extraordinary performance of a hundred Ashvamedha sacrifices. The demigods, having lost their celestial abode, approached Lord Vishnu for protection. The Lord appeared as Vamana — a beautiful dwarf Brahmin boy — and approached Bali during a grand sacrifice. With just three paces of land, Vamana covered the entire universe: one pace measured the earth, the second measured the heavens, and for the third, Bali offered his own head. The Lord pushed Bali down to the netherworld (Patala) but blessed him with the sovereignty of Patala and the boon of being worshipped before Lord Vishnu Himself. This pastime is described in the Srimad-Bhagavatam, Canto 8, Chapters 15-23.', 'Vamanadeva\'s appearance demonstrates the unlimited power隐藏 within the Lord\'s seemingly humble form. The dwarf Brahmin, though small in stature, measured the entire cosmos in three steps — teaching that spiritual power transcends physical appearance. This incarnation also establishes the importance of keeping one\'s word: when Bali Maharaja promised three paces of land, he honored his pledge even at the cost of his kingdom. The festival celebrates the triumph of divine justice and the Lord\'s protection of the cosmic order (dharma). It falls during Shravana month, one of the most auspicious periods for spiritual practices.', 'Observing Vamanadeva\'s appearance day invokes the Lord\'s blessings for humility, truthfulness, and spiritual strength. The fast purifies the mind and helps the devotee develop the quality of keeping one\'s word. Donations made on this day — especially to Brahmins and temples — bring immense spiritual merit. The observer is blessed with protection from enemies, freedom from obstacles, and progress in devotional life. Worshipping Lord Vamana on this day grants the same blessings that Bali Maharaja received: the Lord\'s eternal grace and a place in the spiritual world.', 'festival', NULL, 'assets/images/banners/lord-vamanadeva-appearance-banner.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 101.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:07:56', '2026-07-03 23:27:51', '<p>
        Lord Vamanadeva appeared within this world from the womb of Aditi, the Mother of the Gods. He appeared at midday on the <em>shravan-dvadasi</em>, the 12th day of the lunar month of Shravan when the moon is waxing. The Supreme Lord appeared as the son of Kashyapa and Aditi in the form of a dwarf Brahmana (Vamana) to deliver Bali Maharaja, a great devotee born in the family of demons.
      </p>
      
      <p>
        Vedic history tells of an incident many hundreds of thousands of years ago, during a period of conflict between the Devas and Danavas (universal governing forces and anti-government atheists), when the Danavas came to power, sending the legitimate royal families of Devas into hiding. The Devas prayed to Lord Vishnu, the maintainer of the universe, to help them regain their rightful properties and administrative posts.
      </p>

      <blockquote style=\"border-left:4px solid var(--primary); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"O wonderful dwarf, by Your massive steps You deceive King Bali, and by the Ganges water that has emanated from the nails of your lotus feet, You deliver all living beings within this world.\"
      </blockquote>

      <p>
        The Lord then appeared as a dwarf, the extraordinarily beautiful miniature child brahmana Vamanadeva. In this disguise, the all-powerful Supreme Personality of Godhead approached Bali Maharaja, king of the Danavas.
      </p>
      
      <p>
        Bali could understand that Vamanadeva was a higher being, from His uncommon attractiveness and effulgence. The king was prepared to grant Him anything He asked for. On the pretense of begging, Vamanadeva asked Bali for a seemingly insignificant piece of real estate – three paces of land – to which Bali agreed, despite protests from his guru, Sukracarya.
      </p>
      
      <p>
        Vamanadeva then assumed a gigantic form (Trivikrama) that covered the universe. With His first step, he reached to the heavenly planets, and with His second, He reached the limit of the universe. It appeared that Bali was unable to fulfill his promise, since he had promised Vamanadeva three steps, so he humbly asked the Lord to place His remaining step on his head.
      </p>
      
      <p style=\"margin-top:var(--space-md); border-top:1px dashed var(--border); padding-top:var(--space-lg); font-weight:500; text-align:center; color:var(--primary-dark);\">
        For a more complete version of the history of Vamanadeva, please refer to the Srimad-Bhagavatam, Eighth Canto, chapters 18 and 19.
      </p>', 'Appearance Date: Midday on Shravan Dwadashi (12th day of the waxing moon of Shravan)|Form: Dwarf Brahmana (Vamana)|Parents: Kashyapa Muni & Aditi Devi|Primary Pastime: Begging three paces of land from King Bali Maharaja to reclaim the universe.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (50, 'saphala', 'Saphala Ekadashi', 'Saphala Ekadashi', 'Makes all activities successful and helps the fallen soul achieve pure love of God.', 'Saphala Ekadashi falls during the Krishna Paksha of the Pausha month (December-January). The name \"Saphala\" means \"fruitful\" or \"successful.\" This Ekadashi is described in the Padma Purana, where Lord Krishna narrates its glories to Yudhishthira Maharaja. The story involves King Mahishmati, whose son was cursed by a brahmana to become a demon. The prince lived in a forest, surviving on fruits and roots, and observed this Ekadashi with great devotion. His sincere observance broke the curse, and he regained his human form and kingdom.', 'Saphala Ekadashi is known for granting the fulfillment of desires and making life truly fruitful. Observing this fast purifies the heart and mind, removing obstacles that prevent spiritual progress. The Padma Purana states that even simple observance of this Ekadashi brings results equal to worshipping the Lord with a thousand sacrifices. It is especially powerful for those seeking success in their endeavors and relief from material difficulties.', 'Devotees who observe Saphala Ekadashi with sincerity receive the blessings of Lord Vishnu for success in all undertakings. The fast destroys sins accumulated over many lifetimes and grants material prosperity alongside spiritual advancement. Those who donate food and charity on this day receive manifold returns. The observer is freed from the reactions of sinful activities and progresses toward liberation. Families observe this Ekadashi for overall well-being and harmony.', 'ekadashi', NULL, 'assets/images/banners/saphala-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Saphala Ekadashi is one of the most pious and favorable fasting days. It takes place in the Pausha month during the Krishna Paksha on the 11th day (waning phase of the Moon). Saphala Ekadashi is also well known as Pausha Krishna Ekadashi, which usually falls in the months of December or January as per the Gregorian calendar.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Saphala Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishya-uttara Purana
      </p>
      
      <p>
        Yudhisthira Maharaj said, \"O my Dear Lord Sri Krishna, what is the name of that Ekadasi that occurs during the dark fortnight of the month of Pausha (December-January)? How is it observed, and which Deity is to be worshipped on that sacred day? Please narrate these details to me fully, so that I may understand, Oh Janardana.\"
      </p>
      
      <p>
        The Supreme Personality of Godhead Sri Krishna then replied, \"O best of kings, because you desire to hear, I shall fully describe to you the glories of the Pausha-krishna Ekadasi. I do not become as pleased by sacrifice or charity as I do by My devotees\' observance of a full fast on Ekadasi. To the best of one\'s ability, therefore, one should fast on Ekadasi, the day of Lord Hari.\"
      </p>
      
      <p>
        \"Pausha-krishna Ekadasi is also known as Saphala Ekadasi. On this sacred day, one should worship Lord Narayana, for He is its ruling Deity. Just as among snakes Shesha-naga is the best, among birds Garuda is the best, among sacrifices the Ashvamedha-yajna is the best, among rivers Mother Ganges is the best, among gods Lord Vishnu is best, so among all fasting days Ekadasi is by far the best.\"
      </p>
      
      <p>
        \"On Saphala Ekadasi, My devotee should worship Me by offering Me fresh fruits according to time, place, and circumstance, and by meditating on Me as the all-auspicious Supreme Personality. He should offer Me jambira fruit, pomegranate, betel nuts and leaves, coconut, guava, nuts, cloves, mangoes, and different kinds of aromatic spices. He should also offer Me incense and bright ghee lamps, for such an offering of lamps on Saphala Ekadasi is especially glorious. The devotee should try to stay awake all the Ekadasi night.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of the Sinful Prince Lumpaka</h3>
      <p>
        \"Once there was a city called Champavati, which was ruled by the saintly King Mahishmata. He had four sons, the eldest of whom, Lumpaka, always engaged in all manner of very sinful activities – illicit sexual encounters, gambling, and continual association with prostitutes. His evil deeds gradually reduced the wealth of his father. Lumpaka also became very critical of the numerous devas, the empowered universal attendants of the Lord, as well as toward the brahmins, and every day he would go out of his way to blaspheme the Vaishnavas. At last, King Mahishmata, seeing the unrepentant brazen fallen condition of his son, exiled him to the forest.\"
      </p>
      
      <p>
        \"Bewildered in his exile, Lumpaka entered the darkness of the forest. He killed many animals by day, and by night he sneaked back to steal from the city. The city-dwelling folk apprehended him several times, but out of fear of the king, they left him alone. Though a meat-eater, Lumpaka would also eat fruits. He resided under an old banyan tree that, unknown to him, happened to be very dear to Lord Vasudeva. Indeed, it was worshipped as the representative head of all the trees in the forest.\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"On the eve of the Saphala Ekadasi (Dashami), Lumpaka had to pass the entire night without sleep because of severe cold. The cold not only robbed him of all peace but almost of his very life. By the time the sun rose, he was near dead, his teeth chattering, and near comatose. He remained in that stupor all morning. When midday of the Saphala Ekadasi arrived, Lumpaka finally came to and rose up, but stumbled. Weak from hunger, he couldn\'t hunt and was reduced to collecting fruits that had fallen to the ground. By the time he returned to his banyan tree, the sun had set.\"
      </blockquote>

      <p>
        \"Placing the fruits on the ground at the base of the banyan tree, Lumpaka began to cry out: \'O, woe is me! What should I do? O Sri Hari, please be merciful to me and accept these fruits as an offering!\' He was forced to lie awake the whole night without sleep. But in the meantime, the all-merciful Supreme Personality of Godhead, Lord Madhusudana, had become pleased with Lumpaka\'s humble offering of forest fruits, and He accepted them. Lumpaka had unknowingly observed a full Ekadasi fast.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Redemption and Return</h3>
      <p>
        \"As the sun rose on the day following Ekadasi (Dvadashi), a handsome horse stood next to Lumpaka. At the same time, a voice suddenly boomed out from the clear blue sky saying: \'This horse is for you, Lumpaka! Mount it and ride swiftly to greet your family! O son of King Mahishmata, by the mercy of Lord Vasudeva and the strength of the merit you acquired by Saphala Ekadasi, your kingdom will be returned without hindrances. Go now to your father.\'\"
      </p>
      
      <p>
        \"Lumpaka mounted the horse and rode back to Champavati. He offered his father his humble obeisances, and King Mahishmata, seeing his son decorated with tilak, gave him the kingdom. Lumpaka ruled unopposed for many years, worshipping the Supreme Lord Narayana with great devotion on every Ekadasi. In old age, he handed the kingdom to his son and retired to the forest, purified of all material desires. He left his old body and returned back to home, back to Godhead, near the lotus feet of Sri Krishna.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"O Yudhisthira, anyone who properly observes Saphala Ekadasi – even unknowingly, like Lumpaka – will become famous, liberated at death, and return to Vaikuntha. One who simply hears the glories of Saphala Ekadasi obtains the same merit derived from performing a Rajasuya-yajna.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Pausha month (December/January)|Alternative Names: Pausha Krishna Ekadashi, Saphala Ekadashi|Meaning of name: \"Saphala\" refers to success or make all devotional activities successful (fruitful).|Worshipable Deity: Lord Sri Narayana|Rules: Full fast from grains and beans. Worship the Lord by offering fresh fruits (jambira, pomegranate, coconut, guava) and bright ghee lamps.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (51, 'putrada', 'Pausha-putrada Ekadashi', 'Putrada Ekadashi', 'Bestows a qualified, pious son and delivers ancestors from hellish realms.', 'Pausha Putrada Ekadashi falls during the Krishna Paksha of the Pausha month (December-January). The name means \"bestower of sons.\" This Ekadashi is described in the Brahma Vaivarta Purana, where Lord Krishna explains to Yudhishthira Maharaja the story of a king named Sumedha who had no children despite being righteous. His wife observed this Ekadashi with great devotion and prayed for a child. Pleased by her sincerity, the Lord blessed them with a glorious son who became a great king.', 'Putrada Ekadashi holds special significance for those desiring children and for the welfare of existing children. In Vedic culture, having children — especially devoted sons — is considered one of the most important responsibilities of grihastha life. This Ekadashi is observed to invoke the blessings of Lord Vishnu for progeny and for the protection and well-being of children. It also signifies the importance of raising children in spiritual consciousness.', 'Observing Putrada Ekadashi blesses childless couples with the boon of children. For those who already have children, it ensures their health, wisdom, and spiritual progress. The fast purifies the consciousness of the parents, enabling them to raise their children in a spiritually conducive environment. Donations made on this day — especially to educational institutions and temples — bring lasting merit. The observer is blessed with family happiness and the joy of raising devoted children.', 'ekadashi', NULL, 'assets/images/banners/putrada-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Putrada Ekadasi falls on the 11th lunar day of the fortnight of the waxing moon in the Vedic month of Pausha (December/January). This day is also known as Pausha Putrada Ekadashi, to differentiate it from the other Putrada Ekadashi in the month of Shravana (July/August), which is also called Shravana Putrada Ekadasi.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Putrada Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishya Purana
      </p>
      
      <p>
        The pious and saintly Yudhishthira Maharaj said, \"Oh Lord, You have so nicely explained to us the wonderful glories of the Saphala Ekadasi. Now please be merciful to me and explain to me the details of the Ekadasi that occurs in the light fortnight (Shukla or Gaura paksha) of this month. What is its name, and what Deity is to be worshipped? Oh Purushottama, please also tell me how You can be pleased on this day.\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"Oh saintly king, for the benefit of all humanity I shall now tell you how to observe fasting on the Pausha-shukla Ekadasi. Everyone should observe the rules of the Ekadasi vrata, to the very best of their ability. This injunction also applies to the Ekadasi named Putrada, which destroys all sins and elevates one to the spiritual abode. The Supreme Personality of Godhead Shri Narayana, the original personality, is the worshippable Deity of the Ekadasi, and for His faithful devotees He happily fulfils all desires.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Despair of King Suketuman</h3>
      <p>
        \"There was once a kingdom named Bhadravati, which was ruled by King Suketuman. His queen was the famous Shaibya. Because he had no son, he spent a long time in anxiety, thinking: \'If I have no son, who will carry on my dynasty?\' In this way the king meditated in a religious attitude, thinking: \'Where should I go? What should I do?\' Neither Suketuman nor Queen Shaibya could find happiness anywhere, and they spent their days in deep gloom.\"
      </p>
      
      <p>
        \"Even when they offered tarpana (oblations of water to their forefathers), their mutual misery made them think that it was as undrinkable as boiling water. They thought that they would have no descendants to offer tarpana to them when they died. The king and queen were especially upset to learn that their forefathers were worried that soon there would be no one to offer them tarpana also.\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"The king thought to himself: \'It is said that without a son, marriage is wasted. Indeed, for a family man with no son, both his heart and his house remain vacant. Bereft of a son, a man cannot liquidate the debts that he owes his forefathers, the demigods, and other human beings. A son is proof of the pious activities a man performed in his past lifetimes, proving that one has worshipped Lord Vishnu in the past.\'\"
      </blockquote>

      <p>
        \"Suffering constant anxiety, King Suketuman decided to end his misery by committing suicide. But he realized that suicide throws a person into hellish conditions of rebirth, and so he abandoned that idea. At last, he mounted his horse and left for the dense forest alone.\"
      </p>
      
      <p>
        \"In that forest, which was filled with deer, birds, and wild beasts, the king wandered aimlessly. He saw deer, tigers, wild boars, lions, monkeys, snakes, and cow elephants with their calves. Beholding all these animals with their mates and offspring, the king became so sad that he wandered fitfully. Tormented by hunger and thirst at midday, he thought: \'What sinful deed could I have done to suffer like this? I have pleased the demigods with sacrifices and given gifts to worthy brahmins. Why am I suffering?\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Assembly of the Vishvadevas</h3>
      <p>
        \"Absorbed in these thoughts, the king came upon a beautiful pond filled with lilies, swans, cranes, and lotuses. Nearby were many attractive ashramas, where there resided many saints and sages. When the king saw this, his right arm and right eye began to quiver – an auspicious sign.\"
      </p>
      
      <p>
        \"As the king dismounted and stood before the sages, who were chanting on japa beads, he paid his obeisances. The sages said, \'We are very pleased with you, Oh king. Kindly tell us why you have come here.\' The king replied, \'Oh great sages, who are you? What are your names?\'\"
      </p>
      
      <p>
        \"The sages replied, \'Oh king, we are known as the ten Vishvadevas (the sons of Vishva: Vasu, Satya, Kratu, Daksha, Kaala, Kaama, Dhriti, Pururavaa, Maadrava, and Kuru). We have come to this pond to bathe. The month of Magha will soon be here in five days, and today is the famous Putrada Ekadasi. One who desires a son should strictly observe this fast.\'\"
      </p>
      
      <p>
        \"The king said, \'I have tried so hard to have a son. If you are pleased with me, kindly grant the boon of having a good son.\'\"
      </p>
      
      <p>
        \"The sages replied, \'The very meaning of Putrada is \"giver of a son.\" So please observe a complete fast on this Ekadasi day. If you do so, then by our blessing – and the mercy of Lord Keshava – you will obtain a son.\'\"
      </p>
      
      <p>
        \"On the advice of the Vishvadevas, the king observed the fast of Putrada Ekadasi according to the regulations, and on Dvadashi, after breaking his fast, he paid obeisances to them and returned to his palace.\"
      </p>
      
      <p>
        \"Queen Shaibya immediately became pregnant, and exactly as predicted, a beautiful, bright-faced son was born to them. In due course, he became famous as a heroic prince, succeeding his father and ruling the kingdom conscientiously.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"One who wishes to fulfill his desires should strictly observe Putrada Ekadasi. While on this planet, one will surely obtain a son, and after death achieve liberation. Anyone who reads or hears its glories obtains the merit of a horse sacrifice.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Pausha month (December/January)|Alternative Names: Pausha Putrada Ekadashi|Worshipable Deity: Lord Sri Narayana|Significance: Bestows a qualified, pious son (putra) to carry on the family lineage, delivers ancestors from hellish conditions, and grants ultimate liberation.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (52, 'sattila', 'Sat-tila Ekadashi', 'Sat-tila Ekadashi', 'Purifies through six uses of sesame seeds and provides liberation from poverty and sin.', 'Sat-tila Ekadashi falls during the Krishna Paksha of the Magha month (January-February). The name \"Sat-tila\" refers to the seven types of sesame (tila) used in the observance. This Ekadashi is described in the Padma Purana, where Lord Krishna tells Yudhishthira about a brahmani (brahmana\'s wife) who was very devoted but poor. She observed this Ekadashi by bathing in sesame water, offering sesame in fire sacrifices, eating sesame preparations, and donating sesame to brahmanas. Through this sevenfold use of sesame, she purified herself and attained liberation.', 'Sat-tila Ekadashi emphasizes the spiritual potency of sesame (tila) in Vedic rituals. Sesame is considered highly sacred and is used in Shraddha ceremonies, fire sacrifices, and worship of Lord Vishnu. This Ekadashi teaches that even simple, sattvic offerings made with devotion are more pleasing to the Lord than elaborate rituals performed without sincerity. It is also observed to honor departed ancestors and seek their blessings.', 'Observing Sat-tila Ekadashi with the sevenfold use of sesame grants liberation from sinful reactions. The fast purifies the body and mind, removing impurities accumulated through wrongdoings. Donating sesame to brahmanas and temples on this day is considered extremely meritorious and helps in Shraddha karma for ancestors. The observer receives the grace of Lord Vishnu and progress on the spiritual path. It also brings peace to departed family members.', 'ekadashi', NULL, 'assets/images/banners/sattila-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Sat-tila Ekadasi is also known as Trisprisha Ekadasi. This Ekadasi occurs in the dark fortnight of the month of Magha (January/February). The glories of Sat-tila Ekadasi are narrated in the Bhavisyottara Purana in a conversation between the sage Dalbhya and Pulastya Muni.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Sat-tila Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavisyottara Purana
      </p>
      
      <p>
        Sri Daalbhya Rishi said to Pulastya Muni, \"When the spirit soul comes in contact with the material energy, he immediately begins to perform sinful activities, such as stealing, killing, and illicit sex. He may even perform many other terrible deeds, such as killing a brahmana. Oh purest of personalities, please tell me how these unfortunate souls may escape the punishment of being sent to hellish regions of creation. Kindly inform me how, by giving even a little in charity, one may be easily released from the reactions of his sins.\"
      </p>
      
      <p>
        Pulastya Muni replied, \"Oh fortunate one, you have asked me an important and confidential question, which not even Brahma, Vishnu, Shiva, or Indra has ever asked. Please listen very carefully to my answer.\"
      </p>
      
      <p>
        \"With the arrival of the month of Magha (January - February), one should bathe, carefully control his senses by giving up lust, anger, pride, jealousy, faultfinding, and greed, and meditate on the Supreme Personality of Godhead Lord Sri Krishna. One should then gather up some cow dung before it touches the ground and, after mixing it with sesame seeds and cotton, form 108 balls. This should be done on the day when the constellation of Purva-ashadha nakshatra arrives. Then one should follow the rules of Sri Ekadasi.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Six Pure Uses of Sesame (Tila)</h3>
      <p>
        Pulastya Muni explained that on this day, black sesame seeds are especially suitable for formal worship and fire sacrifices:
      </p>
      
      <ol style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Bathing</strong> in water mixed with sesame seeds.</li>
        <li><strong>Rubbing</strong> sesame seed paste (ubtan) on the body.</li>
        <li><strong>Offering</strong> sesame seeds into the sacred fire in sacrifice (108 cow dung & sesame balls).</li>
        <li><strong>Eating</strong> sesame seeds.</li>
        <li><strong>Giving</strong> sesame seeds away in charity.</li>
        <li><strong>Accepting</strong> charitable gifts of sesame seeds.</li>
      </ol>
      
      <p>
        These are the six (sat) ways in which sesame seeds (tila) are utilized for spiritual purification on this Ekadasi. Therefore it is called Sat-tila Ekadasi.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Stingy Brahmini and the Lump of Mud</h3>
      <p>
        Lord Sri Krishna personally narrated the following story to Devarishi Narada Muni:
      </p>
      
      <p>
        \"Long ago on earth, there lived an old female brahmini who worshipped Me every day with controlled senses. She very faithfully observed many a fast and served Me with full devotion, devoid of any personal motive. Her rigorous fasting made her quite weak and thin. She gave charity to brahmanas and young maidens, and even planned to give away her house. Although this spiritually minded woman gave charitable donations to worthy people, the odd feature of her austerity was that she never gave food to brahmanas or the devas.\"
      </p>
      
      <p>
        \"I began to reflect on this curious omission: \'This fine woman has purified herself by fasting and devotional worship. Therefore she has become eligible to enter My personal abode. So I came down to this planet to examine her, disguising Myself as a follower of Lord Shiva\'s, complete with a begging pot (kamandalu) in My hand.\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"As I approached her, she said to Me, \'Oh respectful one, tell me truthfully why You have come before me.\' I replied, \'Oh beautiful one, I have come to get some alms from you\' – whereupon she angrily threw a dense lump of mud into My begging pot! I simply turned around and went back to My abode.\"
      </blockquote>

      <p>
        \"At last, this austere lady reached the spiritual world in her self-same body. And because she had offered Me a lump of mud, I transformed that mud into a beautiful home. However, this house was completely empty of any grains, food, or furniture. She approached Me and said, \'I have fasted repeatedly on so many occasions, making my body weak and thin. Yet there is no food or wealth to be seen in my new home, Oh Janardana. Why is this?\'\"
      </p>
      
      <p>
        \"I replied, \'Please return to your house. Sometime later the wives of the devas (demigods) will pay you a visit out of curiosity. Do not open your door until they have described to you the glories and importance of Sat-tila Ekadasi.\'\"
      </p>
      
      <p>
        \"Hearing this, she returned. When the devas\' wives arrived and asked to see her, she replied, \'If you want me to open this door, you must describe to me the merit of Sat-tila Ekadasi.\' One of the wives nicely explained the sublime nature of this sacred Ekadasi. When the lady opened her door, they saw that she was simply an ordinary human lady.\"
      </p>
      
      <p>
        \"From then on, the lady observed Sat-tila Ekadasi, which awards all material enjoyment and liberation at the same time. She finally received the beautiful furnishings and grains she had expected. Moreover, her body was transformed into a beautiful spiritual form made of sac-cid-ananda (eternality, knowledge, and bliss).\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"Oh Naradaji, a person should not ostentatiously observe Ekadasi out of greed. Selflessly, he should simply donate sesame seeds, clothes, and food according to his capacity. Following this Ekadasi fast by donating, sacrificing, or eating sesame seeds frees one of all past sins, without a doubt.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Magha month (January/February)|Alternative Names: Trisprisha Ekadasi, Magha Krishna Ekadasi|Meaning of name: \"Sat-tila\" refers to the six (sat) ways sesame seeds (tila) are used for spiritual purification.|Worshipable Deity: Lord Sri Krishna / Janardana|Rules: Full fast from grains and beans. Focus on utilizing sesame seeds in six scriptural ways and giving charity according to capacity.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (53, 'bhaimi', 'Bhaimi Ekadashi (Jaya Ekadashi)', 'Bhaimi Ekadashi', 'Eradicates the heaviest sins, grants spiritual strength, and frees one from ghostly existences.', 'Bhaimi Ekadashi, also known as Jaya Ekadashi, falls during the Krishna Paksha of the Magha month (January-February). This Ekadashi is described in the Vishnu Purana, where the story of King Harishchandra is narrated. The king had lost his kingdom, wife, and son due to a curse. When his son was about to be cremated, the king remembered this Ekadashi and observed it with devotion. Lord Vishnu appeared and restored everything — his son came back to life, his kingdom was returned, and he regained his glory.', 'Bhaimi Ekadashi holds the power to reverse misfortunes and restore what has been lost. It is observed during the auspicious Magha month when the influence of spiritual practices is heightened. This Ekadashi teaches that even in the darkest moments of life, sincere devotion to the Lord can turn the tide. It is also associated with overcoming enemies and obstacles, as the name \"Jaya\" means \"victory.\"', 'Devotees who observe Bhaimi Ekadashi receive divine protection from enemies and obstacles. The fast has the power to reverse curses and restore lost fortunes — wealth, health, relationships, and position. Those who donate food, clothes, and sesame on this day receive immense merit. The observer is blessed with victory over all challenges and the grace of Lord Vishnu for a prosperous and peaceful life.', 'ekadashi', NULL, 'assets/images/banners/bhaimi-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Vaishnava Jaya (Bhaimi) Ekadasi is an important fasting ritual observed on the 11th day during the Shukla Paksha (the bright fortnight of the moon) in the month of Madhava in the Vaishnava calendar. This observance falls between the months of January to February in the Gregorian calendar. Jaya Ekadasi is also popularly called Bhaimi Ekadasi, and it is strongly believed that one who observes a righteous fast on this day will find a place in Vaikuntha. Observing the Vaishnava Jaya Ekadasi vrata is equivalent to observing all other Ekadasi fasts.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Jaya (Bhaimi) Ekadashi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishyottara Purana
      </p>
      
      <p>
        The narration of the glories of Magha-Shukla Ekadasi or Jaya (Bhaimi) Ekadashi is found in the Bhavishyottara Purana in a conversation between Maharaja Yudhishthira and Lord Krishna. It is said that one who observes upavasa (fasting) on this day is granted entry into Lord Vishnu\'s abode, even if they have not performed other vratas of the year. The half-day fast (vrata) for the appearance day of Lord Varahadev on the following day, Varaha Dvadasi, is also observed on this Ekadashi.
      </p>
      
      <p>
        Yudhishthira Maharaj said, \"Oh Lord of the lords, Sri Krishna, all glories unto You! Oh Master of the universe, You alone are the source of the four types of living entities – those born from eggs, those born from perspiration, those born from seeds, and those born from embryos. You alone are the root cause of all, Oh Lord, and therefore You are the creator, maintainer, and destroyer.\"
      </p>
      
      <p>
        \"My Lord, You have so kindly explained to me the day known as Sat-tila Ekadasi. Now please explain to me the Ekadasi that occurs in the light fortnight (shukla or Gaura paksha) of this month of Magha. By what name is it known, and what is the process for observing it? Who is the presiding Deity to be worshipped?\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"Oh Yudhishthira, I shall gladly tell you about the Ekadasi that occurs during the light half of this month of Magha. This Ekadasi obliterates all kinds of sinful reactions and demoniac influences that may be affecting the spirit soul. It is known as Jaya Ekadasi, and the fortunate soul who observes a fast on this sacred day is relieved of the great burden of ghostly existence. Thus there is no better Ekadasi than this, for it bestows freedom from birth and death. Listen to Me very attentively, Oh Pandava, as I explain a wonderful historic episode regarding this Ekadasi, which I have also related in the Padma Purana.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of Malyavan and Pushpavati</h3>
      <p>
        \"Long, long ago in the heavenly planets, Lord Indra ruled his celestial kingdom very nicely, and all the devas (demigods) living there were happy and content. In Nandana Forest, which was beautifully graced with Parijata Flowers, Indra drank ambrosia and enjoyed the dancing of celestial Apsaras.\"
      </p>
      
      <p>
        \"Many singers, led by Pushpadanta, sang in sweet voices beyond compare. Chitrasena, Indra\'s chief musician, was there in the company of his wife Malini and his handsome son Malyavan. An Apsara named Pushpavati became very much attracted to Malyavan; indeed Cupid\'s sharp arrows pierced the core of her heart. Her beautiful body and complexion, along with the enchanting movements of her eyebrows, captivated Malyavan.\"
      </p>
      
      <p>
        \"Seeing Pushpavati in all her heavenly beauty, Malyavan was bewitched at once. They had come with the other performers to please Lord Indra by singing and dancing, but because they had become so enamored of each other, pierced through the heart by the arrows of Cupid, they were utterly unable to sing or dance properly before the lord of the heavenly realms.\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Their pronunciation was wrong and their rhythm careless. Lord Indra understood the source of the errors at once. Offended at the discord in the musical performance, he became very angry and screamed: \'You useless fools! You pretend to sing for me while in a stupor of infatuation with each other! You are mocking me! I curse you both to suffer henceforth as pisachas (hobgoblins). As husband and wife, go to the earthly regions and reap the reactions of your offenses.\'\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Redemption on the Himalayan Peaks</h3>
      <p>
        \"Struck dumb by these harsh words, Malyavan and Pushpavati at once became morose and fell from the beautiful Nandana Forest to a Himalayan peak here on planet Earth. Immeasurably distressed, and their celestial intelligence vastly diminished by the effects of Indra\'s curse, they lost their sense of taste and smell, and even their sense of touch. It was so cold and miserable high on the Himalayan wastes of snow and ice that they could not even enjoy the oblivion of sleep.\"
      </p>
      
      <p>
        \"Roaming aimlessly in those harsh altitudes, they suffered more and more. Even though they were situated in a cave, because of the snowfall and cold their teeth chattered ceaselessly. Malyavan said, \'What abominable sins did we commit to have to suffer in these pisacha bodies? This is absolutely hellish! Therefore it is abundantly clear that one should never commit sins.\'\"
      </p>
      
      <p>
        \"By their great good fortune, however, it so happened that very day was the all-auspicious Jaya Ekadasi. Because of their misery, they neglected to drink any water, kill any game, or eat any fruits. They unknowingly observed Ekadasi by fasting completely from all food and drink. Sunk in misery, Malyavan and Pushpavati collapsed beneath a Pipal tree. The sun set, and the night was even colder. They shivered and embraced just to keep warm. Thus they suffered through the whole night, staying awake in their agony.\"
      </p>
      
      <p>
        \"Still, Oh Yudhishthira, by the mercy of the fast they had by chance (unknowingly) observed on Jaya Ekadasi, and because they had remained awake all night, they were blessed. As Dvadashi dawned, they had given up their demonic forms and were once again beautiful heavenly beings wearing lustrous ornaments. A celestial airplane (vimana) arrived on the spot for them. A chorus of heavenly denizens sang their praises as the reformed couple stepped into the aircraft and proceeded directly to Lord Indra\'s capital city, Amaravati.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Indra\'s Obeisances</h3>
      <p>
        \"Lord Indra was astonished to see them restored to their original status and forms so soon. He asked, \'What extraordinary meritorious deeds have you performed so that you could give up your pisacha bodies so quickly after I cursed you? Who released you?\'\"
      </p>
      
      <p>
        \"Malyavan replied, \'Oh lord, it was by the extreme mercy of the Supreme Personality of Godhead, Lord Sri Krishna (Vasudeva), and also by the powerful influence of the Jaya Ekadasi, that we were released from our suffering condition as pisachas. Because we executed devotional service to Lord Vishnu (even performed unknowingly – by ajnata sukriti) by observing the day most dear to Him, we have happily been restored.\'\"
      </p>
      
      <p>
        \"Indradev then said, \'Because you served the Supreme Lord Sri Keshava by observing Ekadasi, you have become worshipable even by me, and I can see that you are now completely purified of sin. Whosoever engages in devotional service to Lord Sri Hari or Lord Shiva becomes praiseworthy and worshipable even by me. Of this there is no doubt.\' He then gave them free rein to enjoy each other and wander about the heavenly planet.\"
      </p>
      
      <p>
        \"Therefore, Oh Maharaj Yudhishthira, one should strictly observe a fast on the sacred day of Lord Hari, especially on this Jaya Ekadasi, which frees one from the sin of killing even a twice-born brahmana. A great soul who observes this fast with full faith and devotion has in effect given all kinds of charity, performed all kinds of sacrifice, and bathed in all the Holy places. Fasting on Jaya Ekadasi qualifies one to reside in Vaikuntha. One who even hears or reads these glories achieves the merit of performing an Agnistoma fire sacrifice.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Magha month (January/February)|Alternative Names: Jaya Ekadasi, Magha-Shukla Ekadasi|Worshipable Deity: Lord Sri Vishnu / Lord Varahadeva (Appearance day of Lord Varaha is observed on the following day, Dvadashi)|Significance: Eradicates all sins, releases from the burden of ghostly/demonic existences (pishachas), and grants entry to Vaikuntha.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (54, 'vijaya', 'Vijaya Ekadashi', 'Vijaya Ekadashi', 'Bestows victory over all obstacles and adversaries.', 'Vijaya Ekadashi falls during the Krishna Paksha of the Phalguna month (February-March). The name means \"victory.\" This Ekadashi is described in the Brahma Purana, where Lord Krishna narrates the story of a king named甘蔗 (甘蔗) who was a great devotee but faced many military challenges. On the advice of his spiritual master, he observed this Ekadashi with strict vows. The Lord granted him victory over all enemies, and he ruled his kingdom peacefully for many years.', 'Vijaya Ekadashi is observed to seek victory in all endeavors — both material and spiritual. In the battlefield of life, devotees face numerous obstacles from internal enemies (lust, anger, greed) and external challenges. This Ekadashi empowers the devotee to overcome both. It falls during the month of Phalguna, which is associated with the divine pastimes of Lord Krishna, making it especially potent for spiritual advancement.', 'Observing Vijaya Ekadashi grants victory over all forms of adversity — disease, debt, enemies, and obstacles. The fast destroys sinful reactions and grants the observer courage and determination. Those who donate food and worship the Lord with devotion on this day receive special blessings for success in their endeavors. The observer is freed from fear and anxiety, and their life moves toward prosperity and spiritual fulfillment.', 'ekadashi', NULL, 'assets/images/banners/vijaya-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        According to the Vedic calendar, Vijaya Ekadasi falls on the 11th day of the month of Phalgun during the Krishna Paksha (dark fortnight / waning phase) of the moon.
      </p>
      
      <p>
        The significance of Vijaya Ekadashi has been described in several Vedic scriptures. The term \"Vijaya\" in literal meaning signifies victory. Observance of Vijaya Ekadashi and its fast offers success and victory to the observer in the difficult situations and circumstances of life. It helps in providing relief from all sorts of hurdles and obstacles. If people make donations and perform charities on this day, they get relieved from their past and present sins and also earn fruitful results.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Vijaya Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Skanda Purana
      </p>
      
      <p>
        Yudhisthira Maharaj said, \"O Lord Sri Krishna, O glorious son of Vasudeva, please be merciful to me and describe the Ekadasi that occurs during the dark fortnight of the month of Phalguna (February-March).\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"O Yudhisthira, O king of kings, gladly I shall tell you about this great fast, known as Vijaya Ekadasi. Whoever observes it certainly achieves success in this life and the next. All the sins of one who fasts on this Ekadasi and hears its sublime glories are eradicated.\"
      </p>
      
      <p>
        \"Narada Muni once asked lord Brahma about the Vijaya Ekadasi. Sri Narada said, \'O best of all the demigods, kindly tell me the merit one can achieve by faithfully observing Vijaya Ekadasi.\' Narada\'s father replied, \'My dear son, this oldest of fasting days is pure, and it nullifies all sins. I have never revealed this to anyone until today, but you can understand beyond any doubt that this Ekadasi bestows the result indicated by its name (Victory).\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Lord Ramachandra\'s Quest</h3>
      <p>
        \"When Lord Rama was exiled to the forest for fourteen years, He, the goddess Sita, and His divine brother Lakshmana stayed at Panchavati as mendicants. Mother Sita was then kidnapped by the demon Ravana, and Lord Rama seemingly became bewildered by distress. While searching for His beloved consort, the Lord came upon the dying Jatayu, and thereafter killed His enemy Kabandha. The great devotee-vulture Jatayu returned to Vaikuntha after telling Rama how His dear Sita had been abducted by Ravana.\"
      </p>
      
      <p>
        \"Later, Lord Rama and Sugriva, the king of the monkeys, became friends. Together they amassed a grand army of monkeys and bears and sent Hanumanji to Sri Lanka, where he was able to see Janaki (Srimati Sita devi) in an Ashoka grove. He delivered Lord Rama\'s message and showed the ring proving his authenticity.\"
      </p>
      
      <p>
        \"With the help of Sugriva, Lord Rama proceeded toward Sri Lanka. Upon arriving at the shore of the ocean, He saw that the water was uncommonly deep and hostile. Thus, He said to Lakshmana: \'O son of Sumitra, how can We cross this vast ocean, the unfathomable abode of Varuna? I can see no easy way to cross it, teeming as it is with sharks and other ferocious aquatics.\'\"
      </p>
      
      <p>
        \"Lakshmana replied, \'O best of all beings, the great sage Bakad Albhya (Bakadbhya) lives on an island just four miles from here. He has seen many Brahmas come and go, so aged and wise is he. Let us go to him, take his darshan, and ask him how We can safely reach Our goal.\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Instructions of Sage Bakadbhya</h3>
      <p>
        \"So Rama and Lakshmana proceeded to the ashrama of Bakad Albhya Muni. Approaching him, the two Lords paid Their respectful obeisances. The sage immediately understood that Sri Rama was actually the Supreme Personality of Godhead, acting like a human being.\"
      </p>
      
      <p>
        \"Rama said, \'O great twice-born brahmina, I have come here to the ocean shore with My monkey and bear warriors to cross the sea, conquer Lanka, and defeat Ravana. Please tell Me how I can cross this vast ocean.\'\"
      </p>
      
      <p>
        \"The sage replied, \'O Lord Sri Rama, I shall tell you of the most exalted of all fasts, observing which You will surely conquer Ravana. Kindly listen with full attention.\'\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"On the day before Ekadasi (Dashami), fashion a water pot of gold, silver, copper, or clay. Fill it with pure water and decorate it with mango leaves. Place it near a holy altar upon a mound of seven grains (barley, wheat, rice, corn, chickpeas, kukani, and dahl). Worship the water pot with flower garlands, sandalwood paste, incense, a ghee lamp, and sumptious foods, placing a barley-filled lid on top with a golden murti of Lord Sri Narayana. Remain awake that night beside this sacred pot.\"
      </blockquote>

      <p>
        \"\'When Ekadasi dawns, take Your morning bath, decorate the water pot, and worship it again with sandalwood paste, incense, lamps, and flowers. Place cooked foods, pomegranate, and coconut before it, and remain awake overnight. When Dvadashi dawns, take the water pot to the bank of a holy river or pond, worship it again, and offer it to a pure-hearted brahmin expert in the Vedic sciences. If You and Your commanders observe the Vijaya Ekadasi in this way, You will surely be victorious.\'\"
      </p>
      
      <p>
        \"Lord Sri Ramachandra did just as Bakad Albhya Muni instructed, and thus He conquered all demoniac forces. Similarly, anyone who observes the Vijaya Ekadasi in this way will always be victorious in this mortal world, and after leaving this world, will reside forever in the anxiety-free realm of Vaikuntha.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"O Yudhisthira, anyone who reads or hears this history will attain the same great merit as that which is earned by performing a horse sacrifice.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Phalguna month (February/March)|Meaning of name: \"Vijaya\" literally signifies victory; provides victory in difficult situations and removes obstacles.|Worshipable Deity: Lord Sri Narayana (Golden Deity atop the sacred water pot)|Significance: Observed by Lord Ramachandra to cross the ocean and conquer Lanka. Equivalent to performing a horse sacrifice.|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (55, 'amalaki', 'Amalaki Ekadashi', 'Amalaki Ekadashi', 'Worship of the sacred Amalaki tree and Lord Parashurama, yielding immediate liberation.', 'Amalaki Ekadashi falls during the Krishna Paksha of the Phalguna month (February-March). The name refers to the Amalaki (Indian gooseberry) tree, which is considered a manifestation of Lord Vishnu. This Ekadashi is described in the Padma Purana, where Lord Krishna explains that worshipping the Amalaki tree on this day is equivalent to worshipping all the demigods. The story involves a king named Chitraratha who was childless. He worshipped the Amalaki tree on this Ekadashi and was blessed with a son who became a great devotee.', 'Amalaki Ekadashi is observed during the auspicious period leading up to Holi. The Amalaki tree represents the Trimurti — Brahma in the roots, Vishnu in the trunk, and Shiva in the branches. Worshipping this tree on Ekadashi is considered one of the most powerful spiritual practices. It is also observed for good health, as the Amalaki fruit is one of the most healing substances in Ayurveda.', 'Observing Amalaki Ekadashi grants relief from all types of diseases and health problems. The fast purifies the blood, strengthens the immune system, and brings overall physical well-being. Donating Amalaki fruits and food to brahmanas on this day brings immense merit. The observer receives the blessings of Lord Vishnu for good health, prosperity, and spiritual progress. It is especially beneficial for those suffering from chronic illnesses.', 'ekadashi', NULL, 'assets/images/banners/amalaki-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Amalaki-vrata Ekadasi is celebrated during the Shukla Paksha (waxing phase) in the Phalguna month (February–March). Amalaki or Amla is the Indian gooseberry, and the tree is celebrated on this day. It is believed that Lord Vishnu resides in this tree, and this occasion also marks the beginning of Holi — the Indian festival of colors.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Amalaki-vrata Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahmanda Purana
      </p>
      
      <p>
        This Ekadasi is described in the Brahmanda Purana in a conversation between King Mandhata and the great sage Vasishtha.
      </p>
      
      <p>
        King Mandhata once said to Vasishtha Muni, \"O great sage, kindly be merciful to me and tell me of a holy fast that will benefit me eternally.\"
      </p>
      
      <p>
        Vasishtha Muni replied, \"O king, kindly listen as I describe the best of all fast days, Amalaki Ekadasi. He who faithfully observes a fast on this Ekadasi obtains enormous wealth, gets free of the effects of all kinds of sins, and attains liberation. Fasting on this Ekadasi is more purifying than donating one thousand cows in charity to a pure brahmana. So please hear me attentively as I tell you the story of a hunter who, though daily engaged in killing innocent animals for his living, achieved liberation by observing a fast on Amalaki Ekadasi.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Kingdom of Vaidisha</h3>
      <p>
        \"There was once a kingdom named Vaidisha, where all the brahmanas, kshatriyas, vaishyas, and shudras were equally endowed with Vedic knowledge, great bodily strength, and fine intelligence. Oh lion among kings, the whole kingdom was full of Vedic sounds, not a single person was irreligious, and no one sinned. The ruler of this kingdom was King Pashabinduka, a member of the dynasty of Soma, the moon. He was also known as Chitraratha and was very religious and truthful. It is said that King Chitraratha had the strength of ten thousand elephants.\"
      </p>
      
      <p>
        \"During the reign of Maharaja Chitraratha, not a single person in his kingdom attempted to practice another\'s dharma (duty); so perfectly engaged in their own dharmas were all the citizens. The people rendered loving devotional service to the Supreme Personality of Godhead, Lord Vishnu, as did the king, who also rendered special service to Lord Shiva. Moreover, twice a month everyone fasted on Ekadasi. In this way, the citizens of Vaidisha lived many long years in great happiness and prosperity.\"
      </p>
      
      <p>
        \"Once, in the month of Phalguna, the holy fast of Amalaki Ekadasi arrived. King Chitraratha realized that this particular fast would bestow especially great benefit, and thus he and all the citizens observed this sacred Ekadasi very strictly, carefully following all the rules.\"
      </p>
      
      <p>
        \"After bathing in the river, the king and all his subjects went to the temple of Lord Vishnu, where an Amalaki tree grew. They offered the tree a pot filled with water, canopy, shoes, gold, diamonds, rubies, pearls, sapphires, and aromatic incense. Then they worshiped Lord Parashurama with these prayers: \'Oh Lord Parashurama, Oh son of Renuka, Oh all-pleasing one, Oh liberator of the worlds, kindly come beneath this holy Amalaki tree and accept our humble obeisances.\' Then they prayed to the Amalaki tree: \'Oh Amalaki, Oh offspring of Lord Brahma, you can destroy all kinds of sinful reactions. Please accept our respectful obeisances and these humble gifts.\'\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"After offering these prayers, King Chitraratha and his subjects remained awake throughout the night, praying and worshiping. During this time, a very irreligious hunter who maintained himself by killing animals approached. Tired and hungry, he sat down behind the assembly and witnessed the beautiful worship of Lord Damodara beneath the illuminated Amalaki tree. He listened to the glories of the Lord all night, forced by circumstances to stay awake and fast.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Rebirth as King Vasuratha</h3>
      <p>
        \"In due time, the hunter died, but the merit he had gained by fasting on Amalaki Ekadasi and hearing the Lord\'s glories made him eligible to be reborn as a great king named Vasuratha, the son of King Viduratha, ruling over the kingdom of Jayanti.\"
      </p>
      
      <p>
        \"King Vasuratha was strong, handsome, charitable, and a great devotee of Lord Vishnu. One day, while hunting in the jungle, King Vasuratha strayed from the footpath and lost his way. Growing weary, he paused beneath a tree and fell asleep. As he slept, some barbarian tribesmen who were his long-standing enemies came upon him and prepared to kill him with spears, swords, and arrows.\"
      </p>
      
      <p>
        \"But none of their weapons could touch the sleeping king, and the tribesmen grew weak and bewildered. Suddenly, a beautiful woman decorated with ornaments and fiery red eyes appeared from the king\'s body. With her blazing chakra discus, she quickly killed all the tribal hunters who had tried to slay the sleeping king.\"
      </p>
      
      <p>
        \"When the king awoke, he was astonished to see all his enemies dead. He wondered, \'Who has slain them so violently? Who is my great benefactor?\' At that moment he heard a voice from the sky: \'You asked who helped you. Well, who is that person who alone can help anyone in distress? He is none other than Sri Keshava, the Supreme Personality of Godhead, who saves all who take shelter of Him.\'\"
      </p>
      
      <p>
        \"Therefore, King Mandhata,\" Vasishtha Muni concluded, \"anyone who observes this holy Amalaki Ekadasi will undoubtedly attain the supreme abode of Lord Vishnu, so great is the merit earned from this sacred fast.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Phalguna month (February/March)|Alternative Names: Amalaki-vrata Ekadasi|Deity & Tree Worshipped: Lord Parashurama and the sacred Amalaki (Amla/gooseberry) tree.|Significance: More purifying than donating 1,000 cows, destroys all sins, and awards liberation. Marks the beginning of Holi.|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (56, 'papamocani', 'Papamochani Ekadashi', 'Papamochani Ekadashi', 'The liberator from all sinful reactions, bad habits, and planetary curses.', 'Papamochani Ekadashi falls during the Krishna Paksha of the Chaitra month (March-April). The name means \"destroyer of sins.\" This Ekadashi is described in the Brahma Purana, where the story of King Kalmashapada is narrated. The king was cursed by a brahmana to become a man-eating demon. He wandered in the forest, eating human flesh for years. When the curse was about to end, he observed this Ekadashi with great devotion. The Lord freed him from the demoniac form, purified him of all sins, and restored his kingdom.', 'Papamochani Ekadashi falls during the Chaitra month, which marks the beginning of the Hindu New Year. Observing this Ekadashi at the start of the year ensures freedom from sins throughout the year. The name literally means \"the liberator from sins,\" and the scriptures describe it as having extraordinary power to cleanse even the most severe sinful reactions. It is observed for spiritual purification and a fresh start.', 'The primary benefit of Papamochani Ekadashi is complete liberation from all sinful reactions — past, present, and future. The fast destroys sins that other austerities cannot remove. Those who observe this Ekadashi and donate food, gold, and cows on this day receive immense spiritual merit. The observer\'s consciousness is purified, enabling them to engage in devotional service more effectively. It brings peace of mind and freedom from guilt and anxiety.', 'ekadashi', NULL, 'assets/images/banners/papamocani-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Papamocani Ekadasi falls on the 11th day of the Krishna Paksha (the waning phase of moon) in the month of Chaitra as per the North Indian calendar. However, in the South Indian calendar this Ekadasi is observed in the Vedic month of Phalgun. In the English calendar this corresponds to the months of March to April. Papamocani Ekadasi is the last Ekadasi observance of the 24 Ekadasis in the Vedic calendar. It falls between the celebrations of Holika Dahan and Chaitra Navratri.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Papamocani Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishya-uttara Purana
      </p>
      
      <p>
        Sri Yudhisthira Maharaja said, \"Oh Supreme Lord, I have heard from You the explanation of Amalaki Ekadasi which occurs during the light fortnight of the month of Phalguna (February-March), and now I wish to hear about the Ekadasi that occurs during the dark fortnight of the month of Chaitra (March-April). What is its name, Oh Lord, and what results can one attain by observing it?\"
      </p>
      
      <p>
        The Supreme Personality of Godhead, Lord Sri Krishna, replied, \"O best of kings, for the benefit of everyone I shall gladly describe to you the glories of this Ekadasi, which is known as Papamochani. The history of this Ekadasi was once narrated to the Emperor Mandhata by Lomasha Rishi.\"
      </p>
      
      <p>
        \"King Mandhata addressed the Rishi, \'Oh great sage, for the benefit of all people, please tell me the name of the Ekadasi that occurs during the dark fortnight of the month of Chaitra, and please explain the process for observing it. Also, please describe the benefits one gains by observing this Ekadasi.\'\"
      </p>
      
      <p>
        \"Lomasha Rishi replied, \'The Ekadasi that occurs during the dark part of the month of Chaitra is named Papamochani Ekadasi. For the faithful devotee it removes the influences of ghosts and demons. Oh lion among men, this Ekadasi also awards the eight perfections of life, fulfills all kinds of desires, purifies one\'s life of all sinful reactions, and makes a person perfectly virtuous.\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Seduction of Sage Medhavi</h3>
      <p>
        \"Now please listen to a historical account concerning this Ekadasi and Chitraratha, the chief of the Gandharvas (heavenly musicians). During the spring season, in the company of heavenly dancing girls, Chitraratha once came upon a beautiful forest bursting forth with a great variety of flowers. There he and the girls joined the Gandharvas and many Kinnaras, along with Lord Indra himself, the king of heaven, who was enjoying a visit there. Many sages were also present, performing their austerities and penances.\"
      </p>
      
      <p>
        \"A great sage named Medhavi resided in that forest, and the very attractive dancing girls would always attempt to seduce him. One famous girl in particular, Mañjughosha, contrived many ways to allure the exalted Muni, but out of great respect for the sage and fear of his power, which he had attained after years and years of ascetics, she would not come very close to him. At a spot two miles from the sage, she pitched a tent and began singing very sweetly as she played a tamboura. Cupid himself became excited when he saw and heard her perform so nicely and decided to take revenge by seducing Medhavi.\"
      </p>
      
      <p>
        \"Using the eyebrows of Mañjughosha as a bow, her glances as a bowstring, her eyes as arrows, and her breasts as a target, Cupid approached Medhavi in order to tempt him to break his trance and his vows. Cupid engaged Mañjughosha as his assistant, and when she looked at that powerful and attractive young sage, she also became agitated by lust. Seeing that he was highly intelligent and learned, wearing a clean white brahmana\'s thread draped across his shoulder, holding a sannyasi\'s staff, and sitting handsomely in the ashrama of Chyavana Rishi, Mañjughosha came before him.\"
      </p>
      
      <p>
        \"She began to sing seductively, and the small bells of her belt and around her ankles, together with the bangles on her wrists, produced a delightful musical symphony. The sage Medhavi was enchanted. He understood that this beautiful young woman desired union with him, and at that instant Cupid increased his attraction for Mañjughosha by releasing his powerful weapons of taste, touch, sight, smell, and sound.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Slowly Mañjughosha approached Medhavi, her bodily movements and sweet glances attracting him. She gracefully put her tamboura down and embraced the sage with her two arms, just as a creeper winds itself around a strong tree. Captivated, Medhavi gave up his meditation and decided to sport with her – and instantly his purity of heart and mind abandoned him. Forgetting even the difference between night and day, he went away with her to sport for a long, long time.\"
      </blockquote>

      <p>
        \"Seeing that the young yogi\'s sanctity had become seriously eroded, Mañjughosha decided to abandon him and return home. She said, \'O great one, please permit me to return home.\'\"
      </p>
      
      <p>
        \"Medhavi replied, \'But you have only just arrived, O beautiful one. Please stay with me at least until tomorrow.\'\"
      </p>
      
      <p>
        \"Fearful of the sage\'s yogic power, Mañjughosha stayed with Medhavi for precisely fifty-seven years, nine months, and three days, but to Medhavi all this time seemed like a moment. Again she asked him, \'Please permit me to leave.\'\"
      </p>
      
      <p>
        \"Medhavi replied, \'O dear one, listen to me. Stay with me for one more night, and then you may leave tomorrow morning. Just stay with me until I have performed my morning duties and chanted the sacred Gayatri mantra.\'\"
      </p>
      
      <p>
        \"Mañjughosha was still fearful, but she forced a smile and said, \'How long will it take you to finish your morning hymns and rituals? Please be merciful and think of all the time you have already spent with me.\' The sage reflected on the years he had been with Mañjughosha and then said with great astonishment: \'Why, I have spent more than fifty-seven years with you!\' His eyes turned red and began to emanate sparks. He now regarded Mañjughosha as death personified and the destroyer of his spiritual life.\"
      </p>
      
      <p>
        \"\'You rascal woman! You have turned all the hard-earned results of my austerities to ashes!\' Trembling with anger, he cursed Mañjughosha: \'Oh sinful one, Oh hard-hearted, degraded one! You know only sin! May all terrible fortune be yours! Oh rascal woman, I curse you to become an evil hobgoblin – <em>pishacha</em>!\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Redemption and Atonement</h3>
      <p>
        \"Cursed by the sage Medhavi, the beautiful Mañjughosha humbly beseeched him, \'Oh best of the brahmanas, please be merciful to me and revoke your curse! Oh great one, it is said that association with pure devotees gives immediate results but their curses take effect only after seven days. I have been with you for fifty-seven years, Oh master, so please be kind to me!\'\"
      </p>
      
      <p>
        \"Medhavi Muni replied, \'Oh gentle lady what can I possibly do? You have destroyed all my austerities. But even though you have done this sinful deed, I shall tell you a way you can be released from my wrath. In the dark fortnight of the month of Chaitra there is an all-auspicious Ekadasi that removes all one\'s sins. Its name is Papamochani, and whoever fasts on this sacred day becomes completely freed from having to take birth in any kind of devilish form.\'\"
      </p>
      
      <p>
        \"With these words, the sage left at once for his father\'s ashrama. Seeing him enter the hermitage, Chyavana Muni said, \'Oh son, by acting unlawfully you have squandered the wealth of your penances and austerities.\'\"
      </p>
      
      <p>
        \"Medhavi replied, \'Oh Father, kindly reveal what atonement I must perform to remove the obnoxious sin I have incurred by privately associating with the dancing girl Mañjughosha.\'\"
      </p>
      
      <p>
        \"Chyavana Muni answered, \'Dear son, you must fast on Papamochani Ekadasi, which occurs during the dark fortnight of the month of Chaitra. It eradicates all sins, no matter how grievous they may be.\'\"
      </p>
      
      <p>
        \"Medhavi followed his father\'s advice and fasted on Papamochani Ekadasi. Thus all his sins were destroyed and he again became filled with excellent merit. Similarly, Mañjughosha observed the same fast and became free of the hobgoblin curse. Ascending once again to the heavenly spheres, she too returned to her former position.\"
      </p>
      
      <p>
        Lomasha Rishi concluded, \"Thus, Oh king, the great benefit of fasting on Papamochani Ekadasi is that whoever does so with faith and devotion will have all his sins completely destroyed.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"Oh King Yudhishthira, whoever reads or hears about Papamochani Ekadasi obtains the very same merit he would get if he donated a thousand cows in charity, and he also nullifies the sinful reactions he may have incurred by killing a brahmana, killing an embryo through abortion, drinking liquor, or having sex with his guru\'s wife.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Chaitra/Phalguna month (March/April)|Alternative Names: Chaitra Krishna Ekadasi|Meaning of name: \"Papamocani\" means the liberator/remover of all sins.|Significance: Eradicates sins like killing a brahmana, drinking liquor, having illicit relations, and destroys the influence of ghosts and demons (pishachas).|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (57, 'kamada', 'Kamada Ekadashi', 'Kamada Ekadashi', 'Fulfills all righteous desires of the heart and counteracts curses.', 'Kamada Ekadashi falls during the Shukla Paksha of the Chaitra month (March-April). The name means \"fulfiller of desires.\" This Ekadashi is described in the Padma Purana, where Lord Krishna narrates the story of a Gandharva (celestial musician) named Pundarika who was cursed by a sage to become a demon for ignoring the sage during a concert. Desperate to break the curse, Pundarika\'s wife advised him to observe this Ekadashi. He observed it with great devotion, and the Lord freed him from the curse, restoring his celestial form.', 'Kamada Ekadashi falls on the first Ekadashi after Holi, during the Chaitra month. It is observed for the fulfillment of desires — both material and spiritual. The scriptures state that this Ekadashi has the power to fulfill any sincere wish of the devotee. It is especially observed by those seeking to overcome specific problems or achieve particular goals in life. The timing during the spring season adds to its spiritual potency.', 'Observing Kamada Ekadashi fulfills the desires of the sincere devotee. The fast removes all obstacles in the path of the observer and grants success in their endeavors. Those who donate food, clothing, and charity on this day receive manifold returns. The observer is blessed with the grace of Lord Vishnu, who removes all difficulties and grants prosperity. It is especially beneficial for those facing legal issues, relationship problems, or career challenges.', 'ekadashi', NULL, 'assets/images/banners/kamada-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Ekadasi is the 11th day of the moon\'s lunar phase, and Kamada Ekadasi falls on the Shukla Paksha (waxing phase) in the month of Chaitra (March-April). This day is also called Chaitra Shukla Ekadasi.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Kamada Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Varaha Purana
      </p>
      
      <p>
        Sri Suta Goswami said, \"Oh sages, let me offer my humble and respectful obeisances unto the Supreme Lord Hari, Bhagavan Sri Krishna, the son of Devaki and Vasudeva, by whose mercy I can describe the fast day that removes all kinds of sins. It was to the devoted Yudhishthira that Lord Krishna glorified the twenty-four primary Ekadasis, which destroy sin, and now I shall recount one of those narrations to you. Great-learned sages have selected these twenty-four narrations from the eighteen Puranas, for they are truly sublime.\"
      </p>
      
      <p>
        Yudhishthira Maharaja said, \"Oh Lord Krishna, Oh Vasudeva, please accept my humble obeisances. Please describe to me the Ekadasi that occurs during the light part of the month of Chaitra (March-April). What is its name, and what are its glories?\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"Oh Yudhishthira, please listen to Me attentively as I relate the ancient history of this sacred Ekadasi, a history Vasishtha Muni once related to King Dilipa, the great-grandfather of Lord Ramachandra.\"
      </p>
      
      <p>
        \"King Dilipa asked the great sage Vasishtha, \'Oh wise brahmana, I wish to hear about the Ekadasi that comes during the light part of the month of Chaitra. Please describe it to me.\'\"
      </p>
      
      <p>
        \"Vasishtha Muni replied, \'Oh king, your inquiry is glorious. Gladly shall I tell you what you wish to know. The Ekadasi that occurs during the light fortnight of Chaitra is named Kamada Ekadasi. It consumes all sins, as a forest fire consumes a supply of dry firewood. It is very purifying, and it bestows the highest merit upon one who faithfully observes it. Oh king, now hear an ancient history which is so meritorious that it removes all one\'s sins simply by being heard.\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Curse of Lalita</h3>
      <p>
        \"Once, long ago, there existed a city-state named Ratnapura, which was decorated with gold and jewels and in which sharp-fanged snakes would enjoy intoxication. King Pundarika was the ruler of this most beautiful kingdom, which numbered many Gandharvas, Kinnaras, and Apsaras among its citizens.\"
      </p>
      
      <p>
        \"Among the Gandharvas were Lalita and his wife Lalita, who was an especially lovely dancer. These two were intensely attracted to each other, and their home was full of great wealth and fine food. Lalita loved her husband dearly, and likewise he constantly thought of her within his heart.\"
      </p>
      
      <p>
        \"Once, at the court of King Pundarika, many Gandharvas were dancing and Lalita was singing alone, without his wife. He could not help thinking about her as he sang, and because of this distraction he lost track of the song\'s meter and melody. Indeed, Lalita sang the ending of his song improperly, and one of the envious snakes who was in attendance at the king\'s court complained to the king that Lalita was absorbed in thinking of his wife instead of his sovereign.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"The king became furious upon hearing this, and his eyes turned crimson with rage. Suddenly he shouted, \'Oh foolish knave, because you were lustfully thinking of a woman instead of reverently thinking of your king as you performed your court duties, I curse you to at once become a cannibal!\'\"
      </blockquote>

      <p>
        \"Lalita immediately became a fearful cannibal, a great man-eating demon whose appearance terrified everyone. His arms were eight miles long, his mouth was as big as a huge cave, his eyes were as awesome as the sun and moon, his nostrils resembled enormous pits in the earth, his neck was a veritable mountain, his hips were four miles wide, and his gigantic body stood a full sixty-four miles high. Thus poor Lalita, the loving Gandharva singer, had to suffer the reaction of his offense against King Pundarika.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Redemption by Sage Shringi</h3>
      <p>
        \"Seeing her husband suffering as a horrible cannibal, Lalita became overwhelmed with grief. She thought, \'Now that my dear husband is suffering the effects of the king\'s curse, what is to be my lot? What should I do? Where should I go?\' In this way Lalita grieved day and night. Instead of enjoying life as a Gandharva\'s wife, she had to wander everywhere in the thick jungle with her monstrous husband, who was wholly engaged in terrible sinful activities.\"
      </p>
      
      <p>
        \"By good fortune, however, Lalita came upon the sage Shringi one day. He was sitting on the peak of the famous Vindhyachala Hill. Approaching him, she immediately offered the ascetic her respectful obeisances. The sage noticed her bowing down before him and said, \'Oh most beautiful one, who are you? Whose daughter are you, and why have you come here? Please tell me everything in truth.\'\"
      </p>
      
      <p>
        \"Lalita replied, \'Oh great sage, I am the daughter of the great Gandharva Viradhanva, and my name is Lalita. I roam the forests and plains with my dear husband, whom King Pundarika has cursed to become a man-eating demon. Oh brahmana, I am greatly aggrieved to see his ferocious form and terribly sinful activities. Oh master, please tell me how I can perform some act of atonement on behalf of my husband to free him from this demonic form.\'\"
      </p>
      
      <p>
        \"The sage replied, \'Oh heavenly maiden, there is an Ekadasi named Kamada that occurs in the light fortnight of the month of Chaitra. It is coming up soon. Whoever fasts on this day has all his desires fulfilled. If you observe this Ekadasi fast according to its rules and regulations and give the merit you thus earn to your husband, he will be freed from the curse at once.\' Lalita was overjoyed.\"
      </p>
      
      <p>
        \"Lalita faithfully observed the fast of Kamada Ekadasi according to the instructions of the sage Shringi, and on Dvadashi she appeared before him and the Deity of Lord Vasudeva and said: \'I have faithfully observed the fast of Kamada Ekadasi. By the merit earned through my observance of this fast, let my husband be free from the curse that has turned him into a demoniac cannibal.\'\"
      </p>
      
      <p>
        \"As soon as Lalita finished speaking, her husband, who stood nearby, was at once freed from the king\'s curse. He immediately regained his original form as the Gandharva Lalita, a handsome heavenly singer adorned with many beautiful ornaments. At last the Gandharva couple boarded a celestial airplane and ascended to heaven.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"Oh Yudhishthira, best of kings, anyone who hears this wonderful narration should certainly observe holy Kamada Ekadasi to the best of his ability, such great merit does it bestow. It can eradicate even the sin of killing a brahmana, and it also nullifies demoniac curses and cleanses the consciousness.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Chaitra month (March/April)|Alternative Names: Chaitra Shukla Ekadasi|Meaning of name: \"Kamada\" means bestower of all desires.|Significance: Eradicates even the sin of killing a brahmana, nullifies demoniac/ghostly curses, and cleanses the consciousness.|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (58, 'varuthini', 'Varuthini Ekadashi', 'Varuthini Ekadashi', 'Protects the devotee, removes all sins, and turns charity into eternal spiritual assets.', 'Varuthini Ekadashi falls during the Krishna Paksha of the Kartika month (October-November). The name means \"protected\" or \"shielded.\" This Ekadashi is described in the Brahma Vaivarta Purana, where Lord Krishna tells Yudhishthira about a king named Mandhata who was a great devotee but faced constant attacks from his enemies. He observed this Ekadashi with strict vows and prayed for protection. The Lord appeared and blessed him with invincibility and divine protection, and his enemies were vanquished.', 'Varuthini Ekadashi falls during the sacred Kartika month, when devotional practices are especially powerful. The name signifies divine protection — the Lord shields His devotees from all dangers. This Ekadashi is observed for protection from enemies, negative energies, and unforeseen calamities. It is also observed during the period when Lord Vishnu is resting (Chaturmasya), making devotion during this time especially pleasing to the Lord.', 'Observing Varuthini Ekadashi grants divine protection from all forms of danger — physical, mental, and spiritual. The fast acts as a spiritual shield, protecting the observer from negative influences and enemies. Those who donate food, warm clothes, and blankets on this day during the cold Kartika month receive immense merit. The observer is blessed with fearlessness, courage, and the Lord\'s protection throughout the year.', 'ekadashi', NULL, 'assets/images/banners/varuthini-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Varuthini Ekadasi falls in the dark fortnight (Krishna paksha) of the month of Vaisakha. It corresponds to the months of April-May in the Gregorian calendar. On this day, devotees worship and offer prayers to Lord Vamana, the dwarf incarnation of Lord Vishnu. In the literal sense, \"Varuthini\" means protected, and thus the devotees get protected from various negativities and evils by observing Varuthini Ekadashi.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Varuthini Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishya Purana
      </p>
      
      <p>
        Sri Yudhisthira Maharaj said, \"Oh Vasudeva, I offer my most humble obeisances unto You. Please now describe to me the Ekadasi of the dark fortnight (krishna paksha) of the month of Vaisakha (April-May), including its specific merits and influence.\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"Oh King, in this world and the next, the most auspicious and magnanimous Ekadasi is Varuthini Ekadasi, which occurs during the dark fortnight of the month of Vaisakha. Whosoever observes a complete fast on this sacred day has his sins completely removed, obtains continuous happiness, and achieves all good fortune.\"
      </p>
      
      <p>
        \"Fasting on Varuthini Ekadasi makes even an unfortunate woman fortunate. Upon anyone who observes it, this Ekadasi bestows material enjoyment in this life and liberation after the death of this present body. It destroys the sins of all and saves people from the miseries of repeated rebirth.\"
      </p>
      
      <p>
        \"By observing this Ekadasi properly, King Mandhata was liberated. Many other kings also benefited from observing it – kings such as Maharaj Dhundhumara, in the Ikshvaku dynasty, who became free from leprosy resulting from the curse that Lord Shiva had imposed upon him as a punishment.\"
      </p>
      
      <p>
        \"Whatever merit one obtains by performing austerities and penances for ten thousand years is achieved by a person who observes Varuthini Ekadasi. The merit one achieves by donating a great amount of gold during a solar eclipse at Kurukshetra is gained by one who observes this one Ekadasi with love and devotion, and certainly attains his goals in this life and the next. In short, this Ekadasi is pure and very enlivening and the destroyer of all sins.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Hierarchy of Charities</h3>
      <p>
        \"Better than giving horses in charity is giving elephants, and better than giving elephants is giving land. But better still than giving land is the giving of sesame seeds, and better than that is giving of gold. Still better than giving gold is giving food grains – for all the forefathers, demigods, and human beings become satisfied by eating grains. Thus there is no better gift of charity than this in the past, present or future.\"
      </p>
      
      <p>
        \"Yet learned scholars have declared that giving away a young maiden in marriage to a worthy person is equal to giving away food grains in charity. Moreover, Lord Sri Krishna, the Supreme Personality of Godhead, has said that giving cows in charity is equal to giving food grains. Still better than all these charities is teaching spiritual knowledge to the ignorant. Yet all the merits one can attain by performing all these acts of charity are attained by one who fasts on the Varuthini Ekadasi.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"One who lives off the wealth of his daughters suffers a hellish condition until the inundation of the entire universe, Oh Bharata. Therefore one should be especially careful not to use the wealth of his daughter. Any householder who takes his daughter\'s wealth out of greed, who tries to sell his daughter, or who takes money from the man to whom he has given his daughter in marriage – such a householder becomes a lowly cat in his next life.\"
      </blockquote>

      <p>
        \"Therefore it is said that whoever, as a sacred act of charity, gives away in marriage a maiden decorated with various ornaments, and who also gives a dowry with her, obtains merit that cannot be described even by Chitragupta, the chief secretary of Yamaraja in the heavenly planets. That very same merit, however, can be easily achieved by one who fasts on the Varuthini Ekadasi.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Regulative Principles of the Fast</h3>
      <p>
        The scriptures detail specific practices to be observed on the three days surrounding the fast:
      </p>

      <p><strong>On Dashami (the day before the fast):</strong> Give up eating on bell-metal plates, eating urad-dahl, red-lentils, chick-peas, or kondo (a grain eaten by the poor), eating spinach, eating honey, eating in another person\'s home, eating more than once, and participating in sex of any kind.</p>
      
      <p><strong>On Ekadasi (the day of the fast):</strong> Give up gambling, sports, sleeping during the daytime, betel nuts and its leaf, brushing one\'s teeth, spreading rumors, faultfinding, talking to the spiritually fallen, anger, and lying.</p>
      
      <p><strong>On Dvadashi (the day after the fast):</strong> Give up eating on bell-metal plates, eating urad-dahl, red-lentils, or honey, lying, strenuous exercise or labor, eating more than once, any sexual activity, shaving the body, face or head, smearing oils on one\'s body, and eating in another\'s home.</p>
      
      <p>
        Lord Sri Krishna continued, \"Whoever observes the Varuthini Ekadasi in this way becomes free from all sinful reactions and returns to the eternal, spiritual abode. One who worships Lord Janardana on this Ekadasi by staying awake throughout the entire night also becomes free from all his previous sins and attains to the spiritual abode. Therefore, Oh king, he who is frightened of his accumulated sins and their reactions, and thus of death itself, must observe Varuthini Ekadasi by fasting very strictly. Finally, Oh noble Yudhishthira, he who hears or reads this glorification of the sacred Varuthini Ekadasi obtains the merit earned by donating one thousand cows in charity, and at last he returns home to the Supreme abode of Lord Vishnu in the Vaikunthas.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Vaisakha month (April/May)|Meaning of name: \"Varuthini\" literally signifies protected; observers are protected from negativities, sins, and evils.|Worshipable Deity: Lord Sri Vamana (the dwarf incarnation of Lord Vishnu)|Significance: sublime and meritorious fast that eradicates sins, bestows material enjoyment, saves from rebirth, and frees observers from curses.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (59, 'mohini', 'Mohini Ekadashi', 'Mohini Ekadashi', 'Dedicated to Lord Vishnu\'s Mohini form to defeat illusion and cross the material ocean.', 'Mohini Ekadashi falls during the Krishna Paksha of the Vaishakha month (April-May). The name refers to the Mohini avatar of Lord Vishnu, who appeared as a beautiful enchantress to distribute the nectar of immortality (amrita) to the demigods. This Ekadashi is described in the Padma Purana, where Lord Krishna explains that observing this Ekadashi removes the illusion (maya) that binds the soul in material existence.', 'Mohini Ekadashi is observed to overcome the powerful illusion of material existence. Just as Lord Vishnu as Mohini distributed amrita to the demigods, this Ekadashi grants the nectar of spiritual life to the sincere observer. It is especially powerful for breaking free from addictions, bad habits, and material attachments. The Vaishakha month is considered highly auspicious for spiritual practices.', 'Observing Mohini Ekadashi frees the devotee from the clutches of material illusion (maya). The fast breaks attachments to sinful activities and impure consciousness. Those who observe this Ekadashi with devotion receive the ability to discriminate between right and wrong and make spiritually elevated choices. Donations on this day — especially of food and educational materials — bring lasting merit. The observer is blessed with clarity of mind and progress in spiritual life.', 'ekadashi', NULL, 'assets/images/banners/mohini-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Mohini Ekadasi vrata, also known as Vaisakha-sukla Ekadasi, is observed in the auspicious Vedic month of Vaishakha. It is one of the most important of the 24 Ekadashi vratas and is observed on the 11th day during the Shukla Paksha (bright/waxing fortnight).
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Mohini Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Kurma Purana
      </p>
      
      <p>
        Sri Yudhisthira Maharaja said, \"Oh Janardana, what is the name of the Ekadasi that occurs during the light fortnight (sukla paksha) of the month of Vaisakha (April-May)? What is the process for observing it properly? Kindly narrate all of these details to me.\"
      </p>
      
      <p>
        The Supreme Personality of Godhead, Lord Sri Krishna replied, \"Oh blessed son of Dharma, what Vasishtha Muni once told to Lord Ramachandra I shall now describe to you. Please hear Me attentively.\"
      </p>
      
      <p>
        Lord Ramachandra asked Vasishtha Muni, \"Oh great sage, I would like to hear about the best of all fasting days – that day which destroys all kinds of sins and sorrows. I have suffered long enough in separation from My dear Sita, and so I wish to hear from you about how My suffering can be ended.\"
      </p>
      
      <p>
        The sage Vasishtha replied, \"Oh Lord Rama, Oh You whose intelligence is so keen, simply by remembering Your name one can cross the ocean of the material world. You have questioned me in order to benefit all of humanity and fulfill everyone\'s desires. I shall now describe that day of fasting which purifies the whole world.\"
      </p>
      
      <p>
        \"Oh Rama, that day is known as Vaisakha-sukla Ekadasi, which falls on Dvadashi. It removes all sins and is famous as Mohini Ekadasi. Truly, Oh dear Rama, the merit of this Ekadasi frees the fortunate soul who observes it from the network of illusion. Therefore, if You want to relieve Your sufferings, observe this auspicious Ekadasi perfectly, for it removes all obstacles from one\'s path and relieves the greatest miseries. Kindly listen as I describe its glories, because for one who even just hears about this auspicious Ekadasi, the greatest sins are nullified.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Prodigal Son Dhrishthabuddhi</h3>
      <p>
        \"On the banks of the Sarasvati River there was once a beautiful city named Bhadravati, which was ruled by King Dyutiman. Oh Rama, that steadfast, truthful, and highly intelligent king was born in the dynasty of the Moon (Chandra-vamsa). In his kingdom was a merchant named Dhanapala, who possessed a great deal of wealth of food grains and money. He was also very pious. Dhanapala arranged for lakes to be dug, sacrificial arenas to be erected, and beautiful gardens to be cultivated for the benefit of all the citizens of Bhadravati. He was an excellent devotee of Lord Vishnu and had five sons: Sumana, Dyutiman, Medhavi, Sukriti, and Dhrishthabuddhi.\"
      </p>
      
      <p>
        \"Unfortunately, his son Dhrishthabuddhi always engaged in greatly sinful activities, such as sleeping with prostitutes and associating with similar degraded persons. He enjoyed illicit sex, gambling, and many other varieties of acts aimed at gratifying the senses. He disrespected the demigods (devas), the brahmins, the forefathers and other elders of the community, as well as his family\'s guests. The evil-hearted Dhrishthabuddhi spent up his father\'s wealth indiscriminately, always feasting on untouchable foods and drinking alcohol to excess.\"
      </p>
      
      <p>
        \"One day Dhanapala kicked Dhrishthabuddhi out of the house after he saw him walking along the road arm-in-arm with a known prostitute. From then on all Dhrishthabuddhi\'s relatives were highly critical of him and distanced themselves from him also. After he had sold all of his inherited ornaments and become destitute, the prostitute also abandoned him and insulted him because of his poverty.\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Dhrishthabuddhi was now full of anxiety, and also hungry. He thought, \'What should I do? Where should I go? How can I maintain myself?\' He then began to steal. The king\'s constables arrested him, but when they learned who it was, and that his father was the famous Dhanapala, they released him. He was caught and released in this way many times. But at last, sick of his arrogance and total disrespect for others and their property, the ill-mannered Dhrishthabuddhi was apprehended, handcuffed, and beaten. After whipping him, the king\'s marshals warned him: \'Oh evil-minded one! There is no place for you in this kingdom!\'\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Redemption in the Forest</h3>
      <p>
        \"Dhrishthabuddhi was banished from his father\'s house and immediately thereafter entered the dense forest. He wandered here and there, hungry and thirsty and suffering greatly. Eventually he began killing the jungle animals, the lions, deer, boars, and even wolves for food. Always ready in his hand was his bow, always on his shoulder was his quiver full of arrows. He also killed many birds, such as chakoras, peacocks, kankas, doves and pigeons. He unhesitatingly slaughtered many species of birds and animals to maintain his sinful way of life, the sinful results accumulating more and more each day. On account of his previous sins, he was now immersed in an ocean of great sin that was so relentless that it appeared he could not escape.\"
      </p>
      
      <p>
        \"Dhrishthabuddhi was always miserable and anxious, but one day, during the month of Vaisakha, by the force of some of his past merit he chanced upon the sacred ashrama of Kaundinya Muni. The great sage had just finished bathing in the Ganges River, and water was dripping from him still. Dhrishthabuddhi had the great good fortune to touch some of those droplets of water that were falling from the great sage\'s wet clothing. Instantly Dhrishthabuddhi was freed of his ignorance, and his sinful reactions were reduced.\"
      </p>
      
      <p>
        \"Offering his humble obeisances to Kaundinya Muni, Dhrishthabuddhi prayed to him with joined palms: \'Oh great brahmana, please describe to me some of the atonement I may perform without too much endeavor. I have committed so many sins in my life, and these have now made me very poor.\'\"
      </p>
      
      <p>
        \"The great rishi replied, \'Oh son, listen with great attention, for by hearing me your life will change, and you will become free of all your remaining sins. In the light fortnight of this very month, Vaisakha (April-May), there occurs the sacred Mohini Ekadasi, which has the power to nullify sins as vast and weighty as Mount Sumeru. If you follow my advice and faithfully observe a fast on this Ekadasi, which is so dear to Lord Hari, you will be freed from all the sinful reactions of many, many births.\'\"
      </p>
      
      <p>
        \"Hearing these words with great joy, Dhrishthabuddhi promised to observe a fast on Mohini Ekadasi according to the sage\'s instructions. Oh best of kings, Oh Ramachandra Bhagavan, by fasting completely on Mohini Ekadasi, the once sinful Dhrishthabuddhi, the prodigal son of the merchant Dhanapala, became sinless. Afterwards he achieved a beautiful transcendental form and, free at last of all obstacles, rode upon the carrier of Lord Vishnu, Garuda, to the Supreme abode of the Lord.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Conclusion</h3>
      <p>
        \"Oh Ramachandra, the fast day of Mohini Ekadasi removes the darkest illusory attachments (moha) to material existence. There is thus no better fast day in all the three worlds than this.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"And so, Oh Yudhishthira, there is no place of pilgrimage, no sacrifice, and no charity that can bestow merit equal to even one-sixteenth of the merit a faithful devotee of Mine obtains by observing the Mohini Ekadasi. And he who hears and studies the glories of Mohini Ekadasi achieves the merit of giving away one thousand cows in charity.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Vaisakha month (April/May)|Alternative Names: Vaisakha-sukla Ekadasi|Worshipable Deity: Lord Sri Vishnu / Mohini Murti|Significance: Removes dark illusory attachments (moha), eradicates sins as vast as Mount Sumeru, and grants liberation.|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (60, 'apara', 'Apara Ekadashi', 'Apara Ekadashi', 'Grants unlimited merit and acts as an axe cutting down the forest of sinful deeds.', 'Apara Ekadashi falls during the Krishna Paksha of the Jyeshtha month (May-June). The name means \"unlimited\" or \"boundless.\" This Ekadashi is described in the Brahma Purana, where Lord Krishna narrates the story of a king named Kritavirya who was extremely wealthy but had committed many sins through his harsh统治. On the advice of his priests, he observed this Ekadashi with great devotion and donated generously. The Lord forgave his sins and blessed him with liberation.', 'Apara Ekadashi is observed for the destruction of unlimited sins and the accumulation of unlimited merit. The name itself signifies the boundless results of this observance. It falls during the Jyeshtha month when the summer heat intensifies, symbolizing the burning away of sinful reactions through the fire of devotion. This Ekadashi is especially observed by those who have accumulated heavy sinful reactions.', 'Observing Apara Ekadashi destroys sins that are otherwise very difficult to atone for. The fast grants unlimited spiritual merit that accumulates across lifetimes. Those who donate food, water, and cooling drinks during the hot Jyeshtha month receive immense blessings. The observer is freed from the reactions of all types of sinful activities — including those committed knowingly or unknowingly. It brings liberation from the cycle of birth and death.', 'ekadashi', NULL, 'assets/images/banners/apara-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Apara Ekadasi is observed on the 11th day of the Krishna Paksha (dark fortnight of the moon) in the Vedic month of Jyeshtha. It corresponds to the months of May-June in the Gregorian calendar. It is understood that by observing Apara Ekadasi vrata all the sins of the person will be washed away. 
      </p>
      
      <p>
        This Ekadasi is also popular by the name of Achla Ekadasi and gives divine and auspicious results. Like all Ekadasis, the Apara Ekadasi is dedicated to worshipping the Supreme Lord Vishnu, specifically in His form as Lord Trivikrama (the dwarf Vamana incarnation who expanded to cover the universe).
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Apara Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahmanda Purana
      </p>
      
      <p>
        Sri Yudhishthira Maharaj said, \"Oh Janardana, what is the name of the Ekadasi that occurs during the dark fortnight (krishna paksha) of the month of Jyeshtha (May-June)? I wish to hear from You the glories of this sacred day of Hari. Please narrate everything to me.\"
      </p>
      
      <p>
        Lord Sri Krishna said, \"Oh king, your inquiry is wonderful because the answer will benefit the whole human society. This Ekadasi is so sublime and meritorious that even the greatest sins can be erased by its purity.\"
      </p>
      
      <p>
        \"Oh great saintly king, the name of this unlimitedly meritorious Ekadasi is Apara Ekadasi. Whoever fasts on this holy day becomes famous all over the universe. Even such sins as killing a brahmana, a cow, or an embryo; blasphemy; or having sex with another man\'s wife are completely eradicated by observing Apara Ekadasi.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Apara Ekadasi is an axe that cuts down the fully matured forest full of trees of sinful deeds, it is a forest fire that burns sins as if they were kindling firewood, it is the sun blazing before one\'s dark misdeeds, and it is a lion stalking the meek deer of impiety.\"
      </blockquote>

      <p>
        \"Oh king, people who bear false witness are most sinful. A person who falsely or sarcastically glorifies another; one who cheats while weighing something on a scale; one who fails to execute the duties of his varna or ashrama (an unqualified man posing as a brahmin, for example, or a person reciting the Vedas wrongly); one who invents his own scriptures; one who cheats others; one who is a charlatan astrologer, a cheating accountant, or a false Ayurvedic doctor – all these are surely as bad as persons who bear false witness, and they are all destined for hellish punishments. But simply by observing Apara Ekadasi, all such sinners become completely free of their sinful reactions.\"
      </p>
      
      <p>
        \"Warriors who fall from their kshatriya-dharma and flee the battlefield go to a ferocious hell. But, Oh Yudhishthira, even such a fallen kshatriya, if he observes fasting on the Apara Ekadasi, is freed of that great sinful reaction and goes to heaven.\"
      </p>
      
      <p>
        \"That disciple is the greatest sinner who, after receiving a proper spiritual education from his spiritual master, turns around and blasphemes him. Such a so-called disciple suffers unlimitedly. But even he, rascal though he be, if he simply observes Apara Ekadasi, can attain to the spiritual world.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Comparison of Merit</h3>
      <p>
        \"Listen, Oh king, as I describe to you further glories of this amazing Ekadasi. The merit attained by one who performs all of the following acts of piety is equal to the merit achieved by one who observes Apara Ekadasi:\"
      </p>
      
      <ul>
        <li>Bathing three times daily in Pushkara-kshetra during Kartika (October-November);</li>
        <li>Bathing at Prayag in the month of Magha (January-February) when the sun is in the zodiac of Capricorn;</li>
        <li>Rendering service to Lord Shiva at Varanasi (Benares) during Shiva-ratri;</li>
        <li>Offering oblations to one\'s forefathers at Gaya;</li>
        <li>Bathing in the sacred Gautami River when Jupiter transits Leo (Simha);</li>
        <li>Having darshan of Lord Shiva at Kedaranatha;</li>
        <li>Seeing Lord Badrinath when the Sun transits the sign of Aquarius (Kumbha);</li>
        <li>Bathing at the time of a solar eclipse at Kurukshetra and giving cows, elephants, and gold there in charity.</li>
      </ul>
      
      <p>
        \"All the merit one gets from performing these pious acts is gained by a person who observes the Apara Ekadasi fast. Also, the merit attained by one who donates a pregnant cow, along with gold and fertile land, is attained by one who fasts on this day.\"
      </p>
      
      <p>
        \"Therefore, Oh Yudhishthira, whoever truly fears his past and present sins must observe Apara Ekadasi very strictly. One who does not observe this fast must be born again in the material world, like one bubble among millions in a huge body of water, or like a small ant among all other species.\"
      </p>
      
      <p>
        \"Therefore one must faithfully observe the sacred Apara Ekadasi and worship the Supreme Personality of Godhead, Sri Trivikrama. One who does so is freed of all his sins and promoted to the abode of Lord Vishnu. Oh Bharata, for the benefit of all humanity I have thus described to you the importance of the holy Apara Ekadasi. Anyone who hears or reads this description is certainly freed from all kinds of sins, oh best of saintly kings, Yudhishthira.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Jyeshtha month (May/June)|Alternative Names: Achla Ekadasi|Worshipable Deity: Lord Sri Trivikrama (Vamanadeva)|Significance: sublime and meritorious fast that eradicates even the greatest sins (such as killing a brahmana or a cow, blasphemy, etc.) and awards fame and liberation.|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in chanting and seva.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (61, 'nirjala', 'Pandava Nirjala Ekadashi', 'Nirjala Ekadashi', 'The most powerful and austere fast without taking water, yielding merit of all 24 Ekadashis.', 'Pandava Nirjala Ekadashi falls during the Shukla Paksha of the Jyeshtha month (May-June). \"Nirjala\" means \"without water.\" This Ekadashi is described in the Mahabharata, where Bhima — the second Pandava brother — was unable to observe the regular Ekadashis because of his enormous appetite. He requested a single observance that would equal all 24 Ekadashis. Lord Vyasa told him to observe this waterless Ekadashi. Bhima observed it with great difficulty but succeeded, and the Lord blessed him with immense spiritual merit.', 'Nirjala Ekadashi is considered the most powerful of all Ekadashis. Observing it without even drinking water is said to bestow the merit of observing all 24 Ekadashis of the year. It falls during the hottest month of Jyeshtha, making the waterless fast particularly challenging. This Ekadashi teaches the supreme power of determination and sacrifice in spiritual life. It is observed for the purification of the soul and the destruction of all sins.', 'The observer of Nirjala Ekadashi receives the combined merit of all 24 Ekadashis of the year. This single fast destroys all sinful reactions, grants liberation from the cycle of birth and death, and brings the devotee closer to God. Despite the difficulty, those who observe it with faith receive extraordinary spiritual advancement. Donations of water, buttermilk, and food on this day are considered extremely meritorious. The observer is blessed with divine strength and unwavering devotion.', 'ekadashi', NULL, 'assets/images/banners/nirjala-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        During the hottest season of the year (in the northern hemisphere), performing a complete fast (upavasa) without taking even water is an incredible feat of devotion. This special day is known as Pandava Nirjala Ekadasi. On this day, one may take only charanamrta and achamana water for purification purposes.
      </p>
      
      <p>
        Bhima, the mighty warrior of the Pandava dynasty, requested a single vrata day by which he could obtain the fruits of all the other days of vrata that he was incapable of observing due to his insatiable hunger. Vyasadeva advised him to follow this difficult vrata. On this day, it is recommended to worship the Lord in the evening by bathing Him in milk. On the next day, Dvadashi, one should donate full pots of water to qualified brahmanas and feed them nicely before breaking one\'s fast.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <!-- Sanskrit Verse Block 1 -->
      <div style=\"background:var(--light); padding:var(--space-xl); border-radius:var(--radius-sm); border-left:4px solid var(--primary); text-align:center; margin:var(--space-md) 0;\">
        <p style=\"font-family:var(--font-subheading); font-size:var(--font-size-base); font-weight:600; color:var(--primary-dark); line-height:1.6; margin-bottom:12px;\">
          SAMVATSARASYA YA MADHYE EKADASYO BHAVANTI HI<br>
          TASAM PHALAM AVAPNOTI PUTRA ME NA ATRA SAMSAYAH<br>
          ITI MAM KESAVAH PRAHA SANKHA CAKRA GADADHARAH
        </p>
        <p style=\"font-size:var(--font-size-sm); color:var(--text-dark); line-height:1.5; font-style:italic; margin:0;\">
          \"Oh son, Lord Keshava, Who holds the club, disk, conch and lotus flower in His hand, personally told me that all of the merit achieved by fasting on whatever Ekadasis fall in one year can be attained by fasting on this one Ekadasi (Nirjala Ekadasi). Of this, there is no doubt.\"<br>
          <span style=\"font-size:11px; color:var(--text-light); font-weight:600; font-style:normal; display:block; margin-top:6px;\">— Hari Bhakti Vilasa 15/25 from Padma Purana (Vyasadeva to Bhimasena)</span>
        </p>
      </div>

      <!-- Sanskrit Verse Block 2 -->
      <div style=\"background:var(--light); padding:var(--space-xl); border-radius:var(--radius-sm); border-left:4px solid var(--maroon); text-align:center; margin:var(--space-md) 0;\">
        <p style=\"font-family:var(--font-subheading); font-size:var(--font-size-base); font-weight:600; color:var(--maroon); line-height:1.6; margin-bottom:12px;\">
          ATMADROHAH KRTASTES TU YAIR ESA NA HY UPOSITA<br>
          PAPATMANO DURACARA DUSTAS TE NA ATRA SAMSAYAH
        </p>
        <p style=\"font-size:var(--font-size-sm); color:var(--text-dark); line-height:1.5; font-style:italic; margin:0;\">
          \"Anyone who does not fast on this particular Ekadasi (Nirjala Ekadasi), they should be understood to be sinful, corrupted and suicidal person without a doubt.\"<br>
          <span style=\"font-size:11px; color:var(--text-light); font-weight:600; font-style:normal; display:block; margin-top:6px;\">— Hari Bhakti Vilasa 15/33 from Padma Purana (Vyasadeva to Bhimasena)</span>
        </p>
      </div>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of Pandava Nirjala Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        Once Bhimasena, the younger brother of Maharaja Yudhisthira, asked the great sage Shrila Vyasadeva, the grandfather of the Pandavas, if it is possible to return to the spiritual world without having observed all the rules and regulations of the Ekadasi fasts.
      </p>
      
      <p>
        Bhimasena spoke as follows: \"Oh greatly intelligent and learned grandfather, my brother Yudhisthira, my dear mother Kunti, and my beloved wife Draupadi, as well as Arjuna, Nakula and Sahadeva, fast completely on each Ekadasi and strictly follow all the rules, guidelines and regulative injunctions of that sacred day. Being very religious, they always tell me that I should also fast on that day too. But, Oh learned grandfather, I tell them that I cannot live without eating, because as the son of Vayudeva—Samanaprana, (the digestive air) hunger is unbearable to me. I can give widely in charity and worship Lord Keshava properly with all manner of wonderful upacharas (items), but I cannot be asked to fast on Ekadasi. Please tell me how I can obtain the same merits without fasting.\"
      </p>
      
      <p>
        Hearing these words, the grandsire of Bhima, Srila Vyasadeva said, \"If you want to go to the heavenly planets and avoid the hellish planets, you should indeed observe a fast on both the light and dark Ekadasis.\"
      </p>
      
      <p>
        Bhima replied, \"Oh great saintly intelligent grandfather, please listen to my plea. Oh greatest of munis, since I cannot live if I eat only once in a day, how can I possibly live if I fast completely? Within my stomach burns a special fire named Vrika, the fire of digestion.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--primary); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        <strong>The Fire of Digestion (Vrika):</strong> Agni, the fire-god, descends from Lord Vishnu through Brahma, from Brahma to Angirasa, from Angirasa to Brihaspati, and from Brihaspati to Samyu, who was Agni\'s father. Agni is divided into three categories: <em>Davagni</em> (the fire in wood), <em>Jatharagni</em> (the digestive fire in the stomach), and <em>Vadavagni</em> (the fire that creates fog when hot and cold ocean currents mix). Another name for this Jatharagni is Vrika, and it was this powerful digestive fire that resided in Bhima\'s stomach, making hunger completely unbearable for him.
      </blockquote>

      <p>
        \"Only when I eat to my full satisfaction does the fire in my stomach become satisfied. Oh great sage, I might possibly be able to fast only once, so I beg that you tell me of an Ekadasi that is worthy of my fasting and that includes all other Ekadasis. I shall faithfully observe that fast and hopefully still become eligible for liberation\'s release.\"
      </p>
      
      <p>
        Shrila Vyasadeva replied, \"Oh king, you have heard from me about the various kinds of occupational duties, such as elaborate Vedic ceremonies and pujas. In the Kali-yuga, however, no one will be able to observe all these occupational, functional duties properly. I shall therefore tell you how, at practically no expense, one can endure some small austerity and achieve the greatest benefit and resultant happiness. The essence of what is written in the Vedic literatures known as the Puranas is that one should not eat on either the dark or light fortnight Ekadasis. One who fasts on Ekadasi is saved from going to the hellish planets.\"
      </p>
      
      <p>
        Hearing Shrila Vyasadeva\'s words, the son of Vayu, Bhimasena, the strongest of all warriors, became frightened and began to shake like a leaf on a banyan tree in a strong wind. The frightened Bhimasena then said, \"Oh grandfather, what should I do? I am completely unable and ill-equipped to fast twice in a month throughout the year! Please tell me of the one fasting day that will bestow the greatest benefit upon me!\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Injunction of the Nirjala Fast</h3>
      <p>
        Vyasadeva replied, \"Without drinking even water, you should fast on the Ekadasi that occurs during the light fortnight of the month of Jyeshtha (May-June) when the sun travels in the sign of Taurus and Gemini. According to learned personalities, on this day one may bathe and perform Achamana for purification. But while performing Achamana one may drink only that amount of water equal to a drop of gold, or that amount it takes to immerse a single mustard seed. Only this amount of water should be placed in the right palm for sipping, which one should form to resemble a cow\'s ear. If one drinks more water than this, he might as well have drunk wine—despite the soaring heat of summer.\"
      </p>
      
      <p>
        \"One must certainly not eat anything, for if he does so he breaks his fast. This rigid fast is in effect from sunrise on the Ekadasi day to sunrise on the Dvadashi day. If a person endeavors to observe this great fast very strictly, he easily achieves the result of observing all twenty-four other Ekadasi fasts throughout the entire year.\"
      </p>
      
      <p>
        \"On Dvadashi the devotee should bathe early in the morning. Then, according to the prescribed rules, guidelines and regulative injunctions, and of course depending on his ability, he should give some gold and water to worthy brahmanas. Finally, he should cheerfully honor prasadam with a brahmana.\"
      </p>
      
      <p>
        \"Oh Bhimasena, one who can fast on this special Ekadasi in this manner reaps the benefit of having fasted on every Ekadasi during the year. There is no doubt of this. The Supreme Lord Keshava, who holds a conch, discus, club and lotus, personally told me, \'Everyone should take shelter of Me and follow My instructions.\' Then He told me that one who fasts on this Ekadasi, without taking even drinking water or eating, becomes free of all sinful reactions, and that one who observes the difficult nirjala fast on Jyeshtha-shukla Ekadasi truly reaps the benefit of all other Ekadasi fasts.\"
      </p>
      
      <p>
        \"Oh Bhimasena, in the Kali-yuga, the age of quarrel and hypocrisy, when all the principles of the Vedas will have been destroyed or greatly minimized, and when there will be no proper charity or observance of the ancient Vedic principles and ceremonies, how will there be any means of purifying the self? But there is the opportunity to fast on Ekadasi and become free of all one\'s past sins.\"
      </p>
      
      <p>
        \"Oh son of Vayu, what more can I say to you? You should not eat during the Ekadasis that occur during the dark and light fortnights, and you should even give up drinking water on the particularly auspicious Ekadasi day of Jyeshtha-shukla Ekadasi. Oh Vrikodara (voracious eater), whoever fasts on this Ekadasi receives the merits of bathing in all the places of pilgrimage, giving all kinds of charities to worthy persons, and fasting on all the dark and light Ekadasis throughout the year, in one go. Of this there is no doubt.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Deliverance from Yamadutas</h3>
      <p>
        \"Oh tiger among men, whoever fasts on this Ekadasi truly becomes a great person and achieves all manner of opulence and wealth, grains, strength, and health. And at the fearful moment of death, the terrible Yamadutas, whose complexions are yellow and black and who brandish huge maces and twirl pasha ropes in the air for binding their victims, will refuse to approach him. Rather, such a faithful soul will at once be taken to the supreme abode of Lord Vishnu by the Vishnudutas, whose transcendentally beautiful forms are clothed in gorgeous yellowish garments and who each hold a disk, club, conch and lotus in their four hands.\"
      </p>
      
      <p>
        When the other Pandavas heard about the benefits to be gained by following Jyeshtha-shukla Ekadasi, they resolved to observe it exactly as their grandfather Srila Vyasadeva had explained it to their brother, Bhimasena. All the Pandavas observed it by refraining from eating or drinking anything, and thus this day is also known as <strong>Pandava Nirjala Dvadashi</strong>.
      </p>
      
      <p>
        Shrila Vyasadeva continued, \"Oh Bhimasen, therefore you should observe this important fast to remove all your past sinful reactions. You should pray to the Supreme Personality of Godhead, Lord Sri Krishna in this way making your sankalpa declaration: \'Oh Lord of all the devas, Oh Supreme Personality of Godhead, today I shall observe Ekadasi without taking any water. Oh unlimited Anantadev, I shall break fast on the next day, Dvadashi.\' Thereafter, to remove all his sins, the devotee should honor this Ekadasi fast with full faith in the Lord and with full control over his senses. Whether his sins are equal in volume to Mount Sumeru or to Mandarachala Hill, if he or she observes this Ekadasi, the sins that have been accumulated all become nullified and are burned to ashes. Such is the great power of this Ekadasi.\"
      </p>

      <p>
        \"Oh best of human beings, although a person should also give water and cows in charity during this Ekadasi, if for some reason or other he cannot, then he should give a qualified brahmana some cloth or a pot filled with water. Indeed, the merit achieved by giving water alone equals that gained by giving gold ten million times a day.\"
      </p>
      
      <p>
        \"Oh Bhima, Lord Sri Krishna has said that whoever observes this Ekadasi should take a Holy bath, give charity to a worthy person, chant the Lord\'s Holy names on a japa-mala, and perform some kind of recommended sacrifice, for by doing these things on this day one receives imperishable benefits. Observance of this Ekadasi fast alone promotes one to the supreme abode of Sri Vishnu.\"
      </p>
      
      <p>
        \"Remember, whosoever eats any grains on Ekadasi becomes contaminated by sin and verily eats only sin. In effect, he has already become a dog-eater, and after death he suffers a hellish existence. But he who observes this sacred Jyeshtha-shukla Ekadasi and gives something in charity certainly achieves liberation from the cycle of repeated birth and death and attains to the supreme abode. Observing this Ekadasi frees one from the horrible sin of killing a brahmana, drinking liquor, becoming envious of one\'s spiritual master, and continually telling lies.\"
      </p>
      
      <p>
        \"Furthermore, any man or woman who observes this fast properly and worships the Supreme Lord Jalashayi (He who sleeps on the water), and who on the next day satisfies a qualified brahmana with nice sweets and a donation of cows and money—such a person certainly pleases the Supreme Lord Vasudeva, so much so that one hundred previous generations in his family undoubtedly go to the Supreme Lord\'s abode. Indeed, one who observes this amazing Ekadasi rides on a glorious celestial airplane (vimana) to the Lord\'s abode.\"
      </p>
      
      <p>
        \"One who on this day gives a brahmana a waterpot, an umbrella, or shoes surely goes to the heavenly planets. Indeed, he who simply hears these glories also attains to the transcendental abode of the Supreme Lord, Shri Vishnu.\"
      </p>

      <p>
        \"One should clean his teeth properly and, without eating or drinking, observe this Ekadasi to please the Supreme Lord, Keshava. On the day after Ekadasi one should worship the Supreme Personality of Godhead in His form as Trivikrama by offering Him water, flowers, incense, and a brightly burning lamp. Then the devotee should pray from the heart: \'Oh God of gods, Oh deliverer of everyone, Oh Hrishikesha, master of the senses, kindly bestow upon me the gift of liberation, though I can offer you nothing greater than this humble pot filled with water.\' Then the devotee should donate the waterpot to a brahmana.\"
      </p>
      
      <p>
        \"Oh Bhimasena, after this Ekadasi fast and donating the recommended items according to his ability, the devotee should feed brahmanas and thereafter honor prasadam silently. I strongly urge you to fast on this auspicious, purifying, sin-devouring Dvadashi in just the way I have outlined. Thus you will be completely freed of all sins and reach the supreme abode.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Jyeshtha month (May/June)|Alternative Names: Nirjala Ekadasi, Bhimaseni Ekadasi, Pandava Dvadashi|Significance: The most powerful and austere Ekadasi. Fasting completely from water on this day yields the merit of all 24 Ekadasis in a year.|Rules: Strict fast from food and water (no water starting from sunrise on Ekadasi to sunrise on Dvadashi). Only achamana water (amount of a mustard seed) is permitted for purification.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (62, 'yogini', 'Yogini Ekadashi', 'Yogini Ekadashi', 'Equivalent to feeding 88,000 brahmanas, purging diseases and nullifying curses.', 'Yogini Ekadashi falls during the Krishna Paksha of the Ashadha month (June-July). This Ekadashi is described in the Brahma Vaivarta Purana, where Lord Krishna tells Yudhishthira about a gardener named Hem who served the demigod Kubera. One day he failed to deliver flowers on time due to a mistake. Kubera cursed him to become a leper. Hem\'s wife advised him to observe Yogini Ekadashi. He observed it with devotion, and the Lord freed him from the curse, restoring his health and position.', 'Yogini Ekadashi is observed for liberation from diseases, particularly skin ailments and chronic illnesses. The name \"Yogini\" refers to the spiritual energy (yogini shakti) that resides in the devotee during this observance. It falls during the beginning of Chaturmasya, making it especially potent for spiritual practices. This Ekadashi teaches that even those who have made mistakes can be restored through sincere devotion.', 'Observing Yogini Ekadashi cures diseases and grants excellent health. The fast purifies the blood, removes toxins, and strengthens the body\'s natural healing abilities. Those who donate food, medicine, and fruits on this day receive the blessings of Lord Vishnu for good health. The observer is freed from skin diseases, chronic ailments, and the reactions of past sinful activities. It brings physical vitality and spiritual energy.', 'ekadashi', NULL, 'assets/images/banners/yogini-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        The 11th day of Krishna Paksha (moon\'s waning phase) in the month of Ashadha (June – July) is observed as Yogini Ekadasi. It is considered a very auspicious and rewarding day to fulfill one\'s wishes and destroy all the sins of a lifetime. Observing a vow (vrata) on this day is declared in the scriptures to be equivalent to feeding 88,000 pious brahmanas.
      </p>
      
      <p>
        As Gaudiya Vaishnavas, our main aim during Ekadasi is to decrease bodily demands so we can spend more time in seva, especially hearing and chanting about the Lord. It is highly recommended to chant extra rounds and stay up all night chanting and hearing the Lord\'s glories.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Yogini Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        Yudhisthira Maharaj said, \"Oh Supreme Lord, I have heard the glories of the Nirjala Ekadasi, which occurs during the light fortnight of the month of Jyeshtha (May – June). Now I wish to hear from You about the suddha Ekadasi that occurs during the dark fortnight of the month of Ashadha (June – July). Kindly describe to me all about it in detail, Oh killer of the Madhu demon (Madhusudana).\"
      </p>
      
      <p>
        The Supreme Lord, Sri Krishna, then replied, \"Oh king, I shall indeed tell you about the best of all fasting days, the Ekadasi that comes during the dark part of the month of Ashadha. Famous as Yogini Ekadasi, it removes all kinds of sinful reactions and awards supreme liberation.\"
      </p>
      
      <p>
        \"Oh best of kings, this Ekadasi delivers people who are drowning in the vast ocean of material existence and transports them to the shore of the spiritual world. In all the three worlds, it is the chief of all sacred fasting days. I shall now reveal this truth to you by narrating a history recounted in the Puranas.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of Hemamali</h3>
      <p>
        \"The king of Alakapuri – Kuvera, the treasurer of the devas (demigods) – was a steadfast devotee of lord Shiva. He employed a servant named Hemamali as his personal gardener. Hemamali, a Yaksha like Kuvera, was very lustfully attracted to his gorgeous wife, Swarupavati, who had large, enchanting eyes.\"
      </p>
      
      <p>
        \"Hemamali\'s daily duty was to visit Manasarovara Lake and bring back flowers for his master, Kuvera, with which he would use them in the puja offerings to lord Shiva. One day, after picking the flowers, Hemamali went to his wife instead of returning directly to his master and fulfilling his duty by bringing the flowers for the puja. Absorbed in loving affairs of a bodily nature with his wife, he forgot to return to the abode of Kuvera.\"
      </p>
      
      <p>
        \"Oh king, while Hemamali was enjoying with his wife, Kuvera had begun the worship of lord Shiva as normal in his palace and soon discovered that there were no flowers ready to be offered in the midday puja. The lack of such an important item (upachara) angered the great Koshad-yaksha (treasurer of the devas) even more, and he asked a Yaksha messenger, \'Why has dirty-hearted Hemamali not come with the daily offering of flowers? Go find out the exact reason and report back to me in person with your findings.\' The Yaksha returned and told Kuvera, \'Oh dear lord, Hemamali has become lost in freely enjoying coitus with his wife.\'\"
      </p>
      
      <p>
        \"Kuvera became extremely angry when he heard this and at once summoned lowly Hemamali before him. Knowing that he had been remiss and dawdling in his duty and exposed as meditating on his wife\'s body, Hemamali approached his master in great fear. The gardener first paid his obeisances and then stood before his lord, whose eyes had become red with anger and whose lips trembled in rage. So enraged, Kuvera cried out to Hemamali, \'Oh you sinful rascal! Oh destroyer of religious principles! You are a walking offense to the devas! I therefore curse you to suffer from white leprosy and to become separated from your beloved wife! Only great suffering is deservedly yours! Oh lowborn fool, leave this place immediately and betake yourself to the lower planets to suffer!\'\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"And so Hemamali fell at once from grace in Alakapuri and became ill with the terrible affliction of white leprosy. He awoke in a dense and fearful forest, where there was nothing to eat or drink. Thus he passed his days in misery, unable to sleep at night due to pain.\"
      </blockquote>

      <p>
        \"He suffered in both winter and summer season, but because he continued to worship lord Shiva himself with faith, his consciousness remained purely fixed and steady. Although implicated by great sin and its attendant reactions, he remembered his past life because of his piety.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Meeting with Sage Markandeya</h3>
      <p>
        \"After wandering for some time here and there, over mountains and across plains, Hemamali eventually came upon the vast expanse of the Himalayan mountain ranges. There he had the wonderful good fortune to come in contact with the great saintly soul Markandeya Rishi, the best of ascetics, whose duration of life it is said, extends to seven of the days of Brahma.\"
      </p>
      
      <p>
        \"Markandeya Rishi was seated peacefully at his ashrama, looking as effulgent as a second Brahma. Hemamali, feeling very sinful, stood at a distance from the magnificent sage and offered his humble obeisances and choice prayers. Always interested in the welfare of others, Markandeya Rishi saw the leper and called him near: \'Oh you, what sort of sinful deeds have you done to earn this dreadful affliction?\'\"
      </p>
      
      <p>
        \"Hearing this, Hemamali painfully and ashamed replied, \'Dear sir, I am a Yaksha servant of lord Kuvera, and my name is Hemamali. It was my daily service to pick the flowers from the Manasarovara lake for my master\'s worship of lord Shiva, but one day I was negligent and was late in returning with the offering because I had become overwhelmed with lusty passion for enjoying bodily pleasures with my wife. When my master discovered why I was late, he cursed me in great anger to be as I am before you. Thus I am now bereft of my home, my wife, and my service. But fortunately I have come upon you, and now I hope to receive from you an auspicious benediction, for I know that devotees such as you are as merciful as the Supreme Lord and always carry the interest of others uppermost in their hearts. That is your nature. Oh best of sages, please help me!\'\"
      </p>
      
      <p>
        \"Softhearted Markandeya Rishi replied, \'Because you have told me the truth, I shall tell you about a fast day that will benefit you greatly. If you fast on the Ekadasi that comes during the dark fortnight of the month of Ashadha, you will surely be freed of this terrible curse.\'\"
      </p>
      
      <p>
        \"Hemamali fell to the ground in complete gratitude and offered him his humble obeisances again and again. But Markandeya Rishi stood there and lifted poor Hemamali up to his feet, filling him with inexpressible happiness.\"
      </p>
      
      <p>
        \"Thus, as the sage had instructed him, Hemamali dutifully observed the Ekadasi fast, and by its influence he again became a handsome Yaksha. Then he returned home, where he lived very happily with his wife.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"So, you can readily see, Oh Yudhishthira, that fasting on Yogini Ekadasi is very powerful and auspicious. Whatever merit one obtains by feeding eighty-eight thousand brahmins is also obtained simply by observing a strict fast on Yogini Ekadasi. For one who fasts on this sacred Ekadasi, she (Ekadasi Devi), destroys heaps of past sinful reactions and makes him most pious. Oh King, thus I have explained to you the purity of Yogini Ekadasi.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Ashadha month (June/July)|Alternative Names: Ashadhi Ekadasi|Significance: Equivalent to feeding 88,000 pious brahmanas. Destroys heaps of past sinful reactions and awards liberation.|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (63, 'sayana', 'Sayana / Devshayani Ekadashi', 'Sayana Ekadashi', 'Marks the start of Chaturmasya, when Lord Vishnu enters sleep on Shesha Naga.', 'Sayana Ekadashi, also known as Devshayani Ekadashi, falls during the Krishna Paksha of the Ashadha month (June-July). \"Sayana\" means \"sleeping\" — on this day, Lord Vishnu enters His four-month cosmic sleep (Yoga Nidra) on the cosmic ocean (Kshira Sagara). This Ekadashi is described in the Padma Purana, where Lord Krishna explains that no auspicious activities like marriages, house-warming ceremonies, or new ventures should be undertaken during the four months the Lord sleeps. The story of King Yudhishthira\'s question to Lord Krishna about this Ekadashi is narrated in detail.', 'Sayana Ekadashi marks the beginning of Chaturmasya — the four-month period when Lord Vishnu rests. It is observed with great devotion to seek the Lord\'s blessings before He enters cosmic sleep. All auspicious ceremonies are suspended during this period. This Ekadashi teaches the importance of spiritual discipline and restraint. It is also observed to ensure that the observer is protected during the Chaturmasya period.', 'Observing Sayana Ekadashi grants protection during the Chaturmasya period. The fast ensures that the observer\'s spiritual progress continues even while the Lord rests. Those who observe this Ekadashi and donate food, bedding, and clothes receive the Lord\'s special grace. The observer is blessed with the cessation of all sinful reactions and is protected from negative influences during the Chaturmasya months. It brings peace and spiritual stability.', 'ekadashi', NULL, 'assets/images/banners/sayana-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Sayana Ekadasi (also known as Shayani Ekadasi, Maha-ekadasi, Padma Ekadasi, or Devshayani Ekadasi) is the eleventh lunar day of the bright fortnight (Shukla paksha) of the Vedic month of Ashadha (June – July). 
      </p>
      
      <p>
        On this day, Lord Ksirodakasayi Vishnu falls asleep in Ksheersagar—the cosmic ocean of milk—on Shesha Naga, the cosmic serpent. Lord Vishnu finally awakens from His slumber four months later on Prabodhini Ekadasi in the month of Kartika. This four-month period is known as <strong>Chaturmasya</strong> and coincides with the rainy season. Consequently, Shayani Ekadasi marks the beginning of Chaturmasya, and devotees begin their Chaturmasya vows (vrata) on this auspicious day to please the Supreme Lord.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Sayana Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishya-uttara Purana
      </p>
      
      <p>
        The saintly king Yudhishthira Maharaj said, \"Oh Keshava, what is the name of that Ekadasi that occurs during the light fortnight of the month of Ashadha (June – July)? Who is the worshipable Deity for this auspicious day, and what is the process for observing this event?\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"Oh caretaker of this earthly planet, I shall gladly tell you a wonderful historical event that the deva lord Brahma once narrated to his son Narada Muni.\"
      </p>
      
      <p>
        \"One day Narada Muni asked his father, \'What is the name of the Ekadasi that comes during the light part of the month of Ashadha. Kindly tell me how I should observe this Ekadasi and thus please the Supreme Lord, Sri Vishnu.\'\"
      </p>
      
      <p>
        \"Lord Brahma replied, \'Oh great saintly orator, Oh best of all sages, Oh purest devotee of Lord Vishnu, your question is as usual excellent for all mankind. There is nothing better than Ekadasi, the day of Lord Sri Hari, in this or any other world. It nullifies even the worst sins if observed properly. For this reason I shall tell you about this Ashadha-shukla Ekadasi. Fasting on this Ekadasi purifies one of all sins and fulfills all one\'s desires. Therefore, whoever neglects to observe this sacred fast day is a good candidate for entering into hell.\'\"
      </p>
      
      <p>
        \"Ashadha-shukla Ekadasi is also famous as Padma Ekadasi. Just to please the Supreme Lord Hrishikesha, the master of the senses, one should fast on this day. Listen carefully, Oh Narada, as I relate to you a wonderful historical event that was recorded in the scriptures regarding this Ekadasi. Just hearing this account destroys all kinds of sins, along with all obstacles on the path to spiritual perfection.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Piety of King Mandhata</h3>
      <p>
        \"Oh son, there was once a saintly king in the Surya Vamsha (Sun dynasty) whose name was Mandhata. Because he always stood up for the truth, he was appointed emperor. He took care of his subjects as though they were his very own family members and children. On account of his piety and great religiosity, there was no pestilence, drought, or disease of any kind in his entire kingdom. All his subjects were not only free of all kinds of disturbances but also were very wealthy. The king\'s own treasury was free of any ill-gotten moneys, and thus he ruled happily for many years.\"
      </p>
      
      <p>
        \"Once, however, because of some sin in his kingdom, there was a drought for three years. The subjects found themselves beset by famine also. The lack of food grains made it impossible for them to perform the prescribed Vedic sacrifices, offer oblations of ghrita (ghee) to their forefathers and to the devas, engage in any ritualistic worship, or even study the Vedic literatures. Finally, they all came before their beloved king in a great assembly and addressed him.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Oh king, you always see to our welfare, so we humbly beg your assistance now. Everyone and everything in this world needs water. Without water, almost everything is rendered useless or dead. The Vedas call water <em>nara</em>, and because the Supreme Personality of Godhead sleeps upon water, His another name is Narayana. God makes His own abode on water and takes His rest there.\"
      </blockquote>

      <p>
        \"It is said that three things cannot exist without water: pearls, human beings, and flour. The essential quality of a pearl is its luster, and that is due to water. The essence of a man is his semen, whose main constituent is water. And without water, flour cannot be made into dough and then be cooked into various forms of bread, offered and eaten. Sometimes water is called jala-narayana, the Supreme Lord in the form of this life-sustaining substance. In His form as the clouds, the Supreme Lord is present throughout the sky and pours forth rains, from which grow the grains that maintain every living entity. Oh king, the severe drought has caused a great lack of valuable grains; thus, we are all miserable, and the population is decreasing as people die off or leave your kingdom. Oh best ruler on Earth, please find some solutions to this problem and bring us to peace and prosperity once again.\"
      </p>
      
      <p>
        \"The king replied, \'You speak the truth, for grains are like Brahman, the Absolute Truth, who lives within grains and thereby sustains all beings. Indeed, it is because of grains that the entire world lives. Now, why is there a terrible drought in our kingdom? The Holy Scriptures discuss this subject very thoroughly. If a king (or head of the country) is irreligious, both he and his subjects suffer. I have meditated upon the cause of our problem for a long time, but after searching my past and present character I can honestly say that I find no sin. Still, for the good of all you subjects, I shall try to remedy the situation.\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Advice of Sage Angira</h3>
      <p>
        \"Thinking in this way, King Mandhata assembled his army and entourage, paid his obeisances to me (Brahma), and then entered the forest. He wandered here and there, seeking great sages in their Ashrams and inquiring about how to resolve the crisis in his kingdom. At last, he came upon the ashram of one of my other sons, Angira Muni, whose effulgence lit up all directions. Seated in his hermitage, Angira looked like a second Brahma. King Mandhata was very pleased to see that exalted sage, whose senses were completely under control. The king immediately dismounted his horse and offered his respectful obeisances at the lotus feet of Angira Muni. Then the king joined his palms and prayed for the Muni\'s blessings. That saintly person reciprocated by blessing the king with sacred mantras; then he asked him about the welfare of the seven limbs of his kingdom.\"
      </p>
      
      <p>
        \"The seven limbs of a king\'s domain are: the king himself, the ministers, his treasury, his military forces, his allies, the brahmins, and the sacrifices performed in the kingdom along with the needs of the subjects under his care.\"
      </p>
      
      <p>
        \"After telling the sage how the seven limbs of his kingdom were situated, King Mandhata asked the sage about his own situation. Then Angira Muni asked the king why he had undertaken such a difficult journey into the forest, and the king told him of the affliction in his kingdom: \'Oh great sage, I am ruling and maintaining my kingdom while following the Vedic injunctions, and thus I do not know the reason for the drought. To solve this mystery, I have approached you for help. Please help me relieve the suffering of my subjects.\'\"
      </p>
      
      <p>
        \"Angira Rishi said to the king, \'The present age, Satya-yuga, is the best of all ages, for in this age Dharma stands on all four legs (Truthfulness, Austerity, Mercy, and Cleanliness). In this age everyone respects Brahmins as the topmost members of society. Also, everyone fulfills his occupational duties, and only twice-born Brahmins are allowed to perform Vedic austerities and penances. Although this is a standard, Oh lion among kings, there is one shudra (uninitiated, untrained person) who is unlawfully performing the rites of austerity and penance in your kingdom. This is why there is no rain in your land. You should therefore punish this laborer with death, for by so doing you will remove the contamination inflicted by his actions and restore peace to your subjects.\'\"
      </p>
      
      <p>
        \"The king then replied, \'How can I kill an offense-less performer of austerity and sacrifice? Please give me some spiritual solution.\' The great sage Angira Muni then said, \'Oh king, you should observe a fast on the Ekadasi that occurs during the light fortnight of the month of Ashadha. This auspicious day is named Padma Ekadasi, and by its influence plentiful rains and thus grains and other foodstuffs will surely return to your kingdom. This Ekadasi bestows perfection upon its faithful observers, removes all kinds of bad elements, and destroys all obstacles on the path to perfection. Oh king, you, your relatives, and your subjects should all observe this sacred Ekadasi fast. Then everything in your kingdom will undoubtedly return to normal.\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Rains of Prosperity</h3>
      <p>
        \"Upon hearing these words, the king offered his obeisances and then returned to his palace. When the Padma Ekadasi arrived, King Mandhata assembled all the Brahmins, Kshatriyas, Vaishyas and Shudras in his kingdom and instructed them to strictly observe this important fast day. After they had observed it, the rains fell, just as the sage had predicted, and in due course of time there were abundant crops and a rich harvest of grain. By the mercy of the Supreme Lord Hrishikesha, the master of the senses, all the subjects of King Mandhata became extremely happy and prosperous. Therefore, Oh Narada, everyone should observe this Ekadasi fast very strictly, for it bestows all kinds of happiness, as well as ultimate liberation, upon the faithful devotee.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"My dear Yudhishthira, Padma Ekadasi is so powerful that one who simply reads or hears its glories becomes completely sinless. Oh Pandava, one who wishes to please Me should strictly observe this Ekadasi, which is also known as Deva-sayani Ekadasi.\"
      </p>
      
      <p>
        \"Deva-sayani, or Vishnu-sayani, indicates the day when Lord Vishnu goes to sleep with all the devas. It is said that after this day one should not perform any new auspicious ceremonies until Devotthani Ekadasi, which occurs during the month of Kartika (October – November), because the devas, being asleep, cannot be invited to the sacrificial arena and because the Sun is traveling along its Southern course (Dakshinayanam).\"
      </p>
      
      <p>
        Lord Sri Krishna continued, \"Oh lion among kings, Yudhishthira Maharaj, whoever wants liberation should regularly observe a fast on this Ekadasi which is also the day when the Chaturmasya fast begins.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Ashadha month (June/July)|Alternative Names: Shayani Ekadasi, Maha-ekadasi, Padma Ekadasi, Devshayani Ekadasi, Ashadhi Ekadasi|Significance: Beginning of Chaturmasya. Lord Vishnu enters yoga-nidra on Shesha Naga in the Ocean of Milk.|Rules: Strict fast from all grains, legumes, and beans. Devotees decrease bodily demands to spend more time in chanting and seva.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (64, 'kamika', 'Kamika Ekadashi', 'Kamika Ekadashi', 'Highly pleasing to Lord Hari. Awards merit equal to performing a horse sacrifice.', 'Kamika Ekadashi falls during the Krishna Paksha of the Shravana month (July-August). The name means \"desirable\" or \"wish-fulfilling.\" This Ekadashi is described in the Padma Purana, where Lord Krishna tells Yudhishthira that worshipping Lord Vishnu with Tulasi leaves on this day destroys all sins. The story involves a brahmana who accidentally killed a brahmana (brahma-hatya). Desperate for atonement, he observed Kamika Ekadashi with Tulasi worship, and the Lord forgave his grave sin.', 'Kamika Ekadashi falls during the sacred Shravana month when the influence of Lord Vishnu is especially strong. The worship of Tulasi (holy basil) on this day is considered extraordinarily powerful. The Padma Purana states that even looking at Tulasi leaves on this Ekadashi destroys sins. This Ekadashi is observed for the purification of even the most severe sinful reactions, including brahma-hatya (the killing of a brahmana).', 'Observing Kamika Ekadashi destroys even the gravest sins, including brahma-hatya. The worship of Tulasi on this day grants liberation from all sinful reactions. Those who donate Tulasi plants, food, and worship Lord Vishnu with Tulasi leaves receive immense spiritual merit. The observer is blessed with purity of consciousness and freedom from the reactions of past wrongdoings. It brings divine grace and progress toward liberation.', 'ekadashi', NULL, 'assets/images/banners/kamika-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Kamika Ekadasi is celebrated during the Krishna Paksha (dark fortnight) in the sacred month of Shravan. Observing this Ekadasi is considered as auspicious as performing an Ashwamedha Yajna (horse sacrifice). As Gaudiya Vaishnavas, our main aim during Ekadasi is to decrease bodily demands so we can spend more time in seva, especially hearing and chanting about the Lord\'s pastimes and holy name.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Kamika Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        The saintly king Yudhisthira Maharaja said, \"Oh Supreme Lord, I have heard from You the glories of fasting on Deva-sayani Ekadasi, which occurs during the light fortnight of the month of Ashadha. Now I would like to hear from You the glories of the Ekadasi that occurs during the dark fortnight (krishna paksha) of the month of Shravana (July-August). Oh Govindadeva, please be merciful to me and explain its glories. Oh Supreme Vasudeva, I offer my most humble obeisances unto You.\"
      </p>
      
      <p>
        The Supreme Lord, Sri Krishna, replied, \"Oh King, please listen attentively as I describe the auspicious influence of this holy fast day, which removes all sins. Narada Muni once asked Lord Brahma about this same topic.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Oh regent of all beings,\" said Naradaji, \"Oh you who sit upon a water-born lotus throne, please tell me the name of the Ekadasi that occurs during the dark fortnight of the sacred month of Shravana. Please also tell me which Deity is to be worshipped on that Holy day, the process one must follow to observe it, and the merit it awards.\"
      </blockquote>

      <p>
        Lord Brahma replied, \"My dear son Narada, for the benefit of all humanity I shall happily tell you everything you wish to know, for just hearing the glories of the Kamika Ekadasi bestows merit equal to that obtained by one who performs a horse sacrifice. Certainly, great merit is attained by one who worships, and who also meditates on the lotus feet of the four-armed Lord Gadadhara, who holds conchshell, disc, club and lotus in His hands and who is also known as Sridhara, Hari, Vishnu, Madhava, and Madhusudana. And the blessings achieved by such a person/devotee who worships Lord Vishnu exclusively are far greater than those achieved by one who takes a sacred bath in the Ganges at Kashi (Varanasi), in the forest of Naimisharanya, or at Pushkara, which is the only place on the planet where I (Lord Brahma) am formally worshipped.\"
      </p>
      
      <p>
        \"But one who observes this Kamika Ekadasi and also worships Lord Sri Krishna achieves greater merit than one who has darshan of Lord Kedaranatha in the Himalayas, or one who bathes at Kurukshetra during a solar eclipse, or one who donates the whole Earth in charity, including its forests and oceans, or one who bathes in the Gandaki River (where the sacred Saligrams are found) or the Godavari River on a full moon (purnima) day that falls on a Monday when Leo (Simha) and Jupiter (Guru) are conjoined.\"
      </p>
      
      <p>
        \"Observing Kamika Ekadasi bestows the same merit as donating a milk-cow and her auspicious calf, along with their feed. On this all-auspicious day, whosoever worships Lord Sri Sridhara-deva, Vishnu, is glorified by all the devas, Gandharvas, Pannagas, and Nagas. Those who are afraid of their past sins and completely immersed in sinful materialistic life should at least observe this best of Ekadasis according to their ability and thus attain liberation. This Ekadasi is the purest of all days and the most powerful for removing sins.\"
      </p>

      <p>
        \"Oh Naradaji, Lord Sri Hari Himself once said about this Ekadasi, \'One who fasts on Kamika Ekadasi attains much more merit than one who studies all the spiritual literatures. Anyone who fasts on this particular day and remains awake throughout the night will never experience the anger of Yamaraja, the King of death personified.\'\"
      </p>

      <p>
        \"It has been seen that whoever observes Kamika Ekadasi will not have to suffer future births, and in the past too, many yogis of devotion who fasted on this day went to the spiritual world. One should therefore follow in their auspicious footsteps and strictly observe a fast on this most auspicious of Ekadasis.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Inestimable Value of Tulsi Worship</h3>
      <p>
        \"Whosoever worships Lord Sri Hari with Tulsi leaves on this day is freed from all implication of sin. Indeed, he lives untouched by sin, as the lotus leaf, although in the water, is untouched by it. Whosoever offers Lord Sri Hari but a single leaf from the sacred Tulsi tree attains as much merit as one who gives away in charity two hundred grams of gold and eight hundred grams of silver. The Supreme Personality of Godhead is more pleased by one who offers Him a single Tulsi leaf than by one who worships Him with pearls, rubies, topaz, diamonds, lapis lazuli, sapphires, gomeda stones, cats eye gems, and coral.\"
      </p>
      
      <p>
        \"One who offers Lord Keshava newly grown manjari buds from the Tulsi plant gets rid of all the sins he has committed during this or any other lifetime. Indeed, mere darshana of Tulsi on Kamika Ekadasi removes all sins, and merely touching her and praying to her removes all kinds of disease. One who waters Tulsi devi need never fear the Lord of death, Yamaraja. One who plants or transplants Tulsi on this day will eventually reside with Lord Sri Krishna in His own abode. To Srimati Tulsi devi, who awards liberation in devotional service, one should therefore daily offer ones full obeisances.\"
      </p>

      <p>
        \"Even Chitragupta, Yamaraja\'s secretary, cannot calculate the merit obtained by one who offers Srimati Tulsi-devi a perpetually burning ghee lamp. So dear is this sacred Ekadasi to the Supreme Personality of Godhead that all the forefathers of one who offers a bright ghee lamp to Lord Shri Krishna on this day ascend to the heavenly planets and drink the celestial nectar there. Whoever offers a ghee or sesame oil lamp to Shri Krishna on this day is freed from all his sins and enters the abode of Surya, the Sun-god, with a body as bright as ten million lamps. This Ekadasi is so powerful that if one who is unable to fast simply follows the practices as mentioned herein, he is elevated to the heavenly planets, along with all their forefathers.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Conclusion and Warning Against Presumptuous Sins</h3>
      <p>
        \"Oh, Maharaja Yudhisthira,\" Lord Shri Krishna concluded, \"These were the words of Prajapati Brahma to his son Narada Muni concerning the incalculable glories of this Kamika Ekadasi, which removes all sins. This sacred day nullifies even the sin of killing a brahmana or the sin of killing an unborn child in the womb, and it promotes one to the spiritual world by making one supremely meritorious.\"
      </p>
      
      <p>
        \"One who kills the innocent, i.e., a brahmin, a child in the womb, a pious and spotless woman, etc., and then later hears about the glories of Kamika Ekadasi will be relieved of the reaction to ones sins. However, one should NOT think beforehand that one can kill a Brahmin or other innocent people and then go unpunished simply by hearing of this Ekadasi. Such knowing committing of sin is an abomination.\"
      </p>
      
      <p>
        \"Whosoever hears these glories of the Kamika Ekadasi with faith becomes free of all sins and returns home, back to Godhead – Vishnu-loka, Vaikuntha.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Shravana month (July/August)|Alternative Names: Shravana Krishna Ekadasi|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (65, 'pavitropana', 'Pavitropana / Pavitra Ekadashi', 'Pavitropana Ekadashi', 'Grants a noble heir and removes past offenses against cows.', 'Pavitropana Ekadashi, also known as Pavitra Ekadashi, falls during the Krishna Paksha of the Bhadrapada month (August-September). The name means \"making pure.\" This Ekadashi is described in the Brahma Purana, where Lord Krishna narrates the story of King Kuru who performed great austerities but was affected by the reactions of killing many people in battle. He observed this Ekadashi with strict vows and the Lord purified him completely. The \"pavitra\" (sacred thread) ceremony is performed on this day in many traditions.', 'Pavitropana Ekadashi falls near the end of Chaturmasya and is observed for complete purification of body, mind, and soul. The sacred thread ceremony (Pavitropana) performed on this day symbolizes spiritual rebirth. This Ekadashi is observed to cleanse all impurities accumulated during the Chaturmasya period. It marks the spiritual renewal of the devotee and preparation for the festive season ahead.', 'Observing Pavitropana Ekadashi purifies the devotee completely — physically, mentally, and spiritually. The fast cleanses all impurities accumulated over time and renews the observer\'s spiritual life. Donations of sacred threads, food, and clothing on this day bring immense merit. The observer is blessed with spiritual renewal, purity of consciousness, and a fresh beginning in their devotional life. It marks the end of Chaturmasya restrictions and the resumption of auspicious activities.', 'ekadashi', NULL, 'assets/images/banners/pavitropana-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Also known as Shravana Putrada or Pavitra Ekadasi, Pavitropana Ekadasi falls on the 11th lunar day of the fortnight of the waxing moon in the Vedic month of Shravana which in the Gregorian calendar falls in July or August. Fasting on this day is highly beneficial, freeing one from sins and bestowing spiritual merit.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Pavitropana Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Bhavishya Purana
      </p>
      
      <p>
        Shri Yudhisthira Maharaja said, \"Oh Madhusudana, Oh killer of the Madhu demon, please be merciful to me and describe to me the Ekadasi that occurs during the light fortnight of the month of Shravana (July-August).\"
      </p>
      
      <p>
        The Supreme Lord, Sri Krishna, replied, \"Yes, Oh king, I shall happily narrate its glories to you, for just by hearing about this sacred Ekadasi one attains the merit of performing a horse sacrifice.\"
      </p>
      
      <p>
        \"At the dawn of Dvapara-yuga there lived a king by the name of Mahijita, who ruled the kingdom of Mahismati-puri. Because he had no son, his entire kingdom seemed utterly cheerless to him. A married man who has no son gains no happiness in this life or the next. The Sanskrit word for son is <em>putra</em>. <em>Pu</em> is the name of a particular hell, and <em>tra</em> means to deliver. Thus the word <em>putra</em> means a person who delivers one from the hell named Pu. Therefore every married man should produce at least one son and train him properly; then the father will be delivered from a hellish condition of life. But this injunction does not apply to the serious devotees of Lord Vishnu or Krishna, for the Lord becomes their son, father, and mother.\"
      </p>
      
      <p>
        \"For a long time this king tried very hard to obtain an heir, but to no avail. Seeing his years advancing ever onwards, King Mahijita became increasingly anxious. One day he told an assembly of his advisers: \'I have committed no sin in this life, and there is no ill-gotten wealth in my treasury. I have never usurped the offerings to the devas or brahmanas. When I waged war and conquered kingdoms, I followed the rules and regulations of the military art, and I have protected my subjects as if they were my own children. I punished even my own relatives if they broke the law, and if my enemy was gentle and religious I welcomed him. Oh twice-born souls, although I am a religious and faithful follower of the Vedic standards, still my home is without a son. Kindly tell me the reason for this.\'\"
      </p>
      
      <p>
        \"Hearing this, the king\'s brahmana advisers discussed the subject among themselves, and with the aim of benefiting the king they visited the various ashrams of the great sages. At last they came upon a sage who was austere, pure, and self-satisfied, and who was strictly observing a vow of fasting. His senses were completely under control, he had conquered his anger, and he was expert at performing his occupational duty. Indeed, this great sage was expert in all the conclusions of the Vedas, and he had extended his life span to that of Lord Brahma himself. His name was <strong>Lomasa Rishi</strong>, and he knew past, present, and future. After each kalpa passed, one hair would fall out of his body. (One kalpa, or twelve hours of Lord Brahma, equals 4,320,000,000 years.)\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"All the king\'s brahmana advisers very happily approached him one by one to offer their humble respects. Captivated by this great soul, King Mahijita\'s advisers offered obeisances to him and said very respectfully: \'Only because of our great good fortune, Oh sage, have we been allowed to see you.\'\"
      </blockquote>

      <p>
        \"Lomasa Rishi saw them bowing down to him and replied, \'Kindly let me know why you have come here. Why are you praising me? I must do all I can to solve your problems, for sages like me have only one interest: to help others. Do not doubt this.\' Lomasa Rishi had all good qualities because he was a devotee of the Lord.\"
      </p>
      
      <p>
        \"The king\'s representatives said, \'We have come to you, Oh exalted sage, to ask for your help in solving a very serious problem. Oh sage, you are like Lord Brahma. Indeed, there is no better sage in the entire world. Our king, Mahijita, is without a son, though he has sustained and protected us as if we were his sons. Seeing him so unhappy on account of being sonless, we have become very sad, Oh sage, and therefore we have entered the forest to perform severe austerities. By our good fortune we happened upon you. Everyone\'s desires and activities become successful just by your darshana. Thus we humbly ask that you tell us how our kind king can obtain a son.\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Transgression and Its Remedy</h3>
      <p>
        \"Hearing their sincere plea, Lomasa Rishi absorbed himself in deep meditation for a moment and at once understood the king\'s previous life. Then he said, \'Your ruler was a merchant in his past life, and feeling his wealth insufficient, he committed sinful deeds. He traveled to many villages to trade his goods. Once he became thirsty while traveling from place to place. He came upon a beautiful pond on the outskirts of a village, but just as he was about to drink at the pond a cow arrived there with her newborn calf. These two creatures were also very thirsty because of the heat, but when the cow and calf started to drink, the merchant rudely shoved them aside and selfishly slaked his own thirst. This offense against a cow and her calf has resulted in your king\'s being without a son now. But the good deeds he performed in his previous life have given him rulership over an undisturbed kingdom.\'\"
      </p>
      
      <p>
        \"Hearing this, the king\'s advisers replied, \'Oh renowned rishi, we have heard that the Vedas say one can nullify the effects of one\'s past sins by acquiring merit. Be so kind as to give us some instruction by which our king\'s sins can be destroyed; please give him your mercy so that a prince will take birth in his family.\'\"
      </p>
      
      <p>
        \"Lomasa Rishi said, \'There is an Ekadasi called Putrada, which comes during the light fortnight of the month of Shravana. On this day all of you, including your king, should fast and stay awake all night, strictly following the rules and regulations. Then you should give the king whatever merit you gain by this fast. If you follow these instructions of mine, he will surely be blessed with a fine son.\'\"
      </p>
      
      <p>
        \"All the king\'s advisers became very pleased to hear these words from Lomasa Rishi, and they all offered him their grateful obeisances. Then, their eyes bright with happiness, they returned home.\"
      </p>
      
      <p>
        \"When the month of Shravana arrived, the king\'s advisers remembered the advice of Lomasa Rishi, and under their direction all the citizens of Mahismati-puri, as well as the king, fasted on Ekadasi. And on the next day, Dvadashi, the citizens dutifully offered their accrued merit to him. By the strength of all this merit, the queen became pregnant and eventually gave birth to a most beautiful son.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Bestower of a Son</h3>
      <p>
        \"O Yudhisthira,\" Lord Krishna concluded, \"the Ekadasi that comes during the light fortnight of the month of Shravana has thus rightfully become famous as Putrada [bestower of a son].\"
      </p>
      
      <p>
        \"Whoever desires happiness in this world and the next should certainly fast from all grains and legumes on this holy day. Indeed, whoever simply hears the glories of Putrada Ekadasi becomes completely free of all sins, is blessed with a good son, and surely ascends to heaven after death.\"
      </p>', 'Calendar: 11th lunar day of the waxing moon (light fortnight / Shukla Paksha) in Shravana month (July/August)|Alternative Names: Shravana Putrada Ekadasi, Pavitra Ekadasi|Rules: Strict fast from all grains, legumes, and beans. Focus on decreasing bodily demands to increase time in seva, hearing and chanting.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (66, 'annada', 'Annada / Aja Ekadashi', 'Annada Ekadashi', 'Removes all sins, restores lost kingdoms, and relieves suffering.', 'Annada Ekadashi, also known as Aja Ekadashi, falls during the Krishna Paksha of the Bhadrapada month (August-September). The name \"Annada\" means \"giver of food\" and \"Aja\" means \"unborn.\" This Ekadashi is described in the Skanda Purana, where Lord Krishna explains that this Ekadashi was observed by King Bali to regain his kingdom from Vamana Deva. It is also associated with the origin of the Annakut (mountain of food) offering. The story of a poor brahmani who offered simple food on this day and attained liberation is also narrated.', 'Annada Ekadashi emphasizes the supreme importance of food charity (anna-dana) in spiritual life. The scriptures state that feeding a hungry person is equal to feeding the Lord Himself. This Ekadashi is observed for the purification of the digestive system and for the merit earned through food distribution. It falls during the Bhadrapada month, which is associated with the Govardhan Puja and the Annakut offering.', 'Observing Annada Ekadashi grants the merit of feeding thousands. The fast purifies the digestive fire (agni) and removes diseases related to the stomach and intestines. Those who donate food — especially to the poor, travelers, and brahmanas — on this day receive immense spiritual merit. The observer is blessed with never going hungry and with the ability to provide food for others. It brings the blessings of Lord Vishnu for abundance and generosity.', 'ekadashi', NULL, 'assets/images/banners/annada-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Annada Ekadasi, also known as Aja Ekadasi, is observed during the waning phase of the moon (Krishna Paksha) in August/September. The importance of this Ekadasi was mentioned by Lord Krishna to Yudhishthira and is found in the Brahma-vaivarta Purana. It is believed that a person who observes this Ekadasi becomes free from the reactions of his/her sinful activities.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Annada Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        Sri Yudhishthira Maharaja said, \"Oh Janardana, protector of all living entities, please tell me the name of the Ekadasi that occurs during the dark fortnight of the month of Bhadrapada (August-September).\"
      </p>
      
      <p>
        The Supreme Lord, Shri Krishna, replied, \"Oh King, hear me attentively. The name of this sin-removing, sacred Ekadasi is Annada. Any person who fasts completely on this day and worships Hrishikesh, the master of the senses, becomes free of all reactions to his sins. Even one who simply hears about this Ekadasi is freed from his past sins. Oh King, there is no better day than this in all the earthly and heavenly worlds.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Ordeal of King Harishchandra</h3>
      <p>
        \"There once lived a famous king named Harishchandra, who was the emperor of the world and a person of great truth and integrity. His wife\'s name was Chandramati, and he had a son named Lohitashva. By the force of destiny, however, Harishchandra lost his great kingdom and sold his wife and son. The pious king himself became a menial servant of a dog-eater, who made him guard a crematorium. Yet even while doing such menial service, he did not forsake his truthfulness and good character.\"
      </p>
      
      <p>
        \"The king passed many years in this condition. Then one day he sadly thought: \'What shall I do? Where shall I go? How can I be delivered from this plight?\' He drowned in an ocean of anxiety. One day, a great sage happened to pass by, and when the king saw him, he paid his respectful obeisances. The sage\'s name was Gautama Muni. With joined palms, the king stood before him and narrated his pitiful story. Gautama Muni was astonished to hear the king\'s tale of woe, and out of deep compassion, he instructed him on the process of fasting for purification.\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Gautama Muni said: \'Oh king, during the dark fortnight of the month of Bhadrapada, there occurs an especially meritorious Ekadasi named Annada, which removes all sins. Indeed, if you simply fast on that day and perform no other austerity, all your sins will be nullified. It is coming in just seven days. I urge you to fast and remain awake through the night. If you do so, all the reactions of your past sins will come to an end.\' So saying, Sri Gautama Muni disappeared.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Restoration of the Kingdom</h3>
      <p>
        \"King Harishchandra followed Gautama Muni\'s instructions concerning fasting on the day of Annada Ekadasi. Oh Maharaja Yudhishthira, because the king fasted on that day, the reactions to his previous sins were completely destroyed at once. Oh lion among kings, just see the influence of this Ekadasi fast! It immediately vanquishes whatever miseries one may be suffering.\"
      </p>
      
      <p>
        \"Thus, all of Harishchandra\'s miseries were relieved. Just by the power of this wonderful Ekadasi, he was reunited with his wife and son, who had died but were now revived. In the heavenly regions, the devas began beating on their celestial kettledrums and showering down flowers upon Harishchandra, his queen, and their son. By the blessings of the Ekadasi fast, he regained his kingdom without difficulty. Moreover, when King Harishchandra left the planet, his relatives and all his subjects went with him to the spiritual world.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"Oh Pandava, whoever fasts on Annada Ekadasi is surely freed from all his sins and ascends to the spiritual world. And whosoever hears and studies the glories of this Ekadasi achieves the merit gained by performing a horse sacrifice.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Bhadrapada month (August/September)|Alternative Names: Aja Ekadashi, Bhadrapada Krishna Ekadashi|Worshipable Deity: Lord Hrishikesha (the master of the senses)|Significance: Frees observers from all past sinful reactions, reunites separated families, and nullifies miseries.|Rules: Fast completely from grains, legumes, and beans. Focus on chanting Hare Krishna maha-mantra and remaining awake through the night.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (67, 'parivartini', 'Parshva / Parivartini Ekadashi', 'Parivartini Ekadashi', 'Commemorates when Lord Vishnu turns over on His side while sleeping in the milk ocean.', 'Parshva Ekadashi, also known as Parivartini Ekadashi, falls during the Krishna Paksha of the Bhadrapada month (August-September). \"Parivartini\" means \"changing\" — on this day, the Lord shifts from His sleeping position to His left side during cosmic sleep. This Ekadashi is described in the Padma Purana, where Lord Krishna tells Yudhishthira about the significance of the Lord\'s cosmic sleep and His turning point. The story of King Bali and Vamana Deva is also connected to this Ekadashi.', 'Parivartini Ekadashi marks the halfway point of Chaturmasya — the moment when Lord Vishnu changes His sleeping position. This turning point is observed with special devotion and prayers. The change of position symbolizes the beginning of the Lord\'s awakening process, bringing hope and renewal to devotees. This Ekadashi is observed for spiritual transformation and for seeking the Lord\'s blessings as He begins to stir from cosmic sleep.', 'Observing Parivartini Ekadashi brings spiritual transformation and renewal. The fast coincides with the cosmic turning point, making it especially potent for changing one\'s life trajectory. Those who donate food, bedding, and money on this day receive the Lord\'s grace for positive change. The observer is blessed with the courage to make necessary changes in their life and with the Lord\'s guidance during the transition. It brings hope and the promise of spiritual awakening.', 'ekadashi', NULL, 'assets/images/banners/parivartini-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        The Ekadasi Tithi in the month of Bhadrapada, Shukla Paksha (bright phase of the Lunar cycle) is known as Parivartini Ekadashi or Parsva or Vamana Ekadasi. On this day, Lord Vishnu, who is in a state of yogic sleep (Yoga Nidra), changes his posture. Hence, it is referred to as Parivartini Ekadasi (which literally means the Ekadasi of change).
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Parivartini/Parsva/Vamana Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        Sri Yudhishthira Maharaja asked of Lord Sri Krishna, \"What is the name of that Ekadasi that occurs during the light fortnight (shukla paksha) of the month of Bhadrapada (August-September), who is the worshipable Deity for this Ekadasi, and what merit does one attain in observing it? Kindly reveal all of this to me, my Lord.\"
      </p>
      
      <p>
        The Supreme Personality of Godhead Lord Sri Krishna replied, \"This Ekadasi, Oh Yudhishthira, is called Vamana Ekadasi, and it bestows upon those who observe it both great merit and ultimate liberation from material bondage. Because it removes all one\'s sinful reactions, it is also called Jayanti Ekadasi. Just hearing of its glories frees one from all past misdeeds. So auspicious is this fast that observing it bestows the same merit as that earned by performing a horse sacrifice.\"
      </p>
      
      <p>
        \"While observing this holy fast, a Vaishnava should lovingly worship the Supreme Lord in His form as Vamanadeva, the dwarf incarnation, whose eyes are like lotus petals. By doing so, he worships all other Deities as well, including Brahma, Vishnu, and Shiva, and at death he goes to the abode of Sri Hari. The reason this Ekadasi is so auspicious is that it celebrates the day when the sleeping Lord Vishnu turns over on His other side; thus it is also known as Parivartini Ekadasi.\"
      </p>
      
      <p>
        Maharaja Yudhishthira then asked, \"Oh Janardana, please clear up a question I have. How is it that the Supreme Lord sleeps and then turns over on His side? Oh Lord, when You are asleep what happens to all the other living entities? Please also tell me how You bound the king of the demons, Bali Daityaraj (Bali Maharaja), as well as how one may please the brahmanas.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Story of Bali Maharaja and Lord Vamanadeva</h3>
      <p>
        Lord Sri Krishna replied, \"Oh Yudhishthira, lion among Kings, I will gladly narrate to you an historical event. In the Treta-yuga, there once was a king named Bali. Though born in a family dynasty of demons, he was very devoted to Me. He sang many Vedic hymns and performed fire sacrifices to satisfy Me. He respected the twice-born brahmins and engaged them daily.\"
      </p>
      
      <p>
        \"This great soul had a quarrel with Indra, however, and eventually defeated him in battle. Bali took over his entire celestial kingdom. Therefore, Indra and all the demigods, along with many great sages, approached Me and complained about Bali Maharaja. Bowing their heads, they worshipped Me. Thus, I agreed to appear on their behalf as dwarf Vamanadeva, My fifth incarnation.\"
      </p>
      
      <p>
        Yudhishthira enquired, \"Oh Lord, how was it possible for You to conquer such a powerful demon in the form of a dwarf brahmin?\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Lord Sri Krishna replied: \'Though a dwarf, I was a brahmana, and I approached Bali to ask for alms. I said: \"Oh Daityaraj Bali, please give Me just three steps of land in charity.\" Bali agreed to grant My request. But as soon as he vowed, My body began to expand into a gigantic transcendental form. I covered the Earth with My feet, Bhuvarloka with My thighs, Swarga with My waist, Maharloka with My stomach, Janaloka with My chest, Tapoloka with My neck, and Satyaloka with My head. I covered the entire material creation.\'\"
      </blockquote>

      <p>
        \"Seeing this pastime, all the demigods and Shesha Naga began to sing Vedic hymns. I took Bali by the hand and said: \'Oh sinless one, I have covered the Earth with one step and the heavens with the second. Now where shall I place My foot to measure the third step?\' Upon hearing this, Bali Maharaja bowed down in humility and offered Me his head to place My third step. I placed My foot on his head and sent him to Patalaloka. Seeing him thus humbled, I became very pleased and told Bali that henceforth I would permanently reside in his palace. On Parivartini Ekadasi, Bali installed a Deity form of Me in his residence.\"
      </p>
      
      <p>
        \"Until Haribodhini Ekadasi in Karttika, I continue to sleep in the ocean of milk. One should therefore observe Parivartini Ekadasi carefully. On this day, the devotee should worship Lord Trivikrama (Vamanadeva), because on this day I turn over to sleep on My other side. If possible, one should give a qualified person some yogurt mixed with rice, as well as some silver, and remain awake throughout the night. This will free one of all material conditioning, equivalent to a thousand horse sacrifices.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Bhadrapada month (August/September)|Alternative Names: Parsva Ekadasi, Vamana Ekadasi, Jayanti Ekadasi, Parivartini Ekadasi|Meaning of name: \"Parivartini\" refers to the day Lord Vishnu turns over on His side while sleeping on Shesha Naga.|Worshipable Deity: Lord Trivikrama / Vamanadeva (the dwarf incarnation)|Significance: Eradicates all sins, equivalent to performing a horse sacrifice, and marks the midpoint of Lord Vishnu\'s rest.|Observance: Fasting is accompanied by donating yogurt mixed with rice and silver. Check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (68, 'indira', 'Indira Ekadashi', 'Indira Ekadashi', 'Delivers deceased ancestors from hellish planets to Vaikuntha.', 'Indira Ekadashi falls during the Krishna Paksha of the Ashvina month (September-October). This Ekadashi is described in the Brahma Purana, where Lord Krishna narrates the story of King Indradyumna who was a great devotee but had inadvertently neglected his spiritual duties. When his son died, he was devastated. The sage Narada advised him to observe Indira Ekadashi for his son\'s liberation. The king observed it with great devotion, and his son was not only liberated but also restored to life.', 'Indira Ekadashi is observed primarily for the liberation (moksha) of departed ancestors and family members. The name \"Indira\" is associated with Indra, the king of heaven, signifying the royal and powerful nature of this observance. It falls just before the beginning of the festive season, making it an important time for honoring ancestors. This Ekadashi teaches that the devotion of the living can liberate even those who have passed on.', 'Observing Indira Ekadashi liberates departed ancestors from their karmic reactions and grants them a higher birth or liberation. The fast purifies the observer\'s lineage (kula) and removes ancestral curses (pitru dosha). Those who perform Shraddha ceremonies and donate food on this day receive the blessings of their ancestors. The observer is blessed with family harmony, the removal of obstacles, and spiritual progress for both the living and the departed.', 'ekadashi', NULL, 'assets/images/banners/indira-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Ekadasi is the 11th day of the lunar phase of the Moon. Indira Ekadasi is celebrated in the Krishna Paksha (waning Moon phase) in the month of Ashwin (September–October). Since this Ekadasi falls on the Pitru Paksha (15 days in the month of Ashwin dedicated to ancestors), it is also known as Ekadasi Shraddh. This is widely celebrated in Northern India to pay rituals to ancestors.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Indira Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        The delightful glories of Indira Ekadasi are described in the Brahma-vaivarta Purana in the conversation between Sri Krishna and Maharaja Yudhishthira.
      </p>
      
      <p>
        Maharaja Yudhishthira enquired: \"O Krishna! O Madhusudana! What is the name of the Ekadasi that occurs during the waning moon in the month of Asvina (September/October), what is the process for following this sublime vrata, and what merit is obtained by observing it?\"
      </p>
      
      <p>
        Lord Krishna replied, \"The name of this sacred and clement Ekadasi is Indira Ekadasi. By observing this Ekadasi, the sinful reactions of all one\'s forebears as well as one\'s own sinful reactions are entirely eradicated.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">King Indrasena and Narada Muni</h3>
      <p>
        \"O King! There was once a regal and prosperous king named Indrasena, who lived in Satya-Yuga. He was expert in subduing his enemies and ruled his kingdom with great compassion. He lived happily in his city of Mahishmatipuri, always attached to the devotional service of Lord Vishnu, chanting the holy names of Sri Govinda.\"
      </p>
      
      <p>
        \"One day, as the King was sitting on his throne, Sri Narada Muni suddenly appeared before him from the sky. King Indrasena rose with folded palms, offered his respectful obeisances, and worshipped the sage with sixteen ingredients. Once seated, Narada Muni asked Indrasena about the welfare of his kingdom and his devotion.\"
      </p>
      
      <p>
        \"The King replied: \'O best of sages! Everything is well and auspicious by your kind mercy. Today my life has become successful by your darshana. Please tell me the cause of your blessed visit.\'\"
      </p>
      
      <p>
        \"Narada Muni said: \'O lion-like King! Now hear about a wonderfully fortunate incident. Once I went to the abode of Yamaraja from the abode of Lord Brahma. Yamaraja greeted me respectfully. While there, I saw your greatly pious father in the assembly of Yamaraja. As a result of breaking a vow, your father had to go there. He gave me a message for you. He said: \"Indrasena, the king of Mahishmatipuri, is my son. O Lord, please tell him that due to some sinful activities committed in my previous life I am now living in the abode of Yamaraja! Therefore, in order to free me, he should observe the vow of Indira Ekadasi, and transfer its piety to me. Then I will be released.\" Narada Muni continued: \'This is your father\'s request. To deliver your father, you should observe this fast.\'\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"King Indrasena said: \'O sage amongst the demigods, kindly explain to me the procedure for following this Indira Ekadasi.\' Narada Muni replied: \'On the day before Ekadasi (Dashami), take a bath early in the morning and with faith offer oblations to the forefathers. Eat only once and sleep on the floor. On Ekadasi morning, rise early, clean your mouth, bathe, and take a vow to fast completely, praying: \"O lotus-eyed one, I take shelter of You.\"\'\"
      </blockquote>

      <p>
        \"Narada Muni continued: \'Thereafter, feed the brahmanas with sumptuous prasadam and give them dakshina. Offer the prasadam remnants to the cows. During the day, worship Lord Hrishikesha by offering sandalwood paste, flowers, incense, lamps, and foodstuffs. Remain awake throughout the night chanting and hearing the pastimes of the Lord. Break the fast on Dvadashi at the appropriate time, eating with your family in silence. If you follow this, your father will certainly reach Vaikuntha.\' After speaking, Narada Muni departed.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Deliverance of the Father</h3>
      <p>
        \"As per the instructions of Narada Muni, King Indrasena strictly observed this Ekadasi accompanied by his children, servants, and subjects. As a result of observing this Ekadasi, flowers showered from the sky, and the father of King Indrasena immediately rode on the back of Garuda to the Vaikuntha abode of Lord Vishnu.\"
      </p>
      
      <p>
        \"Then, the saintly King Indrasena ruled his kingdom without any impediment, and at the end of his life, he entrusted the kingdom to his son and personally returned to the spiritual world. Such are the glories of Indira Ekadasi. Anyone who reads or hears this narration becomes free from all sinful reactions and ultimately returns to the abode of Vishnu.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Ashvina month (September/October)|Alternative Names: Ekadashi Shraddh (falls during Pitru Paksha, the fortnight dedicated to ancestors)|Worshipable Deity: Lord Hrishikesha|Significance: Eradicates the sins of the observer and their ancestors, freeing deceased parents from Yamaraja\'s realm to ascend to Vaikuntha.|Rules: Strict fast. Offer oblations to forefathers on Dashami, worship Hrishikesha and feed brahmanas & cows on Ekadashi.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (69, 'papankusa', 'Papa-ankusha Ekadashi', 'Papankusha Ekadashi', 'Acts as a goad to control sins, fulfills desires, and awards liberation.', 'Papa-ankusha Ekadashi falls during the Krishna Paksha of the Ashvina month (September-October). The name means \"the goad that hooks sins\" — \"papa\" means sin and \"ankusha\" means a goad or hook used to control elephants. This Ekadashi is described in the Padma Purana, where Lord Krishna explains that observing this Ekadashi removes sins as effectively as an ankusha controls a wild elephant. The story involves a hunter named Kritantasena who accidentally killed many animals. He observed this Ekadashi and was freed from all sinful reactions.', 'Papa-ankusha Ekadashi is observed for the destruction of even the most stubborn sinful habits and reactions. Just as an ankusha controls a wild elephant, this Ekadashi controls and removes the powerful urges of sin. It falls during the Ashvina month when the influence of negative energies is strong, making this observance especially protective. This Ekadashi is observed for overcoming addictions, breaking bad habits, and controlling the mind.', 'Observing Papa-ankusha Ekadashi destroys sinful habits and reactions that are otherwise very difficult to overcome. The fast acts as a spiritual goad, directing the mind away from sin and toward devotion. Those who donate food, clothing, and worship the Lord on this day receive the power to control their senses. The observer is blessed with self-discipline, freedom from addictions, and the strength to follow the spiritual path. It brings liberation from the cycle of sin.', 'ekadashi', NULL, 'assets/images/banners/papankusa-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Pasankusa or Papankusa Ekadasi is one of the most significant Vedic fasting days, observed in the Ashvina month on the eleventh day (Ekadasi) of Shukla Paksha (the bright phase of lunar cycle). Therefore, the festival is also popular as Ashwina-Shukla Ekadasi. According to the Gregorian calendar, this festival is celebrated in the month of September or October. Pasankusa Ekadasi is celebrated to worship Lord Padmanabha, the Lord with a navel like a lotus.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Pasankusa (Papankusa) Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-vaivarta Purana
      </p>
      
      <p>
        Yudhishthira Maharaja said, \"Oh Madhusudana, what is the name of the Ekadashi that comes during the light fortnight of the month of Ashvina (September-October)? Please be merciful and disclose this truth to me.\"
      </p>
      
      <p>
        The Supreme Personality of Godhead Sri Krishna replied, \"Oh king, please listen as I explain the glories of this Ekadashi – Pasankusa Ekadashi – which removes all sins. On this day one should worship the Deity of Padmanabha, the lotus-naveled Lord Vishnu, according to the rules of archana viddhi (regulations). By so doing, one achieves whatever heavenly pleasures one may want in this world, and at last attains liberation. Simply by offering one\'s humble obeisances unto Lord Vishnu, the rider of Garuda, one can achieve the same merit as is gained by performing great penances for a long time. Although a person might have committed unlimited and abominable sins, he can still escape hellish punishment just by paying his obeisances to Lord Sri Hari.\"
      </p>
      
      <p>
        \"The merits gained by going on pilgrimage to the Holy Tirthas of this earthly planet can also be achieved simply by chanting the Holy names of Lord Vishnu. Whosoever chants these sacred names such as Rama, Vishnu, Janardana, or Krishna, especially on Ekadashi, never sees Yamaraja, the king of death\'s punishing abode. Nor does such a devotee who fasts on Pasankusa Ekadashi, which is very dear to Me, see that plutonic abode.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Lord Sri Krishna added: Both the Vaishnava who criticizes Lord Shiva and the Shaivite who criticizes Me certainly go to hell. The merit obtained by performing one hundred horse sacrifices and one hundred Rajasuya sacrifices is not even equal to one-sixteenth of the merit a devotee is able to attain by fasting on Ekadashi. There is no higher merit one can achieve than that attained by fasting on Ekadashi.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Goad of Sinful Reactions</h3>
      <p>
        \"O king, until a person observes a fast on the day of Lord Padmanabha named Pasankusa Ekadashi, he remains sinful, and the reactions of his past sinful activities never leave him. There is no merit in all the three worlds that can match the merit that one gains by observing a fast on this Ekadasi. One who desires liberation, elevation to the heavens, good health, beautiful consorts, wealth, and food grains should simply fast on this Pasankusa Ekadashi. Neither the Ganges, Gaya, Kashi, nor Pushkara, nor even the Holy site of Kurukshetra, can grant as much auspicious merit as this Pasankusa Ekadashi.\"
      </p>
      
      <p>
        \"O Maharaja Yudhishthira, after observing Ekadashi during the daytime, the devotee should remain awake through the night, absorbed in hearing, chanting, and serving the Lord, for by so doing he easily attains to the Supreme abode of Lord Vishnu. Not only that, but ten generations of ancestors on his mother\'s side, ten generations on his father\'s side, and ten generations on his wife\'s side are all liberated by a single observance of a fast on this Ekadashi. All these ancestors attain their original, four-armed transcendental Vaikuntha forms. Wearing yellow garments and beautiful garlands, they ride to the spiritual realm on the back of Garuda. This is the benediction My devotee earns.\"
      </p>
      
      <p>
        \"Fasting on Pasankusa Ekadashi frees one from all sins and makes one immune to suffering a hellish rebirth. Whosoever donates gold, sesame seeds, fertile land, cows, grain, drinking water, an umbrella, or a pair of shoes on this most auspicious of Holy days will never have to visit the abode of Yamaraja. But if a resident of Earth fails to perform spiritual deeds, especially the observance of a fast on days such as Ekadashi, his breathing is said to be no better than the puffing of a blacksmith\'s bellows.\"
      </p>
      
      <p>
        \"O best of the kings, especially on this Pasankusa Ekadashi, even the poor should first bathe and then give some charity according to their means. A person who observes Pasankusa Ekadashi goes to the abode of the Supreme Personality of Godhead, Vishnu.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"Thus, Oh saintly Yudhishthira, I have narrated to you the glories of the auspicious Pasankusa Ekadashi.\"
      </p>', 'Calendar: 11th lunar day of the bright fortnight (Shukla Paksha) in Ashvina month (September/October)|Alternative Names: Pasankusa Ekadasi, Ashwina-Shukla Ekadasi|Worshipable Deity: Lord Padmanabha (the lotus-naveled form of Lord Vishnu)|Meaning of name: \"Papankusa\" acts as an *ankusa* (goad) to control and eradicate sins.|Significance: Removes all sins, grants heavenly pleasures and liberation, and delivers ten generations of ancestors on father\'s, mother\'s, and wife\'s sides to Vaikuntha.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (70, 'rama', 'Rama Ekadashi', 'Rama Ekadashi', 'Beloved of Srimati Radharani. Frees even the most fallen from sinful reactions.', 'Rama Ekadashi falls during the Krishna Paksha of the Kartika month (October-November). This Ekadashi is described in the Skanda Purana, where Lord Krishna tells Yudhishthira about a wealthy merchant named Dharmadhan who had a prostitute\'s daughter as his wife. When he learned of her unchaste behavior, he was devastated. On the advice of a sage, he observed Rama Ekadashi with strict vows. The Lord purified both him and his wife, and they were reunited in a spiritually purified relationship.', 'Rama Ekadashi falls during the auspicious Kartika month and is observed for purification of relationships and the restoration of dharma. The name \"Rama\" refers to Lord Rama, the ideal king and embodiment of dharma. This Ekadashi is observed for overcoming sinful desires, especially those related to illicit relationships, and for cultivating pure, spiritually-based connections. It is also observed for the general welfare of family life.', 'Observing Rama Ekadashi purifies relationships and restores harmony in family life. The fast destroys sinful desires and promotes self-control and spiritual discipline. Those who donate food, clothes, and worship Lord Rama on this day receive the blessings for a harmonious family life. The observer is freed from the reactions of illicit sexual activities and is blessed with pure, devotional relationships. It brings peace, harmony, and spiritual progress in family life.', 'ekadashi', NULL, 'assets/images/banners/rama-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        The 11th day of Krishna Paksha (Moon\'s waning phase) in the month of Kartik (October – November) is celebrated as Rama Ekadasi, named after Lord Vishnu\'s consort, Goddess Rama (Lakshmi). The day is also known as Rambha Ekadasi or Kartik Krishna Ekadasi.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Rama Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Brahma-Vaivarta Purana
      </p>
      
      <p>
        Yudhishthira Maharaj said, \"O Janardana, O protector of all beings, what is the name of the Ekadashi that comes during the dark fortnight (Krishna paksha) of the month of Kartika (October – November)? Please impart this sacred knowledge to me.\"
      </p>
      
      <p>
        The Supreme Lord, Sri Krishna then spoke as follows: \"O lion among kings, please listen as I narrate to you. The Ekadashi that occurs during the dark part of the month of Kartika is called Rama Ekadashi. It is most auspicious, for it at once eradicates the greatest sins and awards one the passage to the spiritual abode. I shall now narrate to you its history and glories.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Strict Fast of King Muchakunda</h3>
      <p>
        \"There once lived a famous king of the name Muchakunda, who was friendly with Lord Indra, the king of the heavenly planets, as well as with Yamaraja, Varuna, and Vibhishana, the brother of Ravana. Muchakunda always spoke the truth and constantly rendered devotional service to Me. Because he ruled according to religious principles, there were no disturbances in his kingdom.\"
      </p>
      
      <p>
        \"Muchakunda\'s daughter was named Chandrabhaga, and the king gave her in marriage to Shobhana, the son of Chandrasena. One day, Shobhana visited his father-in-law\'s palace on the auspicious Ekadashi day. This visit made Shobhana\'s wife Chandrabhaga quite anxious, for she knew that her husband was physically very weak and unable to bear the austerity of a day-long fast. She said to him, \'My father is very strict. On Dashami, the day before, he strikes a large kettledrum and announces: Nobody should eat on Ekadashi, the sacred day of Sri Hari!\'\"
      </p>
      
      <p>
        \"When Shobhana heard this, he said to his wife, \'O beautiful one, what am I to do now? Please tell me how I can save my life and obey your father\'s strictness!\'\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Chandrabhaga spoke, \'My dear husband, in my father\'s house nobody – not even the elephants, horses, or other animals – eats on Ekadashi. None of the animals are given their ration of grains, straw, or even water! So how can you escape fasting? My beloved husband, if you must eat, then you should leave here at once. Now, decide what you have to do.\'\"
      </blockquote>

      <p>
        \"Prince Shobhana said, \'I have decided to fast on the sacred Ekadashi day. Whatever my fate is, it will surely come to pass.\' Deciding thus, Shobhana attempted to fast, but he became unbearably disturbed with hunger and thirst. Eventually the sun set, and the arrival of night made all the Vaishnavas happy. The devotees remained awake all night worshipping the Lord, but Prince Shobhana suffered terribly. Indeed, when the sun rose on the Dvadashi, the Prince was dead.\"
      </p>
      
      <p>
        \"King Muchakunda observed his son-in-law\'s funeral. He instructed his daughter Chandrabhaga not to join her husband on the funeral pyre. Thus Chandrabhaga, after performing the purificatory processes, continued to live in her father\'s house.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Mandarachala Kingdom</h3>
      <p>
        \"Lord Sri Krishna continued: \'O best of the kings, even though Shobhana died because of observing Rama Ekadashi, the merit that he accrued enabled him, after his death, to become the ruler of a kingdom high on the peak of Mandarachala Mountain. This kingdom was like a city of the demigods; very lustrous, with unlimited jewels set in the walls of its buildings. The pillars were made of rubies, and gold inlaid with diamonds shone everywhere. Shobhana sat upon a throne beneath a pure white canopy, served by Gandharvas and Apsaras. He resembled a second Indra.\'\"
      </p>
      
      <p>
        \"One day, a brahmin named Somasharma, who lived in Muchakunda\'s kingdom, happened upon Shobhana\'s kingdom while traveling. Somasharma saw Shobhana in all his resplendent glory and recognized him. Shobhana welcomed him, paid his respectful obeisances, and asked about the welfare of his wife Chandrabhaga and King Muchakunda.\"
      </p>
      
      <p>
        \"Somasharma replied, \'O king, all are well. But I am astonished to find you here! Please tell me how you obtained this city. No one has ever seen such a beautiful city!\' King Shobhana replied, \'Because I observed the Rama Ekadashi, I was given this splendid city to rule over. But for all of its grandeur, it is only temporary. You see, I fasted on the Rama Ekadashi without faith, and thus this kingdom is impermanent. Please return to Chandrabhaaga, and tell her what you have seen. Surely, if you tell her this, my city will soon become permanent.\'\"
      </p>
      
      <p>
        \"The brahmin returned and related the entire episode to Chandrabhaga, who was overjoyed. She said, \'O brahmana, is this a dream, or is it actually factual?\' Somasharma replied, \'O Princess, I have seen your late husband face to face. But he says his kingdom is unstable and could vanish. Therefore he hopes you can find a way to make it permanent.\'\"
      </p>
      
      <p>
        \"Chandrabhaga said, \'O sage, please take me to that place at once, for I greatly desire to see him! Surely I shall make his kingdom permanent with the merit that I have acquired by fasting on every Ekadashi throughout my life.\'\"
      </p>
      
      <p>
        \"Somasharma led Chandrabhaga to Shobhana\'s kingdom. Before reaching it, they stopped at the foot of Mt. Mandarachala, at the ashrama of Vamadeva Muni. Upon hearing their story, Vamadeva chanted Vedic hymns and sprinkled holy water upon Chandrabhaaga. By the influence of the Rishi\'s rites and the merit of her lifelong Ekadashi fasts, her body became transcendental.\"
      </p>
      
      <p>
        \"When Shobhana saw his wife approaching, he was overwhelmed with joy and called out to her. He seated her on his left side, and she said: \'O dearest husband, please listen. Since I was eight years old, I have fasted regularly and with full faith on every Ekadashi. If I transfer to you all the merit I have accumulated, your kingdom will surely become permanent, and its prosperity will grow until the coming of the great inundation!\'\"
      </p>
      
      <p>
        \"O Yudhishthira, in this way Chandrabhaga, beautifully decorated with the finest ornaments and an exquisitely transcendental body, enjoyed peace and happiness with her husband. By the potency of Rama Ekadashi, Shobhana found his kingdom able to fulfill all his desires, like the transcendental Kama-dhenu cow.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"One should not differentiate between the Ekadashis of the light and dark parts of the month. Both award the same high degree of merit, just as black cows and white cows give equally good quality milk. Anyone who simply hears this narration is freed from all kinds of sin and attains the supreme abode of Lord Vishnu.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Kartika month (October/November)|Alternative Names: Rambha Ekadashi, Kartik Krishna Ekadashi|Meaning of name: Named in honor of Goddess Rama, the consort of Lord Vishnu.|Presiding Deity: Goddess Rama and Lord Sri Vishnu / Janardana|Significance: Eradicates the greatest sins, ensures passage to the spiritual world, and establishes everlasting prosperity.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (71, 'utthana', 'Utthana / Devotthan Ekadashi', 'Utthana Ekadashi', 'Marks the end of Chaturmasya, when Lord Vishnu awakens from cosmic slumber.', 'Utthana Ekadashi, also known as Devotthan Ekadashi, falls during the Shukla Paksha of the Kartika month (October-November). \"Utthana\" means \"awakening\" — on this day, Lord Vishnu awakens from His four-month cosmic sleep (Yoga Nidra). This Ekadashi is described in the Padma Purana, where Lord Krishna explains the significance of the Lord\'s awakening. The story of King Talasura, who was a demon haunting the cremation grounds, is also associated — he observed this Ekadashi and was freed from his demoniac form.', 'Utthana Ekadashi marks the end of Chaturmasya — the auspicious moment when Lord Vishnu awakens from cosmic sleep. This awakening signals the resumption of all auspicious ceremonies and activities. It is observed with great joy and celebration across Vaishnava communities. The Kartika month is considered the best month for spiritual practices, and this Ekadashi adds special potency to devotional activities. The Tulasi Vivaha (marriage of Tulasi to Lord Shaligram) is often celebrated around this time.', 'Observing Utthana Ekadashi marks a fresh spiritual beginning as the Lord awakens. The fast renews the observer\'s spiritual energy and dedication. Those who celebrate the Lord\'s awakening with devotional activities, feasts, and donations receive immense blessings. The observer is blessed with renewed spiritual vigor, the resumption of auspicious activities, and the Lord\'s attentive grace. It brings joy, celebration, and a fresh start in spiritual life.', 'ekadashi', NULL, 'assets/images/banners/utthana-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        This Ekadasi has four names: (1) Utthana, (2) Haribodhini, (3) Prabodhini, and (4) Devotthani, and it is the second Ekadasi (Kartik Shukla, light fortnight) in the holy month of Kartik. It is said that Lord Vishnu goes to rest for four months during the period known as Chaturmasya. Starting from Sayana Ekadasi in the month of Ashada, Lord Vishnu rests and awakens on the day of Kartika Shukla Ekadasi, which is why it is known as Utthana Ekadasi.
      </p>
      
      <p>
        It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Haribodhini (Utthana) Ekadasi</h3>
      <p style=\"font-size:var(--font-size-sm); color:var(--text-light); font-weight:600; margin-bottom:0;\">
        From the Skanda Purana
      </p>
      
      <p>
        Lord Brahma said to Narada Muni, \"Dear son, O best of the sages, I shall narrate to you the glories of Haribodhini Ekadasi, which eradicates all kinds of sins and bestows great merit, and ultimately liberation, upon the wise persons who surrender unto the Supreme Lord.\"
      </p>
      
      <p>
        \"O best of the brahmanas, the merits acquired by bathing in the Ganges remain significant only as long as Haribodhini Ekadasi does not come. This Ekadasi is much more purifying than a bath in the ocean, at a place of pilgrimage, or in a lake. This sacred Ekadasi is more powerful in nullifying sin than one thousand Asvamedha sacrifices and one hundred Rajasuya sacrifices.\"
      </p>
      
      <p>
        Narada Muni inquired, \"O father, please describe the relative merits of fasting completely on Ekadasi, eating supper (without grains or beans), or eating once at midday.\"
      </p>
      
      <p>
        Lord Brahma replied, \"If a person eats once at midday on Ekadasi, the sins of his previous birth are erased; if he eats supper, the sins acquired during his previous two births are removed; and if he fasts completely, the sins accumulated during his previous seven births are eradicated. A person whose sins equal Mount Sumeru in volume sees them all reduced to nothing if he simply fasts on Papaharini Ekadasi (Haribodhini). The sins a person has accumulated over a thousand previous births are burned to ashes if he not only fasts but also remains awake throughout Ekadasi night, just as a mountain of cotton can be burned to ashes by a small spark.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Nine Ways to Worship Tulasi Devi</h3>
      <p>
        Lord Brahma highlighted that worshipping Srimati Tulasi Devi in the month of Kartika is highly pleasing to Lord Hari. One who performs these nine services resides in Vaikuntha eternally:
      </p>
      
      <ol style=\"margin-left:var(--space-lg); line-height:1.8; display:flex; flex-direction:column; gap:6px;\">
        <li><strong>Seeing</strong> Tulasi Maharani.</li>
        <li><strong>Touching</strong> her.</li>
        <li><strong>Meditating</strong> on her.</li>
        <li><strong>Narrating</strong> her history and glories.</li>
        <li><strong>Offering obeisances</strong> to her.</li>
        <li><strong>Praying</strong> to her for grace.</li>
        <li><strong>Planting</strong> her.</li>
        <li><strong>Worshipping</strong> her.</li>
        <li><strong>Watering</strong> her.</li>
      </ol>
      
      <p>
        \"One who serves Tulasi-devi in these nine ways achieves happiness in the higher world for as many thousands of yugas as there are roots and subroots growing from a mature tulasi plant. When a full-grown tulasi plant produces seeds, many plants grow from those seeds and spread. For as many thousands of kalpas as there are seeds produced in this way, the forefathers of one who serves tulasi will live in the abode of Lord Hari.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">Worshipping the Lord with Sacred Flowers</h3>
      <p>
        \"One should worship Lord Keshava with camphor, fruits, and aromatic flowers on this day. Worshipping the Lord with <strong>agastya flowers</strong> causes even Lord Indra to offer his respects. Offering <strong>bel leaves</strong> yields immediate liberation. Worshipping with fresh <strong>tulasi leaves</strong> burns to ashes the sins committed for ten thousand births. Offering <strong>kadamba flowers</strong> prevents one from seeing the abode of Yamaraja. Offering <strong>bakula, ashoka, and patali flowers</strong> frees one from misery for as long as the sun and moon exist. Offering <strong>yellow ketaki flowers</strong> frees one from the sins of ten million births.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"On Haribodhini Ekadasi, a devotee of the Lord should not eat in another\'s house or eat food cooked by a non-devotee. Philosophical discussion of Scriptures in the month of Kartika pleases Sri Vishnu more than giving elephants and horses in charity. Whoever chants or hears descriptions of Lord Vishnu\'s qualities, even if but a fourth of a verse, attains the merit of giving away a hundred cows.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Dvadashi Parana & Chaturmasya Conclusion</h3>
      <p>
        \"On Dvadashi morning, the devotee should rise early, bathe, chant japa, and render loving service. To break the fast, one should first offer prasadam and dakshina to qualified brahmanas. One should worship the spiritual master, offering him clothes, gold, and cows. Since Chaturmasya ends on this day, whatever vow or food item was given up during the four months of Chaturmasya should now be donated to the brahmanas.\"
      </p>
      
      <p>
        \"One who has fasted from ghee should donate milk; one who has fasted from grains should donate rice; one who has slept on the floor should donate a bedstead with a quilt; one who has eaten on a leaf plate should donate a pot of ghee; one who has remained silent should donate a bell. One who follows this process of Chaturmasya receives unlimited merit and goes to the abode of Lord Vasudeva after death.\"
      </p>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (72, 'utpanna', 'Utpanna Ekadashi', 'Utpanna Ekadashi', 'Marks the birth of Ekadashi Devi from Lord Vishnu to defeat the demon Mura.', 'Utpanna Ekadashi falls during the Krishna Paksha of the Margashirsha month (November-December). \"Utpanna\" means \"born\" or \"manifested.\" This Ekadashi is described in the Padma Purana, where Lord Krishna tells Yudhishthira that this Ekadashi was \"born\" from the body of the Lord during His battle with the demon Mura. When the Lord was resting in a cave, the demon Mura attacked Him. From the Lord\'s sleeping form, this Ekadashi appeared, fought and killed the demon, and protected the Lord. The Lord was pleased and named her \"Mura-Nashini\" (destroyer of Mura).', 'Utpanna Ekadashi holds special significance as the \"birth\" of Ekadashi itself. The scriptures describe that Ekadashi is a powerful devi (goddess) who was manifested from Lord Vishnu\'s divine energy. Observing this Ekadashi is like worshipping the mother of all Ekadashis. It falls during the beginning of the most auspicious month for devotional practices (Margashirsha/Kartika). This Ekadashi is observed for protection from demons (both external and internal — the six enemies of the mind).', 'Observing Utpanna Ekadashi grants the special blessings of the Ekadashi devi herself. The fast destroys all forms of demonic influence — both external negative energies and internal enemies (lust, anger, greed, etc.). Those who worship the Lord with Tulasi and food on this day receive powerful protection. The observer is blessed with divine protection, freedom from fear, and the destruction of all obstacles on the spiritual path. It brings the grace of the Ekadashi devi for lifelong protection.', 'ekadashi', NULL, 'assets/images/banners/utpanna-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        The 11th day of the waning phase of the moon (Krishna Paksha) in the month of Margashirsha (November–December) is observed as Utpanna Ekadasi. It is believed that fasting on this Ekadasi relieves one from the reactions to sins of past and present lives. This day is also known as Uttpatti Ekadasi.
      </p>
      
      <p>
        The glories of Utpanna Ekadasi are found in the Bhavisya-Uttara Purana. Sri Suta Gosvami addressed the assembly of brahmanas: \"If one hears with devotion and faith the process and glories of executing Ekadasi as prescribed by Sri Krishna, then happiness in this life and liberation in the next is assuredly granted.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Origin of Ekadashi</h3>
      
      <p>
        Arjuna once asked Krishna, \"O Janardana, please describe the fruits of fasting, eating at night, or eating at midday only, on the Ekadasi day.\"
      </p>
      
      <p>
        Lord Krishna replied, \"Oh Arjuna, in the early Autumn, there is an Ekadasi that falls during the waning moon of Margashirsha (November). On this auspicious day, a person should take the vow of Ekadasi. In the early morning, he should make a firm sankalpa (vow) to fast. At high noon, he should purify his body, mind, and senses by taking a bath, praying to Mother Earth to destroy his prarabdha karma (reactions from previous births).\"
      </p>
      
      <p>
        \"Once upon a time, Indra approached the Supreme Personality of Godhead and prayed: \'Oh Lord of the Universe, the demigods have been evicted from their heavenly abodes by the demons. Please protect us. We have fallen to the Earthly stratum and are merged in the ocean of miseries.\'\"
      </p>
      
      <p>
        \"Lord Vishnu asked, \'Who is this great demon who has triumphed over the demigods? What is his name? From whom did he get such power? Have no fear!\'\"
      </p>
      
      <p>
        \"Indra said, \'Oh Lord of all demigods, a mightily ferocious demon named Mura, son of Nadijangha, has attacked us. He lives in the city of Candravati. The Mura demon has invaded the heavenly planets and is now living there. He has dethroned Indra, Agni, Yama, Vayu, Isha, Candrama, Nairita, and Varuna and taken their positions. We demigods could not stop his powerful assault. Oh Lord, please kill this demon.\'\"
      </p>
      
      <p>
        \"Upon hearing this, Lord Vishnu became furiously angry and said, \'Oh king of the demigods, this rascally demon will undoubtedly perish at the hand of My personal might. You should not fear; you can return to the city of Candravati with peace of mind. I will solve this situation post haste!\'\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Battle of ten thousand years</h3>
      <p>
        \"Thereafter, the demigods along with Lord Vishnu proceeded towards the city of Candravati. A wonderful battle scene arose. Lord Vishnu and the demigods prepared an array of weaponry, and the demons also had a formidable arsenal. When the skirmish commenced, the demigods fought with skill, but were eventually scattered by the demons. Lord Vishnu led a group attack, fighting with the demon Mura.\"
      </p>
      
      <p>
        \"In spite of attacking with various weapons, the Lord was unable to kill Mura. He wrestled with the archfiend for more than ten thousand years! Finally, after a considerable struggle, the Divine Lord defeated Mura and went to Badarikashrama. In Badarikashrama, the Lord rested in a splendid cave called Hemavati.\"
      </p>

      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"Lord Krishna continued: \'Oh Arjuna, the Mura demon followed Me to that cave and seeing Me resting, prepared to attack. Suddenly, an incandescent daughter appeared from My body! She held many mystical and divine weapons and began to unmercifully fight the demon. After slaying the demon, the effulgent goddess cleaved his head from his body. When I arose from My slumber, I saw the dead body of the Mura demon and the radiant goddess stood before Me with folded palms.\'\"
      </blockquote>

      <p>
        \"Startled, the Lord asked, \'Who are you?\' The goddess replied, \'Oh my Lord and Master, I am born from out of Your own body. I have removed this demon from his torment by cutting off his head. When he saw You resting, he shamefully thought to kill You in Your sleep! Therefore, I appeared and severed his head.\'\"
      </p>
      
      <p>
        \"The Supreme Lord said: \'Oh Goddess, I am grateful for your protection and well pleased with you. You may ask any benediction you like from Me.\'\"
      </p>
      
      <p>
        \"The goddess replied: \'If You wish to give a boon unto me, then please give unto me the potency to deliver even the most heinous sins from all who fast on this day. It is my heartfelt desire that even if one simply eats in the evening, that person will receive half the benefit of fasting; and if one eats only at noontime, that person will receive half as much credit again. Please gift me with this auspicious favor.\'\"
      </p>
      
      <p>
        \"The Lord said: \'You are My spiritual energy, and since today is called Ekadasi – your name will be Ekadasi. Anybody who observes fasting on this, your day, will have his sinful reactions alleviated and attain unending spiritual bliss.\'\"
      </p>
      
      <p>
        \"Oh Arjuna, from that day until this, all Ekadasi days are vitalized by the Supreme Lord\'s blessings. I award entrance to the supreme abode unto those who observe the day of Ekadasi.\"
      </p>', 'Calendar: 11th lunar day of the waning moon (dark fortnight / Krishna Paksha) in Margashirsha month (November/December)|Alternative Names: Uttpatti Ekadasi, Margashirsha Krishna Ekadasi|Meaning: Marks the day Ekadashi Devi first appeared (manifested) from the body of Lord Vishnu.|Worshipable Deity: Lord Sri Govinda / Ekadashi Devi|Significance: Eradicates the reactions to past and present sins, granting spiritual liberation.|Observance: Held on the scheduled event date. Please check the Vaishnava Calendar for the exact day this year.', NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (73, 'moksada', 'Mokshada Ekadashi (Gita Jayanti)', 'Mokshada Ekadashi', 'Observed on the day Lord Krishna spoke the Bhagavad-gita, granting liberation.', 'Mokshada Ekadashi falls during the Shukla Paksha of the Margashirsha month (November-December). \"Mokshada\" means \"liberator\" or \"granting liberation.\" This Ekadashi is also celebrated as Gita Jayanti — the day Lord Krishna spoke the Bhagavad-gita to Arjuna on the battlefield of Kurukshetra over 5,000 years ago. This Ekadashi is described in the Padma Purana and is also mentioned in the Mahabharata. The story of King Daivavrata, who was devoted to Lord Vishnu and observed this Ekadashi for the liberation of his father from a lower birth, is narrated in the Puranas.', 'Mokshada Ekadashi is one of the most sacred Ekadashis as it coincides with Gita Jayanti — the advent day of the Bhagavad-gita. The scriptures state that Lord Krishna chose this day to reveal the most confidential spiritual knowledge to Arjuna. Observing this Ekadashi is equivalent to studying the entire Bhagavad-gita. It falls during the Margashirsha month, considered the most auspicious month for worship of Lord Krishna. This Ekadashi is observed for liberation (moksha) and for deepening one\'s understanding of the Gita\'s teachings.', 'Observing Mokshada Ekadashi grants liberation (moksha) — the ultimate goal of human life. The fast, combined with the study of the Bhagavad-gita, purifies the consciousness completely. Those who donate food, clothes, and Gita books on this day receive immense spiritual merit. The observer is blessed with deep spiritual understanding, freedom from the cycle of birth and death, and the ability to follow the teachings of the Gita in daily life. It brings the highest spiritual benefit of any Ekadashi observance.', 'ekadashi', NULL, 'assets/images/banners/moksada-ekadashi.jpg', NULL, 1, NULL, NULL, 1, 0, 'one_time', 100.00, 'tiers', 0, 1, 0, NULL, NULL, '2026-06-30 18:34:49', '2026-07-03 23:09:55', '<p>
        Moksada or Vaikuntha Ekadasi, observed on the 11th day of Shukla Paksha (the waxing phase of the moon) during the lunar month of Margashirsha, is a very special Ekadasi in two regards: it is the all-auspicious day on which Lord Sri Krishna spoke the Srimad Bhagavad Gita to Arjuna on the battlefield of Kurukshetra at the place now known as Jyotisha tirtha, and anyone who gifts a Bhagavad Gita to a deserving person on this day is bestowed profuse blessings by Sri Krishna Bhagavan.
      </p>
      
      <p>
        Moksada Ekadashi is also known as Vaikuntha Ekadashi. It is named after Lord Vishnu\'s heavenly abode, Vaikuntha. It is an auspicious start for the rest of the year, and we encourage devotees reading this to kindly consider donating on this day.
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Glories of Moksada Ekadasi</h3>
      
      <p>
        Yudhishthira Maharaj said, \"O Vishnu, master of all, O delight of the three worlds, O Lord of the entire Universe, O creator of the world, O oldest personality, O best of all beings, I offer my most respectful obeisances unto You. O Lord of lords, for the benefit of all living entities, kindly answer some questions that I have. What is the name of the Ekadasi that occurs during the light fortnight of the month of Margashirsha (November-December) and removes all sins? How does one observe it properly, and which Deity is worshipped?\"
      </p>
      
      <p>
        Lord Sri Krishna replied, \"O dear Yudhishthira, your enquiry is very auspicious in itself and will bring you fame. Just as I previously explained to you about the dearest Utpanna Maha-Dvadashi, so I shall now relate to you regarding this Ekadasi that occurs during the light part of the month of Margashirsha.\"
      </p>
      
      <p>
        \"This Ekadasi is famous as Moksada because it purifies the faithful devotee of all sinful reactions and bestows liberation upon him. The worshipable Deity of this all-auspicious day is Lord Damodara. With full attention, one should worship Him with incense, a ghee lamp, fragrant flowers, and Tulsi manjaris (buds).\"
      </p>
      
      <p>
        \"O best of saintly kings, please listen as I narrate to you the ancient and auspicious history of this wonderful Ekadasi. Simply by hearing this history, one can attain the merit earned by performing a horse sacrifice. By the influence of this merit, one\'s forefathers, mothers, sons, and other relatives who have gone to hell can turn around and go to the heavenly kingdom.\"
      </p>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Dream of King Vaikhanasa</h3>
      <p>
        \"There once was a beautiful city named Champaka-nagar, which was decorated with devoted Vaishnavas. There the best of saintly kings, Maharaj Vaikhanasa, ruled over his subjects as if they were his very own dear sons and daughters. The brahmins in that capital city were all expert in four kinds of Vedic knowledge.\"
      </p>
      
      <p>
        \"The king, while ruling properly, had a dream one night in which his father was seen to be suffering the pangs of hellish torture in one of the hellish planets ruled over by Yamaraja. The king was overwhelmed with compassion for his father and shed tears. The next morning, Maharaj Vaikhanasa described what he had seen to his council of learned brahmins: \'O brahmanas, in a dream last night I saw my father suffering on a hellish planet. He was crying out in anguish, \"O son, please deliver me from the torment of this hellish condition!\" Now I have no peace in my mind, and even this beautiful kingdom has become unbearable to me. Please tell me what kind of charity, what mode of fasting, what austerity, or what deep meditation must I perform to deliver my father?\'\"
      </p>
      
      <blockquote style=\"border-left:4px solid var(--maroon); padding-left:var(--space-md); font-style:italic; color:var(--dark); margin:var(--space-md) 0;\">
        \"The learned brahmins replied, \'O king, in the mountainous forest not far from here is the ashram of the great saint Parvata Muni. Please go to him, for he is tri-kala-jna (he knows the past, present, and future) and can surely guide you.\' The king immediately set out to the ashram of the famous sage.\"
      </blockquote>

      <h3 style=\"color:var(--primary); font-family:var(--font-heading); font-size:var(--font-size-xl); margin-top:var(--space-lg);\">The Grievous Sin Revealed</h3>
      <p>
        \"Approaching the holy ashram, the king beheld Parvata Muni seated among the assembly of sages. The king offered his humble obeisances, prostrating before him. After the king had seated himself, Parvata Muni closed his eyes and meditated on the king\'s father\'s past, present, and future. After a few moments, he opened his eyes and said: \'Your father is suffering the results of committing a great sin. In his previous life, he quarreled with his wife and forcibly enjoyed her sexually during her menstrual period. She tried to protest and resist, but he did not stop. It is on account of this grievous sin that your father has fallen into such a hellish condition of suffering.\'\"
      </p>
      
      <p>
        \"King Vaikhanasa asked, \'O greatest among sages, by what process of fasting or charity may I liberate my dear father?\'\"
      </p>
      
      <p>
        \"Parvata Muni replied, \'During the light fortnight of the month of Margashirsha, there occurs an Ekadasi called Moksada. If you observe this sacred Ekadasi strictly, with a full fast, and give directly to your suffering father the merit you thus attain, he will be freed from his pain and instantly liberated.\'\"
      </p>
      
      <p>
        \"Hearing this, Maharaj Vaikhanasa returned to his palace. When the tithi arrived, he and his family observed the Moksada Ekadasi fast with full devotion. He dutifully offered the merit to his father, and as he did, flower petals showered down from the demigods. The king\'s father was immediately escorted to the celestial regions. As he passed his son, the father said, \'My dear son, all auspiciousness unto you!\' At last he reached the heavenly realm, where he began to perform devotional service, returning in due course back to Godhead.\"
      </p>
      
      <p>
        Lord Sri Krishna concluded, \"O son of Pandu, whosoever strictly observes the sacred Moksada Ekadasi achieves full and perfect liberation after death. There is no better fasting day than this Ekadasi, for it is like cintamani, elevating souls from hellish life to the spiritual abode.\"
      </p>', NULL, NULL, NULL);
INSERT IGNORE INTO `donation_causes` (`id`, `slug`, `title`, `short_title`, `description`, `history`, `significance`, `benefits`, `category`, `subcategory`, `image_url`, `parent_cause_id`, `is_time_bound`, `start_date`, `end_date`, `allow_one_time`, `allow_monthly`, `default_mode`, `min_amount`, `form_type`, `sort_order`, `is_active`, `featured`, `page_type`, `page_slug`, `created_at`, `updated_at`, `content_body`, `quick_stats`, `meta_title`, `meta_description`) VALUES (74, 'support-our-digital-initiatives', 'Support Our Digital Initiatives', 'Digital Initiatives', 'Sponsor the temple\'s digital transformation — website, mobile app, live streaming, cloud infrastructure, and online preaching platforms that connect devotees worldwide.', 'In today\'s digital age, temples are embracing technology to spread Krishna consciousness far and wide. ISKCON temples worldwide have adopted digital tools — from live streaming deity darshan to mobile apps for seva booking — to serve the growing global community of devotees. Srila Prabhupada\'s vision of spreading Krishna consciousness to every town and village is now being realized through digital media, reaching millions who cannot physically visit the temple.', 'Digital initiatives are modern extensions of the timeless mission to spread the holy names. The Bhagavad-gita states that knowledge should be shared with all. Technology enables us to reach seekers across the globe — from a student in Tokyo watching live arati to a family in London participating in online prasadam distribution. These digital bridges connect hearts to the divine.', 'Sponsoring digital initiatives multiplies your service impact exponentially. A single live stream can reach thousands simultaneously. A well-designed app can help millions access spiritual content. Your contribution ensures that the temple\'s digital presence remains vibrant, secure, and accessible — bringing the mercy of the Lord to screens worldwide.', 'service', NULL, NULL, NULL, 0, NULL, NULL, 1, 1, 'one_time', 100.00, 'tiers', 15, 1, 1, 'service', 'support-our-digital-initiatives', '2026-07-03 23:19:19', '2026-07-03 23:19:19', NULL, NULL, NULL, NULL);

